import pc from 'picocolors'

export type OutputFormat = 'json' | 'text'

export function printResult(value: unknown, format: OutputFormat): void {
  if (format === 'json') {
    process.stdout.write(`${JSON.stringify(value, null, 2)}\n`)
    return
  }

  if (typeof value === 'string') {
    process.stdout.write(`${value}\n`)
    return
  }

  process.stdout.write(`${renderText(value)}\n`)
}

export function printError(error: Record<string, unknown>): void {
  process.stderr.write(`${pc.red('error')} ${String(error.message ?? 'Unknown error')}\n`)
  if (typeof error.code === 'string') {
    process.stderr.write(`${pc.dim('code')} ${error.code}\n`)
  }
  const detailText = renderErrorDetails(error)
  if (detailText !== '') {
    process.stderr.write(`${detailText}\n`)
  }
}

function renderText(value: unknown): string {
  if (value === null || typeof value !== 'object') {
    return String(value)
  }

  const resultKind = readResultKind(value)
  if (resultKind !== undefined) {
    const renderer = resultRenderers[resultKind]
    if (renderer !== undefined) {
      return renderer(value as Record<string, unknown>)
    }
  }

  if (isSystemDescription(value)) {
    return renderSystemDescription(value)
  }
  if (isSitesResult(value)) {
    return renderSites(value)
  }
  if (isWorkflowsResult(value)) {
    return renderWorkflows(value)
  }
  if (isEndpointsResult(value)) {
    return renderEndpoints(value)
  }
  if (isRecord(value) && isPackageVersionResult(value)) {
    const name = String(value.name ?? 'public-apis-cli')
    return `${name} ${String(value.version ?? '0.0.0')}`
  }

  const lines: string[] = []
  for (const [key, entryValue] of Object.entries(value)) {
    if (entryValue === null || typeof entryValue !== 'object') {
      lines.push(`${pc.bold(key)}: ${String(entryValue)}`)
    }
  }

  return lines.length > 0 ? lines.join('\n') : JSON.stringify(value, null, 2)
}

function renderExperimentalNewsFlashInstall(value: Record<string, unknown>): string {
  const checks = Array.isArray(value.checks) ? value.checks.filter(isRecord) : []
  const smokeRun = isRecord(value.smokeRun) ? value.smokeRun : {}
  const providerEnv = isRecord(value.providerEnv) ? value.providerEnv : {}
  const nextSteps = Array.isArray(value.nextSteps) ? value.nextSteps.map(String) : []
  const lines = [
    `${pc.bold('Experimental news flash monitor')} ${String(value.provider ?? 'unknown')}`,
    `${pc.dim('template')} ${String(value.templateDir ?? '')}`,
    `${pc.dim('label')} ${String(value.label ?? '')}`,
    `${pc.dim('plist')} ${String(value.plistPath ?? '')}`,
    `${pc.dim('interval')} ${String(value.intervalSeconds ?? '?')} seconds`,
    `${pc.dim('shell')} ${String(value.shellPath ?? '')}`,
    `${pc.dim('params')} ${formatNewsFlashProviderEnv(providerEnv)}`,
    `${pc.dim('installed')} ${String(value.installed ?? false)} · ${pc.dim('loaded')} ${String(value.loaded ?? false)} · ${pc.dim('dry run')} ${String(value.dryRun ?? false)}`,
    '',
    pc.bold('Preflight'),
  ]
  for (const check of checks) {
    lines.push(`${check.ok === true ? '✓' : '✗'} ${String(check.name ?? 'check')}: ${String(check.detail ?? '')}`)
  }
  lines.push('', pc.bold('Smoke Run'))
  lines.push(`${smokeRun.ok === true ? '✓' : '✗'} exit=${String(smokeRun.exitCode ?? '?')} duration=${String(smokeRun.durationMs ?? '?')}ms`)
  if (typeof smokeRun.stderrTail === 'string' && smokeRun.stderrTail.trim() !== '') {
    lines.push(`${pc.dim('stderr tail')} ${smokeRun.stderrTail.trim()}`)
  }
  if (nextSteps.length > 0) {
    lines.push('', pc.bold('Next'))
    for (const step of nextSteps) lines.push(`- ${step}`)
  }
  return lines.join('\n')
}

function isPackageVersionResult(value: Record<string, unknown>): boolean {
  return (
    value.kind === 'package.version' &&
    typeof value.name === 'string' &&
    typeof value.version === 'string'
  )
}

function renderExperimentalNewsFlashProviders(value: Record<string, unknown>): string {
  const providers = Array.isArray(value.providers) ? value.providers.filter(isRecord) : []
  const lines = [
    pc.bold('Experimental news flash providers'),
    pc.dim('Lifecycle: providers → doctor → run-once → install → status → uninstall'),
    '',
  ]
  for (const provider of providers) {
    const requiredEnv = Array.isArray(provider.requiredEnv) ? provider.requiredEnv.map(String) : []
    const parameters = Array.isArray(provider.parameters) ? provider.parameters.filter(isRecord) : []
    lines.push(`${pc.bold(String(provider.provider ?? 'unknown'))} ${pc.dim(String(provider.operation ?? ''))}`)
    lines.push(`  ${String(provider.description ?? '')}`)
    lines.push(`  ${pc.dim('keys')} ${requiredEnv.length === 0 ? 'none' : requiredEnv.join(', ')}`)
    lines.push(`  ${pc.dim('params')} ${parameters.length === 0 ? 'none' : parameters.slice(0, 8).map(parameter => String(parameter.option ?? '')).join(', ')}`)
    lines.push(`  ${pc.dim('try')} public-apis experimental news-flash doctor --provider ${String(provider.provider ?? 'provider')}`)
  }
  return lines.join('\n')
}

function renderExperimentalNewsFlashDoctor(value: Record<string, unknown>): string {
  const checks = Array.isArray(value.checks) ? value.checks.filter(isRecord) : []
  const providerEnv = isRecord(value.providerEnv) ? value.providerEnv : {}
  const nextSteps = Array.isArray(value.nextSteps) ? value.nextSteps.map(String) : []
  const lines = [
    `${pc.bold('News flash doctor')} ${String(value.provider ?? 'unknown')} · ${value.ok === true ? pc.green('ready') : pc.yellow('needs attention')}`,
    `${pc.dim('template')} ${String(value.templateDir ?? '')}`,
    `${pc.dim('shell')} ${String(value.shellPath ?? '')}`,
    `${pc.dim('params')} ${formatNewsFlashProviderEnv(providerEnv)}`,
    '',
    pc.bold('Checks'),
  ]
  for (const check of checks) {
    lines.push(`${check.ok === true ? '✓' : '✗'} ${String(check.name ?? 'check')}: ${String(check.detail ?? '')}`)
  }
  if (nextSteps.length > 0) {
    lines.push('', pc.bold('Next'))
    for (const step of nextSteps) lines.push(`- ${step}`)
  }
  return lines.join('\n')
}

function renderExperimentalNewsFlashRunOnce(value: Record<string, unknown>): string {
  const smokeRun = isRecord(value.smokeRun) ? value.smokeRun : {}
  const providerEnv = isRecord(value.providerEnv) ? value.providerEnv : {}
  const nextSteps = Array.isArray(value.nextSteps) ? value.nextSteps.map(String) : []
  const lines = [
    `${pc.bold('News flash run-once')} ${String(value.provider ?? 'unknown')} · ${value.ok === true ? pc.green('complete') : pc.yellow('failed')}`,
    `${pc.dim('template')} ${String(value.templateDir ?? '')}`,
    `${pc.dim('shell')} ${String(value.shellPath ?? '')}`,
    `${pc.dim('params')} ${formatNewsFlashProviderEnv(providerEnv)}`,
    `${pc.dim('run')} exit=${String(smokeRun.exitCode ?? '?')} duration=${String(smokeRun.durationMs ?? '?')}ms`,
  ]
  if (typeof smokeRun.stderrTail === 'string' && smokeRun.stderrTail.trim() !== '') {
    lines.push(`${pc.dim('stderr tail')} ${smokeRun.stderrTail.trim()}`)
  }
  if (nextSteps.length > 0) {
    lines.push('', pc.bold('Next'))
    for (const step of nextSteps) lines.push(`- ${step}`)
  }
  return lines.join('\n')
}

function formatNewsFlashProviderEnv(providerEnv: Record<string, unknown>): string {
  const entries = Object.entries(providerEnv)
    .filter(([, value]) => typeof value === 'string')
    .sort(([left], [right]) => left.localeCompare(right))
  return entries.length === 0 ? 'default' : entries.map(([name, value]) => `${name}=${String(value)}`).join(' ')
}

function renderExperimentalNewsFlashStatus(value: Record<string, unknown>): string {
  const monitors = Array.isArray(value.monitors) ? value.monitors.filter(isRecord) : []
  const nextSteps = Array.isArray(value.nextSteps) ? value.nextSteps.map(String) : []
  const lines = [pc.bold('News flash monitor status')]
  for (const monitor of monitors) {
    lines.push('')
    lines.push(`${pc.bold(String(monitor.provider ?? 'unknown'))} ${String(monitor.label ?? '')}`)
    lines.push(`  ${pc.dim('plist')} ${String(monitor.plistPath ?? '')}`)
    lines.push(`  ${pc.dim('installed')} ${String(monitor.installed ?? false)} · ${pc.dim('loaded')} ${String(monitor.loaded ?? false)}`)
    lines.push(`  ${pc.dim('latest')} ${String(monitor.latestSummaryExists ?? false)} · ${String(monitor.latestSummaryPath ?? '')}`)
    if (typeof monitor.latestSummaryModifiedAt === 'string') {
      lines.push(`  ${pc.dim('modified')} ${monitor.latestSummaryModifiedAt}`)
    }
  }
  if (nextSteps.length > 0) {
    lines.push('', pc.bold('Next'))
    for (const step of nextSteps) lines.push(`- ${step}`)
  }
  return lines.join('\n')
}

function renderExperimentalNewsFlashUninstall(value: Record<string, unknown>): string {
  const nextSteps = Array.isArray(value.nextSteps) ? value.nextSteps.map(String) : []
  const lines = [
    `${pc.bold('News flash uninstall')} ${String(value.provider ?? 'unknown')}`,
    `${pc.dim('label')} ${String(value.label ?? '')}`,
    `${pc.dim('plist')} ${String(value.plistPath ?? '')}`,
    `${pc.dim('removed')} ${String(value.removed ?? false)} · ${pc.dim('unloaded')} ${String(value.unloaded ?? false)}`,
  ]
  if (nextSteps.length > 0) {
    lines.push('', pc.bold('Next'))
    for (const step of nextSteps) lines.push(`- ${step}`)
  }
  return lines.join('\n')
}

function renderErrorDetails(error: Record<string, unknown>): string {
  const details = isRecord(error.details) ? error.details : {}
  const lines: string[] = []
  const provider = typeof details.provider === 'string' ? details.provider : undefined
  const checks = Array.isArray(details.checks) ? details.checks.filter(isRecord) : []
  if (checks.length > 0) {
    lines.push(pc.bold('Failed Checks'))
    for (const check of checks) {
      lines.push(`- ${String(check.name ?? 'check')}: ${redactSensitiveText(String(check.detail ?? ''))}`)
    }
    lines.push(provider === undefined
      ? '- Next: rerun the matching `news-flash doctor --provider <provider>` command after fixing these checks.'
      : `- Next: public-apis experimental news-flash doctor --provider ${provider}`)
  }

  if (isRecord(details.smokeRun)) {
    lines.push(...renderProcessFailure('Smoke Run', details.smokeRun))
    if (provider !== undefined) {
      lines.push(`- Next: public-apis experimental news-flash run-once --provider ${provider} --run-timeout-ms 300000`)
    }
  }

  for (const key of ['bootstrap', 'bootout', 'retry']) {
    const value = details[key]
    if (isRecord(value)) {
      lines.push(...renderProcessFailure(`launchctl ${key}`, value))
    }
  }

  if (typeof details.plistPath === 'string') {
    lines.push(`${pc.dim('plist')} ${redactSensitiveText(details.plistPath)}`)
  }
  return lines.join('\n')
}

function renderProcessFailure(title: string, value: Record<string, unknown>): string[] {
  const lines = [
    pc.bold(title),
    `- exit: ${String(value.exitCode ?? '?')}`,
  ]
  const stderr = typeof value.stderrTail === 'string' ? value.stderrTail : typeof value.stderr === 'string' ? value.stderr : ''
  const stdout = typeof value.stdoutTail === 'string' ? value.stdoutTail : typeof value.stdout === 'string' ? value.stdout : ''
  if (stderr.trim() !== '') lines.push(`- stderr: ${redactSensitiveText(stderr.trim())}`)
  if (stdout.trim() !== '') lines.push(`- stdout: ${redactSensitiveText(stdout.trim())}`)
  return lines
}

function redactSensitiveText(value: string): string {
  return value
    .replace(/\b(sk-[A-Za-z0-9_-]{8,})\b/gu, '<redacted>')
    .replace(/\b(ctx7sk-[A-Za-z0-9_-]{8,})\b/gu, '<redacted>')
    .replace(/\b(Bearer)\s+[A-Za-z0-9._~+/-]+=*/giu, '$1 <redacted>')
    .replace(/\b(ANTHROPIC_API_KEY|ANTHROPIC_BASE_URL|LITELLM_MASTER_KEY|LITELLM_API_KEY|LITELLM_BASE_URL|LITELLM_API_BASE|NEWSAPI_API_KEY|GNEWS_API_KEY|api[_-]?key|token|authorization)\s*[:=]\s*[^,;\s]+/giu, '$1=<redacted>')
    .replace(/https?:\/\/[^/\s:@]+:[^/\s@]+@/gu, 'https://<redacted>@')
}

