function readResultKind(value: unknown): string | undefined {
  if (!isRecord(value)) {
    return undefined
  }

  return typeof value.kind === 'string' ? value.kind : undefined
}

function renderFourChanBoards(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const boards = Array.isArray(value.boards) ? value.boards.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('4chan Boards'))} ${pc.dim(String(api.endpoint ?? 'GET /boards.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? boards.length)} shown · total ${String(value.totalBoards ?? boards.length)} · limit cap ${String(api.limitCap ?? 150)}`,
    `${pc.dim('safety')} ${String(api.contentSafety ?? 'untrusted user-generated content rendered as plain text')}`,
  ]
  if (boards.length === 0) {
    lines.push('', pc.yellow('No 4chan boards matched this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run 4chan.boards -- --query technology --limit 20`)
    lines.push(`${pc.dim('again')} ${buildFourChanBoardsCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildFourChanBoardsCommand(query, 'offline')}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const board of boards.slice(0, 30)) {
    lines.push(`${pc.bold(`/${String(board.board ?? '?')}/`)} ${String(board.title ?? 'untitled board')} · pages ${String(board.pages ?? '?')} · per page ${String(board.perPage ?? '?')}`)
    if (typeof board.metaDescription === 'string' && board.metaDescription.trim() !== '') {
      lines.push(`   ${truncateText(board.metaDescription.trim(), 140)}`)
    }
  }
  if (boards.length > 30) {
    lines.push(pc.dim(`… ${boards.length - 30} more board(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('open board')} ${buildFourChanCatalogCommand({ board: boards[0]?.board ?? 'g', limit: 20 })}`)
  lines.push(`${pc.dim('again')} ${buildFourChanBoardsCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildFourChanBoardsCommand(query, 'offline')}`)
  return lines.join('\n')
}

function buildFourChanBoardsCommand(query: Record<string, unknown>, mode: 'online' | 'offline'): string {
  const parts = ['public-apis apis run 4chan.boards', mode === 'online' ? '--online --persist' : '--offline', '--']
  if (typeof query.query === 'string' && query.query.trim() !== '') {
    parts.push(`--query ${formatCliArg(query.query)}`)
  }
  parts.push(`--limit ${formatCliArg(query.limit ?? 150)}`)
  return parts.join(' ')
}

function renderFourChanCatalog(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const threads = Array.isArray(value.threads) ? value.threads.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('4chan Catalog'))} ${pc.dim(String(api.endpoint ?? 'GET /{board}/catalog.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? threads.length)} returned · total ${String(pagination.totalThreads ?? threads.length)} · pages ${String(pagination.pageCount ?? '?')} · limit ${String(pagination.limit ?? query.limit ?? '?')} / max ${String(pagination.maxLimit ?? '?')}`,
    `${pc.dim('safety')} ${String(api.contentSafety ?? 'untrusted user-generated content rendered as plain text')}`,
  ]
  if (threads.length === 0) {
    lines.push('', pc.yellow('No 4chan catalog threads returned for this board.'))
    lines.push(`${pc.dim('try')} public-apis apis run 4chan.catalog -- --board g --limit 20`)
    lines.push(`${pc.dim('again')} ${buildFourChanCatalogCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildFourChanCatalogCommand(query, 'offline')}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const thread of threads.slice(0, 20)) {
    const title = typeof thread.subject === 'string' && thread.subject.trim() !== '' ? thread.subject : `thread #${String(thread.no ?? '?')}`
    const state = [thread.sticky === true ? 'sticky' : undefined, thread.closed === true ? 'closed' : undefined].filter(Boolean).join(', ')
    lines.push(`${pc.bold(truncateText(title, 100))} ${pc.dim(`#${String(thread.no ?? '-')}${state ? ` · ${state}` : ''}`)}`)
    lines.push(`   replies ${String(thread.replies ?? 0)} · images ${String(thread.images ?? 0)} · ${String(thread.now ?? 'unknown time')}`)
    if (typeof thread.comment === 'string' && thread.comment.trim() !== '') {
      lines.push(`   ${truncateText(thread.comment.trim(), 180)}`)
    }
    if (typeof thread.url === 'string' && thread.url.trim() !== '') {
      lines.push(`   ${pc.blue(thread.url)}`)
    }
  }
  if (threads.length > 20) {
    lines.push(pc.dim(`… ${threads.length - 20} more thread(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} ${buildFourChanCatalogCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildFourChanCatalogCommand(query, 'offline')}`)
  lines.push(`${pc.dim('boards')} ${buildFourChanBoardsCommand({ limit: 20 }, 'online')}`)
  return lines.join('\n')
}

function buildFourChanCatalogCommand(query: Record<string, unknown>, mode?: 'online' | 'offline'): string {
  const parts = ['public-apis apis run 4chan.catalog']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--', `--board ${formatCliArg(query.board ?? 'g')}`, `--limit ${formatCliArg(query.limit ?? 150)}`)
  return parts.join(' ')
}


function renderAdminDivisionsCountry(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const divisions = Array.isArray(value.divisions) ? value.divisions.map(String) : []
  const country = isRecord(value.country) && typeof value.country.code === 'string' ? value.country.code : String(query.country ?? '?')
  const lines = [
    `${pc.bold(pc.cyan('Administrative Divisions'))} ${pc.dim(String(api.endpoint ?? 'GET /api/{country}.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('country')} ${country} · ${String(pagination.returned ?? divisions.length)} shown / ${String(pagination.total ?? divisions.length)} total · limit ${String(pagination.limit ?? query.limit ?? divisions.length)} / ${String(pagination.maxLimit ?? 500)}`,
    `${pc.dim('source')} ${String(api.dataSource ?? 'GitHub-hosted administrative-divisions-db JSON files')}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'GitHub raw/cache limits may apply')}`,
  ]
  if (divisions.length === 0) {
    lines.push('', pc.yellow('No administrative divisions returned for this country.'))
    lines.push(`${pc.dim('try')} public-apis apis run admindivisions.country -- --country KE --limit 100`)
    return lines.join('\n')
  }
  lines.push('')
  for (const division of divisions.slice(0, 50)) {
    lines.push(`- ${division}`)
  }
  if (divisions.length > 50) {
    lines.push(pc.dim(`… ${divisions.length - 50} more division(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} ${buildAdminDivisionsCountryCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildAdminDivisionsCountryCommand(query, 'offline')}`)
  if (country !== 'US') {
    lines.push(`${pc.dim('us')} public-apis apis run admindivisions.country --online --persist -- --country US --limit ${formatCliArg(query.limit ?? 100)}`)
  }
  if (country !== 'KE') {
    lines.push(`${pc.dim('ke')} public-apis apis run admindivisions.country --online --persist -- --country KE --limit ${formatCliArg(query.limit ?? 100)}`)
  }
  return lines.join('\n')
}

function buildAdminDivisionsCountryCommand(query: Record<string, unknown>, mode?: 'online' | 'offline'): string {
  const parts = ['public-apis apis run admindivisions.country']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--', `--country ${formatCliArg(query.country ?? 'KE')}`, `--limit ${formatCliArg(query.limit ?? 100)}`)
  return parts.join(' ')
}

function renderAdresseSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const results = Array.isArray(value.results) ? value.results.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('adresse.data.gouv.fr Search'))} ${pc.dim(String(api.endpoint ?? 'GET /geocodage/search'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? results.length)} returned · limit ${String(pagination.limit ?? query.limit ?? 10)} / ${String(pagination.maxLimit ?? 50)}`,
    `${pc.dim('rate')} ${String(rateLimit.documented ?? '1 request/second observed; 50 result maximum')}`,
    `${pc.dim('privacy')} ${String(api.privacy ?? 'Address queries may reveal locations; persistence is opt-in.')}`,
    `${pc.dim('migration')} ${String(api.migration ?? 'Legacy api-adresse.data.gouv.fr host is deprecated; data.geopf.fr/geocodage is used.')}`,
  ]
  appendAdresseResults(lines, results)
  if (results.length === 0) {
    lines.push('', pc.yellow('No French address candidates returned for this query.'))
    lines.push(`${pc.dim('again')} ${buildAdresseSearchCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildAdresseSearchCommand(query, 'offline')}`)
    lines.push(`${pc.dim('broaden')} ${buildAdresseSearchCommand({ query: '8 bd du port', limit: 10 }, 'online')}`)
    return lines.join('\n')
  }
  lines.push('', `${pc.dim('again')} ${buildAdresseSearchCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildAdresseSearchCommand(query, 'offline')}`)
  const first = results[0]
  if (isRecord(first?.coordinates)) {
    lines.push(`${pc.dim('reverse')} public-apis apis run adresse.reverse --online --persist -- --latitude ${formatCliArg(first.coordinates.latitude ?? 48.357)} --longitude ${formatCliArg(first.coordinates.longitude ?? 2.37)} --limit 5`)
  }
  return lines.join('\n')
}

function renderAdresseReverse(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const results = Array.isArray(value.results) ? value.results.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('adresse.data.gouv.fr Reverse'))} ${pc.dim(String(api.endpoint ?? 'GET /geocodage/reverse'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? results.length)} returned · limit ${String(pagination.limit ?? query.limit ?? 10)} / ${String(pagination.maxLimit ?? 50)}`,
    `${pc.dim('rate')} ${String(rateLimit.documented ?? '1 request/second observed; 50 result maximum')}`,
    `${pc.dim('privacy')} ${String(api.privacy ?? 'Reverse geocoding coordinates may reveal locations; persistence is opt-in.')}`,
    `${pc.dim('migration')} ${String(api.migration ?? 'Legacy api-adresse.data.gouv.fr host is deprecated; data.geopf.fr/geocodage is used.')}`,
  ]
  appendAdresseResults(lines, results)
  if (results.length === 0) {
    lines.push('', pc.yellow('No French reverse-geocoding candidates returned for these coordinates.'))
    lines.push(`${pc.dim('again')} ${buildAdresseReverseCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildAdresseReverseCommand(query, 'offline')}`)
    lines.push(`${pc.dim('try')} ${buildAdresseReverseCommand({ latitude: 48.357, longitude: 2.37, limit: 10 }, 'online')}`)
    return lines.join('\n')
  }
  lines.push('', `${pc.dim('again')} ${buildAdresseReverseCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildAdresseReverseCommand(query, 'offline')}`)
  const firstLabel = typeof results[0]?.label === 'string' ? results[0].label : '8 bd du port'
  lines.push(`${pc.dim('search')} public-apis apis run adresse.search --online --persist -- --query ${formatCliArg(firstLabel)} --limit 5`)
  return lines.join('\n')
}

function appendAdresseResults(lines: string[], results: Record<string, unknown>[]): void {
  if (results.length === 0) {
    return
  }
  lines.push('')
  for (const result of results.slice(0, 12)) {
    const coordinates = isRecord(result.coordinates) ? result.coordinates : {}
    const parts = [
      typeof result.type === 'string' ? result.type : undefined,
      typeof result.score === 'number' ? `score ${result.score.toFixed(3)}` : undefined,
      typeof result.distance === 'number' ? `${String(result.distance)}m` : undefined,
    ].filter((part): part is string => part !== undefined)
    lines.push(`- ${String(result.label ?? result.name ?? 'unnamed candidate')}${parts.length > 0 ? ` · ${parts.join(' · ')}` : ''}`)
    const details = [
      typeof result.city === 'string' ? result.city : undefined,
      typeof result.postcode === 'string' ? result.postcode : undefined,
      typeof result.context === 'string' ? result.context : undefined,
    ].filter((part): part is string => part !== undefined)
    if (details.length > 0) {
      lines.push(`  ${pc.dim(details.join(' · '))}`)
    }
    if (typeof coordinates.latitude === 'number' && typeof coordinates.longitude === 'number') {
      lines.push(`  ${pc.dim('coords')} ${String(coordinates.latitude)}, ${String(coordinates.longitude)}`)
    }
  }
  if (results.length > 12) {
    lines.push(pc.dim(`… ${results.length - 12} more candidate(s); use --format json for full output.`))
  }
}

function buildAdresseSearchCommand(query: Record<string, unknown>, mode?: 'online' | 'offline'): string {
  const parts = ['public-apis apis run adresse.search']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--', `--query ${formatCliArg(query.query ?? '8 bd du port')}`, `--limit ${formatCliArg(query.limit ?? 10)}`)
  if (typeof query.latitude === 'number' && typeof query.longitude === 'number') {
    parts.push(`--latitude ${formatCliArg(query.latitude)}`, `--longitude ${formatCliArg(query.longitude)}`)
  }
  if (typeof query.postcode === 'string') {
    parts.push(`--postcode ${formatCliArg(query.postcode)}`)
  }
  if (typeof query.citycode === 'string') {
    parts.push(`--citycode ${formatCliArg(query.citycode)}`)
  }
  if (typeof query.type === 'string') {
    parts.push(`--type ${formatCliArg(query.type)}`)
  }
  return parts.join(' ')
}

function buildAdresseReverseCommand(query: Record<string, unknown>, mode?: 'online' | 'offline'): string {
  const parts = ['public-apis apis run adresse.reverse']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--', `--latitude ${formatCliArg(query.latitude ?? 48.357)}`, `--longitude ${formatCliArg(query.longitude ?? 2.37)}`, `--limit ${formatCliArg(query.limit ?? 10)}`)
  if (typeof query.type === 'string') {
    parts.push(`--type ${formatCliArg(query.type)}`)
  }
  return parts.join(' ')
}

function renderBdApisDivisions(value: Record<string, unknown>): string {
  const divisions = Array.isArray(value.divisions) ? value.divisions.filter(isRecord) : []
  return renderBdApisCollection(value, 'BdAPIs Divisions', 'GET /api/v1.2/divisions', 'division', divisions, buildBdApisListCommand('bdapis.divisions', isRecord(value.query) ? value.query : {}))
}

function renderBdApisDistricts(value: Record<string, unknown>): string {
  const districts = Array.isArray(value.districts) ? value.districts.filter(isRecord) : []
  return renderBdApisCollection(value, 'BdAPIs Districts', 'GET /api/v1.2/districts', 'district', districts, buildBdApisListCommand('bdapis.districts', isRecord(value.query) ? value.query : {}))
}

function renderBdApisDivision(value: Record<string, unknown>): string {
  const query = isRecord(value.query) ? value.query : {}
  const districts = Array.isArray(value.districts) ? value.districts.filter(isRecord) : []
  return renderBdApisCollection(value, `BdAPIs Division ${String(query.division ?? '')}`.trim(), 'GET /api/v1.2/division/{division}', 'district', districts, buildBdApisDivisionCommand(query))
}

function renderBdApisDistrict(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const district = isRecord(value.district) ? value.district : undefined
  const lines = [
    `${pc.bold(pc.cyan('BdAPIs District'))} ${pc.dim(String(api.endpoint ?? 'GET /api/v1.2/district/{district}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('rate')} ${String(rateLimit.observed ?? 'RateLimit-Policy: 100;w=900 observed')}`,
    `${pc.dim('version')} ${String(api.version ?? 'v1.2')} · ${String(api.source ?? 'Bangladesh administrative geography JSON')}`,
  ]
  if (district === undefined) {
    lines.push('', pc.yellow('No BdAPIs district returned for this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run bdapis.district -- --district dhaka`)
    return lines.join('\n')
  }
  lines.push('')
  appendBdApisDistrict(lines, district)
  lines.push('', `${pc.dim('again')} ${buildBdApisDistrictCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildBdApisDistrictCommand(query, 'offline')}`)
  lines.push(`${pc.dim('all districts')} public-apis apis run bdapis.districts --online --persist -- --limit 64`)
  return lines.join('\n')
}

function renderBdApisCollection(value: Record<string, unknown>, title: string, fallbackEndpoint: string, itemLabel: string, items: Record<string, unknown>[], command: string): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const lines = [
    `${pc.bold(pc.cyan(title))} ${pc.dim(String(api.endpoint ?? fallbackEndpoint))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? items.length)} returned · limit ${String(pagination.limit ?? query.limit ?? 64)} / ${String(pagination.maxLimit ?? 64)}`,
    `${pc.dim('rate')} ${String(rateLimit.observed ?? 'RateLimit-Policy: 100;w=900 observed')}`,
    `${pc.dim('version')} ${String(api.version ?? 'v1.2')} · ${String(api.source ?? 'Bangladesh administrative geography JSON')}`,
  ]
  if (items.length === 0) {
    lines.push('', pc.yellow(`No BdAPIs ${itemLabel} rows returned for this query.`))
    lines.push(`${pc.dim('try')} ${command}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const item of items.slice(0, 20)) {
    if (itemLabel === 'division') {
      appendBdApisDivision(lines, item)
    } else {
      appendBdApisDistrict(lines, item)
    }
  }
  if (items.length > 20) {
    lines.push(pc.dim(`… ${items.length - 20} more ${itemLabel}(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} ${withBdApisMode(command, 'online')}`)
  lines.push(`${pc.dim('replay')} ${withBdApisMode(command, 'offline')}`)
  if (itemLabel === 'division') {
    lines.push(`${pc.dim('division')} public-apis apis run bdapis.division --online --persist -- --division dhaka --limit 64`)
  } else {
    lines.push(`${pc.dim('district')} public-apis apis run bdapis.district --online --persist -- --district dhaka`)
  }
  return lines.join('\n')
}

function appendBdApisDivision(lines: string[], division: Record<string, unknown>): void {
  const coordinates = isRecord(division.coordinates) ? division.coordinates : {}
  lines.push(`- ${String(division.division ?? 'unknown division')}${typeof division.divisionbn === 'string' ? ` · ${division.divisionbn}` : ''}`)
  if (typeof coordinates.latitude === 'number' && typeof coordinates.longitude === 'number') {
    lines.push(`  ${pc.dim('coords')} ${String(coordinates.latitude)}, ${String(coordinates.longitude)}`)
  }
}

function appendBdApisDistrict(lines: string[], district: Record<string, unknown>): void {
  const coordinates = isRecord(district.coordinates) ? district.coordinates : {}
  const upazillas = Array.isArray(district.upazillas) ? district.upazillas.map(String) : []
  lines.push(`- ${String(district.district ?? 'unknown district')}${typeof district.districtbn === 'string' ? ` · ${district.districtbn}` : ''}`)
  const details: string[] = []
  if (typeof coordinates.latitude === 'number' && typeof coordinates.longitude === 'number') {
    details.push(`coords ${String(coordinates.latitude)}, ${String(coordinates.longitude)}`)
  }
  details.push(`${String(upazillas.length)} upazilla(s)`)
  lines.push(`  ${pc.dim(details.join(' · '))}`)
  if (upazillas.length > 0) {
    lines.push(`  ${upazillas.slice(0, 10).join(', ')}${upazillas.length > 10 ? `, … ${upazillas.length - 10} more` : ''}`)
  }
}

function buildBdApisListCommand(operation: 'bdapis.divisions' | 'bdapis.districts', query: Record<string, unknown>): string {
  return `public-apis apis run ${operation} -- --limit ${formatCliArg(query.limit ?? 64)}`
}

function buildBdApisDivisionCommand(query: Record<string, unknown>): string {
  return `public-apis apis run bdapis.division -- --division ${formatCliArg(query.division ?? 'dhaka')} --limit ${formatCliArg(query.limit ?? 64)}`
}

function buildBdApisDistrictCommand(query: Record<string, unknown>, mode?: 'online' | 'offline'): string {
  const parts = ['public-apis apis run bdapis.district']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--', `--district ${formatCliArg(query.district ?? 'dhaka')}`)
  return parts.join(' ')
}

function withBdApisMode(command: string, mode: 'online' | 'offline'): string {
  return command.replace(' -- ', mode === 'online' ? ' --online --persist -- ' : ' --offline -- ')
}

function renderBng2LatLongConvert(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const bounds = isRecord(value.bounds) ? value.bounds : {}
  const conversion = isRecord(value.conversion) ? value.conversion : {}
  const lines = [
    `${pc.bold(pc.cyan('bng2latlong Convert'))} ${pc.dim(String(api.endpoint ?? 'GET /bng2latlong/{easting}/{northing}/json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('system')} ${String(bounds.coordinateSystem ?? 'British National Grid OSGB36 to WGS84')}`,
    `${pc.dim('bounds')} easting 1-${String(bounds.maxEasting ?? 999999)} · northing 1-${String(bounds.maxNorthing ?? 9999999)}`,
    `${pc.dim('note')} ${String(api.note ?? 'JSON API host is consumed directly.')}`,
  ]
  if (typeof conversion.latitude !== 'number' || typeof conversion.longitude !== 'number') {
    lines.push('', pc.yellow('No coordinate conversion returned.'))
    lines.push(`${pc.dim('try')} public-apis apis run bng2latlong.convert -- --easting 319421 --northing 174588`)
    return lines.join('\n')
  }
  lines.push('')
  lines.push(`${pc.bold('WGS84')} ${String(conversion.latitude)}, ${String(conversion.longitude)}`)
  lines.push(`${pc.dim('input')} easting ${String(conversion.easting ?? query.easting)} · northing ${String(conversion.northing ?? query.northing)}`)
  lines.push('', `${pc.dim('again')} ${buildBng2LatLongCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildBng2LatLongCommand(query, 'offline')}`)
  return lines.join('\n')
}

function buildBng2LatLongCommand(query: Record<string, unknown>, mode?: 'online' | 'offline'): string {
  const parts = ['public-apis apis run bng2latlong.convert']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--', `--easting ${formatCliArg(query.easting ?? 319421)}`, `--northing ${formatCliArg(query.northing ?? 174588)}`)
  return parts.join(' ')
}

function renderCountryIsLookup(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const privacy = isRecord(value.privacy) ? value.privacy : {}
  const lookup = isRecord(value.lookup) ? value.lookup : {}
  const location = isRecord(lookup.location) ? lookup.location : {}
  const asn = isRecord(lookup.asn) ? lookup.asn : {}
  const lines = [
    `${pc.bold(pc.cyan('Country.is Lookup'))} ${pc.dim(String(api.endpoint ?? 'GET /{ip?}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('country')} ${String(lookup.country ?? '?')} · ip ${String(lookup.ip ?? query.ip ?? '?')}`,
    `${pc.dim('privacy')} ${String(privacy.note ?? 'IP geolocation can reveal approximate location and network identity.')}`,
    `${pc.dim('cache')} ${String(api.cache ?? 'Specific IP lookups are cacheable upstream for about 3600 seconds.')}`,
  ]
  if (query.includeDetails === true) {
    lines.push(`${pc.dim('details')} city ${String(lookup.city ?? '-')} · continent ${String(lookup.continent ?? '-')} · subdivision ${String(lookup.subdivision ?? '-')} · postal ${String(lookup.postal ?? '-')}`)
    if (typeof location.latitude === 'number' && typeof location.longitude === 'number') {
      lines.push(`${pc.dim('location')} ${String(location.latitude)}, ${String(location.longitude)} · radius ${String(location.accuracyRadius ?? '?')}km · ${String(location.timeZone ?? '-')}`)
    }
    if (typeof asn.number === 'number' || typeof asn.organization === 'string') {
      lines.push(`${pc.dim('asn')} AS${String(asn.number ?? '?')} · ${String(asn.organization ?? '-')}`)
    }
  }
  lines.push('', `${pc.dim('again')} ${buildCountryIsLookupCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildCountryIsLookupCommand(query, 'offline')}`)
  lines.push(`${pc.dim('info')} public-apis apis run countryis.info --online --persist`)
  return lines.join('\n')
}

