function buildAviationWeatherCommand(operation: 'aviationweather.metar' | 'aviationweather.taf', query: Record<string, unknown>, mode?: 'online' | 'offline'): string {
  const parts = [`public-apis apis run ${operation}`]
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  for (const key of operation === 'aviationweather.metar' ? ['ids', 'hours', 'limit'] : ['ids', 'limit']) {
    if (query[key] !== undefined) {
      parts.push(`--${key} ${formatCliArg(query[key])}`)
    }
  }
  return parts.join(' ')
}

function renderAgifyAge(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const prediction = isRecord(value.prediction) ? value.prediction : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const count = typeof prediction.count === 'number' ? prediction.count : 0
  const countrySuffix = typeof prediction.countryId === 'string' ? ` in ${prediction.countryId}` : ''
  const nextCommand = buildAgifyCommand({
    name: typeof query.name === 'string' ? query.name : 'anna',
    countryId: typeof query.countryId === 'string' ? query.countryId : 'US',
  })
  const compareCommand = buildAgifyCompareCommand({
    name: typeof query.name === 'string' ? query.name : 'anna',
    countryId: typeof query.countryId === 'string' ? query.countryId : undefined,
  })
  const lines = [
    `${pc.bold(pc.cyan('Agify Age Prediction'))} ${pc.dim(String(api.endpoint ?? 'GET /?name={name}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('free')} ${String(api.freeRateLimit ?? '100 requests/day unauthenticated')}`,
    `${pc.dim('rate')} ${formatAgifyRateLimit(rateLimit)}`,
    '',
    `${pc.bold(String(prediction.name ?? query.name ?? 'name'))} estimated age ${String(prediction.age ?? 'unknown')} from ${formatInteger(count)} sample(s)${countrySuffix}`,
    `${pc.dim('confidence')} ${formatAgifyConfidence(prediction.age, count)}`,
    '',
    `${pc.dim('again')} ${nextCommand}`,
    `${pc.dim('compare')} ${compareCommand}`,
  ]
  return lines.join('\n')
}

function renderArbeitnowJobs(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const jobs = Array.isArray(value.jobs) ? value.jobs.filter(isRecord) : []
  const page = readArbeitnowPage(query, pagination)
  const visaSponsorship = typeof query.visaSponsorship === 'boolean' ? query.visaSponsorship : undefined
  const lines = [
    `${pc.bold(pc.cyan('Arbeitnow Jobs'))} ${pc.dim(String(api.endpoint ?? 'GET /api/job-board-api'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${String(page)} · ${String(pagination.returned ?? jobs.length)} returned · page size ${String(pagination.pageSize ?? api.defaultPageSize ?? 100)}`,
    `${pc.dim('rate')} remaining ${String(rateLimit.remaining ?? '?')} / ${String(rateLimit.limit ?? '?')} · ${String(api.rateLimitPolicy ?? 'respect the free public API')}`,
  ]
  if (typeof api.parameterPolicy === 'string') {
    lines.push(`${pc.dim('params')} ${api.parameterPolicy}`)
  }
  if (jobs.length === 0) {
    lines.push('', pc.yellow('No Arbeitnow jobs returned for this query.'))
    lines.push(`${pc.dim('again')} ${buildArbeitnowJobsCommand({ page, visaSponsorship }, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildArbeitnowJobsCommand({ page, visaSponsorship }, 'offline')}`)
    lines.push(`${pc.dim('all jobs')} ${buildArbeitnowJobsCommand({ page: 1 }, 'online')}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const job of jobs.slice(0, 12)) {
    const tags = Array.isArray(job.tags) ? job.tags.filter((entry): entry is string => typeof entry === 'string').slice(0, 3).join(', ') : ''
    const jobTypes = Array.isArray(job.jobTypes) ? job.jobTypes.filter((entry): entry is string => typeof entry === 'string').slice(0, 3).join(', ') : ''
    const flags = [
      job.remote === true ? 'remote' : undefined,
      job.visaSponsorship === true ? 'visa sponsorship' : undefined,
      typeof job.createdAtIso === 'string' ? job.createdAtIso.slice(0, 10) : undefined,
    ].filter((entry): entry is string => typeof entry === 'string')
    lines.push(`${pc.bold(String(job.title ?? 'untitled job'))} ${pc.dim(String(job.companyName ?? 'unknown company'))}`)
    lines.push(`   ${String(job.location ?? 'unknown location')} · ${flags.join(' · ') || 'onsite/unspecified'} · ${jobTypes || 'job type n/a'}`)
    if (tags !== '') {
      lines.push(`   ${pc.dim(`tags: ${tags}`)}`)
    }
    if (typeof job.descriptionText === 'string') {
      lines.push(`   ${truncateText(job.descriptionText, 140)}`)
    }
    if (typeof job.url === 'string') {
      lines.push(`   ${pc.blue(job.url)}`)
    }
  }
  if (jobs.length > 12) {
    lines.push(pc.dim(`… ${jobs.length - 12} more job(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} ${buildArbeitnowJobsCommand({ page, visaSponsorship }, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildArbeitnowJobsCommand({ page, visaSponsorship }, 'offline')}`)
  if (page > 1) {
    lines.push(`${pc.dim('prev page')} ${buildArbeitnowJobsCommand({ page: page - 1, visaSponsorship }, 'online')}`)
  }
  lines.push(`${pc.dim('next page')} ${buildArbeitnowJobsCommand({ page: page + 1, visaSponsorship }, 'online')}`)
  if (visaSponsorship === true) {
    lines.push(`${pc.dim('all jobs')} ${buildArbeitnowJobsCommand({ page: 1 }, 'online')}`)
  } else {
    lines.push(`${pc.dim('visa jobs')} ${buildArbeitnowJobsCommand({ page: 1, visaSponsorship: true }, 'online')}`)
  }
  return lines.join('\n')
}

function readArbeitnowPage(query: Record<string, unknown>, pagination: Record<string, unknown>): number {
  const page = Number(pagination.currentPage ?? query.page ?? 1)
  return Number.isInteger(page) && page > 0 ? page : 1
}

function buildArbeitnowJobsCommand(options: { page: number; visaSponsorship?: boolean | undefined }, mode: 'online' | 'offline'): string {
  const storageFlags = mode === 'online' ? '--online --persist' : '--offline'
  const parts = [`public-apis apis run arbeitnow.jobs ${storageFlags} -- --page ${String(options.page)}`]
  if (options.visaSponsorship !== undefined) {
    parts.push(`--visa-sponsorship ${String(options.visaSponsorship)}`)
  }
  return parts.join(' ')
}

function renderGenderizePredict(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const prediction = isRecord(value.prediction) ? value.prediction : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const probability = typeof prediction.probability === 'number' ? `${Math.round(prediction.probability * 100)}%` : 'unknown'
  const name = String(prediction.name ?? query.name ?? 'name')
  const countrySuffix = typeof prediction.countryId === 'string' ? ` in ${prediction.countryId}` : ''
  const lines = [
    `${pc.bold(pc.cyan('Genderize Prediction'))} ${pc.dim(String(api.endpoint ?? 'GET /?name={name}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('free')} ${String(api.freeRateLimit ?? '100 requests/day unauthenticated')}`,
    `${pc.dim('rate')} remaining ${String(rateLimit.remaining ?? '?')} / ${String(rateLimit.limit ?? '?')} · reset ${String(rateLimit.reset ?? '?')}`,
  ]
  if (prediction.gender === null || prediction.gender === undefined || prediction.count === 0) {
    lines.push(
      '',
      pc.yellow(`No reliable gender estimate found for ${name}${countrySuffix}.`),
      `${pc.dim('reason')} sample count ${String(prediction.count ?? 0)} · probability ${probability}`,
      `${pc.dim('try')} public-apis apis run genderize.predict -- --name ${formatCliArg(name)} --country-id US`,
      `${pc.dim('example')} public-apis apis run genderize.predict -- --name anna --country-id US`,
    )
    return lines.join('\n')
  }
  const nextCommand = typeof query.countryId === 'string'
    ? `public-apis apis run genderize.predict -- --name ${formatCliArg(name)}`
    : `public-apis apis run genderize.predict -- --name ${formatCliArg(name)} --country-id US`
  lines.push(
    '',
    `${pc.bold(name)} likely ${String(prediction.gender)} at ${probability} from ${String(prediction.count)} sample(s)${countrySuffix}`,
    '',
    `${pc.dim(typeof query.countryId === 'string' ? 'compare global' : 'compare country')} ${nextCommand}`,
    `${pc.dim('example')} public-apis apis run genderize.predict -- --name anna --country-id US`,
  )
  return lines.join('\n')
}


function renderGeoApiCommunes(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const communes = Array.isArray(value.communes) ? value.communes.filter(isRecord) : []
  const command = buildGeoApiCommunesCommand(query)
  const lines = [
    `${pc.bold(pc.cyan('GeoApi Communes'))} ${pc.dim(String(api.endpoint ?? 'GET /communes'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')} · ${String(api.owner ?? 'geo.api.gouv.fr')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('pagination')} returned ${String(pagination.returned ?? communes.length)} · limit ${String(pagination.limit ?? query.limit ?? '?')} · max ${String(pagination.maxLimit ?? '?')}`,
  ]

  if (communes.length === 0) {
    lines.push('', pc.yellow('No GeoApi communes matched this query.'))
    lines.push(`${pc.dim('again')} public-apis apis run geoapi.communes --online --persist -- ${command}`)
    lines.push(`${pc.dim('replay')} public-apis apis run geoapi.communes --offline -- ${command}`)
    lines.push(`${pc.dim('try')} public-apis apis run geoapi.communes --online --persist -- --query Paris --limit 10`)
    lines.push(`${pc.dim('postal')} public-apis apis run geoapi.communes --online --persist -- --postal-code 75001 --limit 10`)
    return lines.join('\n')
  }

  for (const commune of communes.slice(0, 25)) {
    const department = isRecord(commune.department) ? `${String(commune.department.code ?? '?')} ${String(commune.department.name ?? '')}` : '-'
    const region = isRecord(commune.region) ? `${String(commune.region.code ?? '?')} ${String(commune.region.name ?? '')}` : '-'
    const postalCodes = Array.isArray(commune.postalCodes) ? commune.postalCodes.slice(0, 6).map(String).join(', ') : '-'
    lines.push('', `${pc.bold(String(commune.name ?? 'commune'))} ${pc.dim(String(commune.code ?? ''))}`)
    lines.push(`${pc.dim('postal')} ${postalCodes}${Array.isArray(commune.postalCodes) && commune.postalCodes.length > 6 ? ', …' : ''} · ${pc.dim('population')} ${String(commune.population ?? '-')}`)
    lines.push(`${pc.dim('department')} ${department} · ${pc.dim('region')} ${region}`)
    if (typeof commune.latitude === 'number' && typeof commune.longitude === 'number') {
      lines.push(`${pc.dim('centre')} ${String(commune.latitude)}, ${String(commune.longitude)}`)
    }
  }
  if (communes.length > 25) {
    lines.push(pc.dim(`… ${communes.length - 25} more commune row(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} public-apis apis run geoapi.communes --online --persist -- ${command}`)
  lines.push(`${pc.dim('replay')} public-apis apis run geoapi.communes --offline -- ${command}`)
  lines.push(`${pc.dim('departments')} public-apis apis run geoapi.departments --online --persist -- --limit 10`)
  return lines.join('\n')
}

