function buildGeoApiCommunesCommand(query: Record<string, unknown>): string {
  const parts: string[] = []
  if (typeof query.query === 'string') parts.push(`--query ${formatCliArg(query.query)}`)
  if (typeof query.postalCode === 'string') parts.push(`--postal-code ${formatCliArg(query.postalCode)}`)
  if (typeof query.departmentCode === 'string') parts.push(`--department-code ${formatCliArg(query.departmentCode)}`)
  if (typeof query.regionCode === 'string') parts.push(`--region-code ${formatCliArg(query.regionCode)}`)
  parts.push(`--limit ${formatCliArg(query.limit ?? 10)}`)
  if (query.includeGeometry === true) parts.push('--include-geometry true')
  return parts.join(' ')
}

function buildGeoApiDepartmentsCommand(query: Record<string, unknown>): string {
  const parts: string[] = []
  if (typeof query.regionCode === 'string') parts.push(`--region-code ${formatCliArg(query.regionCode)}`)
  parts.push(`--limit ${formatCliArg(query.limit ?? 10)}`)
  return parts.join(' ')
}

function buildGeoApiRegionsCommand(query: Record<string, unknown>): string {
  return `--limit ${formatCliArg(query.limit ?? 10)}`
}

