function renderChroniclingAmericaSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const items = Array.isArray(value.items) ? value.items.filter(isRecord) : []
  const searchQuery = typeof query.query === 'string' && query.query.trim() !== '' ? query.query.trim() : 'lincoln'
  const count = readChroniclingAmericaCount(query, pagination)
  const page = readChroniclingAmericaPage(query, pagination)
  const dates = typeof query.dates === 'string' && query.dates.trim() !== '' ? query.dates.trim() : undefined
  const lines = [
    `${pc.bold(pc.cyan('Chronicling America Search'))} ${pc.dim(String(api.endpoint ?? 'GET /collections/chronicling-america/'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${String(page)} · ${String(pagination.returned ?? items.length)} returned · total ${formatInteger(pagination.total)} · count ${String(count)} / max ${String(pagination.maxCount ?? '?')}`,
    `${pc.dim('rate')} ${String(api.rateLimitPolicy ?? 'respect LOC API request guidance')}`,
  ]
  if (typeof api.migrationNote === 'string') {
    lines.push(`${pc.dim('api')} ${api.migrationNote}`)
  }
  if (items.length === 0) {
    lines.push('', pc.yellow('No Chronicling America newspaper results returned for this query.'))
    lines.push(`${pc.dim('again')} ${buildChroniclingAmericaSearchCommand({ query: searchQuery, count, page, dates }, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildChroniclingAmericaSearchCommand({ query: searchQuery, count, page, dates }, 'offline')}`)
    lines.push(`${pc.dim('try lincoln')} ${buildChroniclingAmericaSearchCommand({ query: 'lincoln', count: 20, page: 1 }, 'online')}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const item of items.slice(0, 12)) {
    const formats = Array.isArray(item.onlineFormats) ? item.onlineFormats.filter((entry): entry is string => typeof entry === 'string').slice(0, 3).join(', ') : ''
    const locations = Array.isArray(item.locations) ? item.locations.filter((entry): entry is string => typeof entry === 'string').slice(0, 3).join(', ') : ''
    const subjects = Array.isArray(item.subjects) ? item.subjects.filter((entry): entry is string => typeof entry === 'string').slice(0, 3).join(', ') : ''
    lines.push(`${pc.bold(String(item.title ?? 'untitled item'))} ${pc.dim(String(item.date ?? 'unknown date'))}`)
    lines.push(`   ${item.digitized === true ? 'digitized' : 'digitization unknown'} · ${formats || 'format n/a'} · ${locations || 'location n/a'}`)
    if (subjects !== '') {
      lines.push(`   ${pc.dim(`subjects: ${subjects}`)}`)
    }
    if (typeof item.description === 'string') {
      lines.push(`   ${truncateText(item.description, 160)}`)
    }
    if (typeof item.url === 'string') {
      lines.push(`   ${pc.blue(item.url)}`)
    }
  }
  if (items.length > 12) {
    lines.push(pc.dim(`… ${items.length - 12} more newspaper result(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} ${buildChroniclingAmericaSearchCommand({ query: searchQuery, count, page, dates }, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildChroniclingAmericaSearchCommand({ query: searchQuery, count, page, dates }, 'offline')}`)
  if (page > 1) {
    lines.push(`${pc.dim('prev page')} ${buildChroniclingAmericaSearchCommand({ query: searchQuery, count, page: page - 1, dates }, 'online')}`)
  }
  lines.push(`${pc.dim('next page')} ${buildChroniclingAmericaSearchCommand({ query: searchQuery, count, page: page + 1, dates }, 'online')}`)
  if (dates !== undefined) {
    lines.push(`${pc.dim('remove dates')} ${buildChroniclingAmericaSearchCommand({ query: searchQuery, count, page: 1 }, 'online')}`)
  } else {
    lines.push(`${pc.dim('civil war dates')} ${buildChroniclingAmericaSearchCommand({ query: 'civil war', count, page: 1, dates: '1861/1865' }, 'online')}`)
  }
  return lines.join('\n')
}

function readChroniclingAmericaPage(query: Record<string, unknown>, pagination: Record<string, unknown>): number {
  const page = Number(pagination.current ?? query.page ?? 1)
  return Number.isInteger(page) && page > 0 ? page : 1
}

function readChroniclingAmericaCount(query: Record<string, unknown>, pagination: Record<string, unknown>): number {
  const count = Number(pagination.perPage ?? query.count ?? 20)
  return Number.isInteger(count) && count > 0 ? count : 20
}

function buildChroniclingAmericaSearchCommand(
  options: { query: string; count: number; page: number; dates?: string | undefined },
  mode: 'online' | 'offline',
): string {
  const storageFlags = mode === 'online' ? '--online --persist' : '--offline'
  const parts = [
    `public-apis apis run chroniclingamerica.search ${storageFlags} -- --query ${formatCliArg(options.query)}`,
    `--count ${String(options.count)}`,
    `--page ${String(options.page)}`,
  ]
  if (options.dates !== undefined) {
    parts.push(`--dates ${formatCliArg(options.dates)}`)
  }
  return parts.join(' ')
}

function renderDisifyValidation(value: Record<string, unknown>, options: { title: string; endpoint: string; subjectLabel: string; subject: string; next: string }): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const validation = isRecord(value.validation) ? value.validation : {}
  const domainInfo = isRecord(validation.domainInfo) ? validation.domainInfo : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const signals = Array.isArray(validation.signals) ? validation.signals.filter((entry): entry is string => typeof entry === 'string') : []
  const mxInfo = Array.isArray(validation.mxInfo) ? validation.mxInfo.filter((entry): entry is string => typeof entry === 'string') : []
  const lines = [
    `${pc.bold(pc.cyan(options.title))} ${pc.dim(String(api.endpoint ?? options.endpoint))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('rate')} remaining ${String(rateLimit.remaining ?? '?')} / ${String(rateLimit.limit ?? '?')}`,
    '',
    `${pc.bold(options.subject)} ${pc.dim(`${options.subjectLabel} validation`)}`,
    `  format ${formatBooleanBadge(validation.format)} · dns ${formatBooleanBadge(validation.dns)} · disposable ${formatBooleanBadge(validation.disposable)}`,
    `  free ${formatBooleanBadge(validation.free)} · role ${formatBooleanBadge(validation.role)} · whitelist ${formatBooleanBadge(validation.whitelist)}`,
    `  confidence ${String(validation.confidence ?? '?')} · domain ${String(validation.domain ?? '-')}`,
  ]
  const domainParts = [
    typeof domainInfo.tld === 'string' ? `tld ${domainInfo.tld}` : undefined,
    typeof domainInfo.isSubdomain === 'boolean' ? `subdomain ${String(domainInfo.isSubdomain)}` : undefined,
    typeof domainInfo.parentDomain === 'string' ? `parent ${domainInfo.parentDomain}` : undefined,
  ].filter((entry): entry is string => typeof entry === 'string')
  if (domainParts.length > 0) {
    lines.push(`  ${pc.dim(domainParts.join(' · '))}`)
  }
  if (signals.length > 0) {
    lines.push(`  ${pc.dim(`signals: ${signals.slice(0, 8).join(', ')}`)}`)
  }
  if (mxInfo.length > 0) {
    lines.push(`  ${pc.dim(`mx: ${mxInfo.slice(0, 5).join(', ')}`)}`)
  }
  lines.push('', `${pc.dim('next')} ${options.next}`)
  return lines.join('\n')
}

function renderKickboxDisposable(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const result = isRecord(value.result) ? value.result : {}
  const target = String(result.target ?? query.target ?? api.defaultTarget ?? 'gmail.com')
  const disposable = result.disposable === true
  const comparisonTarget = disposable ? String(api.defaultTarget ?? 'gmail.com') : 'mailinator.com'
  const userCheckTarget = target.includes('@') ? target : `test@${target}`
  const lines = [
    `${pc.bold(pc.cyan('Kickbox Disposable'))} ${pc.dim(String(api.endpoint ?? 'GET /v1/disposable/{emailOrDomain}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('scope')} ${String(api.scope ?? 'Disposable email/domain detection only')}`,
    '',
    `${pc.bold(target)} disposable ${formatBooleanBadge(result.disposable)}`,
    '',
    `${pc.dim(disposable ? 'compare' : 'try disposable')} public-apis apis run kickbox.disposable -- --target ${formatCliArg(comparisonTarget)}`,
    `${pc.dim('deeper check')} public-apis apis run usercheck.email -- --email ${formatCliArg(userCheckTarget)}`,
  ]
  return lines.join('\n')
}

function renderUserCheckEmail(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const validation = isRecord(value.validation) ? value.validation : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const mxRecords = Array.isArray(validation.mxRecords) ? validation.mxRecords.filter(isRecord) : []
  const mxProviders = Array.isArray(validation.mxProviders) ? validation.mxProviders.filter(isRecord) : []
  const email = String(validation.email ?? query.email ?? api.defaultEmail ?? 'test@example.com')
  const domain = typeof validation.domain === 'string' && validation.domain.trim() !== '' ? validation.domain : email.split('@')[1] ?? 'example.com'
  const comparisonEmail = domain === 'mailinator.com' ? 'test@example.com' : `test@${domain === 'example.com' ? 'mailinator.com' : domain}`
  const lines = [
    `${pc.bold(pc.cyan('UserCheck Email'))} ${pc.dim(String(api.endpoint ?? 'GET /email/{email}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('rate')} remaining ${String(rateLimit.remaining ?? '?')} / ${String(rateLimit.limit ?? '?')}`,
    `${pc.dim('rebrand')} ${String(api.rebrand ?? 'MailCheck.ai is now UserCheck.com')}`,
    '',
    `${pc.bold(email)} ${pc.dim(domain)}`,
    `  mx ${formatBooleanBadge(validation.mx)} · disposable ${formatBooleanBadge(validation.disposable)} · public ${formatBooleanBadge(validation.publicDomain)} · relay ${formatBooleanBadge(validation.relayDomain)}`,
    `  role ${formatBooleanBadge(validation.roleAccount)} · alias ${formatBooleanBadge(validation.alias)} · spam ${formatBooleanBadge(validation.spam)} · blocklisted ${formatBooleanBadge(validation.blocklisted)}`,
  ]
  if (validation.domainAgeInDays !== undefined) {
    lines.push(`  ${pc.dim(`domain age: ${String(validation.domainAgeInDays)} day(s)`)}`)
  }
  if (typeof validation.didYouMean === 'string' && validation.didYouMean !== '') {
    lines.push(`  ${pc.yellow(`did you mean: ${validation.didYouMean}`)}`)
  }
  if (mxProviders.length > 0) {
    lines.push(`  ${pc.dim(`mx providers: ${mxProviders.slice(0, 5).map(provider => [provider.slug, provider.type, provider.grade].filter(part => typeof part === 'string').join('/')).join(', ')}`)}`)
  }
  if (mxRecords.length > 0) {
    lines.push(`  ${pc.dim(`mx records: ${mxRecords.slice(0, 5).map(record => String(record.hostname ?? '-')).join(', ')}`)}`)
  }
  lines.push('', `${pc.dim('compare')} public-apis apis run usercheck.email -- --email ${formatCliArg(comparisonEmail)}`)
  return lines.join('\n')
}

function renderEnergiDataServiceRightNow(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const records = Array.isArray(value.records) ? value.records.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('Energi Data Service Right Now'))} ${pc.dim(String(api.endpoint ?? 'GET /dataset/PowerSystemRightNow'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? records.length)} returned · ${String(pagination.total ?? '?')} total · limit ${String(pagination.limit ?? query.limit ?? api.defaultLimit ?? 100)}`,
    `${pc.dim('rate')} remaining ${String(rateLimit.remainingCalls ?? '?')} / ${String(rateLimit.totalCalls ?? '?')} · ${String(api.requestGuidance ?? 'respect dataset rate limits')}`,
  ]
  if (records.length === 0) {
    lines.push('', pc.yellow('No Energi Data Service right-now records returned for this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run energidataservice.rightnow -- --start now-PT1H --limit ${String(query.limit ?? api.defaultLimit ?? 100)}`)
    lines.push(`${pc.dim('prices')} public-apis apis run energidataservice.elspotprices -- --price-area DK1 --limit 24`)
    return lines.join('\n')
  }
  lines.push('')
  for (const [recordIndex, record] of records.slice(0, 12).entries()) {
    const production = Number(record.ProductionGe100MW ?? 0) + Number(record.ProductionLt100MW ?? 0)
    const wind = Number(record.OffshoreWindPower ?? 0) + Number(record.OnshoreWindPower ?? 0)
    lines.push(`${pc.bold(`${recordIndex + 1}. ${String(record.Minutes1UTC ?? '-')}`)} CO2 ${formatNumber(record.CO2Emission)} g/kWh`)
    lines.push(`   production ${formatNumber(production)} MW · solar ${formatNumber(record.SolarPower)} MW · wind ${formatNumber(wind)} MW · exchange ${formatNumber(record.Exchange_Sum)} MW`)
  }
  if (records.length > 12) {
    lines.push(pc.dim(`… ${records.length - 12} more record(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('next')} public-apis apis run energidataservice.elspotprices -- --price-area DK1 --limit 100`)
  return lines.join('\n')
}

