function renderFrankfurterConvert(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const conversion = isRecord(value.conversion) ? value.conversion : {}
  const lines = [
    `${pc.bold(pc.cyan('Frankfurter Convert'))} ${pc.dim(String(api.endpoint ?? 'GET /v2/rate/{base}/{quote}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')} · ${pc.dim('cache')} ${String(api.cachePolicy ?? 'public cache')}`,
    `${pc.dim('rate limit')} ${String(api.rateLimit ?? 'No quota; rate-limited to prevent abuse')}`,
  ]
  if (Object.keys(conversion).length === 0) {
    lines.push('', pc.yellow('No Frankfurter conversion returned for this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run frankfurter.convert -- --base EUR --quote USD --amount 100`)
    lines.push(`${pc.dim('again')} ${buildFrankfurterCommand('frankfurter.convert', query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildFrankfurterCommand('frankfurter.convert', query, 'offline')}`)
    return lines.join('\n')
  }
  lines.push(
    '',
    `${pc.bold(`${formatNumber(conversion.amount)} ${String(conversion.base ?? query.base ?? '-')}`)} = ${pc.bold(`${formatNumber(conversion.converted)} ${String(conversion.quote ?? query.quote ?? '-')}`)}`,
    `${pc.dim('rate')} 1 ${String(conversion.base ?? query.base ?? '-')} = ${formatNumber(conversion.rate)} ${String(conversion.quote ?? query.quote ?? '-')} · ${String(conversion.date ?? query.date ?? 'latest')}`,
    '',
    `${pc.dim('rates')} public-apis apis run frankfurter.rates -- --base ${formatCliArg(conversion.base ?? query.base ?? 'EUR')} --quotes ${formatCliArg(conversion.quote ?? query.quote ?? 'USD')}`,
    `${pc.dim('again')} ${buildFrankfurterCommand('frankfurter.convert', query, 'online')}`,
    `${pc.dim('replay')} ${buildFrankfurterCommand('frankfurter.convert', query, 'offline')}`,
  )
  return lines.join('\n')
}

function buildFrankfurterCommand(operation: 'frankfurter.currencies' | 'frankfurter.rates' | 'frankfurter.convert', query: Record<string, unknown>, mode?: 'online' | 'offline'): string {
  const parts = [`public-apis apis run ${operation}`]
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  const keys = operation === 'frankfurter.currencies'
    ? ['scope', 'search', 'limit']
    : operation === 'frankfurter.rates'
      ? ['base', 'quotes', 'date', 'limit']
      : ['base', 'quote', 'amount', 'date']
  for (const key of keys) {
    const raw = query[key]
    if (raw !== undefined && raw !== '') {
      const value = Array.isArray(raw) ? raw.join(',') : raw
      parts.push(`--${key} ${formatCliArg(value)}`)
    }
  }
  return parts.join(' ')
}

function selectFrankfurterQuote(query: Record<string, unknown>, rates: Record<string, unknown>[]): string {
  const base = String(query.base ?? 'EUR').toUpperCase()
  const firstRateQuote = rates.find(rate => typeof rate.quote === 'string' && rate.quote.toUpperCase() !== base)?.quote
  if (typeof firstRateQuote === 'string' && firstRateQuote !== '') {
    return firstRateQuote
  }
  return base === 'USD' ? 'EUR' : 'USD'
}

