function renderIsdayoffDay(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const status = isRecord(value.status) ? value.status : {}
  const lines = [
    `${pc.bold(pc.cyan('isDayOff Day'))} ${pc.dim(
      String(api.endpoint ?? 'GET /api/getdata?year={YYYY}&month={MM}&day={DD}'),
    )}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS text/plain')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Documented getdata only.')}`,
    `${pc.dim('freshness')} ${String(api.freshness ?? 'See provider DB page.')}`,
    '',
    [
      pc.bold(String(status.date ?? query.date ?? '?')),
      String(status.label ?? 'unknown'),
      `code ${String(status.code ?? '?')}`,
    ].join(' · '),
  ]
  lines.push(
    pc.dim([
      status.isWorkingDay === true ? 'working' : 'non-working',
      status.isShortenedDay === true ? 'shortened' : undefined,
      status.isHoliday === true ? 'holiday' : undefined,
    ].filter(Boolean).join(' · ')),
  )
  lines.push('', `${pc.dim('range')} ${buildIsdayoffRangeCommand({
    from: query.date,
    countryCode: query.countryCode,
    includeShortened: query.includeShortened,
    sixDay: query.sixDay,
    markHoliday: query.markHoliday,
    days: 14,
  }, 'online')}`)
  lines.push(`${pc.dim('again')} ${buildIsdayoffDayCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildIsdayoffDayCommand(query, 'offline')}`)
  return lines.join('\n')
}

function renderIsdayoffRange(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const totals = isRecord(value.totals) ? value.totals : {}
  const days = Array.isArray(value.days) ? value.days.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('isDayOff Range'))} ${pc.dim(
      String(api.endpoint ?? 'GET /api/getdata?date1={YYYYMMDD}&date2={YYYYMMDD}'),
    )}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS text/plain')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    [
      `${pc.dim('count')} ${String(value.count ?? days.length)}`,
      `working ${String(totals.workingDays ?? '?')}`,
      `non-working ${String(totals.nonWorkingDays ?? '?')}`,
      `shortened ${String(totals.shortenedDays ?? '?')}`,
      `holidays ${String(totals.holidays ?? '?')}`,
    ].join(' · '),
    `${pc.dim('scope')} ${String(api.boundary ?? 'Documented getdata only.')}`,
    `${pc.dim('freshness')} ${String(api.freshness ?? 'See provider DB page.')}`,
  ]

  if (days.length === 0) {
    lines.push('', pc.yellow('No isDayOff day statuses returned.'))
    lines.push(`${pc.dim('try')} ${buildIsdayoffRangeCommand({
      ...query,
      from: query.from ?? query.date,
      days: api.defaultRangeDays ?? 14,
    }, 'online')}`)
    return lines.join('\n')
  }

  for (const day of days.slice(0, 40)) {
    const flags = [
      day.isWorkingDay === true ? 'working' : 'non-working',
      day.isShortenedDay === true ? 'shortened' : undefined,
      day.isHoliday === true ? 'holiday' : undefined,
    ].filter(Boolean).join(' · ')
    lines.push(
      `${pc.bold(String(day.date ?? '?'))} · ${String(day.label ?? 'unknown')} ` +
        `${pc.dim(`code ${String(day.code ?? '?')} · ${flags}`)}`,
    )
  }
  if (days.length > 40) {
    lines.push(pc.dim(
      `showing 40 of ${days.length} day(s); use --format json for full output.`,
    ))
  }
  lines.push('', `${pc.dim('day')} ${buildIsdayoffDayCommand({
    date: query.from,
    countryCode: query.countryCode,
    includeShortened: query.includeShortened,
    sixDay: query.sixDay,
    markHoliday: query.markHoliday,
  }, 'online')}`)
  lines.push(`${pc.dim('again')} ${buildIsdayoffRangeCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildIsdayoffRangeCommand(query, 'offline')}`)
  return lines.join('\n')
}

