function renderIpfastLookup(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const ip = isRecord(value.ip) ? value.ip : {}
  const geo = isRecord(value.geo) ? value.geo : {}
  const network = isRecord(value.network) ? value.network : {}
  const locale = isRecord(value.locale) ? value.locale : {}
  const response = isRecord(value.response) ? value.response : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const storage = isRecord(value.storage) ? value.storage : {}
  const nextAction =
    storage.mode === 'offline'
      ? `${pc.dim('refresh')} public-apis apis run ipfast.lookup --online --persist`
      : storage.persisted === true
        ? `${pc.dim('offline')} public-apis apis run ipfast.lookup --offline`
        : `${pc.dim('save')} public-apis apis run ipfast.lookup --online --persist`
  const location = [geo.city, geo.region, geo.countryName ?? geo.country]
    .filter(entry => typeof entry === 'string' && entry.trim() !== '')
    .join(', ')
  const coordinates = [geo.latitude, geo.longitude]
    .filter(entry => typeof entry === 'string' && entry.trim() !== '')
    .join(', ')
  return [
    `${pc.bold(pc.cyan('IPFast IP Geo Lookup'))} ${pc.dim(String(api.endpoint ?? 'GET /json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON')} · ${pc.dim('rate')} limit ${String(rateLimit.limit ?? '120 observed')} · remaining ${String(rateLimit.remaining ?? '?')} · reset ${String(rateLimit.reset ?? '?')}`,
    `${pc.dim('endpoint')} ${String(response.endpoint ?? 'https://ipfast.dev/json')}`,
    `${pc.dim('docs')} ${String(api.docs ?? 'https://ipfast.dev')} · ${pc.dim('listed docs')} ${String(api.publicApisListedDocsStatus ?? 'public-apis listed docs may be stale')}`,
    '',
    `${pc.bold('ip')} ${String(ip.address ?? '-')}`,
    `${pc.bold('geo')} ${location === '' ? '-' : location}${coordinates === '' ? '' : pc.dim(` · ${coordinates}`)}${typeof geo.timezone === 'string' ? pc.dim(` · ${geo.timezone}`) : ''}`,
    `${pc.bold('network')} ASN ${String(network.asn ?? '-')} · ${String(network.asOrganization ?? '-')}${typeof network.colo === 'string' ? pc.dim(` · ${network.colo}`) : ''}`,
    `${pc.bold('locale')} ${String(locale.languages ?? '-')} · ${String(locale.currency ?? '-')}${typeof locale.callingCode === 'string' ? pc.dim(` · ${locale.callingCode}`) : ''}`,
    '',
    nextAction,
  ].join('\n')
}

function renderIpifyIp(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const ip = isRecord(value.ip) ? value.ip : {}
  const response = isRecord(value.response) ? value.response : {}
  const currentProtocol = query.protocol === 'ipv4' ? 'ipv4' : 'auto'
  const nextProtocol = currentProtocol === 'ipv4' ? 'auto' : 'ipv4'
  return [
    `${pc.bold(pc.cyan('IPify IP Address'))} ${pc.dim(String(api.endpoint ?? 'GET /?format=json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON')} · ${pc.dim('rate')} ${String(api.rateLimit ?? 'official homepage says no limit')}`,
    `${pc.dim('endpoint')} ${String(response.endpoint ?? '-')}`,
    `${pc.dim('content-type')} ${String(response.contentType ?? 'application/json')}`,
    '',
    `${pc.bold('ip')} ${String(ip.address ?? '-')} ${pc.dim(`IPv${String(ip.version ?? '?')}`)}`,
    `${pc.dim('formats')} ${String(api.excludedFormats ?? 'plain text and JSONP excluded from CLI projection')}`,
    '',
    `${pc.dim(currentProtocol === 'ipv4' ? 'compare auto' : 'compare ipv4')} public-apis apis run ipify.ip -- --protocol ${nextProtocol}`,
  ].join('\n')
}

function renderJikanAnime(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const animeRows = Array.isArray(value.anime) ? value.anime.filter(isRecord) : []
  const queryText = typeof query.query === 'string' && query.query.trim() !== '' ? query.query : undefined
  const filterArgs = [
    queryText === undefined ? undefined : `--query ${formatCliArg(queryText)}`,
    typeof query.sfw === 'boolean' ? `--sfw ${String(query.sfw)}` : undefined,
    typeof query.type === 'string' && query.type.trim() !== '' ? `--type ${formatCliArg(query.type)}` : undefined,
    typeof query.status === 'string' && query.status.trim() !== '' ? `--status ${formatCliArg(query.status)}` : undefined,
    typeof query.orderBy === 'string' && query.orderBy.trim() !== '' ? `--order-by ${formatCliArg(query.orderBy)}` : undefined,
    typeof query.sort === 'string' && query.sort.trim() !== '' ? `--sort ${formatCliArg(query.sort)}` : undefined,
  ].filter((part): part is string => part !== undefined)
  const lines = [
    `${pc.bold(pc.cyan('Jikan Anime'))} ${pc.dim(String(api.endpoint ?? 'GET /anime'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${String(pagination.currentPage ?? query.page ?? 1)} / ${String(pagination.lastVisiblePage ?? '-')} · total ${String(pagination.total ?? '-')}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? '3 requests/second and 60 requests/minute')} · cache ${String(api.cacheTtl ?? '24 hours')}`,
  ]

  if (animeRows.length === 0) {
    lines.push('', pc.yellow('No Jikan anime results returned for this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run jikan.anime -- --query "cowboy bebop" --limit 5 --sfw true`)
    return lines.join('\n')
  }

  for (const [animeIndex, anime] of animeRows.entries()) {
    const summary = [
      anime.type,
      typeof anime.score === 'number' ? `score ${anime.score}` : undefined,
      typeof anime.episodes === 'number' ? `${anime.episodes} ep` : undefined,
      anime.status,
    ].filter(valuePart => typeof valuePart === 'string' && valuePart.trim() !== '').join(' · ')
    lines.push(`${pc.bold(`${animeIndex + 1}.`)} ${String(anime.title ?? '-')}${summary === '' ? '' : pc.dim(` — ${summary}`)}`)
    if (typeof anime.url === 'string') {
      lines.push(`   ${pc.blue(anime.url)}`)
    }
    if (typeof anime.synopsis === 'string' && anime.synopsis.trim() !== '') {
      lines.push(`   ${wrapLine(anime.synopsis, 110)}`)
    }
  }
  if (pagination.hasNextPage === true) {
    const nextPage = Number(query.page ?? pagination.currentPage ?? 1) + 1
    lines.push('', `${pc.dim('next')} public-apis apis run jikan.anime -- ${filterArgs.join(' ')} --page ${nextPage} --limit ${String(query.limit ?? 25)}`.replace(/\s+/gu, ' ').trim())
  } else {
    lines.push('', `${pc.dim('next')} public-apis apis run jikan.anime -- --query "cowboy bebop" --limit 5`)
  }
  return lines.join('\n')
}

function renderJsdelivrMetadata(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const packageInfo = isRecord(value.package) ? value.package : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const tags = isRecord(packageInfo.tags) ? packageInfo.tags : {}
  const versions = Array.isArray(packageInfo.versions) ? packageInfo.versions.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('jsDelivr npm Package Metadata'))} ${pc.dim(String(api.endpoint ?? 'GET /v1/packages/npm/{package}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} versions ${String(pagination.shown ?? versions.length)} / ${String(pagination.total ?? packageInfo.versionCount ?? versions.length)} shown`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'free API with no hard rate limit')}`,
  ]

  if (versions.length === 0) {
    lines.push('', pc.yellow('No jsDelivr package versions returned for this query.'))
    return lines.join('\n')
  }

  lines.push(
    '',
    `${pc.bold(String(packageInfo.name ?? query.packageName ?? 'package'))} latest ${String(packageInfo.latest ?? tags.latest ?? '-')}`,
  )
  for (const [tag, version] of Object.entries(tags).slice(0, 6)) {
    lines.push(`  ${pc.dim(`tag ${tag}`)} ${String(version)}`)
  }
  lines.push('', pc.bold('versions'))
  for (const version of versions.slice(0, 10)) {
    lines.push(`  ${String(version.version ?? '-')}`)
  }
  if (versions.length > 10) {
    lines.push(`  ${pc.dim(`…${versions.length - 10} more shown in --format json`)}`)
  }
  lines.push('', `${pc.dim('next')} public-apis apis run jsdelivr.stats -- --package ${String(query.packageName ?? packageInfo.name ?? 'jquery')} --period month`)
  return lines.join('\n')
}

function renderJsdelivrStats(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const stats = isRecord(value.stats) ? value.stats : {}
  const hits = isRecord(stats.hits) ? stats.hits : {}
  const bandwidth = isRecord(stats.bandwidth) ? stats.bandwidth : {}
  const hitDates = Array.isArray(hits.dates) ? hits.dates.filter(isRecord) : []
  const bandwidthDates = Array.isArray(bandwidth.dates) ? bandwidth.dates.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('jsDelivr npm Package Stats'))} ${pc.dim(String(api.endpoint ?? 'GET /v1/stats/packages/npm/{package}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'free API with no hard rate limit')}`,
    `${pc.dim('delay')} ${String(api.statsDelay ?? 'usage statistics are available with a 48 hour delay')}`,
    '',
    `${pc.bold('hits')} total ${formatInteger(hits.total)} · rank ${String(hits.rank ?? '-')} · previous ${formatInteger(hits.previousTotal)}`,
    `${pc.bold('bandwidth')} total ${formatBytes(bandwidth.total)} · rank ${String(bandwidth.rank ?? '-')} · previous ${formatBytes(bandwidth.previousTotal)}`,
  ]

  if (hitDates.length === 0) {
    lines.push('', pc.yellow('No jsDelivr stats date buckets returned for this query.'))
    return lines.join('\n')
  }

  lines.push('', pc.bold('recent hits'))
  for (const date of hitDates.slice(-8)) {
    lines.push(`  ${String(date.date ?? '-')}  ${formatInteger(date.value)}`)
  }
  if (bandwidthDates.length > 0) {
    const latestBandwidth = bandwidthDates[bandwidthDates.length - 1]
    lines.push('', `${pc.dim('latest bandwidth')} ${String(latestBandwidth?.date ?? '-')} ${formatBytes(latestBandwidth?.value)}`)
  }
  lines.push('', `${pc.dim('next')} public-apis apis run jsdelivr.metadata -- --package ${String(query.packageName ?? 'jquery')}`)
  return lines.join('\n')
}

function renderMeowFacts(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const facts = Array.isArray(value.facts) ? value.facts.filter(fact => typeof fact === 'string') : []
  const lang = typeof query.lang === 'string' && query.lang.trim() !== '' ? query.lang : undefined
  const langArg = lang === undefined ? '' : ` --lang ${formatCliArg(lang)}`
  const lines = [
    `${pc.bold(pc.cyan('MeowFacts'))} ${pc.dim(String(api.endpoint ?? 'GET /'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? facts.length)}`,
  ]

  if (facts.length === 0) {
    lines.push('', 'No cat facts returned for this query.')
    lines.push(`${pc.dim('try')} public-apis apis run meowfacts.facts -- --count 1${langArg}`)
    return lines.join('\n')
  }

  for (const [factIndex, fact] of facts.entries()) {
    lines.push(`- ${factIndex + 1}. ${wrapLine(fact, 120)}`)
  }
  const nextCount = Math.max(3, typeof query.count === 'number' ? query.count : facts.length)
  lines.push('', `${pc.dim('next')} public-apis apis run meowfacts.facts -- --count ${String(nextCount)}${langArg}`)
  lines.push(`${pc.dim('languages')} public-apis apis run meowfacts.facts -- --count 3 --lang eng-us | esp-mx | ukr-ua`)
  return lines.join('\n')
}

function renderNbpTables(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const rates = Array.isArray(value.rates) ? value.rates.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan(`NBP Table ${String(value.table ?? query.table ?? 'A')}`))} ${pc.dim(String(api.endpoint ?? 'GET /api/exchangerates/tables/{table}/'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('date')} ${String(value.effectiveDate ?? '-')} · no ${String(value.no ?? '-')}${typeof value.tradingDate === 'string' ? ` · trading ${value.tradingDate}` : ''}`,
    `${pc.dim('count')} ${String(pagination.returned ?? rates.length)} returned · limit ${String(pagination.limit ?? query.limit ?? '?')} / ${String(pagination.maxLimit ?? '?')}`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')} · ${String(api.windowLimit ?? 'history capped by NBP window')}`,
  ]
  if (rates.length === 0) {
    lines.push('', pc.yellow('No NBP table rates returned for this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run nbp.tables -- --table A --code USD`)
    return lines.join('\n')
  }
  lines.push('')
  for (const rate of rates.slice(0, 30)) {
    const valueText = typeof rate.mid === 'number' ? `mid ${formatNumber(rate.mid)}` : `bid ${formatNumber(rate.bid)} · ask ${formatNumber(rate.ask)}`
    lines.push(`- ${pc.bold(String(rate.code ?? '-'))} ${String(rate.currency ?? '')} · ${valueText}`)
  }
  if (rates.length > 30) {
    lines.push(pc.dim(`… ${rates.length - 30} more rate(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('next')} public-apis apis run nbp.history -- --code ${String(query.code || 'USD')} --count 93`)
  return lines.join('\n')
}

function renderNbpHistory(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const rates = Array.isArray(value.rates) ? value.rates.filter(isRecord) : []
  const visibleRates = [...rates].reverse().slice(0, 30)
  const latestRate = visibleRates[0]
  const lines = [
    `${pc.bold(pc.cyan(`NBP ${String(value.code ?? query.code ?? 'USD')} History`))} ${pc.dim(String(api.endpoint ?? 'GET /api/exchangerates/rates/{table}/{code}/last/{count}/'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('series')} table ${String(value.table ?? query.table ?? 'A')} · ${String(value.currency ?? '-')}`,
    `${pc.dim('count')} ${String(pagination.returned ?? rates.length)} returned · count ${String(pagination.count ?? query.count ?? '?')} / ${String(pagination.maxCount ?? '?')}`,
    `${pc.dim('view')} latest first${latestRate !== undefined ? ` · latest ${String(latestRate.effectiveDate ?? '-')} ${typeof latestRate.mid === 'number' ? `mid ${formatNumber(latestRate.mid)}` : `bid ${formatNumber(latestRate.bid)} · ask ${formatNumber(latestRate.ask)}`}` : ''}`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')} · ${String(api.windowLimit ?? 'history capped by NBP window')}`,
  ]
  if (rates.length === 0) {
    lines.push('', pc.yellow('No NBP historical rates returned for this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run nbp.history -- --table A --code USD --count 93`)
    return lines.join('\n')
  }
  lines.push('')
  for (const rate of visibleRates) {
    const valueText = typeof rate.mid === 'number' ? `mid ${formatNumber(rate.mid)}` : `bid ${formatNumber(rate.bid)} · ask ${formatNumber(rate.ask)}`
    lines.push(`- ${pc.bold(String(rate.effectiveDate ?? '-'))} ${valueText} · no ${String(rate.no ?? '-')}`)
  }
  if (rates.length > 30) {
    lines.push(pc.dim(`… ${rates.length - 30} more rate(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('next')} public-apis apis run nbp.tables -- --table ${String(query.table ?? 'A')} --code ${String(value.code ?? query.code ?? 'USD')}`)
  return lines.join('\n')
}

function renderNekosBestRandom(value: Record<string, unknown>): string {
  return renderNekosBestAssets(value, 'NekosBest Random', 'GET /:category', 'random')
}

function renderNekosBestSearch(value: Record<string, unknown>): string {
  return renderNekosBestAssets(value, 'NekosBest Search', 'GET /search', 'search')
}

function renderNominatimSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const places = Array.isArray(value.places) ? value.places.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('Nominatim Search'))} ${pc.dim(String(api.endpoint ?? 'GET /search'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? places.length)} returned · limit ${String(pagination.limit ?? query.limit ?? 3)} / ${String(pagination.maxLimit ?? 5)}`,
    `${pc.dim('policy')} ${String(api.rateLimit ?? '≤1 request/second; cache with --persist and replay with --offline')}`,
    `${pc.dim('attribution')} ${String(api.attribution ?? 'Data © OpenStreetMap contributors, ODbL 1.0')}`,
  ]
  if (places.length === 0) {
    lines.push('', pc.yellow('No Nominatim places returned for this query.'))
    lines.push(`${pc.dim('again')} ${buildNominatimSearchCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildNominatimSearchCommand(query, 'offline')}`)
    lines.push(`${pc.dim('reset')} public-apis apis run nominatim.search --online --persist -- --query Berlin --limit 3 --language en`)
    return lines.join('\n')
  }
  lines.push('')
  for (const [index, place] of places.slice(0, 8).entries()) {
    const coords = `${String(place.latitude ?? '?')}, ${String(place.longitude ?? '?')}`
    const kind = [place.category, place.type, place.addressType].filter((entry): entry is string => typeof entry === 'string' && entry.trim() !== '').join('/')
    lines.push(`${pc.bold(`${index + 1}.`)} ${String(place.displayName ?? place.name ?? 'unknown place')}`)
    lines.push(`   ${coords} · ${kind || 'place'} · importance ${typeof place.importance === 'number' ? place.importance.toFixed(4) : '-'}`)
  }
  if (places.length > 8) {
    lines.push(pc.dim(`… ${places.length - 8} more place(s); use --format json for full output.`))
  }
  const first = places[0]
  lines.push('', `${pc.dim('again')} ${buildNominatimSearchCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildNominatimSearchCommand(query, 'offline')}`)
  lines.push(`${pc.dim('reverse')} public-apis apis run nominatim.reverse --online --persist -- --latitude ${formatCliArg(first?.latitude ?? 52.5170365)} --longitude ${formatCliArg(first?.longitude ?? 13.3888599)} --language ${formatCliArg(query.language ?? 'en')}`)
  return lines.join('\n')
}

function renderNominatimReverse(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const place = isRecord(value.place) ? value.place : {}
  const address = isRecord(place.address) ? place.address : {}
  const coords = `${String(place.latitude ?? query.latitude ?? '?')}, ${String(place.longitude ?? query.longitude ?? '?')}`
  const kind = [place.category, place.type, place.addressType].filter((entry): entry is string => typeof entry === 'string' && entry.trim() !== '').join('/')
  const addressBits = [address.road, address.suburb, address.city, address.postcode, address.country]
    .filter((entry): entry is string => typeof entry === 'string' && entry.trim() !== '')
    .join(' · ')
  const lines = [
    `${pc.bold(pc.cyan('Nominatim Reverse'))} ${pc.dim(String(api.endpoint ?? 'GET /reverse'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('policy')} ${String(api.rateLimit ?? '≤1 request/second; cache with --persist and replay with --offline')}`,
    `${pc.dim('attribution')} ${String(api.attribution ?? 'Data © OpenStreetMap contributors, ODbL 1.0')}`,
    '',
    `${pc.bold(String(place.displayName ?? 'unknown place'))}`,
    `${pc.dim('coordinates')} ${coords} · ${kind || 'place'} · place ${String(place.placeId ?? '-')}`,
  ]
  if (addressBits !== '') {
    lines.push(`${pc.dim('address')} ${addressBits}`)
  }
  lines.push('', `${pc.dim('again')} ${buildNominatimReverseCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildNominatimReverseCommand(query, 'offline')}`)
  lines.push(`${pc.dim('search')} public-apis apis run nominatim.search --online --persist -- --query ${formatCliArg(address.city ?? place.name ?? 'Berlin')} --limit 3 --language ${formatCliArg(query.language ?? 'en')}`)
  return lines.join('\n')
}

function buildNominatimSearchCommand(query: Record<string, unknown>, mode: 'online' | 'offline'): string {
  const storageFlags = mode === 'online' ? '--online --persist' : '--offline'
  return `public-apis apis run nominatim.search ${storageFlags} -- --query ${formatCliArg(query.query ?? 'Berlin')} --limit ${String(query.limit ?? 3)} --language ${formatCliArg(query.language ?? 'en')}`
}

function buildNominatimReverseCommand(query: Record<string, unknown>, mode: 'online' | 'offline'): string {
  const storageFlags = mode === 'online' ? '--online --persist' : '--offline'
  return `public-apis apis run nominatim.reverse ${storageFlags} -- --latitude ${formatCliArg(query.latitude ?? 52.5170365)} --longitude ${formatCliArg(query.longitude ?? 13.3888599)} --language ${formatCliArg(query.language ?? 'en')}`
}

function renderNpmRegistrySearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const search = isRecord(value.search) ? value.search : {}
  const packages = Array.isArray(search.packages) ? search.packages.filter(isRecord) : []
  const visiblePackages = packages.slice(0, 10)
  const lines = [
    `${pc.bold(pc.cyan('npm Registry Search'))} ${pc.dim(String(api.endpoint ?? 'GET /-/v1/search'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? packages.length)} returned · ${String(pagination.total ?? '?')} total · offset ${String(pagination.from ?? query.from ?? 0)}`,
    `${pc.dim('limit')} request size ${String(pagination.size ?? query.size ?? api.cliDefaultSize ?? 250)} · documented max ${String(api.documentedMaxSize ?? 250)}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'public npm registry; no API key documented for read endpoints')}`,
  ]

  if (packages.length === 0) {
    lines.push('', pc.yellow('No npm packages returned for this query.'))
    return lines.join('\n')
  }

  lines.push('')
  for (const [packageIndex, packageInfo] of visiblePackages.entries()) {
    const score = isRecord(packageInfo.score) ? packageInfo.score : {}
    const details = [
      packageInfo.version,
      typeof score.final === 'number' ? `score ${score.final.toFixed(3)}` : undefined,
      typeof packageInfo.maintainerCount === 'number' ? `${packageInfo.maintainerCount} maintainers` : undefined,
      packageInfo.date,
    ].filter((part): part is string => typeof part === 'string' && part.trim() !== '').join(' · ')
    lines.push(`${pc.bold(`${packageIndex + 1}.`)} ${String(packageInfo.name ?? '-')}${details === '' ? '' : pc.dim(` — ${details}`)}`)
    if (typeof packageInfo.description === 'string' && packageInfo.description.trim() !== '') {
      lines.push(`   ${wrapLine(packageInfo.description.replace(/\s+/gu, ' '), 100)}`)
    }
    const links = isRecord(packageInfo.links) ? packageInfo.links : {}
    if (typeof links.npm === 'string') {
      lines.push(`   ${pc.blue(links.npm)}`)
    }
  }
  if (packages.length > visiblePackages.length) {
    lines.push(pc.dim(`… ${packages.length - visiblePackages.length} more package(s) in this response; use --format json for full cached data.`))
  }

  const nextFrom = typeof pagination.nextFrom === 'number' ? pagination.nextFrom : undefined
  lines.push('', nextFrom === undefined
    ? `${pc.dim('next')} public-apis apis run npmregistry.package -- --package ${String(packages[0]?.name ?? 'typescript')}`
    : `${pc.dim('next')} public-apis apis run npmregistry.search -- --query "${String(query.query ?? 'typescript')}" --from ${nextFrom} --size ${String(query.size ?? 250)}`)
  return lines.join('\n')
}

function renderNpmRegistryPackage(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const packageInfo = isRecord(value.package) ? value.package : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const distTags = isRecord(packageInfo.distTags) ? packageInfo.distTags : {}
  const latestVersion = isRecord(packageInfo.latestVersion) ? packageInfo.latestVersion : {}
  const versions = Array.isArray(packageInfo.versions) ? packageInfo.versions.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('npm Registry Package'))} ${pc.dim(String(api.endpoint ?? 'GET /{package}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} versions ${String(pagination.shownVersions ?? versions.length)} / ${String(pagination.totalVersions ?? packageInfo.versionCount ?? versions.length)} shown`,
    `${pc.dim('projection')} ${String(api.packumentProjection ?? 'summary-only-no-readme-or-full-versions')}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'public npm registry; no API key documented for read endpoints')}`,
    '',
    `${pc.bold(String(packageInfo.name ?? query.packageName ?? 'package'))} latest ${String(distTags.latest ?? latestVersion.version ?? '-')}`,
  ]

  if (typeof packageInfo.description === 'string' && packageInfo.description.trim() !== '') {
    lines.push(wrapLine(packageInfo.description.replace(/\s+/gu, ' '), 110))
  }

  const metadata = [
    packageInfo.license ?? latestVersion.license,
    typeof packageInfo.maintainersCount === 'number' ? `${packageInfo.maintainersCount} maintainers` : undefined,
    typeof latestVersion.dependenciesCount === 'number' ? `${latestVersion.dependenciesCount} deps` : undefined,
    typeof latestVersion.unpackedSize === 'number' ? formatBytes(latestVersion.unpackedSize) : undefined,
  ].filter((part): part is string => typeof part === 'string' && part.trim() !== '').join(' · ')
  if (metadata !== '') {
    lines.push(`${pc.dim('meta')} ${metadata}`)
  }

  const links = [packageInfo.homepage, packageInfo.repository, packageInfo.bugs]
    .filter((part): part is string => typeof part === 'string' && part.trim() !== '')
    .slice(0, 3)
  for (const link of links) {
    lines.push(pc.blue(link))
  }

  if (versions.length === 0) {
    lines.push('', pc.yellow('No npm package versions returned for this projection.'))
    return lines.join('\n')
  }

  lines.push('', pc.bold('recent versions'))
  for (const version of versions.slice(0, 20)) {
    lines.push(`  ${String(version.version ?? '-')} ${pc.dim(String(version.publishedAt ?? ''))}`.trimEnd())
  }
  if (versions.length > 20) {
    lines.push(pc.dim(`… ${versions.length - 20} more version(s); use --format json for the full projection.`))
  }
  lines.push('', `${pc.dim('next')} public-apis apis run npmregistry.search -- --query "${String(packageInfo.name ?? query.packageName ?? 'typescript')}" --size 250`)
  return lines.join('\n')
}

function renderNekosBestAssets(value: Record<string, unknown>, title: string, fallbackEndpoint: string, mode: 'random' | 'search'): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const assets = Array.isArray(value.assets) ? value.assets.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan(title))} ${pc.dim(String(api.endpoint ?? fallbackEndpoint))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? assets.length)} · ${String(api.rateLimit ?? '200 requests/minute category; 7 requests/5 seconds search')}`,
  ]

  if (assets.length === 0) {
    lines.push('', pc.yellow('No NekosBest assets returned for this query.'))
    lines.push(`${pc.dim('try')} ${buildNekosBestRandomCommand({ category: query.category ?? 'neko', amount: query.amount ?? 20 })}`)
    lines.push(`${pc.dim('try')} public-apis apis run nekosbest.search -- --query ${formatCliArg(query.query ?? 'saber')} --type ${formatCliArg(query.type ?? 'image')} --amount ${String(query.amount ?? 20)}`)
    return lines.join('\n')
  }

  for (const [assetIndex, asset] of assets.slice(0, 20).entries()) {
    const dimensions = isRecord(asset.dimensions) ? asset.dimensions : {}
    const attribution = [
      asset.artistName,
      asset.animeName,
      asset.category,
      `${String(dimensions.width ?? '?')}×${String(dimensions.height ?? '?')}`,
      asset.contentType,
    ].filter(part => typeof part === 'string' && part.trim() !== '').join(' · ')
    lines.push(`${pc.bold(`${assetIndex + 1}.`)} ${pc.blue(String(asset.url ?? ''))}`)
    if (attribution !== '') {
      lines.push(`   ${pc.dim(attribution)}`)
    }
    if (typeof asset.sourceUrl === 'string') {
      lines.push(`   ${asset.sourceUrl}`)
    }
  }
  const firstCategory = readFirstNekosBestCategory(assets)
  lines.push('')
  if (mode === 'random') {
    lines.push(`${pc.dim('again')} ${buildNekosBestRandomCommand({ category: query.category ?? firstCategory ?? 'neko', amount: query.amount ?? 20 })}`)
    lines.push(`${pc.dim('search')} public-apis apis run nekosbest.search -- --query ${formatCliArg(firstCategory ?? query.category ?? 'neko')} --type ${formatCliArg(readNekosBestType(query, assets))} --amount ${String(query.amount ?? 20)}`)
  } else {
    const categoryArg = typeof query.category === 'string' && query.category.trim() !== '' ? ` --category ${formatCliArg(query.category)}` : ''
    lines.push(`${pc.dim('again')} public-apis apis run nekosbest.search -- --query ${formatCliArg(query.query ?? 'saber')} --type ${formatCliArg(query.type ?? readNekosBestType(query, assets))}${categoryArg} --amount ${String(query.amount ?? 20)}`)
    if (firstCategory !== undefined) {
      lines.push(`${pc.dim('random')} ${buildNekosBestRandomCommand({ category: firstCategory, amount: query.amount ?? 20 })}`)
    }
  }
  return lines.join('\n')
}

function buildNekosBestRandomCommand(query: Record<string, unknown>): string {
  return `public-apis apis run nekosbest.random -- --category ${formatCliArg(query.category ?? 'neko')} --amount ${String(query.amount ?? 20)}`
}

function readFirstNekosBestCategory(assets: Record<string, unknown>[]): string | undefined {
  const first = assets.find(asset => typeof asset.category === 'string' && asset.category.trim() !== '')
  return typeof first?.category === 'string' ? first.category : undefined
}

function readNekosBestType(query: Record<string, unknown>, assets: Record<string, unknown>[]): string {
  if (typeof query.type === 'string' && query.type.trim() !== '') {
    return query.type
  }
  const firstContentType = assets.find(asset => asset.contentType === 'gif' || asset.contentType === 'image')?.contentType
  return typeof firstContentType === 'string' ? firstContentType : 'image'
}

