function renderQuickChartRender(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const chart = isRecord(value.chart) ? value.chart : {}
  const dimensions = isRecord(chart.dimensions) ? chart.dimensions : {}
  const dataUrl = typeof chart.dataUrl === 'string' ? chart.dataUrl : ''
  const labels = Array.isArray(query.labels) ? query.labels.map(String).join(',') : String(query.labels ?? '')
  const data = Array.isArray(query.data) ? query.data.map(String).join(',') : String(query.data ?? '')
  const lines = [
    `${pc.bold(pc.cyan('QuickChart Render'))} ${pc.dim(String(api.endpoint ?? 'GET /chart'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('image')} ${String(chart.mediaType ?? chart.contentType ?? 'image/png')} · ${String(dimensions.width ?? query.width ?? '?')}×${String(dimensions.height ?? query.height ?? '?')} · ${formatBytes(chart.bytes)}`,
    `${pc.dim('limits')} width ${String(isRecord(api.documentedMaximums) ? api.documentedMaximums.width ?? 2000 : 2000)} · height ${String(isRecord(api.documentedMaximums) ? api.documentedMaximums.height ?? 2000 : 2000)}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'no API key documented for basic chart rendering; terms may apply for high-volume use')}`,
    typeof chart.url === 'string' ? pc.blue(chart.url) : '',
    dataUrl === '' ? '' : `${pc.dim('binary')} data URL omitted from text output; use --format json for the base64 artifact`,
    '',
    `${pc.dim('next')} public-apis apis run quickchart.render -- --type line --labels ${labels || 'A,B,C'} --data ${data || '3,7,4'} --title "${String(query.title ?? 'Public APIs')}"`,
  ].filter(line => line !== '').join('\n')
  return lines
}

function renderRandomDogFiles(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const files = Array.isArray(value.files) ? value.files.filter(isRecord) : []
  const mediaType = typeof query.mediaType === 'string' && query.mediaType.trim() !== '' ? query.mediaType : 'image'
  const currentLimit = typeof query.limit === 'number' ? query.limit : files.length
  const nextLimit = Math.min(Math.max(currentLimit * 2, 20), 200)
  const otherMediaType = mediaType === 'video' ? 'image' : 'video'
  const lines = [
    `${pc.bold(pc.cyan('RandomDog Files'))} ${pc.dim(String(api.endpoint ?? 'GET /doggos'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? files.length)} shown · ${String(value.totalKnownFiles ?? '?')} known`,
  ]

  if (files.length === 0) {
    lines.push('', 'No RandomDog files matched this query.')
    lines.push(`${pc.dim('try')} public-apis apis run randomdog.files -- --media-type ${otherMediaType} --limit 20`)
    return lines.join('\n')
  }

  for (const file of files.slice(0, 30)) {
    lines.push(`- ${String(file.name ?? '')} · ${String(file.mediaType ?? '-')} · ${String(file.url ?? '')}`)
  }
  if (files.length > 30) {
    lines.push(pc.dim(`… ${files.length - 30} more file(s); use --format json for the full list.`))
  }
  if (nextLimit > currentLimit) {
    lines.push('', `${pc.dim('more')} public-apis apis run randomdog.files -- --media-type ${mediaType} --limit ${String(nextLimit)}`)
  }
  lines.push(`${pc.dim('switch')} public-apis apis run randomdog.files -- --media-type ${otherMediaType} --limit ${String(currentLimit)}`)
  lines.push(`${pc.dim('random')} public-apis apis run randomdog.woof`)
  return lines.join('\n')
}

