function renderNetworkCalcSubnet(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const address = isRecord(value.address) ? value.address : {}
  const meta = isRecord(value.meta) ? value.meta : {}
  const binary = isRecord(address.binary) ? address.binary : {}
  const lines = [
    `${pc.bold(pc.cyan('NetworkCalc Subnet'))} ${pc.dim(String(api.endpoint ?? 'GET /api/ip/{ip}/{cidr}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('network')} ${String(address.cidr_notation ?? `${String(query.ip ?? '?')}/${String(query.cidr ?? '?')}`)} · mask ${String(address.subnet_mask ?? '?')} · wildcard ${String(address.wildcard_mask ?? '?')}`,
    `${pc.dim('range')} ${String(address.network_address ?? '?')} → ${String(address.broadcast_address ?? '?')} · hosts ${String(address.assignable_hosts ?? '?')}`,
    `${pc.dim('usable')} ${String(address.first_assignable_host ?? '?')} → ${String(address.last_assignable_host ?? '?')}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'No public rate limit documented; use persistence for repeats.')}`,
  ]
  if (typeof binary.address === 'string') {
    lines.push(`${pc.dim('binary')} ${String(binary.address)} · network ${String(binary.network_address ?? '?')}`)
  }
  if (typeof meta.permalink === 'string') {
    lines.push(pc.blue(meta.permalink))
  }
  lines.push('', `${pc.dim('again')} ${buildNetworkCalcSubnetCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildNetworkCalcSubnetCommand(query, 'offline')}`)
  lines.push(`${pc.dim('next')} ${buildNetworkCalcSubnetCommand({ ip: address.first_assignable_host ?? query.ip, cidr: query.cidr, binary: query.binary }, 'online')}`)
  lines.push(`${pc.dim('convert')} ${buildNetworkCalcBinaryCommand({ value: 'ff', from: 16, to: 2 }, 'online')}`)
  return lines.join('\n')
}

function renderNetworkCalcBinary(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const conversion = isRecord(value.conversion) ? value.conversion : {}
  const lines = [
    `${pc.bold(pc.cyan('NetworkCalc Binary'))} ${pc.dim(String(api.endpoint ?? 'GET /api/binary/{value}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('input')} base ${String(conversion.from ?? query.from ?? '?')} · ${String(conversion.original ?? query.value ?? '')}`,
    `${pc.dim('output')} base ${String(conversion.to ?? query.to ?? '?')} · ${String(conversion.converted ?? '')}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'No public rate limit documented; use persistence for repeats.')}`,
    '',
    `${pc.dim('again')} ${buildNetworkCalcBinaryCommand({ value: query.value ?? conversion.original, from: query.from ?? conversion.from, to: query.to ?? conversion.to }, 'online')}`,
    `${pc.dim('replay')} ${buildNetworkCalcBinaryCommand({ value: query.value ?? conversion.original, from: query.from ?? conversion.from, to: query.to ?? conversion.to }, 'offline')}`,
    `${pc.dim('subnet')} ${buildNetworkCalcSubnetCommand({ ip: '10.5.1.0', cidr: 27 }, 'online')}`,
  ]
  return lines.join('\n')
}

function buildNetworkCalcSubnetCommand(query: Record<string, unknown>, mode?: 'online' | 'offline'): string {
  const parts = ['public-apis apis run networkcalc.subnet']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  parts.push(`--ip ${formatCliArg(query.ip ?? '10.5.1.0')}`)
  parts.push(`--cidr ${formatCliArg(query.cidr ?? 27)}`)
  if (query.binary !== undefined) {
    parts.push(`--binary ${formatCliArg(query.binary)}`)
  }
  return parts.join(' ')
}

function buildNetworkCalcBinaryCommand(query: Record<string, unknown>, mode?: 'online' | 'offline'): string {
  const parts = ['public-apis apis run networkcalc.binary']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  parts.push(`--value ${formatCliArg(query.value ?? '1e7d6d')}`)
  parts.push(`--from ${formatCliArg(query.from ?? 16)}`)
  parts.push(`--to ${formatCliArg(query.to ?? 2)}`)
  return parts.join(' ')
}

function renderNewtonCompute(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const calculation = isRecord(value.calculation) ? value.calculation : {}
  const supported = Array.isArray(api.supportedOperations)
    ? api.supportedOperations.map(String)
    : []
  const lines = [
    `${pc.bold(pc.cyan('Newton Math Calculation'))} ${pc.dim(
      String(api.endpoint ?? 'GET /api/v2/{operation}/{expression}'),
    )}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('engine')} ${String(api.engine ?? '@metadelta/core')}`,
    `${pc.dim('scope')} ${String(
      api.boundary ?? 'Fixed documented math operations only.',
    )}`,
    `${pc.dim('input')} ${String(
      api.expressionPolicy ?? 'Bounded math expression path parameter.',
    )}`,
    '',
    `${pc.bold(String(calculation.expression ?? query.expression ?? ''))}`,
    `${pc.dim(String(calculation.operation ?? query.operation ?? 'simplify'))} ${
      String(calculation.resultText ?? calculation.result ?? '')
    }`,
  ]
  if (supported.length > 0) {
    lines.push('', `${pc.dim('operations')} ${supported.join(', ')}`)
  }
  lines.push('', `${pc.dim('again')} ${buildNewtonComputeCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildNewtonComputeCommand(query, 'offline')}`)
  lines.push(`${pc.dim('derive')} ${buildNewtonComputeCommand({
    operation: 'derive',
    expression: 'x^2',
  }, 'online')}`)
  lines.push(`${pc.dim('zeroes')} ${buildNewtonComputeCommand({
    operation: 'zeroes',
    expression: 'x^2+2x',
  }, 'online')}`)
  return lines.join('\n')
}

function buildNewtonComputeCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run newton.compute']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  parts.push(`--operation ${formatCliArg(query.operation ?? 'simplify')}`)
  parts.push(`--expression ${formatCliArg(query.expression ?? '2^2+2(2)')}`)
  return parts.join(' ')
}

function renderNoctuaStats(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const stats = isRecord(value.stats) ? value.stats : {}
  const byTypes = Array.isArray(stats.byTypes) ? stats.byTypes.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('Noctua Skysource Stats'))} ${pc.dim(
      String(api.endpoint ?? 'GET /skysources/stats/'),
    )}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery({})}`,
    `${pc.dim('total')} ${formatInteger(stats.total)} sky source(s)`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Read-only skysources only.')}`,
  ]

  for (const entry of byTypes.slice(0, 12)) {
    lines.push(`- ${String(entry.type ?? '?')}: ${formatInteger(entry.count)}`)
  }

  lines.push('', `${pc.dim('source')} ${buildNoctuaSourceCommand({}, 'online')}`)
  lines.push(`${pc.dim('again')} public-apis apis run noctua.stats --online --persist`)
  lines.push(`${pc.dim('replay')} public-apis apis run noctua.stats --offline`)
  return lines.join('\n')
}

function renderNoctuaSource(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const source = isRecord(value.source) ? value.source : {}
  const modelData = isRecord(source.modelData) ? source.modelData : {}
  const names = Array.isArray(source.names) ? source.names.map(String) : []
  const types = Array.isArray(source.types) ? source.types.map(String) : []
  const extraKeys = Array.isArray(modelData.extraKeys)
    ? modelData.extraKeys.map(String)
    : []
  const lines = [
    `${pc.bold(pc.cyan('Noctua Sky Source'))} ${pc.dim(
      String(api.endpoint ?? 'GET /skysources/name/{str}'),
    )}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Read-only skysources only.')}`,
    '',
    pc.bold(String(source.shortName ?? query.name ?? 'sky source')),
  ]

  const meta = [
    typeof source.match === 'string' ? `match ${source.match}` : undefined,
    typeof source.model === 'string' ? `model ${source.model}` : undefined,
    typeof source.interest === 'number'
      ? `interest ${formatNumber(source.interest)}`
      : undefined,
    types.length > 0 ? `types ${types.join(', ')}` : undefined,
  ].filter((part): part is string => typeof part === 'string')
  if (meta.length > 0) lines.push(pc.dim(meta.join(' · ')))
  if (names.length > 0) lines.push(`${pc.dim('names')} ${names.slice(0, 8).join(', ')}`)

  const modelParts = [
    modelData.parent !== undefined ? `parent ${String(modelData.parent)}` : undefined,
    modelData.radius !== undefined ? `radius ${String(modelData.radius)}` : undefined,
    modelData.albedo !== undefined ? `albedo ${String(modelData.albedo)}` : undefined,
    modelData.jplHorizonId !== undefined
      ? `JPL ${String(modelData.jplHorizonId)}`
      : undefined,
  ].filter((part): part is string => typeof part === 'string')
  if (modelParts.length > 0) lines.push(`${pc.dim('model')} ${modelParts.join(' · ')}`)
  if (typeof modelData.orbitPreview === 'string') {
    lines.push(`${pc.dim('orbit')} ${truncateText(modelData.orbitPreview, 160)}`)
  }
  if (extraKeys.length > 0) {
    lines.push(`${pc.dim('extra keys')} ${extraKeys.join(', ')}`)
  }

  lines.push('', `${pc.dim('again')} ${buildNoctuaSourceCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildNoctuaSourceCommand(query, 'offline')}`)
  lines.push(`${pc.dim('stats')} public-apis apis run noctua.stats --online --persist`)
  return lines.join('\n')
}

function buildNoctuaSourceCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run noctua.source']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  parts.push(`--name ${formatCliArg(query.name ?? 'Mars')}`)
  return parts.join(' ')
}

function renderRigVedaBook(value: Record<string, unknown>): string {
  return renderRigVedaRecords(value, 'Rig Veda Book Metadata', 'rigveda.book')
}

function renderRigVedaSearch(value: Record<string, unknown>): string {
  return renderRigVedaRecords(value, 'Rig Veda Metadata Search', 'rigveda.search')
}

function renderRigVedaRecords(
  value: Record<string, unknown>,
  title: string,
  operation: 'rigveda.book' | 'rigveda.search',
): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const facets = isRecord(value.facets) ? value.facets : {}
  const verses = Array.isArray(value.verses) ? value.verses.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan(title))} ${pc.dim(String(api.endpoint ?? 'GET /rv/v2/meta'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    [
      `${pc.dim('pagination')} returned`,
      `${String(pagination.returned ?? verses.length)} /`,
      `${String(pagination.total ?? verses.length)} · limit`,
      `${String(pagination.limit ?? query.limit ?? '?')} · offset`,
      String(pagination.offset ?? query.offset ?? 0),
    ].join(' '),
    `${pc.dim('scope')} ${String(api.boundary ?? 'Read-only metadata only.')}`,
    `${pc.dim('categories')} ${String(
      api.categoryPolicy ?? 'Documented categories only.',
    )}`,
  ]

  const facetLine = formatRigVedaFacets(facets)
  if (facetLine !== '') lines.push(`${pc.dim('facets')} ${facetLine}`)

  if (verses.length === 0) {
    lines.push('', pc.yellow('No Rig Veda metadata records returned.'))
    lines.push(`${pc.dim('again')} ${buildRigVedaCommand(operation, query, 'online')}`)
    lines.push(
      `${pc.dim('replay')} ${buildRigVedaCommand(operation, query, 'offline')}`,
    )
    lines.push(`${pc.dim('sample')} ${[
      'public-apis apis run rigveda.search --online --persist --',
      '--field god --value ganga --limit 10',
    ].join(' ')}`)
    return lines.join('\n')
  }

  lines.push('')
  for (const [index, verse] of verses.slice(0, 20).entries()) {
    lines.push(formatRigVedaVerse(index, verse))
  }
  if (verses.length > 20) {
    lines.push(pc.dim(`… ${verses.length - 20} more record(s); use --format json.`))
  }

  lines.push(
    '',
    `${pc.dim('again')} ${buildRigVedaCommand(operation, query, 'online')}`,
  )
  lines.push(
    `${pc.dim('replay')} ${buildRigVedaCommand(operation, query, 'offline')}`,
  )
  if (typeof pagination.nextOffset === 'number') {
    lines.push(
      `${pc.dim('next')} ${buildRigVedaNextCommand(operation, query, pagination)}`,
    )
  }
  if (operation === 'rigveda.book') {
    lines.push(`${pc.dim('search')} ${[
      'public-apis apis run rigveda.search --online --persist --',
      `--field god --value ${formatCliArg(firstString(facets.gods, 'agni'))}`,
      `--limit ${String(query.limit ?? 20)}`,
    ].join(' ')}`)
  } else {
    lines.push(`${pc.dim('book')} ${[
      'public-apis apis run rigveda.book --online --persist --',
      `--mandal ${String(firstVerseMandal(verses, query.mandal ?? 1))}`,
      `--limit ${String(query.limit ?? 20)}`,
    ].join(' ')}`)
  }
  return lines.join('\n')
}

function formatRigVedaVerse(index: number, verse: Record<string, unknown>): string {
  const location = [
    `mandal ${String(verse.mandal ?? '?')}`,
    `sukta ${String(verse.sukta ?? '?')}`,
  ].join(' · ')
  const poet = `${String(verse.sungby ?? '-')} (${String(verse.sungbycategory ?? '-')})`
  const god = [
    String(verse.sungfor ?? '-'),
    `(${String(verse.sungforcategory ?? '-')})`,
  ].join(' ')
  return [
    `${pc.bold(`${index + 1}.`)} ${location} · meter ${String(verse.meter ?? '-')}`,
    `   ${pc.dim('poet')} ${poet}`,
    `   ${pc.dim('god')} ${god}`,
  ].join('\n')
}

function formatRigVedaFacets(facets: Record<string, unknown>): string {
  const meters = readStringList(facets.meters)
  const poets = readStringList(facets.poets)
  const gods = readStringList(facets.gods)
  const parts = [
    meters.length > 0 ? `meters ${meters.slice(0, 3).join(', ')}` : undefined,
    poets.length > 0 ? `poets ${poets.slice(0, 2).join(', ')}` : undefined,
    gods.length > 0 ? `gods ${gods.slice(0, 3).join(', ')}` : undefined,
  ].filter((part): part is string => typeof part === 'string')
  return parts.join(' · ')
}

function buildRigVedaCommand(
  operation: 'rigveda.book' | 'rigveda.search',
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = [`public-apis apis run ${operation}`]
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  if (operation === 'rigveda.book') {
    parts.push(`--mandal ${String(query.mandal ?? 1)}`)
  } else {
    parts.push(`--field ${formatCliArg(query.field ?? 'god')}`)
    parts.push(`--value ${formatCliArg(query.value ?? 'ganga')}`)
    if (query.mandal !== undefined) parts.push(`--mandal ${String(query.mandal)}`)
    if (query.poet !== undefined) parts.push(`--poet ${formatCliArg(query.poet)}`)
    if (query.poetCategory !== undefined) {
      parts.push(`--poet-category ${formatCliArg(query.poetCategory)}`)
    }
  }
  parts.push(`--limit ${String(query.limit ?? 20)}`)
  const offset = Number(query.offset ?? 0)
  if (Number.isFinite(offset) && offset > 0) parts.push(`--offset ${String(offset)}`)
  return parts.join(' ')
}

function buildRigVedaNextCommand(
  operation: 'rigveda.book' | 'rigveda.search',
  query: Record<string, unknown>,
  pagination: Record<string, unknown>,
): string {
  return buildRigVedaCommand(operation, {
    ...query,
    offset: pagination.nextOffset,
  }, 'online')
}

function firstString(value: unknown, fallback: string): string {
  const strings = readStringList(value)
  return strings[0] ?? fallback
}

function firstVerseMandal(
  verses: Record<string, unknown>[],
  fallback: unknown,
): number {
  const mandal = verses.find(verse => typeof verse.mandal === 'number')?.mandal
  return typeof mandal === 'number' ? mandal : Number(fallback)
}

function renderVedicSocietyWords(value: Record<string, unknown>): string {
  return renderVedicSocietyEntries(
    value,
    'Vedic Society Word Lookup',
    'vedicsociety.words',
  )
}

function renderVedicSocietyDescriptions(value: Record<string, unknown>): string {
  return renderVedicSocietyEntries(
    value,
    'Vedic Society Description Search',
    'vedicsociety.descriptions',
  )
}

function renderVedicSocietyCategory(value: Record<string, unknown>): string {
  return renderVedicSocietyEntries(
    value,
    'Vedic Society Category Browser',
    'vedicsociety.category',
  )
}

function renderVedicSocietyEntries(
  value: Record<string, unknown>,
  title: string,
  operation: VedicSocietyOperation,
): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const facets = isRecord(value.facets) ? value.facets : {}
  const entries = Array.isArray(value.entries)
    ? value.entries.filter(isRecord)
    : []
  const lines = [
    `${pc.bold(pc.cyan(title))} ${pc.dim(String(api.endpoint ?? 'GET /vs/v2'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    [
      `${pc.dim('pagination')} returned`,
      `${String(pagination.returned ?? entries.length)} /`,
      `${String(pagination.total ?? entries.length)} · limit`,
      `${String(pagination.limit ?? query.limit ?? '?')} · offset`,
      String(pagination.offset ?? query.offset ?? 0),
    ].join(' '),
    `${pc.dim('scope')} ${String(api.boundary ?? 'Read-only noun metadata only.')}`,
    `${pc.dim('categories')} ${String(
      api.categoryPolicy ?? 'Documented categories only.',
    )}`,
    `${pc.dim('empty')} ${String(
      api.emptyPolicy ?? 'Known not-found text is treated as empty.',
    )}`,
  ]

  const facetLine = formatVedicSocietyFacets(facets)
  if (facetLine !== '') lines.push(`${pc.dim('facets')} ${facetLine}`)

  if (entries.length === 0) {
    lines.push('', pc.yellow('No Vedic Society noun records returned.'))
    lines.push(
      `${pc.dim('again')} ${buildVedicSocietyCommand(operation, query, 'online')}`,
    )
    lines.push(
      `${pc.dim('replay')} ${buildVedicSocietyCommand(operation, query, 'offline')}`,
    )
    lines.push(`${pc.dim('sample')} ${[
      'public-apis apis run vedicsociety.category --online --persist --',
      '--category river --limit 10',
    ].join(' ')}`)
    return lines.join('\n')
  }

  lines.push('')
  for (const [index, entry] of entries.slice(0, 20).entries()) {
    lines.push(formatVedicSocietyEntry(index, entry))
  }
  if (entries.length > 20) {
    lines.push(pc.dim(`… ${entries.length - 20} more record(s); use --format json.`))
  }

  lines.push(
    '',
    `${pc.dim('again')} ${buildVedicSocietyCommand(operation, query, 'online')}`,
  )
  lines.push(
    `${pc.dim('replay')} ${buildVedicSocietyCommand(operation, query, 'offline')}`,
  )
  if (typeof pagination.nextOffset === 'number') {
    lines.push(
      `${pc.dim('next')} ${buildVedicSocietyNextCommand(
        operation,
        query,
        pagination,
      )}`,
    )
  }
  lines.push(buildVedicSocietyRelatedCommand(operation, query, entries, facets))
  return lines.join('\n')
}

type VedicSocietyOperation =
  | 'vedicsociety.words'
  | 'vedicsociety.descriptions'
  | 'vedicsociety.category'

function formatVedicSocietyEntry(
  index: number,
  entry: Record<string, unknown>,
): string {
  const word = String(entry.word ?? '-')
  const nagari = String(entry.nagari ?? '-')
  const category = String(entry.category ?? '-')
  const description = truncateText(String(entry.description ?? '-'), 180)
  return [
    `${pc.bold(`${index + 1}.`)} ${word} · ${nagari} · ${category}`,
    `   ${pc.dim('description')} ${description}`,
  ].join('\n')
}

function formatVedicSocietyFacets(facets: Record<string, unknown>): string {
  const categories = readStringList(facets.categories)
  const words = readStringList(facets.words)
  const descriptions = readStringList(facets.descriptions)
  const parts = [
    categories.length > 0
      ? `categories ${categories.slice(0, 4).join(', ')}`
      : undefined,
    words.length > 0 ? `words ${words.slice(0, 3).join(', ')}` : undefined,
    descriptions.length > 0
      ? `descriptions ${descriptions.slice(0, 2).map(text => {
        return truncateText(text, 34)
      }).join(', ')}`
      : undefined,
  ].filter((part): part is string => typeof part === 'string')
  return parts.join(' · ')
}

function buildVedicSocietyCommand(
  operation: VedicSocietyOperation,
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = [`public-apis apis run ${operation}`]
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  if (operation === 'vedicsociety.words') {
    parts.push(`--word ${formatCliArg(query.word ?? 'agni')}`)
  } else if (operation === 'vedicsociety.descriptions') {
    parts.push(`--description ${formatCliArg(query.description ?? 'fire')}`)
  } else {
    parts.push(`--category ${formatCliArg(query.category ?? 'river')}`)
  }
  parts.push(`--limit ${String(query.limit ?? 20)}`)
  const offset = Number(query.offset ?? 0)
  if (Number.isFinite(offset) && offset > 0) parts.push(`--offset ${String(offset)}`)
  return parts.join(' ')
}

function buildVedicSocietyNextCommand(
  operation: VedicSocietyOperation,
  query: Record<string, unknown>,
  pagination: Record<string, unknown>,
): string {
  return buildVedicSocietyCommand(operation, {
    ...query,
    offset: pagination.nextOffset,
  }, 'online')
}

function buildVedicSocietyRelatedCommand(
  operation: VedicSocietyOperation,
  query: Record<string, unknown>,
  entries: Record<string, unknown>[],
  facets: Record<string, unknown>,
): string {
  const firstEntry = entries[0] ?? {}
  if (operation === 'vedicsociety.category') {
    return `${pc.dim('word')} ${[
      'public-apis apis run vedicsociety.words --online --persist --',
      `--word ${formatCliArg(String(firstEntry.word ?? 'ganga'))}`,
      `--limit ${String(query.limit ?? 20)}`,
    ].join(' ')}`
  }
  if (operation === 'vedicsociety.words') {
    return `${pc.dim('describe')} ${[
      'public-apis apis run vedicsociety.descriptions --online --persist --',
      `--description ${formatCliArg(firstDescriptionWord(firstEntry))}`,
      `--limit ${String(query.limit ?? 20)}`,
    ].join(' ')}`
  }
  return `${pc.dim('category')} ${[
    'public-apis apis run vedicsociety.category --online --persist --',
    `--category ${formatCliArg(firstString(facets.categories, 'river'))}`,
    `--limit ${String(query.limit ?? 20)}`,
  ].join(' ')}`
}

function firstDescriptionWord(entry: Record<string, unknown>): string {
  const description = String(entry.description ?? 'fire')
  return description.split(/\s+/u).find(word => /^[a-z][a-z-]*$/iu.test(word))
    ?? 'fire'
}

function renderRunyankoleBibleBooks(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const books = Array.isArray(value.books) ? value.books.filter(isRecord) : []
  const lines = runyankoleBibleHeader(
    'Runyankole Bible Books',
    String(api.endpoint ?? 'GET /api/books'),
    value,
    query,
    pagination,
    books.length,
  )

  if (books.length === 0) {
    lines.push('', pc.yellow('No Runyankole Bible books returned.'))
  } else {
    lines.push('')
    for (const book of books.slice(0, 30)) {
      lines.push(
        `${pc.bold(String(book.id ?? '?'))} ${String(book.longName ?? '-')}`
        + ` ${pc.dim(String(book.shortName ?? '-'))}`,
      )
    }
  }

  lines.push(
    '',
    `${pc.dim('again')} ${buildRunyankoleBibleCommand('books', query, 'online')}`,
    `${pc.dim('replay')} ${buildRunyankoleBibleCommand('books', query, 'offline')}`,
    `${pc.dim('verse')} ${buildRunyankoleBibleCommand(
      'verse',
      { book: firstNumber(books[0]?.id, 10), chapter: 1, verse: 1 },
      'online',
    )}`,
  )
  if (typeof pagination.nextOffset === 'number') {
    lines.push(
      `${pc.dim('next')} ${buildRunyankoleBibleCommand(
        'books',
        { ...query, offset: pagination.nextOffset },
        'online',
      )}`,
    )
  }
  return lines.join('\n')
}

