function renderHelloSalutTranslate(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const translation = isRecord(value.translation) ? value.translation : {}
  const language = String(query.language ?? translation.code ?? 'fr')
  const code = String(translation.code ?? 'none')
  const matched = translation.matched === true
  const translateArgs = `--language ${formatCliArg(language)}`
  const lines = [
    `${pc.bold(pc.cyan('HelloSalut Translation'))} ${pc.dim(String(api.endpoint ?? 'GET /?lang={language}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')} · fallback ${String(api.fallbackBehavior ?? 'unsupported codes return English Hello')}`,
    `${pc.dim('rate')} ${String(api.rateLimitPolicy ?? 'No official numeric limit found; use persistence for repeated lookups.')}`,
    '',
    `${pc.bold(String(translation.hello ?? 'Hello'))} ${pc.dim(`code ${code}${matched ? '' : ' · fallback'}`)}`,
  ]
  if (!matched) {
    lines.push(pc.yellow('HelloSalut did not return a direct language match; showing the upstream fallback greeting.'))
  }
  lines.push('', `${pc.dim('again')} public-apis apis run hellosalut.translate --online --persist -- ${translateArgs}`)
  lines.push(`${pc.dim('replay')} public-apis apis run hellosalut.translate --offline -- ${translateArgs}`)
  lines.push(`${pc.dim('example')} public-apis apis run hellosalut.translate --online --persist -- --language es`)
  return lines.join('\n')
}

function renderHongKongGeoDataLocationSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const locations = Array.isArray(value.locations) ? value.locations.filter(isRecord) : []
  const commandArgs = buildHongKongGeoDataLocationSearchArgs(query)
  const lines = [
    `${pc.bold(pc.cyan('Hong Kong GeoData Location Search'))} ${pc.dim(String(api.endpoint ?? 'GET /gs/api/v1.0.0/locationSearch'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? locations.length)} shown · ${String(value.totalReturned ?? locations.length)} returned by API · limit cap ${String(api.cliLimitCap ?? 50)}`,
    `${pc.dim('rate')} ${String(api.rateLimitPolicy ?? 'Avoid large bursts; use --persist and --offline for repeated searches.')}`,
    `${pc.dim('migration')} ${String(api.migrationNotice ?? 'Use www.map.gov.hk for the current Location Search API hostname.')}`,
  ]
  if (locations.length === 0) {
    lines.push('', pc.yellow('No Hong Kong GeoData locations matched this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run hongkonggeodata.locationSearch --online --persist -- --query ${formatCliArg('cultural centre')} --limit 10`)
    return lines.join('\n')
  }
  for (const [index, location] of locations.slice(0, 20).entries()) {
    const district = typeof location.districtEnglish === 'string' && location.districtEnglish !== '' ? location.districtEnglish : '-'
    lines.push('', `${pc.bold(`${index + 1}. ${String(location.nameEnglish ?? '(unnamed location)')}`)} ${pc.dim(district)}`)
    if (typeof location.addressEnglish === 'string' && location.addressEnglish !== '') {
      lines.push(`  ${location.addressEnglish}`)
    }
    lines.push(`  HK1980 Grid x=${String(location.x ?? '?')} y=${String(location.y ?? '?')}`)
  }
  if (locations.length > 20) {
    lines.push(pc.dim(`… ${locations.length - 20} more location(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} public-apis apis run hongkonggeodata.locationSearch --online --persist -- ${commandArgs}`)
  lines.push(`${pc.dim('replay')} public-apis apis run hongkonggeodata.locationSearch --offline -- ${commandArgs}`)
  lines.push(`${pc.dim('example')} public-apis apis run hongkonggeodata.locationSearch --online --persist -- --query park --limit 10`)
  return lines.join('\n')
}

function buildHongKongGeoDataLocationSearchArgs(query: Record<string, unknown>): string {
  return `--query ${formatCliArg(query.query ?? 'cultural centre')} --limit ${formatCliArg(query.limit ?? 10)}`
}

function renderIbgeStates(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const states = Array.isArray(value.states) ? value.states.filter(isRecord) : []
  const commandArgs = `--limit ${formatCliArg(query.limit ?? 30)}`
  const lines = [
    `${pc.bold(pc.cyan('IBGE Brazilian States'))} ${pc.dim(String(api.endpoint ?? 'GET /api/v1/localidades/estados'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? states.length)} shown · ${String(value.totalReturned ?? states.length)} returned by API · limit cap ${String(api.cliLimitCap ?? 100)}`,
    `${pc.dim('rate')} ${String(api.rateLimitPolicy ?? 'No official numeric rate limit found; use persistence for repeated lookups.')}`,
  ]
  if (states.length === 0) {
    lines.push('', pc.yellow('No IBGE states returned for this query.'))
    lines.push(`${pc.dim('again')} public-apis apis run ibge.states --online --persist -- ${commandArgs}`)
    lines.push(`${pc.dim('replay')} public-apis apis run ibge.states --offline -- ${commandArgs}`)
    return lines.join('\n')
  }
  for (const state of states.slice(0, 30)) {
    const region = isRecord(state.region) ? state.region : {}
    lines.push(`${pc.bold(String(state.acronym ?? '?'))} ${String(state.name ?? '(unnamed state)')} · ${String(region.name ?? 'unknown region')} (${String(region.acronym ?? '-')}) · id ${String(state.id ?? '?')}`)
  }
  lines.push('', `${pc.dim('again')} public-apis apis run ibge.states --online --persist -- ${commandArgs}`)
  lines.push(`${pc.dim('replay')} public-apis apis run ibge.states --offline -- ${commandArgs}`)
  lines.push(`${pc.dim('municipalities')} public-apis apis run ibge.municipalities --online --persist -- --state SP --limit 30`)
  return lines.join('\n')
}

function renderIbgeMunicipalities(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const municipalities = Array.isArray(value.municipalities) ? value.municipalities.filter(isRecord) : []
  const commandArgs = `--state ${formatCliArg(query.state ?? 'SP')} --limit ${formatCliArg(query.limit ?? 30)}`
  const lines = [
    `${pc.bold(pc.cyan('IBGE Municipalities'))} ${pc.dim(String(api.endpoint ?? 'GET /api/v1/localidades/estados/{state}/municipios'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? municipalities.length)} shown · ${String(value.totalReturned ?? municipalities.length)} returned by API · limit cap ${String(api.cliLimitCap ?? 100)}`,
    `${pc.dim('rate')} ${String(api.rateLimitPolicy ?? 'No official numeric rate limit found; use persistence for repeated lookups.')}`,
  ]
  if (municipalities.length === 0) {
    lines.push('', pc.yellow('No IBGE municipalities returned for this state.'))
    lines.push(`${pc.dim('again')} public-apis apis run ibge.municipalities --online --persist -- ${commandArgs}`)
    lines.push(`${pc.dim('replay')} public-apis apis run ibge.municipalities --offline -- ${commandArgs}`)
    lines.push(`${pc.dim('states')} public-apis apis run ibge.states --online --persist -- --limit 30`)
    return lines.join('\n')
  }
  for (const municipality of municipalities.slice(0, 30)) {
    const state = isRecord(municipality.state) ? municipality.state : {}
    const region = [municipality.immediateRegion, municipality.intermediateRegion].filter((entry): entry is string => typeof entry === 'string' && entry !== '').join(' · ')
    lines.push(`${pc.bold(String(municipality.name ?? '(unnamed municipality)'))} ${pc.dim(`${String(state.acronym ?? query.state ?? '?')} · id ${String(municipality.id ?? '?')}`)}`)
    if (region !== '') {
      lines.push(`  ${region}`)
    }
  }
  lines.push('', `${pc.dim('again')} public-apis apis run ibge.municipalities --online --persist -- ${commandArgs}`)
  lines.push(`${pc.dim('replay')} public-apis apis run ibge.municipalities --offline -- ${commandArgs}`)
  lines.push(`${pc.dim('states')} public-apis apis run ibge.states --online --persist -- --limit 30`)
  return lines.join('\n')
}

function renderIpInfoLookup(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const lookup = isRecord(value.lookup) ? value.lookup : {}
  const coordinates = typeof lookup.latitude === 'number' && typeof lookup.longitude === 'number' ? `${String(lookup.latitude)}, ${String(lookup.longitude)}` : '-'
  const ip = String(lookup.ip ?? query.ip ?? '8.8.8.8')
  const lines = [
    `${pc.bold(pc.cyan('IPinfo Lookup'))} ${pc.dim(String(api.endpoint ?? 'GET /{ip}/json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('boundary')} ${String(api.privacy ?? 'IP geolocation uses explicit IP only; current-client IP is not used by default.')}`,
    `${pc.dim('auth')} ${String(api.freePlanNotes ?? 'No token used; unauthenticated responses may include missingauth readme.')}`,
    '',
    `${pc.bold(ip)} ${String(lookup.country ?? '?')} · ${[lookup.city, lookup.region].filter((entry): entry is string => typeof entry === 'string' && entry !== '').join(', ') || 'unknown location'}`,
    `${pc.dim('coordinates')} ${coordinates} · ${pc.dim('timezone')} ${String(lookup.timezone ?? '-')}`,
    `${pc.dim('network')} ${String(lookup.organization ?? '-')} · hostname ${String(lookup.hostname ?? '-')}`,
  ]
  if (lookup.anycast === true) {
    lines.push(`${pc.dim('anycast')} true`)
  }
  if (typeof lookup.missingAuthReadme === 'string') {
    lines.push(`${pc.dim('readme')} ${lookup.missingAuthReadme}`)
  }
  lines.push('', `${pc.dim('again')} public-apis apis run ipinfo.lookup --online --persist -- --ip ${formatCliArg(ip)}`)
  lines.push(`${pc.dim('replay')} public-apis apis run ipinfo.lookup --offline -- --ip ${formatCliArg(ip)}`)
  lines.push(`${pc.dim('sample')} public-apis apis run ipinfo.lookup --online --persist -- --ip 1.1.1.1`)
  return lines.join('\n')
}

function renderIpApiLookup(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const lookup = isRecord(value.lookup) ? value.lookup : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const transport = isRecord(value.transport) ? value.transport : {}
  const input = typeof query.query === 'string' ? query.query : '8.8.8.8'
  const resolved = typeof lookup.query === 'string' ? lookup.query : input
  const coordinates = typeof lookup.latitude === 'number' && typeof lookup.longitude === 'number'
    ? `${String(lookup.latitude)}, ${String(lookup.longitude)}`
    : 'not provided'
  const location = [lookup.city, lookup.regionName, lookup.country].filter((entry): entry is string => typeof entry === 'string' && entry.trim() !== '').join(', ') || 'unknown location'
  const quota = [
    typeof rateLimit.remaining === 'string' ? `${rateLimit.remaining} remaining` : undefined,
    typeof rateLimit.resetSeconds === 'string' ? `resets in ${rateLimit.resetSeconds}s` : undefined,
  ].filter((entry): entry is string => entry !== undefined).join(' · ') || String(rateLimit.limit ?? '45 requests/minute on free endpoint')
  const lines = [
    `${pc.bold(pc.cyan('ip-api.com Lookup'))} ${pc.dim(String(api.endpoint ?? 'GET /json/{query}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open HTTP REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTP JSON REST')} · ${String(transport.security ?? 'http-only')} · ${String(transport.contentType ?? 'application/json')}`,
    `${pc.dim('privacy')} ${String(api.privacy ?? 'Explicit IP/domain geolocation only; current-client IP is not used by default.')}`,
    `${pc.dim('rate limit')} ${quota}`,
    '',
    `${pc.bold(String(input))} -> ${String(resolved)} · ${location}`,
    `${pc.dim('coordinates')} ${coordinates} · ${pc.dim('timezone')} ${String(lookup.timezone ?? '-')}`,
    `${pc.dim('network')} ${String(lookup.isp ?? '-')} · ${String(lookup.organization ?? '-')} · ${String(lookup.asn ?? '-')}`,
    '',
    `${pc.dim('again')} ${buildIpApiLookupCommand(input, 'online')}`,
    `${pc.dim('replay')} ${buildIpApiLookupCommand(input, 'offline')}`,
    `${pc.dim('sample')} ${buildIpApiLookupCommand('example.com', 'online')}`,
  ]
  return lines.join('\n')
}

function buildIpApiLookupCommand(query: string, mode: 'online' | 'offline'): string {
  const storageFlags = mode === 'online' ? '--online --persist' : '--offline'
  return `public-apis apis run ipapi.lookup ${storageFlags} -- --query ${formatCliArg(query)}`
}

function renderIpGeoLookup(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const lookup = isRecord(value.lookup) ? value.lookup : {}
  const transport = isRecord(value.transport) ? value.transport : {}
  const input = typeof query.query === 'string' ? query.query : '8.8.8.8'
  const resolved = typeof lookup.ip === 'string' ? lookup.ip : input
  const coordinates = typeof lookup.latitude === 'number' && typeof lookup.longitude === 'number'
    ? `${String(lookup.latitude)}, ${String(lookup.longitude)}`
    : 'not provided'
  const location = [lookup.city, lookup.regionName, lookup.country].filter((entry): entry is string => typeof entry === 'string' && entry.trim() !== '').join(', ') || 'unknown location'
  const flags = [
    lookup.mobile === true ? 'mobile' : undefined,
    lookup.proxy === true ? 'proxy' : undefined,
    lookup.hosting === true ? 'hosting' : undefined,
    lookup.cached === true ? 'cached' : undefined,
  ].filter((entry): entry is string => entry !== undefined)
  const lines = [
    `${pc.bold(pc.cyan('IPGEO Lookup'))} ${pc.dim(String(api.endpoint ?? 'GET /ipgeo/{query}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')} · ${String(transport.contentType ?? 'application/json')}`,
    `${pc.dim('privacy')} ${String(api.privacy ?? 'Explicit IP/domain geolocation only; current-client IP is not used by default.')}`,
    '',
    `${pc.bold(String(input))} -> ${String(resolved)} · ${location}`,
    `${pc.dim('coordinates')} ${coordinates} · ${pc.dim('timezone')} ${String(lookup.timezone ?? '-')}`,
    `${pc.dim('network')} ${String(lookup.isp ?? '-')} · ${String(lookup.organization ?? '-')} · ${String(lookup.asn ?? '-')}`,
  ]
  if (typeof lookup.reverse === 'string' && lookup.reverse.trim() !== '') {
    lines.push(`${pc.dim('reverse')} ${lookup.reverse}`)
  }
  if (flags.length > 0) {
    lines.push(`${pc.dim('flags')} ${flags.join(', ')}`)
  }
  lines.push('', `${pc.dim('again')} ${buildIpGeoLookupCommand(input, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildIpGeoLookupCommand(input, 'offline')}`)
  lines.push(`${pc.dim('sample')} ${buildIpGeoLookupCommand('example.com', 'online')}`)
  return lines.join('\n')
}

function buildIpGeoLookupCommand(query: string, mode: 'online' | 'offline'): string {
  const storageFlags = mode === 'online' ? '--online --persist' : '--offline'
  return `public-apis apis run ipgeo.lookup ${storageFlags} -- --query ${formatCliArg(query)}`
}

function renderGNewsArticles(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const articles = Array.isArray(value.articles) ? value.articles.filter(isRecord) : []
  const isHeadlines = value.kind === 'gnews.headlines'
  const page = readGNewsPage(query, pagination)
  const max = readGNewsMax(query, pagination)
  const commandOptions = readGNewsCommandOptions(query, { page, max, isHeadlines })
  const lines = [
    `${pc.bold(pc.cyan(isHeadlines ? 'GNews Top Headlines' : 'GNews Search'))} ${pc.dim(String(api.endpoint ?? (isHeadlines ? 'GET /api/v4/top-headlines' : 'GET /api/v4/search')))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · API key via local config/env · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${String(page)} · ${String(pagination.returned ?? articles.length)} returned · total ${String(pagination.totalArticles ?? '?')} · max ${String(max)} / ${String(pagination.maxResults ?? '?')}`,
  ]
  if (typeof value.information === 'string' && value.information.trim() !== '') {
    lines.push(`${pc.dim('info')} ${truncateText(value.information.trim(), 180)}`)
  }
  if (articles.length === 0) {
    lines.push('', pc.yellow('No GNews articles returned for this query.'))
    lines.push(`${pc.dim('again')} ${buildGNewsCommand(commandOptions, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildGNewsCommand(commandOptions, 'offline')}`)
    lines.push(`${pc.dim(isHeadlines ? 'search' : 'headlines')} ${buildGNewsCommand(isHeadlines ? { operation: 'search', query: 'technology', max, page: 1, language: commandOptions.language, country: commandOptions.country } : { operation: 'headlines', category: 'technology', max, page: 1, language: commandOptions.language, country: commandOptions.country }, 'online')}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const article of articles.slice(0, 12)) {
    const source = isRecord(article.source) ? article.source : {}
    lines.push(`${pc.bold(String(article.title ?? 'untitled article'))} ${pc.dim(String(article.language ?? query.language ?? '-'))}`)
    lines.push(`   ${String(article.publishedAt ?? 'unknown date')} · ${String(source.name ?? 'unknown source')} · ${String(source.country ?? query.country ?? '-')}`)
    if (typeof article.description === 'string' && article.description.trim() !== '') {
      lines.push(`   ${truncateText(article.description.trim(), 160)}`)
    }
    if (typeof article.url === 'string' && article.url.trim() !== '') {
      lines.push(`   ${pc.blue(article.url)}`)
    }
  }
  if (articles.length > 12) {
    lines.push(pc.dim(`… ${articles.length - 12} more article(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} ${buildGNewsCommand(commandOptions, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildGNewsCommand(commandOptions, 'offline')}`)
  if (page > 1) {
    lines.push(`${pc.dim('prev page')} ${buildGNewsCommand({ ...commandOptions, page: page - 1 }, 'online')}`)
  }
  lines.push(`${pc.dim('next page')} ${buildGNewsCommand({ ...commandOptions, page: page + 1 }, 'online')}`)
  if (isHeadlines) {
    lines.push(`${pc.dim('search')} ${buildGNewsCommand({ operation: 'search', query: commandOptions.query ?? commandOptions.category ?? 'technology', max, page: 1, language: commandOptions.language, country: commandOptions.country }, 'online')}`)
  } else {
    lines.push(`${pc.dim('headlines')} ${buildGNewsCommand({ operation: 'headlines', category: 'technology', max, page: 1, language: commandOptions.language, country: commandOptions.country }, 'online')}`)
  }
  return lines.join('\n')
}

type GNewsCommandOptions = {
  operation: 'search' | 'headlines'
  max: number
  page: number
  query?: string | undefined
  category?: string | undefined
  language?: string | undefined
  country?: string | undefined
  searchIn?: string | undefined
  sortBy?: string | undefined
  nullable?: string | undefined
  from?: string | undefined
  to?: string | undefined
}

function readGNewsCommandOptions(query: Record<string, unknown>, fallback: { page: number; max: number; isHeadlines: boolean }): GNewsCommandOptions {
  return {
    operation: fallback.isHeadlines ? 'headlines' : 'search',
    max: fallback.max,
    page: fallback.page,
    ...(typeof query.query === 'string' && query.query.trim() !== '' ? { query: query.query.trim() } : {}),
    ...(typeof query.category === 'string' && query.category.trim() !== '' ? { category: query.category.trim() } : {}),
    ...(typeof query.language === 'string' && query.language.trim() !== '' ? { language: query.language.trim().toLowerCase() } : {}),
    ...(typeof query.country === 'string' && query.country.trim() !== '' ? { country: query.country.trim().toLowerCase() } : {}),
    ...(typeof query.searchIn === 'string' && query.searchIn.trim() !== '' ? { searchIn: query.searchIn.trim() } : {}),
    ...(typeof query.sortBy === 'string' && query.sortBy.trim() !== '' ? { sortBy: query.sortBy.trim() } : {}),
    ...(typeof query.nullable === 'string' && query.nullable.trim() !== '' ? { nullable: query.nullable.trim() } : {}),
    ...(typeof query.from === 'string' && query.from.trim() !== '' ? { from: query.from.trim() } : {}),
    ...(typeof query.to === 'string' && query.to.trim() !== '' ? { to: query.to.trim() } : {}),
  }
}

function readGNewsPage(query: Record<string, unknown>, pagination: Record<string, unknown>): number {
  const page = Number(pagination.page ?? query.page ?? 1)
  return Number.isInteger(page) && page > 0 ? page : 1
}

function readGNewsMax(query: Record<string, unknown>, pagination: Record<string, unknown>): number {
  const max = Number(pagination.max ?? query.max ?? 100)
  return Number.isInteger(max) && max > 0 ? max : 100
}

function buildGNewsCommand(options: GNewsCommandOptions, mode: 'online' | 'offline'): string {
  const operation = options.operation === 'headlines' ? 'gnews.headlines' : 'gnews.search'
  const storageFlags = mode === 'online' ? '--online --persist' : '--offline'
  const parts = [`public-apis apis run ${operation} ${storageFlags} --`]
  if (options.operation === 'headlines') {
    parts.push('--category', formatCliArg(options.category ?? 'general'))
    if (options.query !== undefined) {
      parts.push('--query', formatCliArg(options.query))
    }
  } else {
    parts.push('--query', formatCliArg(options.query ?? 'public api'))
    if (options.searchIn !== undefined) {
      parts.push('--search-in', formatCliArg(options.searchIn))
    }
    if (options.sortBy !== undefined) {
      parts.push('--sort-by', formatCliArg(options.sortBy))
    }
  }
  if (options.language !== undefined) {
    parts.push('--language', formatCliArg(options.language))
  }
  if (options.country !== undefined) {
    parts.push('--country', formatCliArg(options.country))
  }
  if (options.nullable !== undefined) {
    parts.push('--nullable', formatCliArg(options.nullable))
  }
  if (options.from !== undefined) {
    parts.push('--from', formatCliArg(options.from))
  }
  if (options.to !== undefined) {
    parts.push('--to', formatCliArg(options.to))
  }
  parts.push('--max', String(options.max), '--page', String(options.page))
  return parts.join(' ')
}

function renderGuardianSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const articles = Array.isArray(value.articles) ? value.articles.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('The Guardian Content Search'))} ${pc.dim(String(api.endpoint ?? 'GET /search'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · API key via local config/env · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${String(pagination.currentPage ?? query.page ?? 1)} / ${String(pagination.pages ?? '?')} · ${String(pagination.returned ?? articles.length)} returned · total ${String(pagination.total ?? '?')} · page_size ${String(pagination.pageSize ?? query.pageSize ?? '?')} / max ${String(pagination.maxPageSize ?? '?')}`,
  ]
  if (typeof value.userTier === 'string') {
    lines.push(`${pc.dim('tier')} ${value.userTier}${typeof value.orderBy === 'string' ? ` · order ${value.orderBy}` : ''}`)
  }
  if (articles.length === 0) {
    lines.push('', pc.yellow('No Guardian content returned for this query.'))
    lines.push(`${pc.dim('try')} ${buildGuardianSearchCommand({ ...query, query: 'climate', section: undefined, tag: undefined, page: 1, pageSize: 50 })}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const article of articles.slice(0, 12)) {
    const fields = isRecord(article.fields) ? article.fields : {}
    const title = typeof fields.headline === 'string' && fields.headline.trim() !== '' ? stripHtml(fields.headline) : String(article.title ?? 'untitled article')
    lines.push(`${pc.bold(title)} ${pc.dim(String(article.sectionName ?? article.sectionId ?? '-'))}`)
    lines.push(`   ${String(article.publishedAt ?? 'unknown date')} · ${String(fields.byline ?? 'Guardian')} · ${String(article.pillarName ?? '-')}`)
    if (typeof fields.trailText === 'string' && fields.trailText.trim() !== '') {
      lines.push(`   ${truncateText(stripHtml(fields.trailText), 160)}`)
    }
    if (typeof article.webUrl === 'string' && article.webUrl.trim() !== '') {
      lines.push(`   ${pc.blue(article.webUrl)}`)
    }
  }
  if (articles.length > 12) {
    lines.push(pc.dim(`… ${articles.length - 12} more article(s); use --format json for full output.`))
  }
  const currentPage = typeof pagination.currentPage === 'number' ? pagination.currentPage : 1
  lines.push('', `${pc.dim('next')} ${buildGuardianSearchCommand({ ...query, page: currentPage + 1 })}`)
  lines.push(`${pc.dim('again')} ${buildGuardianSearchCommand(query)}`)
  lines.push(`${pc.dim('replay')} ${buildGuardianSearchCommand(query, 'offline')}`)
  return lines.join('\n')
}

function buildGuardianSearchCommand(query: Record<string, unknown>, mode: 'online' | 'offline' | undefined = undefined): string {
  const modeFlag = mode === undefined ? '' : ` --${mode}`
  return `public-apis apis run guardian.search${modeFlag} -- ${buildGuardianSearchArgs(query)}`
}

function buildGuardianSearchArgs(query: Record<string, unknown>): string {
  const args: string[] = []
  pushCliOption(args, '--query', query.query ?? 'public api')
  pushCliOption(args, '--section', query.section)
  pushCliOption(args, '--tag', query.tag)
  pushCliOption(args, '--from-date', query.fromDate)
  pushCliOption(args, '--to-date', query.toDate)
  pushCliOption(args, '--order-by', query.orderBy)
  pushCliOption(args, '--show-fields', query.showFields)
  pushCliOption(args, '--page-size', query.pageSize ?? 50)
  pushCliOption(args, '--page', query.page ?? 1)
  return args.join(' ')
}

function renderHashnodePosts(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const publication = isRecord(value.publication) ? value.publication : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const posts = Array.isArray(value.posts) ? value.posts.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('Hashnode Publication Posts'))} ${pc.dim(String(api.endpoint ?? 'POST https://gql.hashnode.com'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open GraphQL API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('publication')} ${String(publication.title ?? query.host ?? 'unknown')} ${typeof publication.url === 'string' ? pc.dim(publication.url) : ''}`,
    `${pc.dim('page')} ${String(pagination.returned ?? posts.length)} returned · first ${String(pagination.first ?? query.first ?? '?')} / max ${String(pagination.maxFirst ?? '?')} · next ${String(pagination.hasNextPage ?? false)}`,
  ]
  if (posts.length === 0) {
    lines.push('', pc.yellow('No Hashnode posts returned for this publication.'))
    lines.push(`${pc.dim('try')} ${buildHashnodePostsCommand({ host: 'blog.developerdao.com', first: 20 })}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const post of posts.slice(0, 12)) {
    const author = isRecord(post.author) ? post.author : {}
    const tags = Array.isArray(post.tags) ? post.tags.filter(isRecord).map(tag => String(tag.name ?? '')).filter(Boolean).slice(0, 3).join(', ') : ''
    lines.push(`${pc.bold(String(post.title ?? 'untitled post'))} ${pc.dim(String(post.readTimeInMinutes ?? '?'))} min`)
    lines.push(`   ${String(post.publishedAt ?? 'unknown date')} · ${String(author.name ?? author.username ?? 'unknown author')} · ${tags || 'tags n/a'}`)
    if (typeof post.brief === 'string' && post.brief.trim() !== '') lines.push(`   ${truncateText(post.brief.trim(), 160)}`)
    if (typeof post.url === 'string' && post.url.trim() !== '') lines.push(`   ${pc.blue(post.url)}`)
  }
  if (posts.length > 12) lines.push(pc.dim(`… ${posts.length - 12} more post(s); use --format json for full output.`))
  if (typeof pagination.endCursor === 'string' && pagination.endCursor.trim() !== '') {
    lines.push('', `${pc.dim('next')} ${buildHashnodePostsCommand({ ...query, after: pagination.endCursor })}`)
  }
  lines.push(`${pc.dim('again')} ${buildHashnodePostsCommand(query)}`)
  lines.push(`${pc.dim('replay')} ${buildHashnodePostsCommand(query, 'offline')}`)
  return lines.join('\n')
}

function buildHashnodePostsCommand(query: Record<string, unknown>, mode: 'online' | 'offline' | undefined = undefined): string {
  const modeFlag = mode === undefined ? '' : ` --${mode}`
  return `public-apis apis run hashnode.posts${modeFlag} -- ${buildHashnodePostsArgs(query)}`
}

function buildHashnodePostsArgs(query: Record<string, unknown>): string {
  const args: string[] = []
  pushCliOption(args, '--host', query.host ?? 'blog.developerdao.com')
  pushCliOption(args, '--first', query.first ?? 20)
  pushCliOption(args, '--after', query.after)
  return args.join(' ')
}

function renderMarketAuxNews(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const articles = Array.isArray(value.articles) ? value.articles.filter(isRecord) : []
  const page = readMarketAuxPage(query, pagination)
  const limit = readMarketAuxLimit(query, pagination)
  const commandOptions = readMarketAuxCommandOptions(query, { page, limit })
  const lines = [
    `${pc.bold(pc.cyan('MarketAux News'))} ${pc.dim(String(api.endpoint ?? 'GET /v1/news/all'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · API token via local config/env · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${String(page)} · ${String(pagination.returned ?? articles.length)} returned · found ${String(pagination.found ?? '?')} · plan limit ${String(pagination.limit ?? '?')} / requested ${String(limit)}`,
  ]
  if (typeof pagination.limit === 'number' && typeof pagination.requestedLimit === 'number' && pagination.limit < pagination.requestedLimit) {
    lines.push(`${pc.dim('plan')} provider lowered this request to ${String(pagination.limit)} result(s); free-plan limits may be below CLI default.`)
  }
  if (articles.length === 0) {
    lines.push('', pc.yellow('No MarketAux articles returned for this query.'))
    lines.push(`${pc.dim('again')} ${buildMarketAuxCommand(commandOptions, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildMarketAuxCommand(commandOptions, 'offline')}`)
    lines.push(`${pc.dim('search')} ${buildMarketAuxCommand({ ...commandOptions, search: 'TSLA', page: 1 }, 'online')}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const article of articles.slice(0, 12)) {
    const entities = Array.isArray(article.entities) ? article.entities.filter(isRecord).slice(0, 4) : []
    const entitySummary = entities
      .map(entity => `${String(entity.symbol ?? entity.name ?? '?')}${typeof entity.sentimentScore === 'number' ? ` ${formatNumber(entity.sentimentScore)}` : ''}`)
      .join(', ')
    lines.push(`${pc.bold(String(article.title ?? 'untitled article'))} ${pc.dim(String(article.language ?? query.language ?? '-'))}`)
    lines.push(`   ${String(article.publishedAt ?? 'unknown date')} · ${String(article.source ?? 'unknown source')} · ${entitySummary || 'entities n/a'}`)
    if (typeof article.description === 'string' && article.description.trim() !== '') {
      lines.push(`   ${truncateText(article.description.trim(), 160)}`)
    } else if (typeof article.snippet === 'string' && article.snippet.trim() !== '') {
      lines.push(`   ${truncateText(article.snippet.trim(), 160)}`)
    }
    if (typeof article.url === 'string' && article.url.trim() !== '') {
      lines.push(`   ${pc.blue(article.url)}`)
    }
  }
  if (articles.length > 12) {
    lines.push(pc.dim(`… ${articles.length - 12} more article(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} ${buildMarketAuxCommand(commandOptions, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildMarketAuxCommand(commandOptions, 'offline')}`)
  if (page > 1) {
    lines.push(`${pc.dim('prev page')} ${buildMarketAuxCommand({ ...commandOptions, page: page - 1 }, 'online')}`)
  }
  lines.push(`${pc.dim('next page')} ${buildMarketAuxCommand({ ...commandOptions, page: page + 1 }, 'online')}`)
  lines.push(`${pc.dim('search')} ${buildMarketAuxCommand({ ...commandOptions, search: commandOptions.search ?? commandOptions.symbols ?? 'TSLA', page: 1 }, 'online')}`)
  return lines.join('\n')
}

type MarketAuxCommandOptions = {
  search?: string | undefined
  symbols?: string | undefined
  countries?: string | undefined
  language?: string | undefined
  industries?: string | undefined
  sentimentMin?: number | undefined
  sentimentMax?: number | undefined
  publishedAfter?: string | undefined
  publishedBefore?: string | undefined
  limit: number
  page: number
}

function readMarketAuxCommandOptions(query: Record<string, unknown>, fallback: { page: number; limit: number }): MarketAuxCommandOptions {
  return {
    limit: fallback.limit,
    page: fallback.page,
    ...(typeof query.search === 'string' && query.search.trim() !== '' ? { search: query.search.trim() } : {}),
    ...(typeof query.symbols === 'string' && query.symbols.trim() !== '' ? { symbols: query.symbols.trim() } : {}),
    ...(typeof query.countries === 'string' && query.countries.trim() !== '' ? { countries: query.countries.trim() } : {}),
    ...(typeof query.language === 'string' && query.language.trim() !== '' ? { language: query.language.trim() } : {}),
    ...(typeof query.industries === 'string' && query.industries.trim() !== '' ? { industries: query.industries.trim() } : {}),
    ...(typeof query.sentimentMin === 'number' ? { sentimentMin: query.sentimentMin } : {}),
    ...(typeof query.sentimentMax === 'number' ? { sentimentMax: query.sentimentMax } : {}),
    ...(typeof query.publishedAfter === 'string' && query.publishedAfter.trim() !== '' ? { publishedAfter: query.publishedAfter.trim() } : {}),
    ...(typeof query.publishedBefore === 'string' && query.publishedBefore.trim() !== '' ? { publishedBefore: query.publishedBefore.trim() } : {}),
  }
}

function readMarketAuxPage(query: Record<string, unknown>, pagination: Record<string, unknown>): number {
  const value = typeof pagination.page === 'number' ? pagination.page : typeof query.page === 'number' ? query.page : 1
  return Number.isInteger(value) && value > 0 ? value : 1
}

function readMarketAuxLimit(query: Record<string, unknown>, pagination: Record<string, unknown>): number {
  const value = typeof pagination.requestedLimit === 'number' ? pagination.requestedLimit : typeof query.limit === 'number' ? query.limit : 100
  return Number.isInteger(value) && value > 0 ? value : 100
}

function buildMarketAuxCommand(options: MarketAuxCommandOptions, mode: 'online' | 'offline'): string {
  const parts = ['public-apis apis run marketaux.news', mode === 'online' ? '--online --persist' : '--offline', '--',]
  if (options.search !== undefined) {
    parts.push(`--search ${formatCliArg(options.search)}`)
  }
  if (options.symbols !== undefined) {
    parts.push(`--symbols ${formatCliArg(options.symbols)}`)
  }
  if (options.countries !== undefined) {
    parts.push(`--countries ${formatCliArg(options.countries)}`)
  }
  if (options.language !== undefined) {
    parts.push(`--language ${formatCliArg(options.language)}`)
  }
  if (options.industries !== undefined) {
    parts.push(`--industries ${formatCliArg(options.industries)}`)
  }
  if (options.sentimentMin !== undefined) {
    parts.push(`--sentiment-min ${formatCliArg(options.sentimentMin)}`)
  }
  if (options.sentimentMax !== undefined) {
    parts.push(`--sentiment-max ${formatCliArg(options.sentimentMax)}`)
  }
  if (options.publishedAfter !== undefined) {
    parts.push(`--published-after ${formatCliArg(options.publishedAfter)}`)
  }
  if (options.publishedBefore !== undefined) {
    parts.push(`--published-before ${formatCliArg(options.publishedBefore)}`)
  }
  parts.push(`--limit ${String(options.limit)}`)
  parts.push(`--page ${String(options.page)}`)
  return parts.join(' ')
}

function renderNyTimesSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const articles = Array.isArray(value.articles) ? value.articles.filter(isRecord) : []
  const page = readNyTimesPage(query, pagination)
  const commandOptions = readNyTimesSearchCommandOptions(query, page)
  const lines = [
    `${pc.bold(pc.cyan('NYTimes Article Search'))} ${pc.dim(String(api.endpoint ?? 'GET /svc/search/v2/articlesearch.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · API key via local config/env · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${String(page)} · ${String(pagination.returned ?? articles.length)} returned · hits ${String(pagination.hits ?? '?')} · offset ${String(pagination.offset ?? '?')} · page size ${String(pagination.pageSize ?? 10)}`,
  ]
  renderNyTimesArticleList(lines, articles)
  lines.push('', `${pc.dim('again')} ${buildNyTimesSearchCommand(commandOptions, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildNyTimesSearchCommand(commandOptions, 'offline')}`)
  if (page > 0) {
    lines.push(`${pc.dim('prev page')} ${buildNyTimesSearchCommand({ ...commandOptions, page: page - 1 }, 'online')}`)
  }
  lines.push(`${pc.dim('next page')} ${buildNyTimesSearchCommand({ ...commandOptions, page: page + 1 }, 'online')}`)
  lines.push(`${pc.dim('top stories')} ${buildNyTimesTopStoriesCommand({ section: 'technology', limit: 10 }, 'online')}`)
  return lines.join('\n')
}

function renderNyTimesTopStories(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const articles = Array.isArray(value.articles) ? value.articles.filter(isRecord) : []
  const commandOptions = readNyTimesTopStoriesCommandOptions(query, pagination)
  const lines = [
    `${pc.bold(pc.cyan('NYTimes Top Stories'))} ${pc.dim(String(api.endpoint ?? 'GET /svc/topstories/v2/{section}.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · API key via local config/env · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? articles.length)} returned · total ${String(pagination.total ?? '?')} · local limit ${String(commandOptions.limit)} / max ${String(pagination.maxLimit ?? '?')}`,
  ]
  renderNyTimesArticleList(lines, articles)
  lines.push('', `${pc.dim('again')} ${buildNyTimesTopStoriesCommand(commandOptions, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildNyTimesTopStoriesCommand(commandOptions, 'offline')}`)
  lines.push(`${pc.dim('search')} ${buildNyTimesSearchCommand({ query: commandOptions.section, page: 0 }, 'online')}`)
  return lines.join('\n')
}

function renderNyTimesArticleList(lines: string[], articles: Record<string, unknown>[]): void {
  if (articles.length === 0) {
    lines.push('', pc.yellow('No NYTimes articles returned for this query.'))
    return
  }
  lines.push('')
  for (const article of articles.slice(0, 12)) {
    lines.push(`${pc.bold(String(article.title ?? 'untitled article'))} ${pc.dim(String(article.section ?? '-'))}`)
    lines.push(`   ${String(article.publishedAt ?? article.updatedAt ?? 'unknown date')} · ${String(article.byline ?? article.source ?? 'NYTimes')}`)
    if (typeof article.abstract === 'string' && article.abstract.trim() !== '') {
      lines.push(`   ${truncateText(article.abstract.trim(), 160)}`)
    }
    if (typeof article.url === 'string' && article.url.trim() !== '') {
      lines.push(`   ${pc.blue(article.url)}`)
    }
  }
  if (articles.length > 12) {
    lines.push(pc.dim(`… ${articles.length - 12} more article(s); use --format json for full output.`))
  }
}

type NyTimesSearchCommandOptions = {
  query: string
  page: number
  filterQuery?: string | undefined
  beginDate?: string | undefined
  endDate?: string | undefined
  sort?: string | undefined
}

type NyTimesTopStoriesCommandOptions = {
  section: string
  limit: number
}

function readNyTimesSearchCommandOptions(query: Record<string, unknown>, page: number): NyTimesSearchCommandOptions {
  return {
    query: typeof query.query === 'string' && query.query.trim() !== '' ? query.query.trim() : 'public api',
    page,
    ...(typeof query.filterQuery === 'string' && query.filterQuery.trim() !== '' ? { filterQuery: query.filterQuery.trim() } : {}),
    ...(typeof query.beginDate === 'string' && query.beginDate.trim() !== '' ? { beginDate: query.beginDate.trim() } : {}),
    ...(typeof query.endDate === 'string' && query.endDate.trim() !== '' ? { endDate: query.endDate.trim() } : {}),
    ...(typeof query.sort === 'string' && query.sort.trim() !== '' ? { sort: query.sort.trim() } : {}),
  }
}

function readNyTimesTopStoriesCommandOptions(query: Record<string, unknown>, pagination: Record<string, unknown>): NyTimesTopStoriesCommandOptions {
  const limit = typeof pagination.limit === 'number' ? pagination.limit : typeof query.limit === 'number' ? query.limit : 100
  return {
    section: typeof query.section === 'string' && query.section.trim() !== '' ? query.section.trim() : 'home',
    limit: Number.isInteger(limit) && limit > 0 ? limit : 100,
  }
}

function readNyTimesPage(query: Record<string, unknown>, pagination: Record<string, unknown>): number {
  const page = typeof pagination.page === 'number' ? pagination.page : typeof query.page === 'number' ? query.page : 0
  return Number.isInteger(page) && page >= 0 ? page : 0
}

function buildNyTimesSearchCommand(options: NyTimesSearchCommandOptions, mode: 'online' | 'offline'): string {
  const parts = ['public-apis apis run nytimes.search', mode === 'online' ? '--online --persist' : '--offline', '--', `--query ${formatCliArg(options.query)}`]
  if (options.filterQuery !== undefined) {
    parts.push(`--filter-query ${formatCliArg(options.filterQuery)}`)
  }
  if (options.beginDate !== undefined) {
    parts.push(`--begin-date ${formatCliArg(options.beginDate)}`)
  }
  if (options.endDate !== undefined) {
    parts.push(`--end-date ${formatCliArg(options.endDate)}`)
  }
  if (options.sort !== undefined) {
    parts.push(`--sort ${formatCliArg(options.sort)}`)
  }
  parts.push(`--page ${String(options.page)}`)
  return parts.join(' ')
}

function buildNyTimesTopStoriesCommand(options: NyTimesTopStoriesCommandOptions, mode: 'online' | 'offline'): string {
  return [
    'public-apis apis run nytimes.topStories',
    mode === 'online' ? '--online --persist' : '--offline',
    '--',
    `--section ${formatCliArg(options.section)}`,
    `--limit ${String(options.limit)}`,
  ].join(' ')
}

function renderNewsApiArticles(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const articles = Array.isArray(value.articles) ? value.articles.filter(isRecord) : []
  const isHeadlines = value.kind === 'newsapi.headlines'
  const lines = [
    `${pc.bold(pc.cyan(isHeadlines ? 'NewsAPI Top Headlines' : 'NewsAPI Everything'))} ${pc.dim(String(api.endpoint ?? (isHeadlines ? 'GET /v2/top-headlines' : 'GET /v2/everything')))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · API key via local config/env · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${String(pagination.page ?? query.page ?? 1)} · ${String(pagination.returned ?? articles.length)} returned · total ${String(pagination.totalResults ?? '?')} · page_size ${String(pagination.pageSize ?? query.pageSize ?? '?')} / max ${String(pagination.maxPageSize ?? '?')}`,
  ]
  if (articles.length === 0) {
    lines.push('', pc.yellow('No NewsAPI articles returned for this query.'))
    return lines.join('\n')
  }
  lines.push('')
  for (const article of articles.slice(0, 12)) {
    const source = isRecord(article.source) ? article.source : {}
    lines.push(`${pc.bold(String(article.title ?? 'untitled article'))} ${pc.dim(String(source.name ?? 'unknown source'))}`)
    lines.push(`   ${String(article.publishedAt ?? 'unknown date')} · ${String(article.author ?? 'unknown author')}`)
    if (typeof article.description === 'string' && article.description.trim() !== '') {
      lines.push(`   ${truncateText(article.description.trim(), 160)}`)
    }
    if (typeof article.url === 'string' && article.url.trim() !== '') {
      lines.push(`   ${pc.blue(article.url)}`)
    }
  }
  lines.push('', `${pc.dim('next')} public-apis apis run ${isHeadlines ? 'newsapi.headlines -- --country' : 'newsapi.everything -- --query'} ${String(isHeadlines ? query.country ?? 'us' : query.query ?? 'public api')} --page-size ${String(query.pageSize ?? 100)}`)
  return lines.join('\n')
}

function renderNewsDataLatest(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const articles = Array.isArray(value.articles) ? value.articles.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('NewsData.io Latest News'))} ${pc.dim(String(api.endpoint ?? 'GET /api/1/latest'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · API key via local config/env · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${String(pagination.returned ?? articles.length)} returned · total ${String(pagination.totalResults ?? '?')} · size ${String(pagination.size ?? query.size ?? '?')} / free max ${String(pagination.maxFreeSize ?? '?')}`,
    `${pc.dim('rate')} free ${String(rateLimit.freeCreditsPer15Minutes ?? '?')} credits / 15m · ${String(rateLimit.freeCreditsPerDay ?? '?')} credits / day`,
  ]
  if (typeof pagination.nextPage === 'string' && pagination.nextPage.trim() !== '') {
    lines.push(`${pc.dim('nextPage')} ${pagination.nextPage}`)
  }
  if (articles.length === 0) {
    lines.push('', pc.yellow('No NewsData.io articles returned for this query.'))
    lines.push(`${pc.dim('try')} ${buildNewsDataLatestCommand({ ...query, query: undefined, searchIn: 'all', category: undefined, page: undefined, size: 10 })}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const article of articles.slice(0, 12)) {
    const source = isRecord(article.source) ? article.source : {}
    const categories = Array.isArray(article.categories) ? article.categories.filter((entry): entry is string => typeof entry === 'string').slice(0, 3).join(', ') : ''
    const countries = Array.isArray(article.countries) ? article.countries.filter((entry): entry is string => typeof entry === 'string').slice(0, 3).join(', ') : ''
    lines.push(`${pc.bold(String(article.title ?? 'untitled article'))} ${pc.dim(String(article.language ?? query.language ?? '-'))}`)
    lines.push(`   ${String(article.publishedAt ?? 'unknown date')} · ${String(source.name ?? 'unknown source')} · ${categories || 'category n/a'} · ${countries || 'country n/a'}`)
    if (typeof article.description === 'string' && article.description.trim() !== '') {
      lines.push(`   ${truncateText(article.description.trim(), 160)}`)
    } else if (typeof article.content === 'string' && article.content.trim() !== '') {
      lines.push(`   ${truncateText(article.content.trim(), 160)}`)
    }
    if (typeof article.url === 'string' && article.url.trim() !== '') {
      lines.push(`   ${pc.blue(article.url)}`)
    }
  }
  if (articles.length > 12) {
    lines.push(pc.dim(`… ${articles.length - 12} more article(s); use --format json for full output.`))
  }
  if (typeof pagination.nextPage === 'string' && pagination.nextPage.trim() !== '') {
    lines.push('', `${pc.dim('next')} ${buildNewsDataLatestCommand({ ...query, page: pagination.nextPage })}`)
  }
  lines.push(`${pc.dim('again')} ${buildNewsDataLatestCommand({ ...query, page: undefined })}`)
  lines.push(`${pc.dim('replay')} ${buildNewsDataLatestCommand({ ...query, page: undefined }, 'offline')}`)
  return lines.join('\n')
}

function buildNewsDataLatestCommand(query: Record<string, unknown>, mode: 'online' | 'offline' | undefined = undefined): string {
  const args = buildNewsDataLatestArgs(query)
  const modeFlag = mode === undefined ? '' : ` --${mode}`
  return `public-apis apis run newsdata.latest${modeFlag} -- ${args}`
}

function buildNewsDataLatestArgs(query: Record<string, unknown>): string {
  const args: string[] = []
  pushCliOption(args, '--query', query.query)
  pushCliOption(args, '--search-in', query.searchIn)
  pushCliOption(args, '--language', query.language ?? 'en')
  pushCliOption(args, '--country', query.country)
  pushCliOption(args, '--category', query.category)
  pushCliOption(args, '--domain', query.domain)
  pushCliOption(args, '--sort', query.sort)
  if (query.dedupe === true) args.push('--dedupe')
  pushCliOption(args, '--size', query.size ?? 10)
  pushCliOption(args, '--page', query.page)
  return args.join(' ')
}

function pushCliOption(args: string[], flag: string, value: unknown): void {
  if (value === undefined || value === null || value === '') return
  args.push(flag, formatCliArg(value))
}

function renderTheNewsAll(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const articles = Array.isArray(value.articles) ? value.articles.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('TheNewsAPI All News'))} ${pc.dim(String(api.endpoint ?? 'GET /v1/news/all'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · API token via local config/env · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${String(pagination.page ?? query.page ?? 1)} · ${String(pagination.returned ?? articles.length)} returned · found ${String(pagination.found ?? '?')} · provider limit ${String(pagination.limit ?? '?')}${pagination.requestedLimit === undefined ? ' (plan default)' : ` / requested ${String(pagination.requestedLimit)}`}`,
  ]
  if (typeof pagination.limit === 'number' && typeof pagination.requestedLimit === 'number' && pagination.limit < pagination.requestedLimit) {
    lines.push(`${pc.dim('plan')} provider lowered this request to ${String(pagination.limit)} result(s); subscription limits may be below CLI request.`)
  }
  if (articles.length === 0) {
    lines.push('', pc.yellow('No TheNewsAPI articles returned for this query.'))
    lines.push(`${pc.dim('try')} ${buildTheNewsAllCommand({ ...query, search: 'markets', page: 1 })}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const article of articles.slice(0, 12)) {
    const categories = Array.isArray(article.categories) ? article.categories.filter((entry): entry is string => typeof entry === 'string').slice(0, 3).join(', ') : ''
    lines.push(`${pc.bold(String(article.title ?? 'untitled article'))} ${pc.dim(String(article.language ?? query.language ?? '-'))}`)
    lines.push(`   ${String(article.publishedAt ?? 'unknown date')} · ${String(article.source ?? 'unknown source')} · ${categories || 'category n/a'} · ${String(article.locale ?? '-')}`)
    if (typeof article.description === 'string' && article.description.trim() !== '') {
      lines.push(`   ${truncateText(article.description.trim(), 160)}`)
    } else if (typeof article.snippet === 'string' && article.snippet.trim() !== '') {
      lines.push(`   ${truncateText(article.snippet.trim(), 160)}`)
    }
    if (typeof article.url === 'string' && article.url.trim() !== '') {
      lines.push(`   ${pc.blue(article.url)}`)
    }
  }
  if (articles.length > 12) {
    lines.push(pc.dim(`… ${articles.length - 12} more article(s); use --format json for full output.`))
  }
  const currentPage = typeof pagination.page === 'number' ? pagination.page : 1
  lines.push('', `${pc.dim('next')} ${buildTheNewsAllCommand({ ...query, page: currentPage + 1 })}`)
  lines.push(`${pc.dim('again')} ${buildTheNewsAllCommand(query)}`)
  lines.push(`${pc.dim('replay')} ${buildTheNewsAllCommand(query, 'offline')}`)
  return lines.join('\n')
}

function buildTheNewsAllCommand(query: Record<string, unknown>, mode: 'online' | 'offline' | undefined = undefined): string {
  const modeFlag = mode === undefined ? '' : ` --${mode}`
  return `public-apis apis run thenews.all${modeFlag} -- ${buildTheNewsAllArgs(query)}`
}

function buildTheNewsAllArgs(query: Record<string, unknown>): string {
  const args: string[] = []
  pushCliOption(args, '--search', query.search ?? 'public api')
  pushCliOption(args, '--language', query.language ?? 'en')
  pushCliOption(args, '--locale', query.locale)
  pushCliOption(args, '--categories', query.categories)
  pushCliOption(args, '--domains', query.domains)
  pushCliOption(args, '--published-after', query.publishedAfter)
  pushCliOption(args, '--published-before', query.publishedBefore)
  pushCliOption(args, '--published-on', query.publishedOn)
  pushCliOption(args, '--sort', query.sort)
  pushCliOption(args, '--limit', query.limit)
  pushCliOption(args, '--page', query.page ?? 1)
  return args.join(' ')
}

function renderNycOpenDataDatasets(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const datasets = Array.isArray(value.datasets) ? value.datasets.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('NYC Open Data Datasets'))} ${pc.dim(String(api.endpoint ?? 'GET /api/catalog/v1'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')} · Socrata`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('pagination')} returned ${String(pagination.returned ?? datasets.length)} / matched ${String(pagination.totalMatched ?? '?')} · limit ${String(pagination.limit ?? query.limit ?? '?')} · max ${String(pagination.maxLimit ?? '?')}`,
  ]

  if (datasets.length === 0) {
    lines.push('', pc.yellow('No NYC Open Data datasets matched this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run nycopendata.datasets --online --persist -- --query 311 --limit 100`)
    lines.push(`${pc.dim('311')} public-apis apis run nycopendata.311Requests --online --persist -- --borough BROOKLYN --limit 1000`)
    return lines.join('\n')
  }

  for (const dataset of datasets.slice(0, 20)) {
    lines.push('', `${pc.bold(String(dataset.name ?? 'dataset'))} ${pc.dim(String(dataset.id ?? ''))}`)
    lines.push(`${pc.dim('category')} ${String(dataset.category ?? '-')} · ${pc.dim('attribution')} ${String(dataset.attribution ?? '-')}`)
    if (typeof dataset.description === 'string') {
      lines.push(`  ${dataset.description.replace(/<[^>]*>/gu, ' ').replace(/\s+/gu, ' ').slice(0, 180)}`)
    }
  }
  if (datasets.length > 20) {
    lines.push(pc.dim(`… ${datasets.length - 20} more dataset(s); use --format json for full output.`))
  }
  const queryText = typeof query.query === 'string' && query.query.length > 0 ? query.query : '311'
  const limit = String(query.limit ?? pagination.limit ?? 100)
  lines.push('', `${pc.dim('again')} public-apis apis run nycopendata.datasets --online --persist -- --query ${formatCliArg(queryText)} --limit ${limit}`)
  lines.push(`${pc.dim('replay')} public-apis apis run nycopendata.datasets --offline -- --query ${formatCliArg(queryText)} --limit ${limit}`)
  lines.push(`${pc.dim('311')} public-apis apis run nycopendata.311Requests --online --persist -- --borough BROOKLYN --limit 1000`)
  return lines.join('\n')
}

function renderNycOpenData311Requests(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const requests = Array.isArray(value.requests) ? value.requests.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('NYC Open Data 311 Requests'))} ${pc.dim(String(api.endpoint ?? 'GET /resource/erm2-nwe9.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')} · Socrata`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('limit policy')} ${String(api.limitPolicy ?? 'bounded unauthenticated Socrata request')}`,
    `${pc.dim('pagination')} returned ${String(pagination.returned ?? requests.length)} · limit ${String(pagination.limit ?? query.limit ?? '?')} · max ${String(pagination.maxLimit ?? '?')}`,
  ]

  if (requests.length === 0) {
    lines.push('', pc.yellow('No NYC 311 requests returned for this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run nycopendata.311Requests --online --persist -- --borough BROOKLYN --limit 1000`)
    lines.push(`${pc.dim('datasets')} public-apis apis run nycopendata.datasets --online --persist -- --query 311 --limit 100`)
    return lines.join('\n')
  }

  for (const request of requests.slice(0, 20)) {
    lines.push(`- ${String(request.uniqueKey ?? '-')} · ${String(request.createdDate ?? '-')} · ${String(request.borough ?? '-')} · ${String(request.agency ?? '-')} · ${String(request.complaintType ?? '-')} · ${String(request.status ?? '-')}`)
  }
  if (requests.length > 20) {
    lines.push(pc.dim(`… ${requests.length - 20} more request(s); use --format json for full output.`))
  }
  const borough = typeof query.borough === 'string' && query.borough.length > 0 ? query.borough : 'BROOKLYN'
  const limit = String(query.limit ?? pagination.limit ?? 1000)
  lines.push('', `${pc.dim('again')} public-apis apis run nycopendata.311Requests --online --persist -- --borough ${formatCliArg(borough)} --limit ${limit}`)
  lines.push(`${pc.dim('replay')} public-apis apis run nycopendata.311Requests --offline -- --borough ${formatCliArg(borough)} --limit ${limit}`)
  lines.push(`${pc.dim('datasets')} public-apis apis run nycopendata.datasets --online --persist -- --query 311 --limit 100`)
  return lines.join('\n')
}

function renderOpenBreweryDbBreweries(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const breweries = Array.isArray(value.breweries) ? value.breweries.filter(isRecord) : []
  const isSearch = value.kind === 'openbrewerydb.search'
  const title = isSearch ? 'Open Brewery DB Search' : 'Open Brewery DB Breweries'
  const lines = [
    `${pc.bold(pc.cyan(title))} ${pc.dim(String(api.endpoint ?? 'GET /v1/breweries'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${String(pagination.page ?? query.page ?? 1)} · ${String(pagination.returned ?? breweries.length)} returned · per_page ${String(pagination.perPage ?? query.perPage ?? '?')} · max ${String(pagination.maxPerPage ?? 200)}`,
    `${pc.dim('rate')} remaining ${String(rateLimit.remaining ?? '?')} / ${String(rateLimit.limit ?? '?')}`,
  ]
  if (breweries.length === 0) {
    lines.push('', pc.yellow('No Open Brewery DB breweries returned for this query.'))
    const retryQuery = isSearch
      ? { ...query, query: query.query ?? 'dogfish', perPage: query.perPage ?? 200, page: 1 }
      : { ...query, city: query.city ?? 'san_diego', perPage: query.perPage ?? 200, page: 1 }
    lines.push(`${pc.dim('try')} ${buildOpenBreweryDbResultsCommand(isSearch, retryQuery, 'online')}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const brewery of breweries.slice(0, 15)) {
    const location = [brewery.city, brewery.stateProvince ?? brewery.state, brewery.country].filter(entry => typeof entry === 'string' && entry !== '').join(', ')
    lines.push(`${pc.bold(String(brewery.name ?? 'unnamed brewery'))} ${pc.dim(String(brewery.id ?? ''))}`)
    lines.push(`   ${String(brewery.breweryType ?? 'unknown type')} · ${location || 'unknown location'} · ${String(brewery.phone ?? '-')}`)
    if (typeof brewery.websiteUrl === 'string') {
      lines.push(`   ${pc.blue(brewery.websiteUrl)}`)
    }
  }
  if (breweries.length > 15) {
    lines.push(pc.dim(`… ${breweries.length - 15} more brewery/breweries; use --format json for full output.`))
  }
  const metaQuery = buildOpenBreweryDbMetaQuery(query, breweries[0])
  const nextPageQuery = { ...query, page: Number(query.page ?? pagination.page ?? 1) + 1, perPage: query.perPage ?? pagination.perPage ?? 200 }
  lines.push('', `${pc.dim('meta')} ${buildOpenBreweryDbMetaCommand(metaQuery, 'online')}`)
  lines.push(`${pc.dim('more')} ${buildOpenBreweryDbResultsCommand(isSearch, nextPageQuery, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildOpenBreweryDbResultsCommand(isSearch, query, 'offline')}`)
  return lines.join('\n')
}

function renderNhtsaDecodeVin(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const decode = isRecord(value.decode) ? value.decode : {}
  const vin = formatCliArg(query.vin ?? decode.vin ?? '1HGCM82633A004352')
  const modelYearArg = query.modelYear === undefined ? '' : ` --model-year ${formatCliArg(query.modelYear)}`
  const decodeArgs = `--vin ${vin}${modelYearArg}`
  const lines = [
    `${pc.bold(pc.cyan('NHTSA vPIC VIN Decode'))} ${pc.dim(String(api.endpoint ?? 'GET /vehicles/DecodeVinValues/{vin}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? (Object.keys(decode).length > 0 ? 1 : 0))} result · ${String(value.message ?? 'response')}`,
    `${pc.dim('rate')} ${String(api.rateControl ?? 'NHTSA automated traffic rate control applies')}`,
  ]
  if (Object.keys(decode).length === 0) {
    lines.push('', pc.yellow('No NHTSA VIN decode result returned for this query.'))
    lines.push(`${pc.dim('retry')} public-apis apis run nhtsa.decodeVin --online --persist -- ${decodeArgs}`)
    lines.push(`${pc.dim('example')} public-apis apis run nhtsa.decodeVin --online --persist -- --vin 1HGCM82633A004352 --model-year 2003`)
    lines.push(`${pc.dim('makes')} public-apis apis run nhtsa.makesForType --online --persist -- --vehicle-type car --limit 200`)
    return lines.join('\n')
  }
  lines.push('')
  lines.push(`${pc.bold([decode.modelYear, decode.make, decode.model].filter(entry => typeof entry === 'string' && entry !== '').join(' ') || String(query.vin ?? 'VIN'))}`)
  lines.push(`${String(decode.vehicleType ?? 'unknown type')} · ${String(decode.bodyClass ?? 'unknown body')} · ${String(decode.fuelTypePrimary ?? 'unknown fuel')}`)
  lines.push(`${pc.dim('plant')} ${String(decode.plantCountry ?? '?')} · ${pc.dim('manufacturer')} ${String(decode.manufacturer ?? '?')}`)
  lines.push(`${pc.dim('status')} ${String(decode.errorCode ?? '?')} · ${truncateText(String(decode.errorText ?? 'unknown'), 180)}`)
  lines.push('', `${pc.dim('again')} public-apis apis run nhtsa.decodeVin --online --persist -- ${decodeArgs}`)
  lines.push(`${pc.dim('replay')} public-apis apis run nhtsa.decodeVin --offline -- ${decodeArgs}`)
  lines.push(`${pc.dim('makes')} public-apis apis run nhtsa.makesForType --online --persist -- --vehicle-type car --limit 200`)
  return lines.join('\n')
}

function renderNvdCves(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const cves = Array.isArray(value.cves) ? value.cves.filter(isRecord) : []
  const args = buildNvdCvesArgs(query, pagination)
  const endpoint = String(api.endpoint ?? 'GET /rest/json/cves/2.0')
  const boundary = 'open REST API only · no auth · no Chrome clickstream'
  const safety = String(
    api.safety ??
      'Raw exploit databases and arbitrary references are not exposed.',
  )
  const returned = String(pagination.returned ?? cves.length)
  const totalMatched = String(pagination.totalMatched ?? '?')
  const limit = String(pagination.limit ?? query.limit ?? '?')
  const maxLimit = String(pagination.maxLimit ?? '?')
  const title = [
    pc.bold(pc.cyan('National Vulnerability Database CVEs')),
    pc.dim(endpoint),
  ].join(' ')
  const lines = [
    title,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} ${boundary} · read-only CVE metadata`,
    [
      `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
      String(api.platform ?? 'NVD 2.0 CVE API'),
    ].join(' · '),
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('safety')} ${safety}`,
    [
      `${pc.dim('pagination')} returned ${returned} / matched ${totalMatched}`,
      `limit ${limit}`,
      `max ${maxLimit}`,
    ].join(' · '),
  ]

  if (cves.length === 0) {
    lines.push('', pc.yellow('No NVD CVE metadata matched this query.'))
    lines.push(
      [
        pc.dim('again'),
        'public-apis apis run nvd.cves --online --persist --',
        args,
      ].join(' '),
    )
    lines.push(
      [
        pc.dim('default'),
        'public-apis apis run nvd.cves --online --persist -- --keyword',
        `${formatCliArg(String(api.defaultSearch ?? 'openssl'))} --limit 10`,
      ].join(' '),
    )
    lines.push(
      [
        pc.dim('cve'),
        'public-apis apis run nvd.cves --online --persist --',
        '--cve-id CVE-2024-3094 --limit 1',
      ].join(' '),
    )
    lines.push(
      [
        pc.dim('replay'),
        `public-apis apis run nvd.cves --offline -- ${args}`,
      ].join(' '),
    )
    return lines.join('\n')
  }

  for (const cve of cves.slice(0, 20)) {
    const cvss = isRecord(cve.cvss) ? cve.cvss : {}
    lines.push(
      '',
      [
        pc.bold(String(cve.id ?? 'CVE')),
        String(cve.status ?? 'status unknown'),
      ].join(' '),
    )
    const meta = [
      typeof cvss.baseSeverity === 'string'
        ? `severity ${cvss.baseSeverity}`
        : undefined,
      typeof cvss.baseScore === 'number'
        ? `score ${String(cvss.baseScore)}`
        : undefined,
      typeof cvss.version === 'string' ? `CVSS ${cvss.version}` : undefined,
      typeof cve.published === 'string'
        ? `published ${cve.published}`
        : undefined,
      typeof cve.lastModified === 'string'
        ? `modified ${cve.lastModified}`
        : undefined,
    ].filter((entry): entry is string => typeof entry === 'string')
    if (meta.length > 0) {
      lines.push(pc.dim(meta.join(' · ')))
    }
    if (Array.isArray(cve.weaknesses) && cve.weaknesses.length > 0) {
      const weaknesses = cve.weaknesses.slice(0, 5).map(String).join(', ')
      lines.push(`${pc.dim('weaknesses')} ${weaknesses}`)
    }
    if (typeof cve.description === 'string') {
      lines.push(`  ${truncateText(cve.description, 220)}`)
    }
    const refs = Array.isArray(cve.safeReferences)
      ? cve.safeReferences.filter(isRecord)
      : []
    for (const ref of refs.slice(0, 3)) {
      lines.push(`  ${pc.blue(String(ref.url ?? ''))}`)
    }
    if (typeof cve.referenceCount === 'number') {
      const referenceCount = String(cve.referenceCount)
      lines.push(
        pc.dim(
          [
            `  references shown ${Math.min(refs.length, 3)} of ${referenceCount}`,
            'safe/advisory-filtered upstream references',
          ].join(' '),
        ),
      )
    }
  }
  if (cves.length > 20) {
    const moreRows = [
      `… ${cves.length - 20} more CVE row(s);`,
      'use --format json.',
    ].join(' ')
    lines.push(pc.dim(moreRows))
  }
  lines.push(
    '',
    [
      pc.dim('again'),
      'public-apis apis run nvd.cves --online --persist --',
      args,
    ].join(' '),
  )
  lines.push(
    [
      pc.dim('replay'),
      `public-apis apis run nvd.cves --offline -- ${args}`,
    ].join(' '),
  )
  const firstCve = typeof cves[0]?.id === 'string' ? cves[0].id : 'CVE-2024-3094'
  lines.push(
    [
      pc.dim('cve'),
      'public-apis apis run nvd.cves --online --persist -- --cve-id',
      `${formatCliArg(firstCve)} --limit 1`,
    ].join(' '),
  )
  return lines.join('\n')
}

function buildNvdCvesArgs(
  query: Record<string, unknown>,
  pagination: Record<string, unknown> = {},
): string {
  const parts: string[] = []
  if (typeof query.cveId === 'string' && query.cveId.trim() !== '') {
    parts.push('--cve-id', formatCliArg(query.cveId))
  } else if (typeof query.keyword === 'string' && query.keyword.trim() !== '') {
    parts.push('--keyword', formatCliArg(query.keyword))
  }
  if (typeof query.severity === 'string' && query.severity.trim() !== '') {
    parts.push('--severity', formatCliArg(query.severity))
  }
  parts.push('--limit', String(pagination.limit ?? query.limit ?? 10))
  return parts.join(' ')
}

function renderSpaceflightNewsArticles(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const articles = Array.isArray(value.articles) ? value.articles.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('Spaceflight News Articles'))} ${pc.dim(String(api.endpoint ?? 'GET /v4/articles/'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? articles.length)} returned · total ${formatInteger(pagination.total)} · limit ${String(pagination.limit ?? query.limit ?? '?')} / max ${String(pagination.maxLimit ?? '?')} · offset ${String(pagination.offset ?? query.offset ?? 0)}`,
    `${pc.dim('rate')} ${String(api.rateLimitPolicy ?? 'Spaceflight News may return HTTP 429; use --persist and --offline')}`,
  ]
  if (articles.length === 0) {
    lines.push('', pc.yellow('No Spaceflight News articles returned for this query.'))
    lines.push(`${pc.dim('try')} ${buildSpaceflightNewsArticlesCommand({ ...query, search: undefined, newsSite: undefined, offset: 0, limit: 20 })}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const article of articles.slice(0, 12)) {
    const authors = Array.isArray(article.authors) ? article.authors.filter(isRecord).map(author => String(author.name ?? '')).filter(Boolean).slice(0, 3).join(', ') : ''
    const refs = [
      Array.isArray(article.launches) && article.launches.length > 0 ? `${article.launches.length} launch ref(s)` : undefined,
      Array.isArray(article.events) && article.events.length > 0 ? `${article.events.length} event ref(s)` : undefined,
      article.featured === true ? 'featured' : undefined,
    ].filter((entry): entry is string => typeof entry === 'string')
    lines.push(`${pc.bold(String(article.title ?? 'untitled article'))} ${pc.dim(String(article.newsSite ?? 'unknown site'))}`)
    lines.push(`   ${String(article.publishedAt ?? 'unknown date')} · ${authors || 'author n/a'}${refs.length > 0 ? ` · ${refs.join(' · ')}` : ''}`)
    if (typeof article.summary === 'string') {
      lines.push(`   ${truncateText(article.summary, 160)}`)
    }
    if (typeof article.url === 'string') {
      lines.push(`   ${pc.blue(article.url)}`)
    }
  }
  if (articles.length > 12) {
    lines.push(pc.dim(`… ${articles.length - 12} more article(s); use --format json for full output.`))
  }
  const nextOffset = typeof pagination.offset === 'number' && typeof pagination.limit === 'number' ? pagination.offset + pagination.limit : 500
  lines.push('', `${pc.dim('next')} ${buildSpaceflightNewsArticlesCommand({ ...query, offset: nextOffset })}`)
  lines.push(`${pc.dim('again')} ${buildSpaceflightNewsArticlesCommand(query)}`)
  lines.push(`${pc.dim('replay')} ${buildSpaceflightNewsArticlesCommand(query, 'offline')}`)
  return lines.join('\n')
}

function buildSpaceflightNewsArticlesCommand(query: Record<string, unknown>, mode: 'online' | 'offline' | undefined = undefined): string {
  const modeFlag = mode === undefined ? '' : ` --${mode}`
  return `public-apis apis run spaceflightnews.articles${modeFlag} -- ${buildSpaceflightNewsArticlesArgs(query)}`
}

function buildSpaceflightNewsArticlesArgs(query: Record<string, unknown>): string {
  const args: string[] = []
  pushCliOption(args, '--limit', query.limit ?? 500)
  pushCliOption(args, '--offset', query.offset ?? 0)
  pushCliOption(args, '--search', query.search)
  pushCliOption(args, '--news-site', query.newsSite)
  pushCliOption(args, '--ordering', query.ordering)
  return args.join(' ')
}

function renderNhtsaMakesForType(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const makes = Array.isArray(value.makes) ? value.makes.filter(isRecord) : []
  const vehicleType = formatCliArg(query.vehicleType ?? 'car')
  const limit = formatCliArg(pagination.limit ?? query.limit ?? 200)
  const makesArgs = `--vehicle-type ${vehicleType} --limit ${limit}`
  const lines = [
    `${pc.bold(pc.cyan('NHTSA vPIC Makes For Vehicle Type'))} ${pc.dim(String(api.endpoint ?? 'GET /vehicles/GetMakesForVehicleType/{vehicleType}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? makes.length)} returned · ${String(pagination.upstreamTotal ?? '?')} upstream · limit ${String(pagination.limit ?? query.limit ?? '?')}`,
    `${pc.dim('rate')} ${String(api.rateControl ?? 'NHTSA automated traffic rate control applies')}`,
  ]
  if (makes.length === 0) {
    lines.push('', pc.yellow('No NHTSA makes returned for this vehicle type.'))
    lines.push(`${pc.dim('again')} public-apis apis run nhtsa.makesForType --online --persist -- ${makesArgs}`)
    lines.push(`${pc.dim('replay')} public-apis apis run nhtsa.makesForType --offline -- ${makesArgs}`)
    lines.push(`${pc.dim('reset')} public-apis apis run nhtsa.makesForType --online --persist -- --vehicle-type car --limit 200`)
    return lines.join('\n')
  }
  lines.push('')
  for (const make of makes.slice(0, 25)) {
    lines.push(`${pc.bold(String(make.makeName ?? 'unknown make'))} ${pc.dim(`#${String(make.makeId ?? '-')}`)} · ${String(make.vehicleTypeName ?? query.vehicleType ?? 'vehicle')}`)
  }
  if (makes.length > 25) {
    lines.push(pc.dim(`… ${makes.length - 25} more make(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} public-apis apis run nhtsa.makesForType --online --persist -- ${makesArgs}`)
  lines.push(`${pc.dim('replay')} public-apis apis run nhtsa.makesForType --offline -- ${makesArgs}`)
  lines.push(`${pc.dim('decode')} public-apis apis run nhtsa.decodeVin --online --persist -- --vin 1HGCM82633A004352 --model-year 2003`)
  return lines.join('\n')
}

function renderOpenBreweryDbMeta(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const meta = isRecord(value.meta) ? value.meta : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const byType = isRecord(meta.byType) ? Object.entries(meta.byType).filter((entry): entry is [string, number] => typeof entry[1] === 'number') : []
  const byState = isRecord(meta.byState) ? Object.entries(meta.byState).filter((entry): entry is [string, number] => typeof entry[1] === 'number') : []
  const lines = [
    `${pc.bold(pc.cyan('Open Brewery DB Meta'))} ${pc.dim(String(api.endpoint ?? 'GET /v1/breweries/meta'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('total')} ${String(meta.total ?? 0)} breweries · page ${String(meta.page ?? 1)} · per_page ${String(meta.perPage ?? '?')}`,
    `${pc.dim('rate')} remaining ${String(rateLimit.remaining ?? '?')} / ${String(rateLimit.limit ?? '?')}`,
  ]
  if (byType.length === 0 && byState.length === 0) {
    lines.push('', pc.yellow('No Open Brewery DB aggregate buckets returned for this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run openbrewerydb.meta --online --persist -- --city san_diego`)
    return lines.join('\n')
  }
  if (byType.length > 0) {
    lines.push('', pc.bold('By Type'))
    for (const [type, count] of byType.sort((left, right) => right[1] - left[1]).slice(0, 12)) {
      lines.push(`${type.padEnd(16, ' ')} ${formatInteger(count)}`)
    }
  }
  if (byState.length > 0) {
    lines.push('', pc.bold('By State'))
    for (const [state, count] of byState.sort((left, right) => right[1] - left[1]).slice(0, 12)) {
      lines.push(`${state.padEnd(24, ' ')} ${formatInteger(count)}`)
    }
  }
  lines.push('', `${pc.dim('next')} ${buildOpenBreweryDbBreweriesCommand({ ...query, perPage: 200, page: 1 }, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildOpenBreweryDbMetaCommand(query, 'offline')}`)
  return lines.join('\n')
}

function buildOpenBreweryDbMetaQuery(query: Record<string, unknown>, firstBrewery: Record<string, unknown> | undefined): Record<string, unknown> {
  if (typeof query.city === 'string' || typeof query.state === 'string' || typeof query.country === 'string' || typeof query.type === 'string' || typeof query.postal === 'string') {
    return query
  }
  if (typeof firstBrewery?.city === 'string' && firstBrewery.city.trim() !== '') {
    return { city: toOpenBreweryDbFilterValue(firstBrewery.city) }
  }
  return { city: 'san_diego' }
}

function buildOpenBreweryDbBreweriesCommand(query: Record<string, unknown>, mode: 'online' | 'offline'): string {
  const parts = ['public-apis apis run openbrewerydb.breweries', `--${mode}`]
  if (mode === 'online') {
    parts.push('--persist')
  }
  parts.push('--')
  appendOpenBreweryDbFilters(parts, query)
  if (query.perPage !== undefined) parts.push(`--per-page ${String(query.perPage)}`)
  if (query.page !== undefined) parts.push(`--page ${String(query.page)}`)
  if (query.sort !== undefined) parts.push(`--sort ${formatCliArg(query.sort)}`)
  return parts.join(' ')
}

function buildOpenBreweryDbSearchCommand(query: Record<string, unknown>, mode: 'online' | 'offline'): string {
  const parts = ['public-apis apis run openbrewerydb.search', `--${mode}`]
  if (mode === 'online') {
    parts.push('--persist')
  }
  parts.push('--')
  if (query.query !== undefined) parts.push(`--query ${formatCliArg(query.query)}`)
  if (query.perPage !== undefined) parts.push(`--per-page ${String(query.perPage)}`)
  if (query.page !== undefined) parts.push(`--page ${String(query.page)}`)
  return parts.join(' ')
}

function buildOpenBreweryDbResultsCommand(isSearch: boolean, query: Record<string, unknown>, mode: 'online' | 'offline'): string {
  return isSearch ? buildOpenBreweryDbSearchCommand(query, mode) : buildOpenBreweryDbBreweriesCommand(query, mode)
}

function buildOpenBreweryDbMetaCommand(query: Record<string, unknown>, mode: 'online' | 'offline'): string {
  const parts = ['public-apis apis run openbrewerydb.meta', `--${mode}`]
  if (mode === 'online') {
    parts.push('--persist')
  }
  parts.push('--')
  appendOpenBreweryDbFilters(parts, query)
  return parts.join(' ')
}

function appendOpenBreweryDbFilters(parts: string[], query: Record<string, unknown>): void {
  for (const key of ['city', 'state', 'country', 'type', 'postal'] as const) {
    if (query[key] !== undefined) {
      parts.push(`--${key} ${formatCliArg(query[key])}`)
    }
  }
}

function toOpenBreweryDbFilterValue(value: string): string {
  return value.trim().toLowerCase().replace(/\s+/gu, '_')
}

function renderOpenCollectiveAccount(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const account = isRecord(value.account) ? value.account : {}
  const stats = isRecord(account.stats) ? account.stats : {}
  const tags = Array.isArray(account.tags) ? account.tags.filter((tag): tag is string => typeof tag === 'string' && tag.trim() !== '') : []
  const lines = [
    `${pc.bold(pc.cyan('Open Collective Account Summary'))} ${pc.dim(String(api.endpoint ?? 'POST /graphql/v2'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open GraphQL API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('rate')} ${String(api.rateLimitPolicy ?? 'respect public no-auth GraphQL limits')}`,
    `${pc.dim('account')} ${pc.bold(String(account.name ?? query.slug ?? 'unknown'))} ${pc.dim(`@${String(account.slug ?? query.slug ?? '-')}`)} · ${String(account.type ?? 'ACCOUNT')} · ${account.isActive === false ? 'inactive' : 'active'}${account.isVerified === true ? ' · verified' : ''}`,
  ]
  if (typeof account.description === 'string' && account.description.trim() !== '') {
    lines.push(`${pc.dim('about')} ${truncateText(account.description.trim(), 180)}`)
  }
  if (tags.length > 0) {
    lines.push(`${pc.dim('tags')} ${tags.slice(0, 8).join(', ')}`)
  }
  lines.push(
    '',
    `${pc.bold('Financial Stats')}`,
    `balance               ${formatOpenCollectiveMoney(stats.balance)}`,
    `yearly budget         ${formatOpenCollectiveMoney(stats.yearlyBudget)}`,
    `total received        ${formatOpenCollectiveMoney(stats.totalAmountReceived)}`,
  )
  if (typeof account.website === 'string' && account.website.trim() !== '') {
    lines.push('', `${pc.dim('website')} ${pc.blue(account.website)}`)
  }
  lines.push('', `${pc.dim('again')} ${buildOpenCollectiveAccountCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildOpenCollectiveAccountCommand(query, 'offline')}`)
  return lines.join('\n')
}

function buildOpenCollectiveAccountCommand(query: Record<string, unknown>, mode: 'online' | 'offline'): string {
  const slug = query.slug ?? 'webpack'
  const storageFlags = mode === 'online' ? '--online --persist' : '--offline'
  return `public-apis apis run opencollective.account ${storageFlags} -- --slug ${formatCliArg(slug)}`
}

function renderOpenFoodFactsProduct(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const product = isRecord(value.product) ? value.product : {}
  const lines = [
    `${pc.bold(pc.cyan('Open Food Facts Product'))} ${pc.dim(String(api.endpoint ?? 'GET /api/v2/product/{barcode}.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? '100 product reads/min; 10 search reads/min')} · custom User-Agent`,
    `${pc.dim('status')} ${String(value.status ?? '?')} · found ${value.found === true ? 'yes' : 'no'}`,
  ]
  if (value.found !== true || Object.keys(product).length === 0) {
    lines.push('', pc.yellow('No Open Food Facts product returned for this barcode.'))
    lines.push(`${pc.dim('try')} public-apis apis run openfoodfacts.product --online --persist -- --barcode 737628064502`)
    return lines.join('\n')
  }
  lines.push('')
  lines.push(`${pc.bold(String(product.name ?? '(unnamed product)'))} ${pc.dim(String(product.code ?? query.barcode ?? ''))}`)
  lines.push(`${String(product.brands ?? 'unknown brand')} · ${String(product.quantity ?? 'unknown quantity')} · nutriscore ${String(product.nutriscoreGrade ?? '?')} · NOVA ${String(product.novaGroup ?? '?')}`)
  const categories = Array.isArray(product.categoriesTags) ? product.categoriesTags.filter(entry => typeof entry === 'string').slice(0, 5).join(', ') : ''
  const labels = Array.isArray(product.labelsTags) ? product.labelsTags.filter(entry => typeof entry === 'string').slice(0, 5).join(', ') : ''
  if (categories !== '') {
    lines.push(`${pc.dim('categories')} ${categories}`)
  }
  if (labels !== '') {
    lines.push(`${pc.dim('labels')} ${labels}`)
  }
  if (typeof product.ingredientsText === 'string' && product.ingredientsText.trim() !== '') {
    lines.push(`${pc.dim('ingredients')} ${truncateText(product.ingredientsText.trim().replace(/\s+/gu, ' '), 180)}`)
  }
  if (typeof product.url === 'string') {
    lines.push(pc.blue(product.url))
  }
  const barcode = product.code ?? query.barcode ?? '737628064502'
  lines.push('', `${pc.dim('again')} public-apis apis run openfoodfacts.product --online --persist -- --barcode ${formatCliArg(barcode)}`)
  lines.push(`${pc.dim('replay')} public-apis apis run openfoodfacts.product --offline -- --barcode ${formatCliArg(barcode)}`)
  return lines.join('\n')
}

function renderOpenFoodFactsSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const products = Array.isArray(value.products) ? value.products.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('Open Food Facts Search'))} ${pc.dim(String(api.endpoint ?? 'GET /cgi/search.pl'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${String(pagination.page ?? query.page ?? 1)} / ${String(pagination.pageCount ?? '?')} · ${String(pagination.returned ?? products.length)} returned · ${String(pagination.total ?? '?')} total · page_size ${String(pagination.pageSize ?? query.pageSize ?? '?')}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? '100 product reads/min; 10 search reads/min')} · custom User-Agent`,
  ]
  if (products.length === 0) {
    lines.push('', pc.yellow('No Open Food Facts products returned for this query.'))
    return lines.join('\n')
  }
  lines.push('')
  for (const product of products.slice(0, 15)) {
    lines.push(`${pc.bold(String(product.name ?? '(unnamed product)'))} ${pc.dim(String(product.code ?? ''))}`)
    lines.push(`   ${String(product.brands ?? 'unknown brand')} · ${String(product.quantity ?? 'unknown quantity')} · nutriscore ${String(product.nutriscoreGrade ?? '?')} · NOVA ${String(product.novaGroup ?? '?')}`)
    if (typeof product.url === 'string') {
      lines.push(`   ${pc.blue(product.url)}`)
    }
  }
  if (products.length > 15) {
    lines.push(pc.dim(`… ${products.length - 15} more product(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('next')} public-apis apis run openfoodfacts.product -- --barcode ${String(products[0]?.code ?? '737628064502')}`)
  return lines.join('\n')
}


function renderOpenSkyStates(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const aircraft = Array.isArray(value.aircraft) ? value.aircraft.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('OpenSky State Vectors'))} ${pc.dim(String(api.endpoint ?? 'GET /states/all'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('snapshot')} ${String(value.snapshotTime ?? 'unknown')} · ${String(value.count ?? aircraft.length)} aircraft · ${String(api.limitPolicy ?? 'bounded aircraft output')}`,
    `${pc.dim('quota')} ${String(api.anonymousCreditPolicy ?? 'anonymous quota applies')} · remaining ${String(rateLimit.remaining ?? '?')}`,
  ]
  if (aircraft.length === 0) {
    lines.push('', pc.yellow('No OpenSky aircraft returned for this bounding box.'))
    lines.push(`${pc.dim('try')} public-apis apis run opensky.states -- --lamin 45.8 --lomin -124 --lamax 49.2 --lomax -116 --limit 20`)
    lines.push(`${pc.dim('again')} ${buildOpenSkyStatesCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildOpenSkyStatesCommand(query, 'offline')}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const plane of aircraft.slice(0, 25)) {
    const location = typeof plane.latitude === 'number' && typeof plane.longitude === 'number'
      ? `${String(plane.latitude)}, ${String(plane.longitude)}`
      : 'position n/a'
    const altitude = typeof plane.baroAltitude === 'number' ? `${String(Math.round(plane.baroAltitude))}m` : 'alt n/a'
    const velocity = typeof plane.velocity === 'number' ? `${String(Math.round(plane.velocity))}m/s` : 'speed n/a'
    const callsign = typeof plane.callsign === 'string' ? plane.callsign : 'callsign n/a'
    lines.push(`${pc.bold(String(callsign))} ${pc.dim(String(plane.icao24 ?? 'icao24 n/a'))} · ${String(plane.originCountry ?? 'country n/a')}`)
    lines.push(`   ${location} · ${altitude} · ${velocity} · ${plane.onGround === true ? 'ground' : 'airborne'} · last ${String(plane.lastContact ?? '?')}`)
  }
  if (aircraft.length > 25) {
    lines.push(pc.dim(`… ${aircraft.length - 25} more aircraft; use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} ${buildOpenSkyStatesCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildOpenSkyStatesCommand(query, 'offline')}`)
  return lines.join('\n')
}

function buildOpenSkyStatesCommand(query: Record<string, unknown>, mode: 'online' | 'offline'): string {
  const parts = ['public-apis apis run opensky.states', mode === 'online' ? '--online --persist' : '--offline', '--']
  for (const key of ['lamin', 'lomin', 'lamax', 'lomax', 'icao24', 'time', 'extended', 'limit'] as const) {
    if (query[key] !== undefined) {
      parts.push(`--${key} ${formatCliArg(query[key])}`)
    }
  }
  return parts.join(' ')
}

function renderOpenMeteoForecast(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const location = isRecord(value.location) ? value.location : {}
  const current = isRecord(value.current) ? value.current : {}
  const currentUnits = isRecord(value.currentUnits) ? value.currentUnits : {}
  const daily = isRecord(value.daily) ? value.daily : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const times = Array.isArray(daily.time) ? daily.time : []
  const tMax = Array.isArray(daily.temperature_2m_max) ? daily.temperature_2m_max : []
  const tMin = Array.isArray(daily.temperature_2m_min) ? daily.temperature_2m_min : []
  const precipitation = Array.isArray(daily.precipitation_sum) ? daily.precipitation_sum : []
  const latitude = formatCliArg(query.latitude ?? location.latitude ?? 52.52)
  const longitude = formatCliArg(query.longitude ?? location.longitude ?? 13.41)
  const forecastDays = formatCliArg(pagination.forecastDays ?? query.forecastDays ?? 16)
  const timezone = formatCliArg(query.timezone ?? location.timezone ?? 'auto')
  const forecastArgs = `--latitude ${latitude} --longitude ${longitude} --forecast-days ${forecastDays} --timezone ${timezone}`
  const lines = [
    `${pc.bold(pc.cyan('Open-Meteo Forecast'))} ${pc.dim(String(api.endpoint ?? 'GET /v1/forecast'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('location')} ${String(location.latitude ?? query.latitude)}, ${String(location.longitude ?? query.longitude)} · ${String(location.timezone ?? query.timezone ?? 'auto')}`,
    `${pc.dim('window')} ${String(pagination.forecastDays ?? query.forecastDays ?? '?')} day(s) · max ${String(pagination.maxForecastDays ?? 16)} · ${String(pagination.dailyRows ?? times.length)} daily rows`,
  ]
  if (Object.keys(current).length > 0) {
    const tempUnit = String(currentUnits.temperature_2m ?? '')
    const windUnit = String(currentUnits.wind_speed_10m ?? '')
    lines.push(`${pc.dim('current')} ${String(current.time ?? '')} · ${String(current.temperature_2m ?? '?')}${tempUnit} · wind ${String(current.wind_speed_10m ?? '?')}${windUnit} · code ${String(current.weather_code ?? '?')}`)
  }
  if (times.length === 0) {
    lines.push('', pc.yellow('No Open-Meteo daily forecast rows returned for this query.'))
    lines.push(`${pc.dim('again')} public-apis apis run openmeteo.forecast --online --persist -- ${forecastArgs}`)
    lines.push(`${pc.dim('replay')} public-apis apis run openmeteo.forecast --offline -- ${forecastArgs}`)
    lines.push(`${pc.dim('places')} public-apis apis run openmeteo.geocoding --online --persist -- --name Berlin --count 100`)
    return lines.join('\n')
  }
  lines.push('', pc.bold('Daily'))
  for (let index = 0; index < Math.min(times.length, 16); index += 1) {
    lines.push(`${String(times[index])} · max ${String(tMax[index] ?? '?')} · min ${String(tMin[index] ?? '?')} · precip ${String(precipitation[index] ?? '?')}`)
  }
  lines.push('', `${pc.dim('again')} public-apis apis run openmeteo.forecast --online --persist -- ${forecastArgs}`)
  lines.push(`${pc.dim('replay')} public-apis apis run openmeteo.forecast --offline -- ${forecastArgs}`)
  lines.push(`${pc.dim('places')} public-apis apis run openmeteo.geocoding --online --persist -- --name Berlin --count 100`)
  return lines.join('\n')
}

function renderOpenMeteoGeocoding(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const locations = Array.isArray(value.locations) ? value.locations.filter(isRecord) : []
  const countryCodeArg = query.countryCode === undefined ? '' : ` --country-code ${formatCliArg(query.countryCode)}`
  const geocodingArgs = `--name ${formatCliArg(query.name ?? 'Berlin')} --count ${formatCliArg(pagination.count ?? query.count ?? 100)} --language ${formatCliArg(query.language ?? 'en')}${countryCodeArg}`
  const lines = [
    `${pc.bold(pc.cyan('Open-Meteo Geocoding'))} ${pc.dim(String(api.endpoint ?? 'GET /v1/search'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? locations.length)} returned · requested ${String(pagination.count ?? query.count ?? '?')} · max ${String(pagination.maxCount ?? 100)}`,
  ]
  if (locations.length === 0) {
    lines.push('', pc.yellow('No Open-Meteo locations returned for this query.'))
    lines.push(`${pc.dim('again')} public-apis apis run openmeteo.geocoding --online --persist -- ${geocodingArgs}`)
    lines.push(`${pc.dim('replay')} public-apis apis run openmeteo.geocoding --offline -- ${geocodingArgs}`)
    lines.push(`${pc.dim('reset')} public-apis apis run openmeteo.geocoding --online --persist -- --name Berlin --count 100 --language en`)
    return lines.join('\n')
  }
  lines.push('')
  for (const location of locations.slice(0, 20)) {
    const admin = [location.admin1, location.admin2, location.admin3].filter(entry => typeof entry === 'string' && entry !== '').join(', ')
    lines.push(`${pc.bold(String(location.name ?? 'unknown location'))} ${pc.dim(`#${String(location.id ?? '-')}`)} · ${String(location.country ?? location.countryCode ?? '?')}`)
    lines.push(`   ${String(location.latitude ?? '?')}, ${String(location.longitude ?? '?')} · ${String(location.timezone ?? '?')} · pop ${formatInteger(location.population)}`)
    if (admin !== '') {
      lines.push(`   ${pc.dim(admin)}`)
    }
  }
  if (locations.length > 20) {
    lines.push(pc.dim(`… ${locations.length - 20} more location(s); use --format json for full output.`))
  }
  const first = locations[0]
  lines.push('', `${pc.dim('again')} public-apis apis run openmeteo.geocoding --online --persist -- ${geocodingArgs}`)
  lines.push(`${pc.dim('replay')} public-apis apis run openmeteo.geocoding --offline -- ${geocodingArgs}`)
  lines.push(`${pc.dim('forecast')} public-apis apis run openmeteo.forecast --online --persist -- --latitude ${formatCliArg(first?.latitude ?? 52.52)} --longitude ${formatCliArg(first?.longitude ?? 13.41)} --forecast-days 16 --timezone auto`)
  return lines.join('\n')
}

function renderOpenTopoDataLookup(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const elevations = Array.isArray(value.elevations) ? value.elevations.filter(isRecord) : []
  const args = `--locations ${formatCliArg(query.locations ?? '39.7471,-104.9963')} --dataset ${formatCliArg(query.dataset ?? 'srtm90m')} --interpolation ${formatCliArg(query.interpolation ?? 'bilinear')}`
  const querySummary = `locations=${String(query.locations ?? '39.7471,-104.9963')} dataset=${String(query.dataset ?? 'srtm90m')} interpolation=${String(query.interpolation ?? 'bilinear')}`
  const lines = [
    `${pc.bold(pc.cyan('Open Topo Data Lookup'))} ${pc.dim(String(api.endpoint ?? 'GET /v1/{dataset}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${querySummary}`,
    `${pc.dim('count')} ${String(pagination.returned ?? elevations.length)} returned · requested ${String(pagination.requested ?? '?')} · max ${String(pagination.maxLocations ?? 5)}`,
    `${pc.dim('policy')} ${String(api.rateLimit ?? 'public demo server; self-host for high-volume use')}`,
    `${pc.dim('attribution')} ${String(api.attribution ?? 'dataset licences vary; see Open Topo Data docs')}`,
  ]
  if (elevations.length === 0) {
    lines.push('', pc.yellow('No Open Topo Data elevations returned for this query.'))
    lines.push(`${pc.dim('again')} public-apis apis run opentopodata.lookup --online --persist -- ${args}`)
    lines.push(`${pc.dim('replay')} public-apis apis run opentopodata.lookup --offline -- ${args}`)
    lines.push(`${pc.dim('reset')} public-apis apis run opentopodata.lookup --online --persist -- --locations 39.7471,-104.9963 --dataset srtm90m --interpolation bilinear`)
    return lines.join('\n')
  }
  lines.push('')
  for (const [index, entry] of elevations.slice(0, 10).entries()) {
    const location = isRecord(entry.location) ? entry.location : {}
    const elevation = entry.elevation === null ? 'no data' : `${String(entry.elevation ?? '?')} m`
    lines.push(`${pc.bold(`${index + 1}.`)} ${String(location.latitude ?? '?')}, ${String(location.longitude ?? '?')} · ${elevation} · ${String(entry.dataset ?? query.dataset ?? '?')}`)
  }
  if (elevations.length > 10) {
    lines.push(pc.dim(`… ${elevations.length - 10} more point(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} public-apis apis run opentopodata.lookup --online --persist -- ${args}`)
  lines.push(`${pc.dim('replay')} public-apis apis run opentopodata.lookup --offline -- ${args}`)
  lines.push(`${pc.dim('bathymetry')} public-apis apis run opentopodata.lookup --online --persist -- --locations 0,0 --dataset gebco2020 --interpolation bilinear`)
  return lines.join('\n')
}

