  const args = `--region ${formatCliArg(query.region ?? 'portland')}${queryArg} --limit ${String(query.limit ?? pagination.limit ?? 10)}`
  const lines = [
    `${pc.bold(pc.cyan('Pinball Map Locations'))} ${pc.dim(String(api.endpoint ?? 'GET /api/v1/locations.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? locations.length)} returned · limit ${String(pagination.limit ?? query.limit ?? 10)} / ${String(pagination.maxLimit ?? 50)} · no_details=${String(pagination.noDetails ?? true)}`,
    `${pc.dim('boundary')} ${String(api.writeBoundary ?? 'read-only GET endpoints only')}`,
    `${pc.dim('attribution')} ${String(api.attribution ?? 'Include attribution when using Pinball Map data')}`,
  ]
  if (locations.length === 0) {
    lines.push('', pc.yellow('No Pinball Map locations returned for this query.'))
    lines.push(`${pc.dim('again')} public-apis apis run pinballmap.locations --online --persist -- ${args}`)
    lines.push(`${pc.dim('replay')} public-apis apis run pinballmap.locations --offline -- ${args}`)
    lines.push(`${pc.dim('regions')} public-apis apis run pinballmap.regions --online --persist -- --limit 10`)
    return lines.join('\n')
  }
  lines.push('')
  for (const location of locations.slice(0, 12)) {
    const address = [location.street, location.city, location.state, location.zip].filter(entry => typeof entry === 'string' && entry.trim() !== '').join(', ')
    const coords = `${String(location.latitude ?? '?')}, ${String(location.longitude ?? '?')}`
    lines.push(`${pc.bold(String(location.name ?? 'unknown location'))} ${pc.dim(`#${String(location.id ?? '-')}`)} · machines ${String(location.machineCount ?? '?')}`)
    lines.push(`   ${address || String(location.country ?? '')} · ${coords}`)
    if (location.isSternArmy === true || location.icActive === true) {
      lines.push(`   ${pc.dim(`sternArmy=${String(location.isSternArmy === true)} insiderConnected=${String(location.icActive === true)}`)}`)
    }
  }
  if (locations.length > 12) {
    lines.push(pc.dim(`… ${locations.length - 12} more location(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} public-apis apis run pinballmap.locations --online --persist -- ${args}`)
