function renderPostcodeDataNlLookup(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const count = isRecord(value.count) ? value.count : {}
  const addresses = Array.isArray(value.addresses) ? value.addresses.filter(isRecord) : []
  const postcode = typeof query.postcode === 'string' ? query.postcode : '1211EP'
  const streetNumber = typeof query.streetNumber === 'number' ? String(query.streetNumber) : '60'
  const ref = typeof query.ref === 'string' ? query.ref : 'public-apis-tui.local'
  const args = `--postcode ${formatCliArg(postcode)} --street-number ${streetNumber} --ref ${formatCliArg(ref)}`
  const lines = [
    `${pc.bold(pc.cyan('PostcodeData.nl Lookup'))} ${pc.dim(String(api.endpoint ?? 'GET /v1/postcode/'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open HTTP REST API only · no auth · HTTP-only · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(count.returned ?? addresses.length)} address record(s)`,
    `${pc.dim('privacy')} ${String(api.privacy ?? 'postcode and house number are sent over HTTP cleartext')}`,
    `${pc.dim('reliability')} ${String(api.reliability ?? 'legacy reference data; validate official decisions elsewhere')}`,
  ]
  if (addresses.length === 0) {
    lines.push('', pc.yellow('No PostcodeData.nl address records returned for this postcode/house number.'))
    lines.push(`${pc.dim('again')} public-apis apis run postcodedata-nl.lookup --online --persist -- ${args}`)
    lines.push(`${pc.dim('replay')} public-apis apis run postcodedata-nl.lookup --offline -- ${args}`)
    lines.push(`${pc.dim('sample')} public-apis apis run postcodedata-nl.lookup --online --persist -- --postcode 1211EP --street-number 60 --ref public-apis-tui.local`)
    return lines.join('\n')
  }
  lines.push('')
  for (const address of addresses.slice(0, 5)) {
    const coordinates = typeof address.latitude === 'number' && typeof address.longitude === 'number'
      ? `${String(address.latitude)}, ${String(address.longitude)}`
      : 'coordinates not provided'
    lines.push(`${pc.bold(String(address.street ?? 'unknown street'))} ${String(address.postcode ?? postcode)} · ${String(address.city ?? '-')}`)
    lines.push(`   ${String(address.municipality ?? '-')} · ${String(address.province ?? '-')} · ${coordinates}`)
  }
  lines.push('', `${pc.dim('again')} public-apis apis run postcodedata-nl.lookup --online --persist -- ${args}`)
  lines.push(`${pc.dim('replay')} public-apis apis run postcodedata-nl.lookup --offline -- ${args}`)
  lines.push(`${pc.dim('note')} HTTP-only legacy endpoint; avoid sensitive/private address lookups.`)
  return lines.join('\n')
}

