function renderFipeList(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const items = Array.isArray(value.items) ? value.items.filter(isRecord) : []
  const title = value.kind === 'fipe.models' ? 'Fipe Models' : value.kind === 'fipe.years' ? 'Fipe Years' : 'Fipe Brands'
  const lines = [
    `${pc.bold(pc.cyan(title))} ${pc.dim(String(api.endpoint ?? 'GET /fipe/api/v1'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? items.length)} shown · total ${String(value.totalItems ?? '?')} · ${String(api.limitPolicy ?? 'bounded Fipe list output')}`,
    `${pc.dim('quota')} remaining ${String(rateLimit.remaining ?? '?')} / ${String(rateLimit.limit ?? '?')} · reset ${String(rateLimit.reset ?? '?')}s`,
  ]
  if (items.length === 0) {
    lines.push('', pc.yellow('No Fipe rows matched this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run fipe.brands -- --vehicle-type carros --query volks --limit 20`)
    lines.push(`${pc.dim('again')} ${buildFipeListCommand(String(value.kind ?? 'fipe.brands'), query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildFipeListCommand(String(value.kind ?? 'fipe.brands'), query, 'offline')}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const item of items.slice(0, 30)) {
    lines.push(`${pc.bold(String(item.name ?? 'unnamed'))} ${pc.dim(String(item.code ?? 'code n/a'))}`)
  }
  if (items.length > 30) {
    lines.push(pc.dim(`… ${items.length - 30} more row(s); use --format json for full output.`))
  }
  if (value.kind === 'fipe.brands') {
    lines.push('', `${pc.dim('models')} ${buildFipeListCommand('fipe.models', { vehicleType: query.vehicleType, brandCode: items[0]?.code, limit: 100 })}`)
  } else if (value.kind === 'fipe.models') {
    lines.push('', `${pc.dim('years')} ${buildFipeListCommand('fipe.years', { vehicleType: query.vehicleType, brandCode: query.brandCode, modelCode: items[0]?.code, limit: 100 })}`)
  } else {
    lines.push('', `${pc.dim('price')} ${buildFipePriceCommand({ vehicleType: query.vehicleType, brandCode: query.brandCode, modelCode: query.modelCode, yearCode: items[0]?.code })}`)
  }
  lines.push(`${pc.dim('again')} ${buildFipeListCommand(String(value.kind ?? 'fipe.brands'), query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildFipeListCommand(String(value.kind ?? 'fipe.brands'), query, 'offline')}`)
  return lines.join('\n')
}

function buildFipeListCommand(kind: string, query: Record<string, unknown>, mode?: 'online' | 'offline'): string {
  const operation = kind === 'fipe.models' ? 'fipe.models' : kind === 'fipe.years' ? 'fipe.years' : 'fipe.brands'
  const keys = operation === 'fipe.brands' ? ['vehicleType', 'query', 'limit'] : operation === 'fipe.models' ? ['vehicleType', 'brandCode', 'query', 'limit'] : ['vehicleType', 'brandCode', 'modelCode', 'query', 'limit']
  return buildFipeCommand(operation, query, keys, mode)
}

function renderFipePrice(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const price = isRecord(value.price) ? value.price : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  return [
    `${pc.bold(pc.cyan('Fipe Price'))} ${pc.dim(String(api.endpoint ?? 'GET /fipe/api/v1/.../anos/{yearCode}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('price')} ${String(price.value ?? 'n/a')} · ${String(price.referenceMonth ?? 'reference n/a')}`,
    `${pc.dim('quota')} remaining ${String(rateLimit.remaining ?? '?')} / ${String(rateLimit.limit ?? '?')} · reset ${String(rateLimit.reset ?? '?')}s`,
    '',
    `${pc.bold(String(price.brand ?? 'brand n/a'))} · ${String(price.model ?? 'model n/a')}`,
    `   year ${String(price.modelYear ?? '?')} · fuel ${String(price.fuel ?? '?')} · Fipe code ${String(price.fipeCode ?? '?')}`,
    '',
    `${pc.dim('years')} ${buildFipeListCommand('fipe.years', { vehicleType: query.vehicleType, brandCode: query.brandCode, modelCode: query.modelCode, limit: 100 })}`,
    `${pc.dim('again')} ${buildFipePriceCommand(query, 'online')}`,
    `${pc.dim('replay')} ${buildFipePriceCommand(query, 'offline')}`,
  ].join('\n')
}

function buildFipePriceCommand(query: Record<string, unknown>, mode?: 'online' | 'offline'): string {
  return buildFipeCommand('fipe.price', query, ['vehicleType', 'brandCode', 'modelCode', 'yearCode'], mode)
}

function buildFipeCommand(operation: string, query: Record<string, unknown>, keys: string[], mode?: 'online' | 'offline'): string {
  const parts = [`public-apis apis run ${operation}`]
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  for (const key of keys) {
    if (query[key] !== undefined) {
      const option = key.replace(/[A-Z]/gu, match => `-${match.toLowerCase()}`)
      parts.push(`--${option} ${formatCliArg(query[key])}`)
    }
  }
  return parts.join(' ')
}

function renderUsaSpendingAwards(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const page = isRecord(value.page) ? value.page : {}
  const awards = Array.isArray(value.awards) ? value.awards.filter(isRecord) : []
  const messages = Array.isArray(value.messages) ? value.messages.map(message => String(message)) : []
  const awardsArgs = buildUsaSpendingAwardsArgs(query, page)
  const overTimeArgs = buildUsaSpendingOverTimeArgs(query)
  const lines = [
    `${pc.bold(pc.cyan('USAspending Awards'))} ${pc.dim(String(api.endpoint ?? 'POST /api/v2/search/spending_by_award/'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST API')}`,
    `${pc.dim('license')} ${String(api.licenseNote ?? 'public federal spending data')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('limit policy')} ${String(api.limitPolicy ?? 'awards default/cap 100')}`,
    `${pc.dim('count')} ${String(page.returned ?? awards.length)} returned · total ${String(page.total ?? '?')} · page ${String(page.page ?? query.page ?? 1)} · limit ${String(page.limit ?? query.limit ?? '?')} / ${String(page.maxLimit ?? 100)}`,
  ]
  if (messages.length > 0) {
    lines.push(`${pc.dim('messages')} ${truncateText(messages.join(' '), 180)}`)
  }
  if (awards.length === 0) {
    lines.push('', pc.yellow('No USAspending awards returned for this query.'))
    lines.push(`${pc.dim('again')} public-apis apis run usaspending.awards --online --persist -- ${awardsArgs}`)
    lines.push(`${pc.dim('replay')} public-apis apis run usaspending.awards --offline -- ${awardsArgs}`)
    lines.push(`${pc.dim('summary')} public-apis apis run usaspending.overTime --online --persist -- ${overTimeArgs}`)
    lines.push(`${pc.dim('agencies')} public-apis apis run usaspending.agencies --online --persist -- --limit 100`)
    return lines.join('\n')
  }

  lines.push('')
  for (const award of awards.slice(0, 15)) {
    lines.push(`${pc.bold(String(award.awardId ?? award.generatedInternalId ?? 'award'))} ${pc.dim(formatCurrency(award.awardAmount))}`)
    lines.push(`   recipient ${String(award.recipientName ?? '-')} · agency ${String(award.awardingAgency ?? '-')} · ${String(award.startDate ?? '?')}..${String(award.endDate ?? '?')}`)
    if (typeof award.description === 'string' && award.description.trim() !== '') {
      lines.push(`   ${truncateText(award.description.replace(/\s+/gu, ' '), 140)}`)
    }
  }
  if (awards.length > 15) {
    lines.push(pc.dim(`… ${awards.length - 15} more award(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} public-apis apis run usaspending.awards --online --persist -- ${awardsArgs}`)
  lines.push(`${pc.dim('replay')} public-apis apis run usaspending.awards --offline -- ${awardsArgs}`)
  if (page.hasNextPage === true) {
    lines.push(`${pc.dim('next page')} public-apis apis run usaspending.awards --online --persist -- ${buildUsaSpendingAwardsArgs(query, page, Number(page.page ?? query.page ?? 1) + 1)}`)
  }
  if (page.hasPreviousPage === true && Number(page.page ?? query.page ?? 1) > 1) {
    lines.push(`${pc.dim('prev page')} public-apis apis run usaspending.awards --online --persist -- ${buildUsaSpendingAwardsArgs(query, page, Number(page.page ?? query.page ?? 1) - 1)}`)
  }
  lines.push(`${pc.dim('summary')} public-apis apis run usaspending.overTime --online --persist -- ${overTimeArgs}`)
  lines.push(`${pc.dim('agencies')} public-apis apis run usaspending.agencies --online --persist -- --limit 100`)
  return lines.join('\n')
}

function renderUsaSpendingOverTime(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const totals = isRecord(value.totals) ? value.totals : {}
  const periods = Array.isArray(value.periods) ? value.periods.filter(isRecord) : []
  const messages = Array.isArray(value.messages) ? value.messages.map(message => String(message)) : []
  const overTimeArgs = buildUsaSpendingOverTimeArgs(query)
  const awardsArgs = buildUsaSpendingAwardsArgs(query, {})
  const lines = [
    `${pc.bold(pc.cyan('USAspending Over Time'))} ${pc.dim(String(api.endpoint ?? 'POST /api/v2/search/spending_over_time/'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST API')}`,
    `${pc.dim('license')} ${String(api.licenseNote ?? 'public federal spending data')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('limit policy')} ${String(api.limitPolicy ?? 'one aggregate series, no page-size control')}`,
    `${pc.dim('count')} ${String(value.count ?? periods.length)} period(s) · obligations ${formatCurrency(totals.aggregatedAmount)} · outlays ${formatCurrency(totals.totalOutlays)}`,
  ]
  if (messages.length > 0) {
    lines.push(`${pc.dim('messages')} ${truncateText(messages.join(' '), 180)}`)
  }
  if (periods.length === 0) {
    lines.push('', pc.yellow('No USAspending time periods returned for this query.'))
    lines.push(`${pc.dim('again')} public-apis apis run usaspending.overTime --online --persist -- ${overTimeArgs}`)
    lines.push(`${pc.dim('replay')} public-apis apis run usaspending.overTime --offline -- ${overTimeArgs}`)
    lines.push(`${pc.dim('awards')} public-apis apis run usaspending.awards --online --persist -- ${awardsArgs}`)
    lines.push(`${pc.dim('agencies')} public-apis apis run usaspending.agencies --online --persist -- --limit 100`)
    return lines.join('\n')
  }

  lines.push('')
  for (const period of periods.slice(0, 20)) {
    lines.push(`- ${pc.bold(String(period.label ?? 'period'))} obligations ${formatCurrency(period.aggregatedAmount)} · outlays ${formatCurrency(period.totalOutlays)}`)
    lines.push(`  contracts ${formatCurrency(period.contractObligations)} · grants ${formatCurrency(period.grantObligations)} · loans ${formatCurrency(period.loanObligations)}`)
  }
  if (periods.length > 20) {
    lines.push(pc.dim(`… ${periods.length - 20} more period(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} public-apis apis run usaspending.overTime --online --persist -- ${overTimeArgs}`)
  lines.push(`${pc.dim('replay')} public-apis apis run usaspending.overTime --offline -- ${overTimeArgs}`)
  lines.push(`${pc.dim('awards')} public-apis apis run usaspending.awards --online --persist -- ${awardsArgs}`)
  lines.push(`${pc.dim('agencies')} public-apis apis run usaspending.agencies --online --persist -- --limit 100`)
  return lines.join('\n')
}

function renderUsaSpendingAgencies(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const agencies = Array.isArray(value.agencies) ? value.agencies.filter(isRecord) : []
  const agenciesArgs = buildUsaSpendingAgenciesArgs(query, pagination)
  const lines = [
    `${pc.bold(pc.cyan('USAspending Toptier Agencies'))} ${pc.dim(String(api.endpoint ?? 'GET /api/v2/references/toptier_agencies/'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST API')}`,
    `${pc.dim('license')} ${String(api.licenseNote ?? 'public federal spending data')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('limit policy')} ${String(api.limitPolicy ?? 'one public list; CLI caps output/cache payloads')}`,
    `${pc.dim('count')} ${String(pagination.returned ?? agencies.length)} returned · limit ${String(pagination.limit ?? query.limit ?? '?')} / ${String(pagination.maxLimit ?? 200)}`,
  ]
  if (agencies.length === 0) {
    lines.push('', pc.yellow('No USAspending agencies returned.'))
    lines.push(`${pc.dim('again')} public-apis apis run usaspending.agencies --online --persist -- ${agenciesArgs}`)
    lines.push(`${pc.dim('replay')} public-apis apis run usaspending.agencies --offline -- ${agenciesArgs}`)
    lines.push(`${pc.dim('awards')} public-apis apis run usaspending.awards --online --persist -- --limit 100`)
    lines.push(`${pc.dim('summary')} public-apis apis run usaspending.overTime --online --persist -- --group fiscal_year`)
    return lines.join('\n')
  }

  lines.push('')
  const agencyCommands: string[] = []
  for (const agency of agencies.slice(0, 20)) {
    lines.push(`- ${pc.bold(String(agency.agencyName ?? agency.agencyId ?? 'agency'))} ${pc.dim(String(agency.abbreviation ?? agency.toptierCode ?? ''))}`)
    lines.push(`  budget ${formatCurrency(agency.budgetAuthorityAmount)} · obligated ${formatCurrency(agency.obligatedAmount)} · outlay ${formatCurrency(agency.outlayAmount)} · share ${formatPercentDecimal(agency.percentageOfTotalBudgetAuthority)}`)
    if (typeof agency.agencyName === 'string' && agency.agencyName.length > 0 && agencyCommands.length < 3) {
      agencyCommands.push(`public-apis apis run usaspending.awards --online --persist -- --awarding-agency ${formatCliArg(agency.agencyName)} --limit 100`)
    }
  }
  if (agencies.length > 20) {
    lines.push(pc.dim(`… ${agencies.length - 20} more agency/agencies; use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} public-apis apis run usaspending.agencies --online --persist -- ${agenciesArgs}`)
  lines.push(`${pc.dim('replay')} public-apis apis run usaspending.agencies --offline -- ${agenciesArgs}`)
  lines.push(`${pc.dim('awards')} public-apis apis run usaspending.awards --online --persist -- --limit 100`)
  lines.push(`${pc.dim('summary')} public-apis apis run usaspending.overTime --online --persist -- --group fiscal_year`)
  for (const [index, command] of agencyCommands.entries()) {
    lines.push(`${pc.dim(index === 0 ? 'agency awards' : 'agency alt')} ${command}`)
  }
  return lines.join('\n')
}

function buildUsaSpendingAwardsArgs(query: Record<string, unknown>, page: Record<string, unknown>, pageOverride?: number): string {
  const args = [
    '--start-date',
    formatCliArg(query.startDate ?? '2024-10-01'),
    '--end-date',
    formatCliArg(query.endDate ?? '2025-09-30'),
    '--award-type-codes',
    formatCliArg(Array.isArray(query.awardTypeCodes) ? query.awardTypeCodes.join(',') : query.awardTypeCodes ?? 'A,B,C,D'),
    '--limit',
    formatCliArg(page.limit ?? query.limit ?? 100),
    '--page',
    formatCliArg(pageOverride ?? page.page ?? query.page ?? 1),
    '--sort',
    formatCliArg(query.sort ?? 'Award Amount'),
    '--order',
    formatCliArg(query.order ?? 'desc'),
  ]
  if (typeof query.recipient === 'string' && query.recipient.length > 0) {
    args.push('--recipient', formatCliArg(query.recipient))
  }
  if (typeof query.awardingAgency === 'string' && query.awardingAgency.length > 0) {
    args.push('--awarding-agency', formatCliArg(query.awardingAgency))
  }
  return args.join(' ')
}

