function renderPostalPinCodeLookup(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const upstream = isRecord(value.upstream) ? value.upstream : {}
  const postOffices = Array.isArray(value.postOffices) ? value.postOffices.filter(isRecord) : []
  const operationId = value.kind === 'postalpincode.postOffice' ? 'postalpincode.postOffice' : 'postalpincode.pincode'
  const lookupArgs = buildPostalPinCodeArgs(operationId, query, pagination)
  const title = operationId === 'postalpincode.postOffice' ? 'PostalPinCode Post Office Lookup' : 'PostalPinCode PIN Code Lookup'
  const lines = [
    `${pc.bold(pc.cyan(title))} ${pc.dim(String(api.endpoint ?? 'GET /pincode/{pincode}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('upstream')} ${String(upstream.status ?? 'unknown')} · ${String(upstream.message ?? '-')}`,
    `${pc.dim('limit policy')} ${String(api.limitPolicy ?? 'upstream has no pagination; CLI slices locally')}`,
    `${pc.dim('detail policy')} ${String(api.detailPolicy ?? 'HTML search/detail pages are not scraped')}`,
    `${pc.dim('count')} ${String(pagination.returned ?? postOffices.length)} returned · upstream ${String(pagination.upstreamCount ?? upstream.count ?? '?')} · limit ${String(pagination.limit ?? query.limit ?? '?')} / ${String(pagination.maxLimit ?? 50)}`,
  ]
  if (postOffices.length === 0) {
    lines.push('', pc.yellow('No PostalPinCode post office records returned for this query.'))
    lines.push(`${pc.dim('again')} public-apis apis run ${operationId} --online --persist -- ${lookupArgs}`)
    lines.push(`${pc.dim('replay')} public-apis apis run ${operationId} --offline -- ${lookupArgs}`)
    lines.push(`${pc.dim('pincode')} public-apis apis run postalpincode.pincode --online --persist -- --pincode 110001 --limit 10`)
    lines.push(`${pc.dim('office')} public-apis apis run postalpincode.postOffice --online --persist -- --name 'Connaught Place' --limit 10`)
    return lines.join('\n')
  }

  lines.push('')
  for (const postOffice of postOffices.slice(0, 10)) {
    lines.push(`${pc.bold(String(postOffice.name ?? 'post office'))} ${pc.dim(String(postOffice.pincode ?? 'PIN unknown'))}`)
    lines.push(`   ${String(postOffice.branchType ?? '-')} · ${String(postOffice.deliveryStatus ?? '-')} · ${String(postOffice.district ?? '-')} · ${String(postOffice.state ?? '-')}`)
    lines.push(`   ${pc.dim('circle')} ${String(postOffice.circle ?? '-')} · ${pc.dim('division')} ${String(postOffice.division ?? '-')} · ${pc.dim('region')} ${String(postOffice.region ?? '-')}`)
  }
  if (postOffices.length > 10) {
    lines.push(pc.dim(`… ${postOffices.length - 10} more post office record(s); use --format json for full output.`))
  }
  const firstPincode = postOffices.find(postOffice => typeof postOffice.pincode === 'string')
  const firstName = postOffices.find(postOffice => typeof postOffice.name === 'string')
  lines.push('', `${pc.dim('again')} public-apis apis run ${operationId} --online --persist -- ${lookupArgs}`)
  lines.push(`${pc.dim('replay')} public-apis apis run ${operationId} --offline -- ${lookupArgs}`)
  if (firstPincode !== undefined) {
    lines.push(`${pc.dim('pincode')} public-apis apis run postalpincode.pincode --online --persist -- --pincode ${formatCliArg(firstPincode.pincode)} --limit 10`)
  }
  if (firstName !== undefined) {
    lines.push(`${pc.dim('office')} public-apis apis run postalpincode.postOffice --online --persist -- --name ${formatCliArg(firstName.name)} --limit 10`)
  }
  return lines.join('\n')
}

function buildPostalPinCodeArgs(operationId: string, query: Record<string, unknown>, pagination: Record<string, unknown>): string {
  const limit = pagination.limit ?? query.limit ?? 10
  if (operationId === 'postalpincode.postOffice') {
    return [
      '--name',
      formatCliArg(query.name ?? 'Connaught Place'),
      '--limit',
      formatCliArg(limit),
    ].join(' ')
  }
  return [
    '--pincode',
    formatCliArg(query.pincode ?? '110001'),
    '--limit',
    formatCliArg(limit),
  ].join(' ')
}

function renderIstanbulOpenDataSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const datasets = Array.isArray(value.datasets) ? value.datasets.filter(isRecord) : []
  const searchArgs = buildIstanbulOpenDataSearchArgs(query, pagination)
  const lines = [
    `${pc.bold(pc.cyan('Istanbul Open Data Dataset Search'))} ${pc.dim(String(api.endpoint ?? 'GET /api/3/action/package_search'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON CKAN Action API')}`,
    `${pc.dim('license')} ${String(api.licenseNote ?? 'dataset metadata surfaces the IMM Open Data License')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('limit policy')} ${String(api.limitPolicy ?? 'package_search rows defaults/caps at 1000')}`,
    `${pc.dim('count')} ${String(pagination.returned ?? datasets.length)} returned · total ${String(value.total ?? '?')} · limit ${String(pagination.limit ?? query.limit ?? '?')} / ${String(pagination.maxLimit ?? 1000)}`,
  ]
  if (datasets.length === 0) {
    lines.push('', pc.yellow('No Istanbul Open Data datasets returned for this query.'))
    lines.push(`${pc.dim('again')} public-apis apis run istanbulopendata.search --online --persist -- ${searchArgs}`)
    lines.push(`${pc.dim('replay')} public-apis apis run istanbulopendata.search --offline -- ${searchArgs}`)
    lines.push(`${pc.dim('sample')} public-apis apis run istanbulopendata.search --online --persist -- --query metro --limit 1000`)
    return lines.join('\n')
  }

  lines.push('')
  const readCommands: string[] = []
  for (const dataset of datasets.slice(0, 12)) {
    const resources = Array.isArray(dataset.resources) ? dataset.resources.filter(isRecord) : []
    const datastoreResources = resources.filter(resource => resource.datastoreActive === true)
    lines.push(`${pc.bold(String(dataset.title ?? dataset.name ?? `dataset ${String(dataset.id ?? '-')}`))} ${pc.dim(String(dataset.name ?? dataset.id ?? ''))}`)
    lines.push(`   org ${String(dataset.organizationTitle ?? '-')} · resources ${resources.length} · datastore ${datastoreResources.length}`)
    const firstDatastore = datastoreResources.find(resource => typeof resource.id === 'string' && resource.id.length > 0)
    if (firstDatastore !== undefined) {
      const resourceLabel = [firstDatastore.name, firstDatastore.format].filter(entry => typeof entry === 'string' && entry.length > 0).join(' · ')
      lines.push(`   ${pc.dim('resource')} ${resourceLabel === '' ? 'datastore' : resourceLabel} · ${String(firstDatastore.id)}`)
      if (readCommands.length < 3) {
        readCommands.push(`public-apis apis run istanbulopendata.records --online --persist -- --resource-id ${formatCliArg(firstDatastore.id)} --limit 5000`)
      }
    }
  }
  if (datasets.length > 12) {
    lines.push(pc.dim(`… ${datasets.length - 12} more dataset(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} public-apis apis run istanbulopendata.search --online --persist -- ${searchArgs}`)
  lines.push(`${pc.dim('replay')} public-apis apis run istanbulopendata.search --offline -- ${searchArgs}`)
  for (const [index, command] of readCommands.entries()) {
    lines.push(`${pc.dim(index === 0 ? 'read records' : 'read alt')} ${command}`)
  }
  if (readCommands.length === 0) {
    lines.push(`${pc.dim('sample records')} public-apis apis run istanbulopendata.records --online --persist -- --resource-id 32c8813b-544e-4f6e-887d-5bb0835411d1 --limit 5000`)
  }
  return lines.join('\n')
}

function renderIstanbulOpenDataRecords(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const records = Array.isArray(value.records) ? value.records.filter(isRecord) : []
  const fields = Array.isArray(value.fields) ? value.fields.map(field => String(field)) : []
  const recordsArgs = buildIstanbulOpenDataRecordsArgs(query, pagination)
  const lines = [
    `${pc.bold(pc.cyan('Istanbul Open Data Records'))} ${pc.dim(String(api.endpoint ?? 'GET /api/3/action/datastore_search'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON CKAN Action API')}`,
    `${pc.dim('license')} ${String(api.licenseNote ?? 'dataset metadata surfaces the IMM Open Data License')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('limit policy')} ${String(api.limitPolicy ?? 'datastore_search defaults/caps at 5000')}`,
    `${pc.dim('count')} ${String(pagination.returned ?? records.length)} returned · total ${String(value.total ?? '?')} · limit ${String(pagination.limit ?? query.limit ?? '?')} / ${String(pagination.maxLimit ?? 5000)} · fields ${fields.length}`,
  ]
  if (records.length === 0) {
    lines.push('', pc.yellow('No Istanbul Open Data records returned for this resource.'))
    lines.push(`${pc.dim('again')} public-apis apis run istanbulopendata.records --online --persist -- ${recordsArgs}`)
    lines.push(`${pc.dim('replay')} public-apis apis run istanbulopendata.records --offline -- ${recordsArgs}`)
    lines.push(`${pc.dim('search')} public-apis apis run istanbulopendata.search --online --persist -- --query metro --limit 1000`)
    lines.push(`${pc.dim('sample')} public-apis apis run istanbulopendata.records --online --persist -- --resource-id 32c8813b-544e-4f6e-887d-5bb0835411d1 --limit 5000`)
    return lines.join('\n')
  }

  lines.push('', `${pc.dim('fields')} ${fields.slice(0, 8).join(', ') || '-'}`)
  for (const record of records.slice(0, 12)) {
    const summary = Object.entries(record)
      .slice(0, 4)
      .map(([key, entry]) => `${key}=${String(entry)}`)
      .join(' · ')
    lines.push(`- ${summary}`)
  }
  if (records.length > 12) {
    lines.push(pc.dim(`… ${records.length - 12} more record(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('again')} public-apis apis run istanbulopendata.records --online --persist -- ${recordsArgs}`)
  lines.push(`${pc.dim('replay')} public-apis apis run istanbulopendata.records --offline -- ${recordsArgs}`)
  lines.push(`${pc.dim('search')} public-apis apis run istanbulopendata.search --online --persist -- --query metro --limit 1000`)
  return lines.join('\n')
}

