function renderSecEdgarSubmissions(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const company = isRecord(value.company) ? value.company : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const filings = Array.isArray(value.filings) ? value.filings.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('SEC EDGAR Company Submissions'))} ${pc.dim(String(api.endpoint ?? 'GET /submissions/CIK##########.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('company')} ${String(company.name ?? 'unknown')} · CIK ${String(company.cik ?? query.cik ?? '?')} · tickers ${formatArrayPreview(company.tickers)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? filings.length)} shown · total ${String(pagination.total ?? '?')} · limit ${String(pagination.limit ?? query.limit ?? '?')} · max ${String(pagination.maxLimit ?? 1000)}`,
    `${pc.dim('access')} ${String(api.accessPolicy ?? 'SEC APIs require no key; send descriptive User-Agent.')}`,
  ]
  if (filings.length === 0) {
    lines.push('', pc.yellow('No SEC EDGAR submissions returned for this CIK.'))
    lines.push(`${pc.dim('try')} public-apis apis run secedgar.submissions --online --persist -- --cik 0000320193 --limit ${String(query.limit ?? 100)}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const filing of filings.slice(0, 20)) {
    lines.push(`- ${String(filing.form ?? '?')} · filed ${String(filing.filingDate ?? '?')} · ${String(filing.accessionNumber ?? '?')}`)
    const description = String(filing.primaryDocDescription ?? filing.primaryDocument ?? '').trim()
    if (description !== '') {
      lines.push(`  ${pc.dim(wrapLine(description, 110))}`)
    }
  }
  if (filings.length > 20) {
    lines.push(pc.dim(`… ${filings.length - 20} more filing(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('next')} public-apis apis run secedgar.companyConcept --online --persist -- --cik ${formatCliArg(query.cik ?? '0000320193')} --tag AccountsPayableCurrent --limit 100`)
  lines.push(`${pc.dim('replay')} public-apis apis run secedgar.submissions --offline -- --cik ${formatCliArg(query.cik ?? '0000320193')} --limit ${String(query.limit ?? 100)}`)
  return lines.join('\n')
}

function renderSecEdgarCompanyConcept(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const concept = isRecord(value.concept) ? value.concept : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const facts = Array.isArray(value.facts) ? value.facts.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('SEC EDGAR Company Concept'))} ${pc.dim(String(api.endpoint ?? 'GET /api/xbrl/companyconcept/CIK##########/{taxonomy}/{tag}.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('concept')} ${String(concept.label ?? concept.tag ?? query.tag ?? 'unknown')} · ${String(concept.unit ?? query.unit ?? '?')} · units ${formatArrayPreview(concept.availableUnits)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? facts.length)} shown · total ${String(pagination.total ?? '?')} · limit ${String(pagination.limit ?? query.limit ?? '?')} · max ${String(pagination.maxLimit ?? 1000)}`,
    `${pc.dim('access')} ${String(api.accessPolicy ?? 'SEC APIs require no key; send descriptive User-Agent.')}`,
  ]
  if (facts.length === 0) {
    lines.push('', pc.yellow('No SEC EDGAR concept facts returned for this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run secedgar.companyConcept --online --persist -- --cik ${formatCliArg(query.cik ?? '0000320193')} --tag AccountsPayableCurrent --unit USD --limit ${String(query.limit ?? 100)}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const fact of facts.slice(0, 20)) {
    lines.push(`- ${String(fact.end ?? '?')} · ${formatNumber(fact.val)} ${String(concept.unit ?? query.unit ?? '')} · ${String(fact.form ?? '?')} filed ${String(fact.filed ?? '?')}`)
  }
  if (facts.length > 20) {
    lines.push(pc.dim(`… ${facts.length - 20} more fact(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('next')} public-apis apis run secedgar.submissions --online --persist -- --cik ${formatCliArg(query.cik ?? '0000320193')} --limit 100`)
  lines.push(`${pc.dim('replay')} public-apis apis run secedgar.companyConcept --offline -- --cik ${formatCliArg(query.cik ?? '0000320193')} --taxonomy ${formatCliArg(query.taxonomy ?? 'us-gaap')} --tag ${formatCliArg(query.tag ?? 'AccountsPayableCurrent')} --unit ${formatCliArg(query.unit ?? 'USD')} --limit ${String(query.limit ?? 100)}`)
  return lines.join('\n')
}

function renderMfApiSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const schemes = Array.isArray(value.schemes) ? value.schemes.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('Indian Mutual Fund Search'))} ${pc.dim(String(api.endpoint ?? 'GET /mf/search'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? value.count ?? schemes.length)} shown · limit ${String(pagination.limit ?? query.limit ?? '?')} · max ${String(pagination.maxLimit ?? 100)}`,
  ]

  if (schemes.length === 0) {
    lines.push('', pc.yellow('No MFapi mutual fund schemes matched this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run mfapi.search -- --query ${formatCliArg(String(query.query ?? 'SBI Small Cap'))} --limit ${String(query.limit ?? pagination.limit ?? 100)}`)
    lines.push(`${pc.dim('latest')} public-apis apis run mfapi.latest -- --scheme-code 125497`)
    return lines.join('\n')
  }

  lines.push('')
  for (const scheme of schemes.slice(0, 30)) {
    lines.push(`- ${pc.bold(String(scheme.schemeName ?? 'unknown scheme'))} ${pc.dim(String(scheme.schemeCode ?? ''))}`)
  }
  if (schemes.length > 30) {
    lines.push(pc.dim(`… ${schemes.length - 30} more scheme(s); use --format json for full output.`))
  }
  const first = schemes[0]
  lines.push('', `${pc.dim('next')} public-apis apis run mfapi.latest -- --scheme-code ${String(first?.schemeCode ?? 125497)}`)
  return lines.join('\n')
}

function renderMfApiLatest(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const fund = isRecord(value.fund) ? value.fund : {}
  const nav = isRecord(value.nav) ? value.nav : {}
  const lines = [
    `${pc.bold(pc.cyan('Indian Mutual Fund Latest NAV'))} ${pc.dim(String(api.endpoint ?? 'GET /mf/{schemeCode}/latest'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('fund')} ${String(fund.schemeName ?? 'unknown scheme')} ${pc.dim(String(fund.schemeCode ?? query.schemeCode ?? ''))}`,
    `${pc.dim('category')} ${String(fund.fundHouse ?? '-')} · ${String(fund.schemeType ?? '-')} · ${String(fund.schemeCategory ?? '-')}`,
  ]

  if (Object.keys(nav).length === 0) {
    lines.push('', pc.yellow('No latest NAV returned for this MFapi scheme code.'))
    lines.push(`${pc.dim('try')} public-apis apis run mfapi.latest -- --scheme-code ${String(query.schemeCode ?? fund.schemeCode ?? 125497)}`)
    lines.push(`${pc.dim('search')} public-apis apis run mfapi.search -- --query ${formatCliArg(String(fund.fundHouse ?? 'SBI Small Cap'))} --limit 100`)
    return lines.join('\n')
  }

  lines.push('', `${pc.bold(String(nav.date ?? 'unknown date'))} · NAV ${formatNumber(nav.nav)}`)
  if (typeof fund.isinGrowth === 'string') {
    lines.push(`${pc.dim('isin')} ${fund.isinGrowth}`)
  }
  lines.push('', `${pc.dim('next')} public-apis apis run mfapi.search -- --query ${formatCliArg(String(fund.fundHouse ?? 'SBI'))} --limit 100`)
  return lines.join('\n')
}

function renderMsrcVulnerabilities(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const vulnerabilities = Array.isArray(value.vulnerabilities)
    ? value.vulnerabilities.filter(isRecord)
    : []
  const commandArgs = buildMsrcVulnerabilitiesArgs(query, pagination)
  const endpoint = String(api.endpoint ?? 'GET /sug/v2.0/en-US/vulnerability')
  const boundary = 'open REST API only · no auth · no Chrome clickstream'
  const safety = String(
    api.safety ??
      [
        'No report submission, authentication, uploads, or private case',
        'workflows are exposed.',
      ].join(' '),
  )
  const returned = String(pagination.returned ?? vulnerabilities.length)
  const totalMatched = String(pagination.totalMatched ?? '?')
  const limit = String(pagination.limit ?? query.limit ?? '?')
  const maxLimit = String(pagination.maxLimit ?? '?')
  const orderBy = String(pagination.orderBy ?? 'releaseDate desc')
  const title = [
    pc.bold(pc.cyan('MSRC Security Update Guide Vulnerabilities')),
    pc.dim(endpoint),
  ].join(' ')
  const lines = [
    title,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} ${boundary} · read-only public metadata`,
    [
      `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON OData')}`,
      String(api.platform ?? 'Microsoft Security Update Guide API v2.0'),
    ].join(' · '),
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('safety')} ${safety}`,
    [
      `${pc.dim('pagination')} returned ${returned} / matched ${totalMatched}`,
      `limit ${limit}`,
      `max ${maxLimit}`,
      `order ${orderBy}`,
    ].join(' · '),
  ]

  if (vulnerabilities.length === 0) {
    lines.push('', pc.yellow('No MSRC vulnerability metadata matched this query.'))
    lines.push(
      [
        pc.dim('again'),
        'public-apis apis run msrc.vulnerabilities --online --persist --',
        commandArgs,
      ].join(' '),
    )
    lines.push(
      [
        pc.dim('latest'),
        'public-apis apis run msrc.vulnerabilities --online --persist --',
        '--limit 20',
      ].join(' '),
    )
    lines.push(
      [
        pc.dim('release'),
        'public-apis apis run msrc.vulnerabilities --online --persist --',
        '--release-number 2026-May --limit 20',
      ].join(' '),
    )
    lines.push(
      [
        pc.dim('replay'),
        `public-apis apis run msrc.vulnerabilities --offline -- ${commandArgs}`,
      ].join(' '),
    )
    return lines.join('\n')
  }

  for (const vulnerability of vulnerabilities.slice(0, 20)) {
    lines.push(
      '',
      [
        pc.bold(String(vulnerability.cveNumber ?? 'CVE')),
        String(vulnerability.title ?? '(untitled)'),
      ].join(' '),
    )
    const meta = [
      vulnerability.releaseNumber === undefined
        ? undefined
        : `release ${String(vulnerability.releaseNumber)}`,
      vulnerability.severity === undefined
        ? undefined
        : `severity ${String(vulnerability.severity)}`,
      vulnerability.impact === undefined
        ? undefined
        : `impact ${String(vulnerability.impact)}`,
      vulnerability.issuingCna === undefined
        ? undefined
        : `CNA ${String(vulnerability.issuingCna)}`,
      vulnerability.customerActionRequired === true
        ? 'customer action required'
        : undefined,
    ].filter((entry): entry is string => typeof entry === 'string')
    if (meta.length > 0) {
      lines.push(pc.dim(meta.join(' · ')))
    }
    if (typeof vulnerability.releaseDate === 'string') {
      const revision = typeof vulnerability.latestRevisionDate === 'string'
        ? ` · revised ${vulnerability.latestRevisionDate}`
        : ''
      lines.push(`${pc.dim('released')} ${vulnerability.releaseDate}${revision}`)
    }
    if (typeof vulnerability.summary === 'string') {
      lines.push(`  ${truncateText(vulnerability.summary, 220)}`)
    }
    if (typeof vulnerability.mitreUrl === 'string') {
      lines.push(`  ${pc.blue(vulnerability.mitreUrl)}`)
    }
  }
  if (vulnerabilities.length > 20) {
    const moreRows = [
      `… ${vulnerabilities.length - 20} more vulnerability row(s);`,
      'use --format json.',
    ].join(' ')
    lines.push(
      pc.dim(moreRows),
    )
  }
  lines.push(
    '',
    [
      pc.dim('again'),
      'public-apis apis run msrc.vulnerabilities --online --persist --',
      commandArgs,
    ].join(' '),
  )
  lines.push(
    [
      pc.dim('replay'),
      `public-apis apis run msrc.vulnerabilities --offline -- ${commandArgs}`,
    ].join(' '),
  )
  const firstCve = typeof vulnerabilities[0]?.cveNumber === 'string'
    ? vulnerabilities[0].cveNumber
    : 'CVE-2026-7896'
  lines.push(
    [
      pc.dim('cve'),
      'public-apis apis run msrc.vulnerabilities --online --persist -- --cve',
      `${formatCliArg(firstCve)} --limit 1`,
    ].join(' '),
  )
  return lines.join('\n')
}

function buildMsrcVulnerabilitiesArgs(
  query: Record<string, unknown>,
  pagination: Record<string, unknown> = {},
): string {
  const parts: string[] = []
  if (typeof query.cve === 'string' && query.cve.trim() !== '') {
    parts.push('--cve', formatCliArg(query.cve))
  }
  if (typeof query.releaseNumber === 'string' && query.releaseNumber.trim() !== '') {
    parts.push('--release-number', formatCliArg(query.releaseNumber))
  }
  if (typeof query.severity === 'string' && query.severity.trim() !== '') {
    parts.push('--severity', formatCliArg(query.severity))
  }
  parts.push('--limit', String(pagination.limit ?? query.limit ?? 20))
  return parts.join(' ')
}

function renderOpenLibrarySearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const works = Array.isArray(value.works) ? value.works.filter(isRecord) : []
  const renderedWorks = works.slice(0, 20)
  const lines = [
    `${pc.bold(pc.cyan('Open Library Search'))} ${pc.dim(String(api.endpoint ?? 'GET /search.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} start ${String(pagination.start ?? 0)} · ${String(renderedWorks.length)} text shown / ${String(value.count ?? works.length)} returned · ${String(pagination.total ?? '?')} total · limit ${String(pagination.limit ?? query.limit ?? 100)}`,
    `${pc.dim('limit')} docs default ${String(api.documentedDefaultLimit ?? 100)} · CLI cap ${String(api.cliLimitCap ?? 100)}`,
  ]

  if (works.length === 0) {
    lines.push('', pc.yellow('No Open Library works returned for this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run openlibrary.search -- --query ${quoteCliArg(String(query.query ?? 'pride and prejudice'))} --language eng --limit ${String(query.limit ?? 100)}`)
    return lines.join('\n')
  }

  for (const [workIndex, work] of renderedWorks.entries()) {
    const authors = Array.isArray(work.authors) ? work.authors.filter(entry => typeof entry === 'string').slice(0, 3).join(', ') : ''
    const languages = Array.isArray(work.languages) ? work.languages.filter(entry => typeof entry === 'string').slice(0, 6).join(', ') : ''
    const meta = [
      authors,
      work.firstPublishYear !== undefined ? `first ${String(work.firstPublishYear)}` : undefined,
      work.editionCount !== undefined ? `${String(work.editionCount)} edition(s)` : undefined,
      work.ebookAccess !== undefined ? `ebook ${String(work.ebookAccess)}` : undefined,
      languages !== '' ? `lang ${languages}` : undefined,
    ].filter((entry): entry is string => typeof entry === 'string' && entry !== '')
    lines.push('', `${pc.bold(`${workIndex + 1}. ${String(work.title ?? '(untitled)')}`)} ${pc.dim(String(work.key ?? ''))}`)
    if (meta.length > 0) {
      lines.push(pc.dim(meta.join(' · ')))
    }
    if (typeof work.url === 'string') {
      lines.push(pc.blue(work.url))
    }
    if (typeof work.coverUrl === 'string') {
      lines.push(`${pc.dim('cover')} ${pc.blue(work.coverUrl)}`)
    }
  }
  if (works.length > renderedWorks.length) {
    lines.push(pc.dim(`… ${works.length - renderedWorks.length} more returned work(s); use --format json for the full projected page.`))
  }

  const nextKey = typeof works[0]?.key === 'string' ? String(works[0].key) : '/works/OL66554W'
  lines.push('', `${pc.dim('open first')} public-apis apis run openlibrary.work -- --work-key ${quoteCliArg(nextKey)}`)
  const nextOffset = typeof pagination.nextOffset === 'number' ? pagination.nextOffset : undefined
  const total = typeof pagination.total === 'number' ? pagination.total : undefined
  if (nextOffset !== undefined && total !== undefined && nextOffset < total) {
    lines.push(`${pc.dim('next page')} ${buildOpenLibrarySearchCommand(query, nextOffset)}`)
  }
  return lines.join('\n')
}

function renderOpenLibraryWork(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const work = isRecord(value.work) ? value.work : {}
  const subjects = Array.isArray(work.subjects) ? work.subjects.filter(entry => typeof entry === 'string') : []
  const authors = Array.isArray(work.authors) ? work.authors.filter(entry => typeof entry === 'string') : []
  const lines = [
    `${pc.bold(pc.cyan('Open Library Work'))} ${pc.dim(String(api.endpoint ?? 'GET /works/{id}.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.bold(String(work.title ?? '(untitled)'))} ${pc.dim(String(work.key ?? ''))}`,
  ]

  const meta = [
    work.firstPublishDate !== undefined ? `first published ${String(work.firstPublishDate)}` : undefined,
    authors.length > 0 ? `authors ${authors.slice(0, 5).join(', ')}` : undefined,
    work.revision !== undefined ? `revision ${String(work.revision)}` : undefined,
  ].filter((entry): entry is string => typeof entry === 'string')
  if (meta.length > 0) {
    lines.push(pc.dim(meta.join(' · ')))
  }
  if (typeof work.description === 'string' && work.description.trim() !== '') {
    lines.push('', wrapText(work.description.trim(), 100))
  }
  if (subjects.length > 0) {
    lines.push('', `${pc.dim('subjects')} ${subjects.slice(0, 12).join(' · ')}`)
  }
  if (typeof work.url === 'string') {
    lines.push('', pc.blue(work.url))
  }
  lines.push('', `${pc.dim('related search')} public-apis apis run openlibrary.search -- --query ${quoteCliArg(String(work.title ?? 'books'))} --limit 100`)
  return lines.join('\n')
}

function renderGbifSpecies(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const species = Array.isArray(value.species)
    ? value.species.filter(isRecord)
    : []
  const header = String(api.endpoint ?? 'GET /v1/species/search')
  const lines = [
    `${pc.bold(pc.cyan('GBIF Species Search'))} ${pc.dim(header)}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    formatGbifPageLine(pagination, species.length, query),
    `${pc.dim('rate')} ${formatGbifRate(api)}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Read-only search summaries only.')}`,
  ]

  if (species.length === 0) {
    lines.push('', pc.yellow('No GBIF species usages matched this query.'))
    lines.push(`${pc.dim('try')} ${buildGbifSpeciesCommand({}, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildGbifSpeciesCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildGbifSpeciesCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const [index, item] of species.slice(0, 20).entries()) {
    const lineage = [
      item.kingdom,
      item.family,
      item.genus,
      item.species,
    ].filter((part): part is string => typeof part === 'string' && part.trim() !== '')
    const status = [
      item.rank,
      item.taxonomicStatus,
      item.nameType,
      item.synonym === true ? 'synonym' : undefined,
      typeof item.numOccurrences === 'number'
        ? `${formatInteger(item.numOccurrences)} occurrence(s)`
        : undefined,
    ].filter((part): part is string => typeof part === 'string' && part.trim() !== '')
    lines.push(
      '',
      formatGbifHeading(index, item, 'Unnamed taxon'),
    )
    if (status.length > 0) {
      lines.push(pc.dim(status.join(' · ')))
    }
    if (lineage.length > 0) {
      lines.push(`${pc.dim('lineage')} ${lineage.join(' › ')}`)
    }
  }
  if (species.length > 20) {
    lines.push(pc.dim(
      `… ${species.length - 20} more taxon(s); use --format json for full output.`,
    ))
  }

  lines.push('', `${pc.dim('again')} ${buildGbifSpeciesCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildGbifSpeciesCommand(query, 'offline')}`)
  const nextOffset = typeof pagination.nextOffset === 'number'
    ? pagination.nextOffset
    : undefined
  if (nextOffset !== undefined && nextOffset <= Number(api.offsetCap ?? 10000)) {
    const command = buildGbifSpeciesCommand({ ...query, offset: nextOffset }, 'online')
    lines.push(`${pc.dim('more')} ${command}`)
  }
  lines.push(`${pc.dim('occurrences')} ${
    buildGbifOccurrencesFromSpeciesCommand(query, species[0])
  }`)
  return lines.join('\n')
}

function renderGbifOccurrences(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const occurrences = Array.isArray(value.occurrences)
    ? value.occurrences.filter(isRecord)
    : []
  const header = String(api.endpoint ?? 'GET /v1/occurrence/search')
  const lines = [
    `${pc.bold(pc.cyan('GBIF Occurrence Search'))} ${pc.dim(header)}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    formatGbifPageLine(pagination, occurrences.length, query),
    `${pc.dim('rate')} ${formatGbifRate(api)}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Read-only search summaries only.')}`,
  ]

  if (occurrences.length === 0) {
    lines.push('', pc.yellow('No GBIF occurrence records matched this query.'))
    lines.push(`${pc.dim('try')} ${
      buildGbifOccurrencesCommand({ country: 'GB' }, 'online')
    }`)
    lines.push(`${pc.dim('again')} ${buildGbifOccurrencesCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildGbifOccurrencesCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const [index, item] of occurrences.slice(0, 20).entries()) {
    const coordinates = isRecord(item.coordinates)
      ? formatCoordinates(item.coordinates)
      : undefined
    const meta = [
      item.basisOfRecord,
      item.countryCode ?? item.country,
      item.eventDate ?? item.year,
      item.license,
      coordinates !== undefined ? `coords ${coordinates}` : undefined,
      typeof item.mediaCount === 'number'
        ? `media ${String(item.mediaCount)}`
        : undefined,
    ].filter((part): part is string => typeof part === 'string' && part.trim() !== '')
    lines.push(
      '',
      formatGbifHeading(index, item, 'Unnamed occurrence'),
    )
    if (meta.length > 0) {
      lines.push(pc.dim(meta.join(' · ')))
    }
    if (typeof item.datasetTitle === 'string') {
      lines.push(`${pc.dim('dataset')} ${item.datasetTitle}`)
    }
    const issues = Array.isArray(item.issues)
      ? item.issues.filter(issue => typeof issue === 'string').slice(0, 5)
      : []
    if (issues.length > 0) {
      lines.push(`${pc.dim('issues')} ${issues.join(', ')}`)
    }
  }
  if (occurrences.length > 20) {
    const hiddenCount = occurrences.length - 20
    lines.push(pc.dim(
      `… ${hiddenCount} more record(s); use --format json for full output.`,
    ))
  }

  lines.push('', `${pc.dim('again')} ${buildGbifOccurrencesCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildGbifOccurrencesCommand(query, 'offline')}`)
  const nextOffset = typeof pagination.nextOffset === 'number'
    ? pagination.nextOffset
    : undefined
  if (nextOffset !== undefined && nextOffset <= Number(api.offsetCap ?? 10000)) {
    const command = buildGbifOccurrencesCommand(
      { ...query, offset: nextOffset },
      'online',
    )
    lines.push(`${pc.dim('more')} ${command}`)
  }
  lines.push(`${pc.dim('species')} ${buildGbifSpeciesCommand({
    query: String(query.scientificName ?? 'Quercus robur'),
    limit: 10,
  }, 'online')}`)
  return lines.join('\n')
}

function formatGbifPageLine(
  pagination: Record<string, unknown>,
  returnedCount: number,
  query: Record<string, unknown>,
): string {
  const returned = String(pagination.returned ?? returnedCount)
  const total = String(pagination.total ?? '?')
  const limit = String(pagination.limit ?? query.limit ?? '?')
  const offset = String(pagination.offset ?? query.offset ?? 0)
  return [
    pc.dim('page'),
    `${returned} returned / ${total} total`,
    `· limit ${limit}`,
    `· offset ${offset}`,
  ].join(' ')
}

function formatGbifRate(api: Record<string, unknown>): string {
  return String(api.rateLimitPolicy ?? 'GBIF search APIs may be rate limited.')
}

function formatGbifHeading(
  index: number,
  item: Record<string, unknown>,
  fallback: string,
): string {
  const name = String(item.scientificName ?? item.canonicalName ?? fallback)
  const key = String(item.key ?? item.gbifID ?? '')
  return `${pc.bold(`${index + 1}. ${name}`)} ${pc.dim(key)}`
}

function formatCoordinates(coordinates: Record<string, unknown>): string {
  return [
    formatNumber(coordinates.latitude),
    formatNumber(coordinates.longitude),
  ].join(', ')
}

function buildGbifSpeciesCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run gbif.species']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  for (const [flag, value] of [
    ['--query', query.query],
    ['--rank', query.rank],
    ['--status', query.status],
  ] as const) {
    if (typeof value === 'string' && value.trim() !== '') {
      parts.push(flag, formatCliArg(value))
    }
  }
  if (typeof query.higherTaxonKey === 'number') {
    parts.push('--higher-taxon-key', String(query.higherTaxonKey))
  }
  parts.push('--limit', String(query.limit ?? 10))
  parts.push('--offset', String(query.offset ?? 0))
  return parts.join(' ')
}

function buildGbifOccurrencesCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run gbif.occurrences']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  for (const [flag, value] of [
    ['--scientific-name', query.scientificName],
    ['--country', query.country],
    ['--year', query.year],
    ['--basis-of-record', query.basisOfRecord],
  ] as const) {
    if (typeof value === 'string' && value.trim() !== '') {
      parts.push(flag, formatCliArg(value))
    }
  }
  if (typeof query.hasCoordinate === 'boolean') {
    parts.push('--has-coordinate', String(query.hasCoordinate))
  }
  parts.push('--limit', String(query.limit ?? 10))
  parts.push('--offset', String(query.offset ?? 0))
  return parts.join(' ')
}

function buildGbifOccurrencesFromSpeciesCommand(
  query: Record<string, unknown>,
  species: Record<string, unknown> | undefined,
): string {
  const name = typeof species?.canonicalName === 'string'
    ? species.canonicalName
    : typeof species?.scientificName === 'string'
      ? species.scientificName
      : String(query.query ?? 'Quercus robur')
  return [
    'public-apis apis run gbif.occurrences --online --persist --',
    '--scientific-name',
    formatCliArg(name),
    '--country GB --limit 10',
  ].join(' ')
}

function renderIdigbioRecords(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const records = Array.isArray(value.records)
    ? value.records.filter(isRecord)
    : []
  const endpoint = String(api.endpoint ?? 'GET /v2/search/records/')
  const queryFormat = String(
    api.queryFormat ?? 'Query Format JSON in GET params',
  )
  const lines = [
    `${pc.bold(pc.cyan('iDigBio Records Search'))} ${pc.dim(endpoint)}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatIdigbioRecordsQuery(query)}`,
    formatIdigbioPageLine(pagination, records.length, query),
    `${pc.dim('format')} ${queryFormat}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Read-only JSON search only.')}`,
  ]
  if (typeof value.lastModified === 'string') {
    lines.push(`${pc.dim('modified')} ${value.lastModified}`)
  }

  if (records.length === 0) {
    lines.push('', pc.yellow('No iDigBio specimen records matched this query.'))
    lines.push(`${pc.dim('try')} ${buildIdigbioRecordsCommand({}, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildIdigbioRecordsCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildIdigbioRecordsCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const [index, record] of records.slice(0, 20).entries()) {
    const meta = [
      formatIdigbioText(record.family),
      formatIdigbioText(record.country),
      formatIdigbioText(record.stateProvince),
      formatIdigbioText(record.eventDate),
      formatIdigbioText(record.basisOfRecord),
      formatIdigbioText(record.institutionCode),
      typeof record.hasImage === 'boolean'
        ? `image ${formatBooleanBadge(record.hasImage)}`
        : undefined,
    ].filter((part): part is string => typeof part === 'string' && part.trim() !== '')
    const code = [
      record.collectionCode,
      record.catalogNumber,
    ].filter((part): part is string => typeof part === 'string' && part.trim() !== '')
    lines.push('', formatIdigbioHeading(index, record, 'Unnamed specimen'))
    if (meta.length > 0) {
      lines.push(pc.dim(meta.join(' · ')))
    }
    if (code.length > 0) {
      lines.push(`${pc.dim('collection')} ${
        code.map(formatIdigbioText).join(' · ')
      }`)
    }
    if (isRecord(record.coordinates)) {
      lines.push(`${pc.dim('coords')} ${formatCoordinates(record.coordinates)}`)
    }
  }
  if (records.length > 20) {
    lines.push(pc.dim(
      `… ${records.length - 20} more record(s); use --format json.`,
    ))
  }

  lines.push('', `${pc.dim('again')} ${buildIdigbioRecordsCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildIdigbioRecordsCommand(query, 'offline')}`)
  const nextOffset = typeof pagination.nextOffset === 'number'
    ? pagination.nextOffset
    : undefined
  if (nextOffset !== undefined && nextOffset <= Number(api.offsetCap ?? 10000)) {
    lines.push(`${pc.dim('more')} ${
      buildIdigbioRecordsCommand({ ...query, offset: nextOffset }, 'online')
    }`)
  }
  lines.push(`${pc.dim('media')} ${
    buildIdigbioMediaFromRecordsCommand(query, records[0])
  }`)
  return lines.join('\n')
}

function renderIdigbioMedia(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const media = Array.isArray(value.media) ? value.media.filter(isRecord) : []
  const endpoint = String(api.endpoint ?? 'GET /v2/search/media/')
  const queryFormat = String(
    api.queryFormat ?? 'Query Format JSON in GET params',
  )
  const scope = String(api.boundary ?? 'Metadata only; downloads excluded.')
  const lines = [
    `${pc.bold(pc.cyan('iDigBio Media Search'))} ${pc.dim(endpoint)}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatIdigbioMediaQuery(query)}`,
    formatIdigbioPageLine(pagination, media.length, query),
    `${pc.dim('format')} ${queryFormat}`,
    `${pc.dim('scope')} ${scope}`,
  ]
  if (typeof value.lastModified === 'string') {
    lines.push(`${pc.dim('modified')} ${value.lastModified}`)
  }

  if (media.length === 0) {
    lines.push('', pc.yellow('No iDigBio media metadata matched this query.'))
    lines.push(`${pc.dim('try')} ${buildIdigbioMediaCommand({}, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildIdigbioMediaCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildIdigbioMediaCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const [index, item] of media.slice(0, 20).entries()) {
    const meta = [
      formatIdigbioText(item.mediaType),
      formatIdigbioText(item.format),
      formatIdigbioText(item.rights),
      typeof item.hasSpecimen === 'boolean'
        ? `specimen ${formatBooleanBadge(item.hasSpecimen)}`
        : undefined,
    ].filter((part): part is string => typeof part === 'string' && part.trim() !== '')
    lines.push('', formatIdigbioHeading(index, item, 'Untitled media'))
    if (meta.length > 0) {
      lines.push(pc.dim(meta.join(' · ')))
    }
    if (typeof item.description === 'string' && item.description.trim() !== '') {
      lines.push(wrapLine(stripHtml(item.description), 104))
    }
    if (typeof item.accessUri === 'string' && item.accessUri.trim() !== '') {
      lines.push(`${pc.dim('access')} ${pc.blue(item.accessUri)}`)
    }
    if (typeof item.attributionUrl === 'string' && item.attributionUrl.trim() !== '') {
      lines.push(`${pc.dim('attribution')} ${pc.blue(item.attributionUrl)}`)
    }
  }
  if (media.length > 20) {
    lines.push(pc.dim(
      `… ${media.length - 20} more media item(s); use --format json.`,
    ))
  }

  lines.push('', `${pc.dim('again')} ${buildIdigbioMediaCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildIdigbioMediaCommand(query, 'offline')}`)
  const nextOffset = typeof pagination.nextOffset === 'number'
    ? pagination.nextOffset
    : undefined
  if (nextOffset !== undefined && nextOffset <= Number(api.offsetCap ?? 10000)) {
    lines.push(`${pc.dim('more')} ${
      buildIdigbioMediaCommand({ ...query, offset: nextOffset }, 'online')
    }`)
  }
  lines.push(`${pc.dim('records')} ${buildIdigbioRecordsCommand({
    scientificName: query.scientificName ?? 'Quercus robur',
    limit: 10,
  }, 'online')}`)
  return lines.join('\n')
}

function formatIdigbioPageLine(
  pagination: Record<string, unknown>,
  returnedCount: number,
  query: Record<string, unknown>,
): string {
  const returned = String(pagination.returned ?? returnedCount)
  const total = String(pagination.total ?? '?')
  const limit = String(pagination.limit ?? query.limit ?? 10)
  const offset = String(pagination.offset ?? query.offset ?? 0)
  return [
    pc.dim('page'),
    `${returned} returned / ${total} total`,
    `· limit ${limit}`,
    `· offset ${offset}`,
  ].join(' ')
}

function formatIdigbioHeading(
  index: number,
  item: Record<string, unknown>,
  fallback: string,
): string {
  const title = stripHtml(String(item.scientificName ?? item.title ?? fallback))
  const uuid = typeof item.uuid === 'string' ? item.uuid : ''
  return `${pc.bold(`${index + 1}. ${title}`)} ${pc.dim(uuid)}`
}

function buildIdigbioRecordsCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run idigbio.records']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  for (const [flag, value] of [
    ['--scientific-name', query.scientificName],
    ['--family', query.family],
    ['--country', query.country],
  ] as const) {
    if (typeof value === 'string' && value.trim() !== '') {
      parts.push(flag, formatCliArg(value))
    }
  }
  if (typeof query.hasImage === 'boolean') {
    parts.push('--has-image', String(query.hasImage))
  }
  parts.push('--limit', String(query.limit ?? 10))
  parts.push('--offset', String(query.offset ?? 0))
  return parts.join(' ')
}

function formatIdigbioRecordsQuery(query: Record<string, unknown>): string {
  return formatQuery({
    scientificName: query.scientificName,
    family: query.family,
    country: query.country,
    hasImage: query.hasImage,
    limit: query.limit,
    offset: query.offset,
  })
}

function formatIdigbioMediaQuery(query: Record<string, unknown>): string {
  return formatQuery({
    scientificName: query.scientificName,
    mediaType: query.mediaType,
    hasSpecimen: query.hasSpecimen,
    limit: query.limit,
    offset: query.offset,
  })
}

function formatIdigbioText(value: unknown): string | undefined {
  if (typeof value !== 'string') return undefined
  const text = stripHtml(value)
  return text === '' ? undefined : text
}

function buildIdigbioMediaCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run idigbio.media']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  for (const [flag, value] of [
    ['--scientific-name', query.scientificName],
    ['--media-type', query.mediaType],
  ] as const) {
    if (typeof value === 'string' && value.trim() !== '') {
      parts.push(flag, formatCliArg(value))
    }
  }
  if (typeof query.hasSpecimen === 'boolean') {
    parts.push('--has-specimen', String(query.hasSpecimen))
  }
  parts.push('--limit', String(query.limit ?? 10))
  parts.push('--offset', String(query.offset ?? 0))
  return parts.join(' ')
}

function buildIdigbioMediaFromRecordsCommand(
  query: Record<string, unknown>,
  record: Record<string, unknown> | undefined,
): string {
  const name = typeof record?.scientificName === 'string'
    ? record.scientificName
    : String(query.scientificName ?? 'Quercus robur')
  return buildIdigbioMediaCommand({
    scientificName: name,
    mediaType: 'images',
    limit: 10,
  }, 'online')
}

function renderMinorPlanetCenterSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const asteroids = Array.isArray(value.asteroids)
    ? value.asteroids.filter(isRecord)
    : []
  const lines = [
    [
      pc.bold(pc.cyan('Minor Planet Center Asteroids')),
      pc.dim(String(api.endpoint ?? 'GET /api/mpc')),
    ].join(' '),
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatMinorPlanetCenterQuery(query)}`,
    [
      `${String(pagination.returned ?? asteroids.length)} returned`,
      `limit ${String(pagination.limit ?? query.limit ?? 10)}`,
    ].join(' · ').replace(/^/u, `${pc.dim('count')} `),
    `${pc.dim('source')} ${String(api.sourceDataset ?? 'MPCORB.DAT via Asterank')}`,
    `${pc.dim('updates')} ${String(
      api.updatePolicy ?? 'Nightly MPC data updates are documented.',
    )}`,
    `${pc.dim('scope')} ${String(
      api.boundary ?? 'Read-only bounded asteroid records only.',
    )}`,
  ]

  if (asteroids.length === 0) {
    lines.push(
      '',
      pc.yellow('No Minor Planet Center asteroids matched this query.'),
    )
    lines.push(
      `${pc.dim('try')} ${buildMinorPlanetCenterSearchCommand({}, 'online')}`,
    )
    lines.push(
      `${pc.dim('again')} ${buildMinorPlanetCenterSearchCommand(query, 'online')}`,
    )
    lines.push(
      `${pc.dim('replay')} ${buildMinorPlanetCenterSearchCommand(query, 'offline')}`,
    )
    return lines.join('\n')
  }

  for (const [index, asteroid] of asteroids.slice(0, 20).entries()) {
    lines.push('', formatMinorPlanetCenterAsteroidHeading(index, asteroid))
    const orbit = [
      formatMinorPlanetCenterMetric('a', asteroid.semiMajorAxisAu, 'AU'),
      formatMinorPlanetCenterMetric('e', asteroid.eccentricity),
      formatMinorPlanetCenterMetric('i', asteroid.inclinationDeg, 'deg'),
      formatMinorPlanetCenterMetric('H', asteroid.absoluteMagnitude),
    ].filter((part): part is string => typeof part === 'string')
    if (orbit.length > 0) {
      lines.push(`${pc.dim('orbit')} ${orbit.join(' · ')}`)
    }
    const observations = [
      typeof asteroid.observations === 'number'
        ? `${String(asteroid.observations)} obs`
        : undefined,
      typeof asteroid.oppositions === 'number'
        ? `${String(asteroid.oppositions)} opp`
        : undefined,
      typeof asteroid.lastObservation === 'string'
        ? `last ${asteroid.lastObservation}`
        : undefined,
      typeof asteroid.epoch === 'string' ? `epoch ${asteroid.epoch}` : undefined,
    ].filter((part): part is string => typeof part === 'string')
    if (observations.length > 0) {
      lines.push(`${pc.dim('data')} ${observations.join(' · ')}`)
    }
    if (typeof asteroid.reference === 'string') {
      lines.push(`${pc.dim('ref')} ${asteroid.reference}`)
    }
  }
  if (asteroids.length > 20) {
    lines.push(pc.dim(
      `… ${asteroids.length - 20} more asteroid(s); use --format json.`,
    ))
  }

  lines.push(
    '',
    `${pc.dim('again')} ${buildMinorPlanetCenterSearchCommand(query, 'online')}`,
  )
  lines.push(
    `${pc.dim('replay')} ${buildMinorPlanetCenterSearchCommand(query, 'offline')}`,
  )
  lines.push(
    `${pc.dim('low orbit')} ${buildMinorPlanetCenterSearchCommand({
      query: '',
      maxEccentricity: 0.1,
      maxInclination: 4,
      maxSemiMajorAxis: 1.5,
      minObservations: 100,
      limit: 10,
    }, 'online')}`,
  )
  return lines.join('\n')
}

function formatMinorPlanetCenterAsteroidHeading(
  index: number,
  asteroid: Record<string, unknown>,
): string {
  const title = String(asteroid.readableDesignation ?? 'Unnamed asteroid')
  const designation = typeof asteroid.designation === 'string'
    ? ` ${asteroid.designation}`
    : ''
  return `${pc.bold(`${index + 1}. ${title}`)}${pc.dim(designation)}`
}

function formatMinorPlanetCenterMetric(
  label: string,
  value: unknown,
  unit?: string | undefined,
): string | undefined {
  if (typeof value !== 'number' || !Number.isFinite(value)) return undefined
  return `${label} ${formatNumber(value)}${unit === undefined ? '' : ` ${unit}`}`
}

function formatMinorPlanetCenterQuery(query: Record<string, unknown>): string {
  return formatQuery({
    query: query.query,
    maxEccentricity: query.maxEccentricity,
    maxInclination: query.maxInclination,
    maxSemiMajorAxis: query.maxSemiMajorAxis,
    minObservations: query.minObservations,
    limit: query.limit,
  })
}

function buildMinorPlanetCenterSearchCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run minorplanetcenter.search']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  if (query.query !== '') {
    pushCliOption(parts, '--query', query.query ?? 'Ceres')
  }
  pushCliOption(parts, '--max-eccentricity', query.maxEccentricity)
  pushCliOption(parts, '--max-inclination', query.maxInclination)
  pushCliOption(parts, '--max-semi-major-axis', query.maxSemiMajorAxis)
  pushCliOption(parts, '--min-observations', query.minObservations)
  pushCliOption(parts, '--limit', query.limit ?? 10)
  return parts.join(' ')
}

function renderNasaSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const items = Array.isArray(value.items) ? value.items.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('NASA Image Library Search'))} ${pc.dim(
      String(api.endpoint ?? 'GET /search'),
    )}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatNasaSearchQuery(query)}`,
    [
      `${String(pagination.returned ?? items.length)} returned`,
      `${String(pagination.totalHits ?? 0)} total hits`,
      `page ${String(pagination.page ?? query.page ?? 1)}`,
      `page size ${String(pagination.pageSize ?? query.pageSize ?? 10)}`,
    ].join(' · ').replace(/^/u, `${pc.dim('count')} `),
    `${pc.dim('scope')} ${String(
      api.boundary ?? 'NASA Image and Video Library metadata only.',
    )}`,
    `${pc.dim('excluded')} ${String(
      api.keyRequiredBoundary ?? 'api.nasa.gov api_key endpoints are excluded.',
    )}`,
  ]

  if (items.length === 0) {
    lines.push('', pc.yellow('No NASA media items matched this query.'))
    lines.push(`${pc.dim('try')} ${buildNasaSearchCommand({}, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildNasaSearchCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildNasaSearchCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const [index, item] of items.slice(0, 12).entries()) {
    lines.push('', formatNasaSearchItemHeading(index, item))
    const meta = [
      typeof item.center === 'string' ? `center ${item.center}` : undefined,
      typeof item.dateCreated === 'string'
        ? `created ${item.dateCreated.slice(0, 10)}`
        : undefined,
      typeof item.mediaType === 'string' ? `media ${item.mediaType}` : undefined,
    ].filter((part): part is string => typeof part === 'string')
    if (meta.length > 0) lines.push(`${pc.dim('meta')} ${meta.join(' · ')}`)
    if (typeof item.description === 'string') {
      lines.push(`${pc.dim('desc')} ${truncateText(item.description, 180)}`)
    }
    const keywords = Array.isArray(item.keywords)
      ? item.keywords.map(String).slice(0, 8)
      : []
    if (keywords.length > 0) {
      lines.push(`${pc.dim('keywords')} ${keywords.join(', ')}`)
    }
    if (typeof item.previewUrl === 'string') {
      lines.push(`${pc.dim('preview')} ${item.previewUrl}`)
    }
    if (typeof item.nasaId === 'string') {
      lines.push(`${pc.dim('asset')} ${buildNasaAssetCommand({
        nasaId: item.nasaId,
        limit: 10,
      }, 'online')}`)
    }
  }
  if (items.length > 12) {
    lines.push(pc.dim(`… ${items.length - 12} more item(s); use --format json.`))
  }

  lines.push('', `${pc.dim('again')} ${buildNasaSearchCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildNasaSearchCommand(query, 'offline')}`)
  return lines.join('\n')
}

function renderNasaAsset(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const files = Array.isArray(value.files) ? value.files.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('NASA Asset Manifest'))} ${pc.dim(
      String(api.endpoint ?? 'GET /asset/{nasa_id}'),
    )}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery({
      nasaId: query.nasaId,
      limit: query.limit,
    })}`,
    [
      `${String(pagination.returned ?? files.length)} returned`,
      `limit ${String(pagination.limit ?? query.limit ?? 10)}`,
    ].join(' · ').replace(/^/u, `${pc.dim('count')} `),
    `${pc.dim('scope')} ${String(
      api.boundary ?? 'NASA Image and Video Library manifest URLs only.',
    )}`,
  ]

  if (files.length === 0) {
    lines.push('', pc.yellow('No NASA asset files returned.'))
    lines.push(`${pc.dim('try')} ${buildNasaAssetCommand({}, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildNasaAssetCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildNasaAssetCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const [index, file] of files.slice(0, 20).entries()) {
    const filename = String(file.filename ?? file.href ?? 'asset file')
    const role = String(file.role ?? 'file')
    lines.push('', `${pc.bold(`${index + 1}. ${filename}`)} ${pc.dim(role)}`)
    if (typeof file.href === 'string') {
      lines.push(`${pc.dim('url')} ${file.href}`)
    }
  }
  if (files.length > 20) {
    lines.push(pc.dim(`… ${files.length - 20} more file(s); use --format json.`))
  }

  lines.push('', `${pc.dim('again')} ${buildNasaAssetCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildNasaAssetCommand(query, 'offline')}`)
  lines.push(`${pc.dim('search')} ${buildNasaSearchCommand({
    query: String(query.nasaId ?? 'apollo 11').replace(/[-_]/gu, ' '),
    mediaType: 'image',
    pageSize: 10,
    page: 1,
  }, 'online')}`)
  return lines.join('\n')
}

function formatNasaSearchItemHeading(
  index: number,
  item: Record<string, unknown>,
): string {
  const title = String(item.title ?? 'Untitled NASA item')
  const nasaId = typeof item.nasaId === 'string' ? ` ${item.nasaId}` : ''
  return `${pc.bold(`${index + 1}. ${title}`)}${pc.dim(nasaId)}`
}

function formatNasaSearchQuery(query: Record<string, unknown>): string {
  return formatQuery({
    query: query.query,
    mediaType: query.mediaType,
    center: query.center,
    yearStart: query.yearStart,
    yearEnd: query.yearEnd,
    page: query.page,
    pageSize: query.pageSize,
  })
}

function buildNasaSearchCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run nasa.search']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  pushCliOption(parts, '--query', query.query ?? 'apollo 11')
  pushCliOption(parts, '--media-type', query.mediaType ?? 'image')
  pushCliOption(parts, '--center', query.center)
  pushCliOption(parts, '--year-start', query.yearStart)
  pushCliOption(parts, '--year-end', query.yearEnd)
  pushCliOption(parts, '--page', query.page ?? 1)
  pushCliOption(parts, '--page-size', query.pageSize ?? 10)
  return parts.join(' ')
}

function buildNasaAssetCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run nasa.asset']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  pushCliOption(parts, '--nasa-id', query.nasaId ?? 'as11-40-5874')
  pushCliOption(parts, '--limit', query.limit ?? 10)
  return parts.join(' ')
}

function renderInspireHepSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const papers = Array.isArray(value.papers)
    ? value.papers.filter(isRecord)
    : []
  const endpoint = String(api.endpoint ?? 'GET /api/literature')
  const lines = [
    `${pc.bold(pc.cyan('INSPIRE HEP Literature Search'))} ${pc.dim(endpoint)}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatInspireHepSearchQuery(query)}`,
    formatInspireHepPageLine(pagination, papers.length, query),
    `${pc.dim('rate')} ${formatInspireHepRate(rateLimit, api)}`,
    `${pc.dim('terms')} ${String(api.terms ?? 'Metadata terms apply.')}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Literature metadata only.')}`,
  ]

  if (papers.length === 0) {
    lines.push('', pc.yellow('No INSPIRE HEP literature records matched this query.'))
    lines.push(`${pc.dim('try')} ${buildInspireHepSearchCommand({}, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildInspireHepSearchCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildInspireHepSearchCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const [index, paper] of papers.slice(0, 20).entries()) {
    lines.push('', formatInspireHepPaperHeading(index, paper))
    const meta = [
      paper.publication,
      paper.earliestDate,
      paper.primaryArxivCategory,
      typeof paper.citationCount === 'number'
        ? `${formatInteger(paper.citationCount)} citations`
        : undefined,
    ].filter((part): part is string => typeof part === 'string' && part.trim() !== '')
    if (meta.length > 0) {
      lines.push(pc.dim(meta.join(' · ')))
    }
    const authors = formatStringArrayPreview(paper.authors, 4)
    if (authors !== undefined) {
      lines.push(`${pc.dim('authors')} ${authors}`)
    }
    const identifiers = formatInspireHepIdentifiers(paper)
    if (identifiers !== undefined) {
      lines.push(`${pc.dim('ids')} ${identifiers}`)
    }
    if (typeof paper.abstract === 'string' && paper.abstract.trim() !== '') {
      lines.push(wrapLine(paper.abstract, 110))
    }
    if (isRecord(paper.links) && typeof paper.links.record === 'string') {
      lines.push(`${pc.dim('record')} ${pc.blue(paper.links.record)}`)
    }
  }
  if (papers.length > 20) {
    lines.push(pc.dim(
      `${papers.length - 20} more paper(s); use --format json for full output.`,
    ))
  }

  lines.push('', `${pc.dim('again')} ${buildInspireHepSearchCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildInspireHepSearchCommand(query, 'offline')}`)
  const firstRecid = typeof papers[0]?.recid === 'number' ? papers[0].recid : undefined
  if (firstRecid !== undefined) {
    lines.push(`${pc.dim('open first')} ${buildInspireHepRecordCommand({
      recid: firstRecid,
      abstractLength: query.abstractLength,
    }, 'online')}`)
  }
  if (typeof pagination.nextPage === 'number') {
    lines.push(`${pc.dim('more')} ${
      buildInspireHepSearchCommand({ ...query, page: pagination.nextPage }, 'online')
    }`)
  }
  return lines.join('\n')
}

function renderInspireHepRecord(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const rateLimit = isRecord(value.rateLimit) ? value.rateLimit : {}
  const paper = isRecord(value.paper) ? value.paper : undefined
  const endpoint = String(api.endpoint ?? 'GET /api/literature/{recid}')
  const lines = [
    `${pc.bold(pc.cyan('INSPIRE HEP Literature Record'))} ${pc.dim(endpoint)}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('rate')} ${formatInspireHepRate(rateLimit, api)}`,
    `${pc.dim('terms')} ${String(api.terms ?? 'Metadata terms apply.')}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Literature metadata only.')}`,
  ]

  if (paper === undefined) {
    lines.push('', pc.yellow('No INSPIRE HEP literature record returned.'))
    lines.push(`${pc.dim('search')} ${buildInspireHepSearchCommand({}, 'online')}`)
    return lines.join('\n')
  }

  lines.push('', formatInspireHepPaperHeading(0, paper))
  const meta = [
    paper.publication,
    paper.earliestDate,
    paper.preprintDate,
    paper.primaryArxivCategory,
    paper.documentType,
    typeof paper.citationCount === 'number'
      ? `${formatInteger(paper.citationCount)} citations`
      : undefined,
  ].filter((part): part is string => typeof part === 'string' && part.trim() !== '')
  if (meta.length > 0) {
    lines.push(pc.dim(meta.join(' · ')))
  }
  const authors = formatStringArrayPreview(paper.authors, 12)
  if (authors !== undefined) {
    lines.push(`${pc.dim('authors')} ${authors}`)
  }
  const identifiers = formatInspireHepIdentifiers(paper)
  if (identifiers !== undefined) {
    lines.push(`${pc.dim('ids')} ${identifiers}`)
  }
  const categories = formatStringArrayPreview(paper.inspireCategories, 8)
  if (categories !== undefined) {
    lines.push(`${pc.dim('categories')} ${categories}`)
  }
  const texkeys = formatStringArrayPreview(paper.texkeys, 6)
  if (texkeys !== undefined) {
    lines.push(`${pc.dim('texkeys')} ${texkeys}`)
  }
  if (typeof paper.abstract === 'string' && paper.abstract.trim() !== '') {
    lines.push('', `${pc.dim('abstract')} ${wrapLine(paper.abstract, 110)}`)
  }
  if (isRecord(paper.links)) {
    if (typeof paper.links.record === 'string') {
      lines.push(`${pc.dim('record')} ${pc.blue(paper.links.record)}`)
    }
    if (typeof paper.links.citations === 'string') {
      lines.push(`${pc.dim('citations')} ${pc.blue(paper.links.citations)}`)
    }
  }
  lines.push('', `${pc.dim('again')} ${buildInspireHepRecordCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildInspireHepRecordCommand(query, 'offline')}`)
  lines.push(`${pc.dim('related search')} ${buildInspireHepSearchCommand({
    query: String(paper.title ?? 'higgs').slice(0, 80),
    limit: 10,
  }, 'online')}`)
  return lines.join('\n')
}

function formatInspireHepPageLine(
  pagination: Record<string, unknown>,
  returnedCount: number,
  query: Record<string, unknown>,
): string {
  const returned = String(pagination.returned ?? returnedCount)
  const total = formatInteger(pagination.total)
  const size = String(pagination.size ?? query.size ?? query.limit ?? 10)
  const page = String(pagination.page ?? query.page ?? 1)
  return [
    pc.dim('page'),
    `${returned} returned / ${total} total`,
    `· size ${size}`,
    `· page ${page}`,
  ].join(' ')
}

function formatInspireHepPaperHeading(
  index: number,
  paper: Record<string, unknown>,
): string {
  const title = stripHtml(String(paper.title ?? '(untitled INSPIRE record)'))
  const recid = String(paper.recid ?? '-')
  return `${pc.bold(`${index + 1}. ${title}`)} ${pc.dim(`recid:${recid}`)}`
}

function formatInspireHepRate(
  rateLimit: Record<string, unknown>,
  api: Record<string, unknown>,
): string {
  const limit = typeof rateLimit.limit === 'string' ? rateLimit.limit : undefined
  const remaining = typeof rateLimit.remaining === 'string'
    ? rateLimit.remaining
    : undefined
  const policy = String(api.rateLimitPolicy ?? '15 requests per 5 seconds per IP.')
  if (limit === undefined && remaining === undefined) return policy
  return [
    limit !== undefined ? `limit ${limit}` : undefined,
    remaining !== undefined ? `remaining ${remaining}` : undefined,
    policy,
  ].filter((part): part is string => part !== undefined).join(' · ')
}

function formatInspireHepIdentifiers(
  paper: Record<string, unknown>,
): string | undefined {
  const parts = [
    formatArrayLabel('arXiv', paper.arxivIds),
    formatArrayLabel('DOI', paper.dois),
  ].filter((part): part is string => part !== undefined)
  return parts.length > 0 ? parts.join(' · ') : undefined
}

function formatArrayLabel(label: string, value: unknown): string | undefined {
  const preview = formatStringArrayPreview(value, 3)
  return preview === undefined ? undefined : `${label} ${preview}`
}

function formatStringArrayPreview(
  value: unknown,
  count: number,
): string | undefined {
  if (!Array.isArray(value)) return undefined
  const strings = value.filter((entry): entry is string => (
    typeof entry === 'string' && entry.trim() !== ''
  ))
  if (strings.length === 0) return undefined
  const shown = strings.slice(0, count).join('; ')
  return strings.length > count ? `${shown}; +${strings.length - count}` : shown
}

function formatInspireHepSearchQuery(query: Record<string, unknown>): string {
  return formatQuery({
    query: query.q ?? query.query,
    sort: query.sort,
    limit: query.size ?? query.limit,
    page: query.page,
    fields: typeof query.fields === 'string' ? 'curated metadata fields' : undefined,
    abstractLength: query.abstractLength,
  })
}

function buildInspireHepSearchCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run inspirehep.search']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  parts.push('--query', formatCliArg(query.q ?? query.query ?? 'higgs'))
  if (typeof query.sort === 'string' && query.sort.trim() !== '') {
    parts.push('--sort', formatCliArg(query.sort))
  }
  parts.push('--limit', String(query.size ?? query.limit ?? 10))
  parts.push('--page', String(query.page ?? 1))
  if (typeof query.abstractLength === 'number') {
    parts.push('--abstract-length', String(query.abstractLength))
  }
  return parts.join(' ')
}

function buildInspireHepRecordCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run inspirehep.record']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  parts.push('--recid', String(query.recid ?? 4328))
  if (typeof query.abstractLength === 'number') {
    parts.push('--abstract-length', String(query.abstractLength))
  }
  return parts.join(' ')
}

function renderOsfNodes(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const nodes = Array.isArray(value.nodes) ? value.nodes.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('OSF Public Nodes'))} ${
      pc.dim(String(api.endpoint ?? 'GET /v2/nodes/'))
    }`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON:API REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${formatOsfPage(pagination, nodes.length)}`,
    `${pc.dim('auth')} ${String(api.authBoundary ?? 'Public list only.')}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Public OSF metadata only.')}`,
  ]

  if (nodes.length === 0) {
    lines.push('', pc.yellow('No public OSF nodes matched this query.'))
    lines.push(`${pc.dim('try')} ${buildOsfNodesCommand({}, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildOsfNodesCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildOsfNodesCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const [index, node] of nodes.slice(0, 20).entries()) {
    lines.push('', formatOsfHeading(index, node, 'node'))
    const meta = [
      typeof node.category === 'string' ? `category ${node.category}` : undefined,
      typeof node.dateModified === 'string'
        ? `modified ${node.dateModified.slice(0, 10)}`
        : undefined,
      node.public === true ? 'public' : undefined,
      node.preprint === true ? 'has preprint' : undefined,
    ].filter((part): part is string => part !== undefined)
    if (meta.length > 0) lines.push(pc.dim(meta.join(' · ')))
    if (typeof node.description === 'string') {
      lines.push(wrapLine(stripHtml(node.description), 110))
    }
    const tags = formatStringArrayPreview(node.tags, 8)
    if (tags !== undefined) lines.push(`${pc.dim('tags')} ${tags}`)
    const subjects = formatStringArrayPreview(node.subjects, 4)
    if (subjects !== undefined) lines.push(`${pc.dim('subjects')} ${subjects}`)
    if (isRecord(node.links) && typeof node.links.html === 'string') {
      lines.push(`${pc.dim('html')} ${pc.blue(node.links.html)}`)
    }
  }
  if (nodes.length > 20) {
    lines.push(pc.dim(
      `${nodes.length - 20} more node(s); use --format json for full output.`,
    ))
  }

  lines.push('', `${pc.dim('again')} ${buildOsfNodesCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildOsfNodesCommand(query, 'offline')}`)
  if (typeof pagination.nextPage === 'number') {
    lines.push(`${pc.dim('more')} ${
      buildOsfNodesCommand({ ...query, page: pagination.nextPage }, 'online')
    }`)
  }
  return lines.join('\n')
}

function renderOsfPreprints(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const preprints = Array.isArray(value.preprints)
    ? value.preprints.filter(isRecord)
    : []
  const lines = [
    `${pc.bold(pc.cyan('OSF Public Preprints'))} ${
      pc.dim(String(api.endpoint ?? 'GET /v2/preprints/'))
    }`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON:API REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${formatOsfPage(pagination, preprints.length)}`,
    `${pc.dim('auth')} ${String(api.authBoundary ?? 'Public list only.')}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Public OSF metadata only.')}`,
  ]

  if (preprints.length === 0) {
    lines.push('', pc.yellow('No public OSF preprints matched this query.'))
    lines.push(`${pc.dim('try')} ${buildOsfPreprintsCommand({}, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildOsfPreprintsCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildOsfPreprintsCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const [index, preprint] of preprints.slice(0, 20).entries()) {
    lines.push('', formatOsfHeading(index, preprint, 'preprint'))
    const meta = [
      typeof preprint.provider === 'string'
        ? `provider ${preprint.provider}`
        : undefined,
      typeof preprint.datePublished === 'string'
        ? `published ${preprint.datePublished.slice(0, 10)}`
        : undefined,
      typeof preprint.reviewsState === 'string'
        ? `review ${preprint.reviewsState}`
        : undefined,
      preprint.isLatestVersion === true ? 'latest version' : undefined,
    ].filter((part): part is string => part !== undefined)
    if (meta.length > 0) lines.push(pc.dim(meta.join(' · ')))
    if (typeof preprint.description === 'string') {
      lines.push(wrapLine(stripHtml(preprint.description), 110))
    }
    const tags = formatStringArrayPreview(preprint.tags, 8)
    if (tags !== undefined) lines.push(`${pc.dim('tags')} ${tags}`)
    const subjects = formatStringArrayPreview(preprint.subjects, 4)
    if (subjects !== undefined) lines.push(`${pc.dim('subjects')} ${subjects}`)
    const dataLinks = formatStringArrayPreview(preprint.dataLinks, 2)
    if (dataLinks !== undefined) lines.push(`${pc.dim('data links')} ${dataLinks}`)
    if (isRecord(preprint.links)) {
      if (typeof preprint.links.html === 'string') {
        lines.push(`${pc.dim('html')} ${pc.blue(preprint.links.html)}`)
      }
      if (typeof preprint.links.doi === 'string') {
        lines.push(`${pc.dim('doi')} ${pc.blue(preprint.links.doi)}`)
      }
    }
  }
  if (preprints.length > 20) {
    lines.push(pc.dim(
      `${preprints.length - 20} more preprint(s); use --format json.`,
    ))
  }

  lines.push('', `${pc.dim('again')} ${buildOsfPreprintsCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildOsfPreprintsCommand(query, 'offline')}`)
  if (typeof pagination.nextPage === 'number') {
    lines.push(`${pc.dim('more')} ${
      buildOsfPreprintsCommand({ ...query, page: pagination.nextPage }, 'online')
    }`)
  }
  return lines.join('\n')
}

function formatOsfPage(
  pagination: Record<string, unknown>,
  fallbackReturned: number,
): string {
  const returned = String(pagination.returned ?? fallbackReturned)
  const total = typeof pagination.total === 'number'
    ? formatInteger(pagination.total)
    : 'unknown'
  const limit = String(pagination.limit ?? 10)
  const page = String(pagination.page ?? 1)
  return `${returned} returned / ${total} total · limit ${limit} · page ${page}`
}

function formatOsfHeading(
  index: number,
  item: Record<string, unknown>,
  label: string,
): string {
  const title = stripHtml(String(item.title ?? `Untitled OSF ${label}`))
  const id = String(item.id ?? '-')
  return `${pc.bold(`${index + 1}. ${title}`)} ${pc.dim(`${label}:${id}`)}`
}

