function renderShareSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const search = isRecord(value.search) ? value.search : {}
  const works = Array.isArray(value.works) ? value.works.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('SHARE Creative Works'))} ${
      pc.dim(String(api.endpoint ?? 'POST /api/v2/search/creativeworks/_search'))
    }`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${formatSharePage(pagination, works.length)}`,
    `${pc.dim('search')} took ${String(search.took ?? '?')}ms · timed out ${
      String(search.timedOut ?? false)
    }`,
    `${pc.dim('policy')} ${String(api.queryPolicy ?? 'Curated query only.')}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Public SHARE metadata only.')}`,
  ]

  if (works.length === 0) {
    lines.push('', pc.yellow('No SHARE creative works matched this query.'))
    lines.push(`${pc.dim('try')} ${buildShareSearchCommand({}, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildShareSearchCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildShareSearchCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const [index, work] of works.slice(0, 20).entries()) {
    lines.push('', formatShareWorkHeading(index, work))
    const meta = [
      typeof work.type === 'string' ? `type ${work.type}` : undefined,
      typeof work.date === 'string' ? `date ${work.date.slice(0, 10)}` : undefined,
      work.retracted === true ? 'retracted' : undefined,
      work.withdrawn === true ? 'withdrawn' : undefined,
      typeof work.score === 'number' ? `score ${work.score.toFixed(2)}` : undefined,
    ].filter((part): part is string => part !== undefined)
    if (meta.length > 0) lines.push(pc.dim(meta.join(' · ')))
    if (typeof work.description === 'string') {
      lines.push(wrapLine(stripHtml(work.description), 110))
    }
    const contributors = formatStringArrayPreview(work.contributors, 5)
    if (contributors !== undefined) lines.push(`${pc.dim('contributors')} ${contributors}`)
    const sources = formatStringArrayPreview(work.sources, 5)
    if (sources !== undefined) lines.push(`${pc.dim('sources')} ${sources}`)
    const tags = formatStringArrayPreview(work.tags, 8)
    if (tags !== undefined) lines.push(`${pc.dim('tags')} ${tags}`)
    const subjects = formatStringArrayPreview(work.subjects, 4)
    if (subjects !== undefined) lines.push(`${pc.dim('subjects')} ${subjects}`)
    if (isRecord(work.links)) {
      if (typeof work.links.primary === 'string') {
        lines.push(`${pc.dim('link')} ${pc.blue(work.links.primary)}`)
      }
      if (typeof work.links.doi === 'string') {
        lines.push(`${pc.dim('doi')} ${pc.blue(work.links.doi)}`)
      }
    }
  }
  if (works.length > 20) {
    lines.push(pc.dim(
      `${works.length - 20} more work(s); use --format json for full output.`,
    ))
  }

  lines.push('', `${pc.dim('again')} ${buildShareSearchCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildShareSearchCommand(query, 'offline')}`)
  if (typeof pagination.nextOffset === 'number') {
    lines.push(`${pc.dim('more')} ${
      buildShareSearchCommand({ ...query, offset: pagination.nextOffset }, 'online')
    }`)
  }
  lines.push(`${pc.dim('sources')} ${buildShareSourcesCommand({}, 'online')}`)
  return lines.join('\n')
}

function renderShareSources(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const sources = Array.isArray(value.sources) ? value.sources.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('SHARE Sources'))} ${
      pc.dim(String(api.endpoint ?? 'GET /api/v2/sources/'))
    }`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${formatSharePage(pagination, sources.length, 'local')}`,
    `${pc.dim('upstream')} first page ${
      String(pagination.upstreamReturned ?? sources.length)
    } returned · next ${String(pagination.upstreamNext ?? 'available via API')}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Public SHARE source metadata only.')}`,
  ]

  if (sources.length === 0) {
    lines.push('', pc.yellow('No SHARE sources matched this local filter.'))
    lines.push(`${pc.dim('try')} ${buildShareSourcesCommand({}, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildShareSourcesCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildShareSourcesCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const [index, source] of sources.slice(0, 30).entries()) {
    const title = String(source.longTitle ?? source.name ?? source.id ?? 'Source')
    lines.push('', `${pc.bold(`${index + 1}. ${title}`)} ${
      pc.dim(`source:${String(source.id ?? '-')}`)
    }`)
    const meta = [
      typeof source.name === 'string' ? `name ${source.name}` : undefined,
      typeof source.sourceConfigCount === 'number'
        ? `configs ${source.sourceConfigCount}`
        : undefined,
    ].filter((part): part is string => part !== undefined)
    if (meta.length > 0) lines.push(pc.dim(meta.join(' · ')))
    if (typeof source.homePage === 'string' && source.homePage.trim() !== '') {
      lines.push(`${pc.dim('homepage')} ${pc.blue(source.homePage)}`)
    }
    if (isRecord(source.links) && typeof source.links.self === 'string') {
      lines.push(`${pc.dim('self')} ${pc.blue(source.links.self)}`)
    }
  }
  if (sources.length > 30) {
    lines.push(pc.dim(
      `${sources.length - 30} more source(s); use --format json for full output.`,
    ))
  }

  lines.push('', `${pc.dim('again')} ${buildShareSourcesCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildShareSourcesCommand(query, 'offline')}`)
  if (typeof pagination.nextOffset === 'number') {
    lines.push(`${pc.dim('more')} ${
      buildShareSourcesCommand({ ...query, offset: pagination.nextOffset }, 'online')
    }`)
  }
  lines.push(`${pc.dim('search')} ${buildShareSearchCommand({}, 'online')}`)
  return lines.join('\n')
}

function formatSharePage(
  pagination: Record<string, unknown>,
  fallbackReturned: number,
  totalLabel = 'total',
): string {
  const returned = String(pagination.returned ?? fallbackReturned)
  const total = typeof pagination.total === 'number'
    ? formatInteger(pagination.total)
    : 'unknown'
  const limit = String(pagination.limit ?? 10)
  const offset = String(pagination.offset ?? 0)
  return `${returned} returned / ${total} ${totalLabel} · limit ${limit} · offset ${offset}`
}

function formatShareWorkHeading(
  index: number,
  work: Record<string, unknown>,
): string {
  const title = stripHtml(String(work.title ?? 'Untitled SHARE work'))
  const id = String(work.id ?? '-')
  return `${pc.bold(`${index + 1}. ${truncateText(title, 120)}`)} ${
    pc.dim(`work:${id}`)
  }`
}

function buildShareSearchCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run share.search']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  pushCliOption(parts, '--query', query.query ?? 'reproducibility')
  pushCliOption(parts, '--type', query.type)
  pushCliOption(parts, '--source', query.source)
  pushCliOption(parts, '--sort', query.sort ?? 'relevance')
  pushCliOption(parts, '--limit', query.limit ?? 10)
  pushCliOption(parts, '--offset', query.offset ?? 0)
  pushCliOption(parts, '--description-length', query.descriptionLength)
  return parts.join(' ')
}

function buildShareSourcesCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run share.sources']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  pushCliOption(parts, '--query', query.query)
  pushCliOption(parts, '--limit', query.limit ?? 10)
  pushCliOption(parts, '--offset', query.offset ?? 0)
  return parts.join(' ')
}

function renderSpaceXCompany(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const company = isRecord(value.company) ? value.company : {}
  const links = isRecord(company.links) ? company.links : {}
  const headquarters = isRecord(company.headquarters) ? company.headquarters : {}
  const lines = [
    `${pc.bold(pc.cyan('SpaceX Company'))} ${
      pc.dim(String(api.endpoint ?? 'GET /v4/company'))
    }`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} default parameters`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Read-only SpaceX metadata only.')}`,
    '',
    `${pc.bold(String(company.name ?? 'SpaceX'))} ${
      pc.dim(`founded ${String(company.founded ?? '-')}`)
    }`,
  ]
  if (typeof company.summary === 'string') {
    lines.push(wrapLine(company.summary, 110))
  }
  lines.push(`${pc.dim('leadership')} ${
    formatSpaceXPeople(company, ['founder', 'ceo', 'cto', 'coo'])
  }`)
  lines.push(`${pc.dim('scale')} employees ${formatInteger(company.employees)} · ${
    'vehicles'
  } ${formatInteger(company.vehicles)} · launch sites ${
    formatInteger(company.launchSites)
  } · valuation ${formatCurrency(company.valuation)}`)
  lines.push(`${pc.dim('hq')} ${
    [headquarters.address, headquarters.city, headquarters.state]
      .filter(item => typeof item === 'string' && item.trim() !== '')
      .join(', ') || '-'
  }`)
  for (const [label, url] of Object.entries(links)) {
    if (typeof url === 'string' && url.trim() !== '') {
      lines.push(`${pc.dim(label)} ${pc.blue(url)}`)
    }
  }
  lines.push('', `${pc.dim('again')} ${buildSpaceXCompanyCommand('online')}`)
  lines.push(`${pc.dim('replay')} ${buildSpaceXCompanyCommand('offline')}`)
  lines.push(`${pc.dim('launches')} ${buildSpaceXLaunchesCommand({}, 'online')}`)
  return lines.join('\n')
}

function renderSpaceXRockets(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const rockets = Array.isArray(value.rockets) ? value.rockets.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('SpaceX Rockets'))} ${
      pc.dim(String(api.endpoint ?? 'GET /v4/rockets'))
    }`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${formatSpaceXLocalPage(pagination, rockets.length)}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Read-only SpaceX metadata only.')}`,
  ]
  if (rockets.length === 0) {
    lines.push('', pc.yellow('No SpaceX rockets matched this query.'))
    lines.push(`${pc.dim('try')} ${buildSpaceXRocketsCommand({}, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildSpaceXRocketsCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildSpaceXRocketsCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const [index, rocket] of rockets.slice(0, 20).entries()) {
    lines.push('', `${pc.bold(`${index + 1}. ${String(rocket.name ?? 'Rocket')}`)} ${
      pc.dim(`rocket:${String(rocket.id ?? '-')}`)
    }`)
    const meta = [
      rocket.active === true
        ? 'active'
        : rocket.active === false
          ? 'inactive'
          : undefined,
      typeof rocket.firstFlight === 'string'
        ? `first flight ${rocket.firstFlight}`
        : undefined,
      typeof rocket.country === 'string' ? rocket.country : undefined,
      typeof rocket.successRatePct === 'number'
        ? `success ${rocket.successRatePct}%`
        : undefined,
    ].filter((part): part is string => part !== undefined)
    if (meta.length > 0) lines.push(pc.dim(meta.join(' · ')))
    lines.push(`${pc.dim('size')} height ${formatNumberUnit(
      rocket.heightMeters,
      'm',
    )} · diameter ${formatNumberUnit(rocket.diameterMeters, 'm')} · mass ${
      formatNumberUnit(rocket.massKg, 'kg')
    }`)
    lines.push(`${pc.dim('engines')} ${String(rocket.engineCount ?? '-')} ${
      [rocket.engineType, rocket.engineVersion].filter(Boolean).join(' ') || '-'
    } · propellants ${
      formatStringArrayPreview(rocket.propellants, 3) ?? '-'
    }`)
    if (typeof rocket.description === 'string') {
      lines.push(wrapLine(rocket.description, 110))
    }
    if (typeof rocket.wikipedia === 'string') {
      lines.push(`${pc.dim('wiki')} ${pc.blue(rocket.wikipedia)}`)
    }
  }
  lines.push('', `${pc.dim('again')} ${buildSpaceXRocketsCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildSpaceXRocketsCommand(query, 'offline')}`)
  if (typeof pagination.nextOffset === 'number') {
    lines.push(`${pc.dim('more')} ${
      buildSpaceXRocketsCommand({ ...query, offset: pagination.nextOffset }, 'online')
    }`)
  }
  return lines.join('\n')
}

function renderSpaceXLaunchpads(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const launchpads = Array.isArray(value.launchpads)
    ? value.launchpads.filter(isRecord)
    : []
  const lines = [
    `${pc.bold(pc.cyan('SpaceX Launchpads'))} ${
      pc.dim(String(api.endpoint ?? 'GET /v4/launchpads'))
    }`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${formatSpaceXLocalPage(pagination, launchpads.length)}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Read-only SpaceX metadata only.')}`,
  ]
  if (launchpads.length === 0) {
    lines.push('', pc.yellow('No SpaceX launchpads matched this query.'))
    lines.push(`${pc.dim('try')} ${buildSpaceXLaunchpadsCommand({}, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildSpaceXLaunchpadsCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildSpaceXLaunchpadsCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const [index, launchpad] of launchpads.slice(0, 20).entries()) {
    lines.push('', `${pc.bold(`${index + 1}. ${
      String(launchpad.fullName ?? launchpad.name ?? 'Launchpad')
    }`)} ${pc.dim(`launchpad:${String(launchpad.id ?? '-')}`)}`)
    const meta = [
      typeof launchpad.status === 'string' ? `status ${launchpad.status}` : undefined,
      typeof launchpad.locality === 'string' ? launchpad.locality : undefined,
      typeof launchpad.region === 'string' ? launchpad.region : undefined,
      typeof launchpad.timezone === 'string' ? launchpad.timezone : undefined,
    ].filter((part): part is string => part !== undefined)
    if (meta.length > 0) lines.push(pc.dim(meta.join(' · ')))
    lines.push(`${pc.dim('launches')} attempts ${
      formatInteger(launchpad.launchAttempts)
    } · successes ${formatInteger(launchpad.launchSuccesses)} · listed ${
      formatInteger(launchpad.launchCount)
    }`)
    if (
      typeof launchpad.latitude === 'number' &&
      typeof launchpad.longitude === 'number'
    ) {
      lines.push(`${pc.dim('coords')} ${launchpad.latitude}, ${launchpad.longitude}`)
    }
    const rockets = formatStringArrayPreview(launchpad.rocketIds, 4)
    if (rockets !== undefined) lines.push(`${pc.dim('rockets')} ${rockets}`)
  }
  lines.push('', `${pc.dim('again')} ${
    buildSpaceXLaunchpadsCommand(query, 'online')
  }`)
  lines.push(`${pc.dim('replay')} ${buildSpaceXLaunchpadsCommand(query, 'offline')}`)
  if (typeof pagination.nextOffset === 'number') {
    lines.push(`${pc.dim('more')} ${
      buildSpaceXLaunchpadsCommand(
        { ...query, offset: pagination.nextOffset },
        'online',
      )
    }`)
  }
  return lines.join('\n')
}

function renderSpaceXLaunches(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const launches = Array.isArray(value.launches) ? value.launches.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('SpaceX Launches'))} ${
      pc.dim(String(api.endpoint ?? 'POST /v5/launches/query'))
    }`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${formatSpaceXLaunchPage(pagination, launches.length)}`,
    `${pc.dim('policy')} ${String(api.queryPolicy ?? 'Curated query only.')}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Read-only SpaceX metadata only.')}`,
  ]
  if (launches.length === 0) {
    lines.push('', pc.yellow('No SpaceX launches matched this query.'))
    lines.push(`${pc.dim('try')} ${buildSpaceXLaunchesCommand({}, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildSpaceXLaunchesCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildSpaceXLaunchesCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const [index, launch] of launches.slice(0, 20).entries()) {
    lines.push('', `${pc.bold(`${index + 1}. ${String(launch.name ?? 'Launch')}`)} ${
      pc.dim(`launch:${String(launch.id ?? '-')}`)
    }`)
    const status = launch.upcoming === true
      ? 'upcoming'
      : launch.success === true
        ? 'success'
        : launch.success === false
          ? 'failed'
          : 'status unknown'
    const meta = [
      typeof launch.flightNumber === 'number'
        ? `flight ${launch.flightNumber}`
        : undefined,
      typeof launch.dateUtc === 'string' ? launch.dateUtc.slice(0, 10) : undefined,
      status,
      typeof launch.datePrecision === 'string'
        ? `precision ${launch.datePrecision}`
        : undefined,
    ].filter((part): part is string => part !== undefined)
    lines.push(pc.dim(meta.join(' · ')))
    if (typeof launch.details === 'string') {
      lines.push(wrapLine(launch.details, 110))
    }
    lines.push(`${pc.dim('refs')} rocket ${String(launch.rocketId ?? '-')} · ${
      'launchpad'
    } ${String(launch.launchpadId ?? '-')} · payloads ${
      String(launch.payloadCount ?? 0)
    } · crew ${String(launch.crewCount ?? 0)}`)
    if (Array.isArray(launch.failureReasons) && launch.failureReasons.length > 0) {
      lines.push(`${pc.dim('failures')} ${
        formatStringArrayPreview(launch.failureReasons, 3) ?? '-'
      }`)
    }
    if (isRecord(launch.links)) {
      for (const key of ['webcast', 'article', 'wikipedia'] as const) {
        const url = launch.links[key]
        if (typeof url === 'string' && url.trim() !== '') {
          lines.push(`${pc.dim(key)} ${pc.blue(url)}`)
        }
      }
    }
  }
  lines.push('', `${pc.dim('again')} ${buildSpaceXLaunchesCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildSpaceXLaunchesCommand(query, 'offline')}`)
  if (typeof pagination.nextPage === 'number') {
    lines.push(`${pc.dim('more')} ${
      buildSpaceXLaunchesCommand({ ...query, page: pagination.nextPage }, 'online')
    }`)
  }
  lines.push(`${pc.dim('rockets')} ${buildSpaceXRocketsCommand({}, 'online')}`)
  return lines.join('\n')
}

function formatSpaceXPeople(
  company: Record<string, unknown>,
  keys: string[],
): string {
  const parts = keys
    .map(key => (typeof company[key] === 'string' ? `${key} ${company[key]}` : ''))
    .filter(part => part !== '')
  return parts.length > 0 ? parts.join(' · ') : '-'
}

function formatSpaceXLocalPage(
  pagination: Record<string, unknown>,
  fallbackReturned: number,
): string {
  const returned = String(pagination.returned ?? fallbackReturned)
  const matched = formatInteger(pagination.matched)
  const total = formatInteger(pagination.total)
  const offset = String(pagination.offset ?? 0)
  const limit = String(pagination.limit ?? 10)
  const more = pagination.hasMore === true ? ' · more available' : ''
  return [
    `${returned}/${matched} matched`,
    `total ${total}`,
    `offset ${offset}`,
    `limit ${limit}${more}`,
  ].join(' · ')
}

function formatSpaceXLaunchPage(
  pagination: Record<string, unknown>,
  fallbackReturned: number,
): string {
  const returned = String(pagination.returned ?? fallbackReturned)
  const total = formatInteger(pagination.total)
  const page = String(pagination.page ?? 1)
  const totalPages = String(pagination.totalPages ?? 1)
  const limit = String(pagination.limit ?? 10)
  return `${returned}/${total} returned · page ${page}/${totalPages} · limit ${limit}`
}

function formatNumberUnit(value: unknown, unit: string): string {
  return typeof value === 'number' && Number.isFinite(value)
    ? `${formatInteger(value)} ${unit}`
    : '-'
}

