function renderSunriseSunsetTimes(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const times = isRecord(value.times) ? value.times : {}
  const lines = [
    `${pc.bold(pc.cyan('Sunrise and Sunset Times'))} ${
      pc.dim(String(api.endpoint ?? 'GET /json'))
    }`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('tzid')} ${String(value.tzid ?? query.tzid ?? 'UTC')} · ${
      'status'
    } ${String(value.status ?? 'OK')}`,
    `${pc.dim('attribution')} ${
      api.attributionRequired === true
        ? 'required by Sunrise-Sunset.org docs'
        : 'not recorded'
    }`,
    '',
    `${pc.bold('Sun')} sunrise ${formatSunriseSunsetInstant(
      times.sunrise,
    )} · sunset ${
      formatSunriseSunsetInstant(times.sunset)
    }`,
    `${pc.dim('solar noon')} ${formatSunriseSunsetInstant(
      times.solarNoon,
    )} · day length ${
      formatDurationSeconds(times.dayLengthSeconds)
    }`,
    `${pc.dim('civil')} ${formatSunriseSunsetInstant(
      times.civilTwilightBegin,
    )} -> ${
      formatSunriseSunsetInstant(times.civilTwilightEnd)
    }`,
    `${pc.dim('nautical')} ${formatSunriseSunsetInstant(
      times.nauticalTwilightBegin,
    )} -> ${
      formatSunriseSunsetInstant(times.nauticalTwilightEnd)
    }`,
    `${pc.dim('astronomical')} ${
      formatSunriseSunsetInstant(times.astronomicalTwilightBegin)
    } -> ${formatSunriseSunsetInstant(times.astronomicalTwilightEnd)}`,
    '',
    `${pc.dim('again')} ${buildSunriseSunsetTimesCommand(query, 'online')}`,
    `${pc.dim('replay')} ${buildSunriseSunsetTimesCommand(query, 'offline')}`,
  ]
  return lines.join('\n')
}

function buildSunriseSunsetTimesCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run sunrisesunset.times']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  pushCliOption(parts, '--latitude', query.latitude ?? 36.72016)
  pushCliOption(parts, '--longitude', query.longitude ?? -4.42034)
  pushCliOption(parts, '--date', query.date ?? '2026-05-11')
  pushCliOption(parts, '--tzid', query.tzid ?? 'UTC')
  return parts.join(' ')
}

function formatSunriseSunsetInstant(value: unknown): string {
  if (typeof value !== 'string' || value.trim() === '') return '-'
  if (/^1970-01-01T00:00:0[01]/u.test(value)) {
    return 'unavailable (provider 1970 sentinel)'
  }
  return value
}

function renderTleSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const satellites = Array.isArray(value.satellites)
    ? value.satellites.filter(isRecord)
    : []
  const lines = [
    `${pc.bold(pc.cyan('TLE Satellite Search'))} ${
      pc.dim(String(api.endpoint ?? 'GET /api/tle/'))
    }`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    [
      `${pc.dim('page')} ${String(pagination.page ?? query.page ?? 1)}`,
      `${pc.dim('returned')} ${String(pagination.returned ?? satellites.length)}`,
      `${pc.dim('total')} ${String(pagination.totalItems ?? '-')}`,
      `${pc.dim('page size')} ${String(pagination.pageSize ?? api.pageSize ?? 20)}`,
    ].join(' · '),
    `${pc.dim('source')} ${String(api.dataSource ?? 'CelesTrak')}`,
  ]

  if (satellites.length === 0) {
    lines.push('', pc.yellow('No TLE satellites matched this query.'))
    lines.push(`${pc.dim('try')} ${buildTleSearchCommand({}, 'online')}`)
  } else {
    for (const satellite of satellites.slice(0, 10)) {
      appendTleSatelliteSummary(lines, satellite)
    }
  }

  const page = typeof pagination.page === 'number'
    ? pagination.page
    : Number(query.page ?? 1)
  if (pagination.hasMore === true) {
    lines.push(
      '',
      `${pc.dim('next page')} ${
        buildTleSearchCommand({ ...query, page: page + 1 }, 'online')
      }`,
    )
  }
  lines.push('', `${pc.dim('again')} ${buildTleSearchCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildTleSearchCommand(query, 'offline')}`)
  if (satellites.length > 0) {
    const first = satellites[0]
    lines.push(`${pc.dim('open first')} ${
      buildTleSatelliteCommand({
        satelliteId: first?.satelliteId ?? query.satelliteId ?? 25544,
      }, 'online')
    }`)
  }
  return lines.join('\n')
}

function renderTleSatellite(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const satellite = isRecord(value.satellite) ? value.satellite : {}
  const lines = [
    `${pc.bold(pc.cyan('TLE Satellite'))} ${
      pc.dim(String(api.endpoint ?? 'GET /api/tle/{satelliteId}'))
    }`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('source')} ${String(api.dataSource ?? 'CelesTrak')}`,
  ]
  appendTleSatelliteSummary(lines, satellite, true)
  lines.push('', `${pc.dim('again')} ${buildTleSatelliteCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildTleSatelliteCommand(query, 'offline')}`)
  if (typeof satellite.name === 'string') {
    lines.push(`${pc.dim('search name')} ${
      buildTleSearchCommand({ search: satellite.name, page: 1 }, 'online')
    }`)
  }
  return lines.join('\n')
}

function appendTleSatelliteSummary(
  lines: string[],
  satellite: Record<string, unknown>,
  includeLines = false,
): void {
  const orbital = isRecord(satellite.orbital) ? satellite.orbital : {}
  lines.push(
    '',
    `${pc.bold(String(satellite.name ?? 'Unknown satellite'))} ${
      pc.dim(`#${String(satellite.satelliteId ?? '-')}`)
    }`,
    `${pc.dim('epoch')} ${String(satellite.date ?? '-')}`,
    [
      `${pc.dim('incl')} ${formatTleNumber(orbital.inclinationDegrees, 4)} deg`,
      `${pc.dim('raan')} ${formatTleNumber(orbital.rightAscensionDegrees, 4)} deg`,
      `${pc.dim('ecc')} ${formatTleNumber(orbital.eccentricity, 7)}`,
      `${pc.dim('mean motion')} ${
        formatTleNumber(orbital.meanMotionRevsPerDay, 8)
      } rev/day`,
    ].join(' · '),
  )
  if (includeLines) {
    lines.push(
      `${pc.dim('line1')} ${String(satellite.line1 ?? '-')}`,
      `${pc.dim('line2')} ${String(satellite.line2 ?? '-')}`,
    )
  }
}

function formatTleNumber(value: unknown, maximumFractionDigits: number): string {
  return typeof value === 'number' && Number.isFinite(value)
    ? new Intl.NumberFormat('en-US', { maximumFractionDigits }).format(value)
    : '-'
}

function buildTleSearchCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run tle.search']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  pushCliOption(parts, '--search', query.search ?? 'ISS')
  pushCliOption(parts, '--page', query.page ?? 1)
  return parts.join(' ')
}

function buildTleSatelliteCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run tle.satellite']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  pushCliOption(parts, '--satellite-id', query.satelliteId ?? 25544)
  return parts.join(' ')
}

function renderUrantiaToc(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const totals = isRecord(value.totals) ? value.totals : {}
  const parts = Array.isArray(value.parts) ? value.parts.filter(isRecord) : []
  const lines = createUrantiaHeader(
    value,
    'Urantia Papers TOC',
    String(api.endpoint ?? 'GET /toc'),
  )
  lines.push(
    `${pc.dim('query')} ${formatQuery(query)}`,
    [
      `${pc.dim('returned')} ${String(pagination.returned ?? parts.length)}`,
      `${pc.dim('parts')} ${String(totals.parts ?? pagination.total ?? '-')}`,
      `${pc.dim('papers')} ${String(totals.papers ?? '-')}`,
    ].join(' · '),
  )

  if (parts.length === 0) {
    lines.push('', pc.yellow('No Urantia parts returned.'))
  } else {
    for (const part of parts) {
      const papers = Array.isArray(part.papers) ? part.papers.filter(isRecord) : []
      lines.push('', `${pc.bold(String(part.title ?? 'Untitled part'))} ${
        pc.dim(`part ${String(part.id ?? '-')}`)
      }`)
      for (const paper of papers.slice(0, 8)) {
        lines.push(`  ${String(paper.id ?? '-')} · ${String(paper.title ?? '-')}`)
      }
      if (papers.length > 8) {
        lines.push(`  ${pc.dim(`... ${papers.length - 8} more`)}`)
      }
    }
  }

  const nextOffset = typeof pagination.nextOffset === 'number'
    ? pagination.nextOffset
    : undefined
  if (nextOffset !== undefined) {
    lines.push(
      '',
      `${pc.dim('more')} ${
        buildUrantiaTocCommand({ ...query, offset: nextOffset }, 'online')
      }`,
    )
  }
  lines.push('', `${pc.dim('again')} ${buildUrantiaTocCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildUrantiaTocCommand(query, 'offline')}`)
  lines.push(
    `${pc.dim('open')} ${buildUrantiaPaperCommand({ paperId: '0' }, 'online')}`,
  )
  return lines.join('\n')
}

function renderUrantiaPaper(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const paper = isRecord(value.paper) ? value.paper : {}
  const paragraphs = Array.isArray(value.paragraphs)
    ? value.paragraphs.filter(isRecord)
    : []
  const lines = createUrantiaHeader(
    value,
    'Urantia Paper',
    String(api.endpoint ?? 'GET /papers/{id}'),
  )
  lines.push(
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('paper')} ${String(paper.id ?? query.paperId ?? '-')} · ${
      String(paper.title ?? '-')
    }`,
    [
      `${pc.dim('returned')} ${String(pagination.returned ?? paragraphs.length)}`,
      `${pc.dim('total paragraphs')} ${String(pagination.total ?? '-')}`,
      `${pc.dim('offset')} ${String(pagination.offset ?? query.offset ?? 0)}`,
    ].join(' · '),
  )

  if (paragraphs.length === 0) {
    lines.push('', pc.yellow('No Urantia paragraphs returned for this page.'))
  } else {
    for (const paragraph of paragraphs.slice(0, 10)) {
      appendUrantiaParagraph(lines, paragraph)
    }
  }

  const nextOffset = typeof pagination.nextOffset === 'number'
    ? pagination.nextOffset
    : undefined
  if (nextOffset !== undefined) {
    lines.push(
      '',
      `${pc.dim('next')} ${
        buildUrantiaPaperCommand({ ...query, offset: nextOffset }, 'online')
      }`,
    )
  }
  lines.push('', `${pc.dim('again')} ${buildUrantiaPaperCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildUrantiaPaperCommand(query, 'offline')}`)
  if (paragraphs.length > 0) {
    lines.push(`${pc.dim('open first')} ${
      buildUrantiaParagraphCommand({
        ref: paragraphs[0]?.standardReferenceId,
      }, 'online')
    }`)
  }
  return lines.join('\n')
}

function renderUrantiaParagraph(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const paragraph = isRecord(value.paragraph) ? value.paragraph : {}
  const navigation = isRecord(value.navigation) ? value.navigation : {}
  const lines = createUrantiaHeader(
    value,
    'Urantia Paragraph',
    String(api.endpoint ?? 'GET /paragraphs/{ref}'),
  )
  lines.push(`${pc.dim('query')} ${formatQuery(query)}`)
  appendUrantiaParagraph(lines, paragraph, 900)
  lines.push('', `${pc.dim('again')} ${
    buildUrantiaParagraphCommand(query, 'online')
  }`)
  lines.push(`${pc.dim('replay')} ${buildUrantiaParagraphCommand(query, 'offline')}`)
  if (typeof navigation.previous === 'string') {
    lines.push(`${pc.dim('previous')} ${
      buildUrantiaParagraphCommand({ ...query, ref: navigation.previous }, 'online')
    }`)
  }
  if (typeof navigation.next === 'string') {
    lines.push(`${pc.dim('next')} ${
      buildUrantiaParagraphCommand({ ...query, ref: navigation.next }, 'online')
    }`)
  }
  if (typeof paragraph.paperId === 'string') {
    lines.push(`${pc.dim('paper')} ${
      buildUrantiaPaperCommand({
        paperId: paragraph.paperId,
        lang: query.lang,
      }, 'online')
    }`)
  }
  return lines.join('\n')
}

