function createUrantiaHeader(
  value: Record<string, unknown>,
  title: string,
  endpoint: string,
): string[] {
  return [
    `${pc.bold(pc.cyan(title))} ${pc.dim(endpoint)}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} HTTPS JSON REST`,
    `${pc.dim('media')} audio/video/html fields omitted from CLI projection`,
  ]
}

function appendUrantiaParagraph(
  lines: string[],
  paragraph: Record<string, unknown>,
  maxLength = 420,
): void {
  const labels = Array.isArray(paragraph.labels)
    ? paragraph.labels.filter((entry): entry is string => typeof entry === 'string')
    : []
  const section = typeof paragraph.sectionTitle === 'string'
    ? paragraph.sectionTitle
    : '-'
  lines.push(
    '',
    `${pc.bold(String(paragraph.standardReferenceId ?? paragraph.id ?? '-'))} ${
      pc.dim(String(paragraph.paperTitle ?? '-'))
    }`,
    `${pc.dim('section')} ${section} · ${pc.dim('paper')} ${
      String(paragraph.paperId ?? '-')
    } · ${pc.dim('paragraph')} ${String(paragraph.paragraphId ?? '-')}`,
    truncateText(String(paragraph.text ?? ''), maxLength),
  )
  if (labels.length > 0) {
    lines.push(`${pc.dim('labels')} ${labels.slice(0, 6).join(', ')}`)
  }
}

