function renderUsgsEarthquakeSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const metadata = isRecord(value.metadata) ? value.metadata : {}
  const events = Array.isArray(value.events) ? value.events.filter(isRecord) : []
  const lines = createUsgsEarthquakeHeader(
    value,
    'USGS Earthquake Search',
    String(api.endpoint ?? 'GET /query'),
  )
  lines.push(
    `${pc.dim('query')} ${formatQuery(query)}`,
    [
      `${pc.dim('returned')} ${String(pagination.returned ?? events.length)}`,
      `${pc.dim('limit')} ${String(pagination.limit ?? query.limit ?? 10)}`,
      `${pc.dim('offset')} ${String(pagination.offset ?? query.offset ?? 1)}`,
      `${pc.dim('api')} ${String(metadata.apiVersion ?? '-')}`,
    ].join(' · '),
    `${pc.dim('reliability')} ${
      String(api.reliability ?? 'Near-real-time earthquake data can be revised.')
    }`,
  )

  if (events.length === 0) {
    lines.push('', pc.yellow('No USGS earthquake events matched this query.'))
    lines.push(`${pc.dim('try')} ${buildUsgsEarthquakeSearchCommand({}, 'online')}`)
  } else {
    for (const event of events.slice(0, 10)) {
      appendUsgsEarthquakeEvent(lines, event)
    }
  }

  const nextOffset = typeof pagination.nextOffset === 'number'
    ? pagination.nextOffset
    : undefined
  if (nextOffset !== undefined) {
    lines.push(
      '',
      `${pc.dim('next')} ${
        buildUsgsEarthquakeSearchCommand({ ...query, offset: nextOffset }, 'online')
      }`,
    )
  }
  lines.push('', `${pc.dim('again')} ${
    buildUsgsEarthquakeSearchCommand(query, 'online')
  }`)
  lines.push(`${pc.dim('replay')} ${
    buildUsgsEarthquakeSearchCommand(query, 'offline')
  }`)
  if (events.length > 0) {
    lines.push(`${pc.dim('open first')} ${
      buildUsgsEarthquakeEventCommand({
        eventId: events[0]?.id,
      }, 'online')
    }`)
  }
  return lines.join('\n')
}

function renderUsgsEarthquakeEvent(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const event = isRecord(value.event) ? value.event : {}
  const lines = createUsgsEarthquakeHeader(
    value,
    'USGS Earthquake Event',
    String(api.endpoint ?? 'GET /query?eventid={eventId}'),
  )
  lines.push(
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('reliability')} ${
      String(api.reliability ?? 'Near-real-time earthquake data can be revised.')
    }`,
  )
  appendUsgsEarthquakeEvent(lines, event, true)
  lines.push('', `${pc.dim('again')} ${
    buildUsgsEarthquakeEventCommand(query, 'online')
  }`)
  lines.push(`${pc.dim('replay')} ${
    buildUsgsEarthquakeEventCommand(query, 'offline')
  }`)
  lines.push(`${pc.dim('search recent')} ${
    buildUsgsEarthquakeSearchCommand({}, 'online')
  }`)
  return lines.join('\n')
}

function createUsgsEarthquakeHeader(
  value: Record<string, unknown>,
  title: string,
  endpoint: string,
): string[] {
  return [
    `${pc.bold(pc.cyan(title))} ${pc.dim(endpoint)}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} HTTPS GeoJSON REST`,
    `${pc.dim('products')} product attachments and binary assets omitted`,
  ]
}

function appendUsgsEarthquakeEvent(
  lines: string[],
  event: Record<string, unknown>,
  includeDetail = false,
): void {
  const coordinates = isRecord(event.coordinates) ? event.coordinates : {}
  const productTypes = Array.isArray(event.productTypes)
    ? event.productTypes.filter((entry): entry is string => typeof entry === 'string')
    : []
  const sources = Array.isArray(event.sources)
    ? event.sources.filter((entry): entry is string => typeof entry === 'string')
    : []
  const coords = typeof coordinates.latitude === 'number' &&
    typeof coordinates.longitude === 'number'
    ? [
      formatNumber(coordinates.latitude),
      formatNumber(coordinates.longitude),
      typeof coordinates.depthKm === 'number'
        ? `${formatNumber(coordinates.depthKm)} km`
        : undefined,
    ].filter(Boolean).join(', ')
    : '-'
  lines.push(
    '',
    `${pc.bold(String(event.title ?? 'Unknown earthquake'))} ${
      pc.dim(String(event.id ?? '-'))
    }`,
    [
      `${pc.dim('time')} ${String(event.time ?? '-')}`,
      `${pc.dim('mag')} ${formatNumber(event.magnitude)}`,
      `${pc.dim('status')} ${String(event.status ?? '-')}`,
      `${pc.dim('alert')} ${String(event.alert ?? '-')}`,
    ].join(' · '),
    [
      `${pc.dim('place')} ${String(event.place ?? '-')}`,
      `${pc.dim('coords')} ${coords}`,
    ].join(' · '),
    [
      `${pc.dim('felt')} ${formatNumber(event.felt)}`,
      `${pc.dim('mmi')} ${formatNumber(event.mmi)}`,
      `${pc.dim('tsunami')} ${event.tsunami === true ? 'yes' : 'no'}`,
      `${pc.dim('sig')} ${formatNumber(event.significance)}`,
    ].join(' · '),
  )
  if (includeDetail) {
    lines.push(
      `${pc.dim('network')} ${String(event.network ?? '-')} · ${
        pc.dim('code')
      } ${String(event.code ?? '-')} · ${pc.dim('mag type')} ${
        String(event.magnitudeType ?? '-')
      }`,
      `${pc.dim('sources')} ${sources.length > 0 ? sources.join(', ') : '-'}`,
      `${pc.dim('products')} ${
        productTypes.length > 0 ? productTypes.slice(0, 12).join(', ') : '-'
      }`,
    )
    if (typeof event.url === 'string') {
      lines.push(`${pc.dim('event page')} ${event.url}`)
    }
  } else if (productTypes.length > 0) {
    lines.push(`${pc.dim('products')} ${productTypes.slice(0, 6).join(', ')}`)
  }
}

function buildUsgsEarthquakeSearchCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run usgsearthquake.search']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  pushCliOption(parts, '--min-magnitude', query.minMagnitude ?? 4.5)
  pushCliOption(parts, '--limit', query.limit ?? 10)
  pushCliOption(parts, '--offset', query.offset ?? 1)
  pushCliOption(parts, '--order-by', query.orderBy ?? 'time')
  pushCliOption(parts, '--start-time', query.startTime)
  pushCliOption(parts, '--end-time', query.endTime)
  return parts.join(' ')
}

function buildUsgsEarthquakeEventCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run usgsearthquake.event']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  pushCliOption(
    parts,
    '--event-id',
    query.eventId ?? 'official20110311054624120_30',
  )
  return parts.join(' ')
}

function renderUsgsWaterInstantaneous(value: Record<string, unknown>): string {
  return renderUsgsWaterSeriesResult(
    value,
    'USGS Water Instantaneous Values',
    'usgswater.instantaneous',
  )
}

function renderUsgsWaterDaily(value: Record<string, unknown>): string {
  return renderUsgsWaterSeriesResult(
    value,
    'USGS Water Daily Values',
    'usgswater.daily',
  )
}

function renderUsgsWaterSeriesResult(
  value: Record<string, unknown>,
  title: string,
  operation: 'usgswater.instantaneous' | 'usgswater.daily',
): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const series = Array.isArray(value.series) ? value.series.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan(title))} ${pc.dim(String(api.endpoint ?? 'GET /nwis'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} HTTPS WaterML JSON REST`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    [
      `${pc.dim('series')} ${String(pagination.returnedSeries ?? series.length)}`,
      `${pc.dim('values')} ${String(pagination.returnedValues ?? '?')}`,
      `${pc.dim('limit')} ${String(pagination.limit ?? query.limit ?? 10)}`,
    ].join(' · '),
    `${pc.dim('reliability')} ${
      String(api.reliability ?? 'Recent values can be provisional.')
    }`,
    `${pc.dim('scope')} single-site bounded values; bulk exports omitted`,
  ]

  if (series.length === 0) {
    lines.push('', pc.yellow('No USGS water values matched this query.'))
    lines.push(`${pc.dim('try')} ${buildUsgsWaterCommand(operation, {}, 'online')}`)
  } else {
    appendUsgsWaterSeries(lines, series)
  }

  lines.push('', `${pc.dim('again')} ${
    buildUsgsWaterCommand(operation, query, 'online')
  }`)
  lines.push(`${pc.dim('replay')} ${
    buildUsgsWaterCommand(operation, query, 'offline')
  }`)
  if (operation === 'usgswater.instantaneous') {
    lines.push(`${pc.dim('daily')} ${
      buildUsgsWaterCommand('usgswater.daily', query, 'online')
    }`)
  } else {
    lines.push(`${pc.dim('current')} ${
      buildUsgsWaterCommand('usgswater.instantaneous', query, 'online')
    }`)
  }
  return lines.join('\n')
}

function appendUsgsWaterSeries(
  lines: string[],
  series: Record<string, unknown>[],
): void {
  for (const entry of series.slice(0, 8)) {
    const site = isRecord(entry.site) ? entry.site : {}
    const variable = isRecord(entry.variable) ? entry.variable : {}
    const readings = Array.isArray(entry.readings)
      ? entry.readings.filter(isRecord)
      : []
    const qualifiers = Array.isArray(entry.qualifiers)
      ? entry.qualifiers.filter(isRecord)
      : []
    lines.push(
      '',
      `${pc.bold(String(site.name ?? 'USGS site'))} ${pc.dim(String(site.code ?? '-'))}`,
      [
        `${pc.dim('parameter')} ${String(variable.code ?? '-')}`,
        `${pc.dim('unit')} ${String(variable.unit ?? '-')}`,
        `${pc.dim('stat')} ${String(variable.statisticCode ?? '-')}`,
      ].join(' · '),
      `${pc.dim('variable')} ${String(variable.description ?? variable.name ?? '-')}`,
    )
    const coords = typeof site.latitude === 'number' &&
      typeof site.longitude === 'number'
      ? `${formatNumber(site.latitude)}, ${formatNumber(site.longitude)}`
      : undefined
    if (coords !== undefined) {
      lines.push(`${pc.dim('coords')} ${coords}`)
    }
    for (const reading of readings.slice(0, 10)) {
      const qualifierText = Array.isArray(reading.qualifiers)
        ? reading.qualifiers.join(',')
        : ''
      lines.push(
        `- ${String(reading.dateTime ?? '-')} · ${
          String(reading.value ?? '-')
        }${qualifierText !== '' ? ` · ${qualifierText}` : ''}`,
      )
    }
    if (qualifiers.length > 0) {
      lines.push(
        `${pc.dim('qualifiers')} ${
          qualifiers.map(formatUsgsWaterQualifier).slice(0, 4).join('; ')
        }`,
      )
    }
  }
}

function formatUsgsWaterQualifier(value: Record<string, unknown>): string {
  const code = String(value.code ?? '-')
  const description = String(value.description ?? '').trim()
  return description === '' ? code : `${code}: ${description}`
}

function buildUsgsWaterCommand(
  operation: 'usgswater.instantaneous' | 'usgswater.daily',
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = [`public-apis apis run ${operation}`]
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  pushCliOption(parts, '--site', query.site ?? '01646500')
  pushCliOption(
    parts,
    '--parameter-codes',
    readUsgsWaterParameterCodes(query, operation),
  )
  if (operation === 'usgswater.instantaneous') {
    pushCliOption(parts, '--period', query.period)
  } else {
    pushCliOption(parts, '--statistic-code', query.statisticCode ?? '00003')
    pushCliOption(parts, '--start-date', query.startDate ?? '2026-05-01')
    pushCliOption(parts, '--end-date', query.endDate ?? '2026-05-11')
  }
  pushCliOption(parts, '--limit', query.limit ?? 10)
  return parts.join(' ')
}

function readUsgsWaterParameterCodes(
  query: Record<string, unknown>,
  operation: 'usgswater.instantaneous' | 'usgswater.daily',
): unknown {
  if (Array.isArray(query.parameterCodes)) {
    return query.parameterCodes.join(',')
  }
  return query.parameterCodes ??
    (operation === 'usgswater.daily' ? '00060' : '00060,00065')
}

function renderIsEvenCheck(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const result = isRecord(value.result) ? value.result : {}
  const upstream = isRecord(value.upstream) ? value.upstream : {}
  const freeRange = isRecord(api.freeRange) ? api.freeRange : {}
  const number = readIsEvenNumber(query, result)
  const parity = String(result.parity ?? (result.isEven === true ? 'even' : 'odd'))
  const lines = [
    `${pc.bold(pc.cyan('isEven Parity Check'))} ${
      pc.dim(String(api.endpoint ?? 'GET /iseven/{number}/'))
    }`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('free range')} ${String(freeRange.min ?? 0)}-${
      String(freeRange.max ?? 999_999)
    }`,
    `${pc.dim('tier')} ${
      String(api.tierPolicy ?? 'Only the public free range is exposed.')
    }`,
    `${pc.dim('ads')} ${
      String(api.adPolicy ?? 'Free responses may include provider ad metadata.')
    }`,
    '',
    `${pc.bold(String(number))} is ${pc.bold(parity)}`,
  ]

  if (typeof upstream.ad === 'string' && upstream.ad.trim() !== '') {
    lines.push(`${pc.dim('provider ad')} ${upstream.ad}`)
  }

  lines.push('', `${pc.dim('again')} ${buildIsEvenCheckCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildIsEvenCheckCommand(query, 'offline')}`)
  if (number < 999_999) {
    lines.push(`${pc.dim('nearby')} ${
      buildIsEvenCheckCommand({ number: number + 1 }, 'online')
    }`)
  }
  return lines.join('\n')
}

function readIsEvenNumber(
  query: Record<string, unknown>,
  result: Record<string, unknown>,
): number {
  if (typeof result.number === 'number') return result.number
  return typeof query.number === 'number' ? query.number : 6
}

function buildIsEvenCheckCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const number = typeof query.number === 'number' ? query.number : 6
  const parts = ['public-apis apis run iseven.check']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--', `--number ${formatCliArg(number)}`)
  return parts.join(' ')
}

function renderIsroCatalog(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const items = Array.isArray(value.items) ? value.items.filter(isRecord) : []
  const resource = String(query.resource ?? 'spacecrafts')
  const lines = [
    `${pc.bold(pc.cyan('ISRO Catalog'))} ${pc.dim(String(api.endpoint ?? 'GET /api/{resource}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
    `${pc.dim('resource')} ${resource}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${formatIsroPage(pagination, items.length)}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Read-only JSON catalog resources only.')}`,
  ]

  if (items.length === 0) {
    lines.push('', pc.yellow('No ISRO catalog rows matched this query.'))
    lines.push(`${pc.dim('try')} ${buildIsroCatalogCommand({ resource }, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildIsroCatalogCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildIsroCatalogCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const item of items.slice(0, 20)) {
    lines.push(formatIsroItem(resource, item))
  }

  if (pagination.hasMore === true) {
    const nextOffset = Number(pagination.offset ?? 0) + Number(pagination.returned ?? items.length)
    lines.push(`${pc.dim('next')} ${
      buildIsroCatalogCommand({ ...query, offset: nextOffset }, 'online')
    }`)
  }
  lines.push('', `${pc.dim('again')} ${buildIsroCatalogCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildIsroCatalogCommand(query, 'offline')}`)
  return lines.join('\n')
}

function formatIsroPage(
  pagination: Record<string, unknown>,
  fallbackReturned: number,
): string {
  const returned = String(pagination.returned ?? fallbackReturned)
  const matched = String(pagination.matched ?? returned)
  const total = String(pagination.total ?? matched)
  const offset = String(pagination.offset ?? 0)
  const limit = String(pagination.limit ?? returned)
  const more = pagination.hasMore === true ? ' · more available' : ''
  return `${returned}/${matched} matched · total ${total} · offset ${offset} · limit ${limit}${more}`
}

function formatIsroItem(resource: string, item: Record<string, unknown>): string {
  if (resource === 'launchers') {
    return `- ${pc.bold(String(item.id ?? 'unknown launcher'))}`
  }
  if (resource === 'customer_satellites') {
    const mass = String(item.mass ?? '').trim()
    const massText = mass === '' ? '' : ` · ${mass} kg`
    return [
      `- ${pc.bold(String(item.id ?? 'unknown satellite'))}`,
      `${String(item.country ?? 'unknown country')}`,
      `${String(item.launchDate ?? 'unknown date')}`,
      `${String(item.launcher ?? 'unknown launcher')}${massText}`,
    ].join(' · ')
  }
  if (resource === 'centres') {
    return [
      `- ${pc.bold(String(item.name ?? 'unknown centre'))}`,
      `${String(item.place ?? 'unknown place')}`,
      String(item.state ?? 'unknown state'),
    ].join(' · ')
  }
  return `- ${pc.bold(String(item.name ?? 'unknown spacecraft'))} ${pc.dim(`#${String(item.id ?? '?')}`)}`
}

function buildIsroCatalogCommand(
  query: Record<string, unknown>,
  mode?: 'online' | 'offline',
): string {
  const parts = ['public-apis apis run isro.catalog']
  if (mode !== undefined) {
    parts.push(mode === 'online' ? '--online --persist' : '--offline')
  }
  parts.push('--')
  parts.push('--resource', formatCliArg(query.resource ?? 'spacecrafts'))
  if (typeof query.search === 'string' && query.search.trim() !== '') {
    parts.push('--search', formatCliArg(query.search))
  }
  parts.push('--limit', String(query.limit ?? 20))
  parts.push('--offset', String(query.offset ?? 0))
  return parts.join(' ')
}

function renderItisSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const names = Array.isArray(value.names) ? value.names.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('ITIS Scientific Name Search'))} ${
      pc.dim(String(api.endpoint ?? 'GET /searchByScientificName'))
    }`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')} · ${
      String(api.contentType ?? 'text/json')
    }`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('page')} ${formatItisPage(pagination, names.length)}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Read-only ITIS JSON service calls only.')}`,
  ]

  if (names.length === 0) {
    lines.push('', pc.yellow('No ITIS scientific names matched this query.'))
    lines.push(`${pc.dim('try')} ${buildItisSearchCommand({}, 'online')}`)
    lines.push(`${pc.dim('again')} ${buildItisSearchCommand(query, 'online')}`)
    lines.push(`${pc.dim('replay')} ${buildItisSearchCommand(query, 'offline')}`)
    return lines.join('\n')
  }

  for (const name of names.slice(0, 20)) {
    const label = String(name.combinedName ?? 'unknown name')
    const tsn = String(name.tsn ?? '?')
    const parts = [
      `- ${pc.bold(label)}`,
      `TSN ${tsn}`,
      typeof name.author === 'string' ? name.author : undefined,
      typeof name.kingdom === 'string' ? name.kingdom : undefined,
    ].filter((part): part is string => part !== undefined)
    lines.push(parts.join(' · '))
  }

  if (pagination.hasMore === true) {
    const nextOffset = Number(pagination.offset ?? 0) + Number(pagination.returned ?? names.length)
    lines.push(`${pc.dim('next')} ${
      buildItisSearchCommand({ ...query, offset: nextOffset }, 'online')
    }`)
  }
  const first = names[0]
  if (first !== undefined && typeof first.tsn === 'string') {
    lines.push(`${pc.dim('record')} ${
      buildItisRecordCommand({ tsn: first.tsn }, 'online')
    }`)
  }
  lines.push('', `${pc.dim('again')} ${buildItisSearchCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildItisSearchCommand(query, 'offline')}`)
  return lines.join('\n')
}

function renderItisRecord(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const record = isRecord(value.record) ? value.record : {}
  const counts = isRecord(value.counts) ? value.counts : {}
  const scientificName = isRecord(record.scientificName) ? record.scientificName : {}
  const hierarchy = isRecord(record.hierarchy) ? record.hierarchy : {}
  const links = isRecord(record.links) ? record.links : {}
  const commonNames = Array.isArray(record.commonNames)
    ? record.commonNames.filter(isRecord)
    : []
  const synonyms = Array.isArray(record.synonyms)
    ? record.synonyms.filter(isRecord)
    : []
  const lines = [
    `${pc.bold(pc.cyan('ITIS Taxonomy Record'))} ${
      pc.dim(String(api.endpoint ?? 'GET /getFullRecordFromTSN'))
    }`,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')} · ${
      String(api.contentType ?? 'text/json')
    }`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('scope')} ${String(api.boundary ?? 'Read-only ITIS JSON service calls only.')}`,
    '',
    `${pc.bold(String(scientificName.combinedName ?? hierarchy.taxonName ?? 'unknown taxon'))} ${
      pc.dim(`TSN ${String(record.tsn ?? query.tsn ?? '?')}`)
    }`,
    `${pc.dim('rank')} ${String(record.rank ?? hierarchy.rankName ?? 'unknown')} · ${
      pc.dim('usage')
    } ${String(record.usage ?? 'unknown')}`,
    `${pc.dim('kingdom')} ${String(record.kingdom ?? scientificName.kingdom ?? 'unknown')} · ${
      pc.dim('credibility')
    } ${String(record.credibility ?? 'unknown')}`,
  ]

  if (typeof hierarchy.parentName === 'string') {
    lines.push(`${pc.dim('parent')} ${hierarchy.parentName} · TSN ${
      String(hierarchy.parentTsn ?? '?')
    }`)
  }
  lines.push(`${pc.dim('counts')} commonNames=${String(counts.commonNames ?? 0)} · synonyms=${
    String(counts.synonyms ?? 0)
  } · jurisdictions=${String(counts.jurisdictionalOrigins ?? 0)}`)

  if (commonNames.length > 0) {
    lines.push('', pc.bold('Common Names'))
    for (const commonName of commonNames.slice(0, 10)) {
      lines.push(`- ${String(commonName.commonName ?? '')} ${
        pc.dim(String(commonName.language ?? ''))
      }`.trim())
    }
  }
  if (synonyms.length > 0) {
    lines.push('', pc.bold('Synonyms'))
    for (const synonym of synonyms.slice(0, 10)) {
      lines.push(`- ${String(synonym.scientificName ?? '')} ${
        pc.dim(`TSN ${String(synonym.tsn ?? '?')}`)
      }`.trim())
    }
  }

  if (typeof links.report === 'string') {
    lines.push('', `${pc.dim('report')} ${links.report}`)
  }
  lines.push(`${pc.dim('again')} ${buildItisRecordCommand(query, 'online')}`)
  lines.push(`${pc.dim('replay')} ${buildItisRecordCommand(query, 'offline')}`)
  lines.push(`${pc.dim('search')} ${
    buildItisSearchCommand({
      query: scientificName.combinedName ?? hierarchy.taxonName ?? 'Quercus robur',
    }, 'online')
  }`)
  return lines.join('\n')
}

function formatItisPage(
  pagination: Record<string, unknown>,
  fallbackReturned: number,
): string {
  const returned = String(pagination.returned ?? fallbackReturned)
  const matched = String(pagination.matched ?? returned)
  const offset = String(pagination.offset ?? 0)
  const limit = String(pagination.limit ?? returned)
  const more = pagination.hasMore === true ? ' · more available' : ''
  return `${returned}/${matched} matched · offset ${offset} · limit ${limit}${more}`
}

