function renderPm25OpenDataFeed(
  value: Record<string, unknown>,
  options: { title: string; endpoint: string; next: string; maxLimit: number },
): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const summary = isRecord(value.summary) ? value.summary : {}
  const feeds = Array.isArray(value.feeds) ? value.feeds.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan(options.title))} ${pc.dim(String(api.endpoint ?? options.endpoint))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(pagination.returned ?? feeds.length)} feed row(s) · source records ${String(pagination.sourceRecords ?? '?')} · max ${String(pagination.maxLimit ?? options.maxLimit)}`,
    `${pc.dim('summary')} avg PM2.5 ${formatNumber(summary.averagePm25)} · max ${formatNumber(summary.maxPm25)} · latest ${String(summary.latestTimestamp ?? 'unknown')}`,
  ]
  if (feeds.length === 0) {
    lines.push('', pc.yellow('No PM2.5 Open Data feed rows returned.'))
    lines.push(`${pc.dim('try')} ${options.next}`)
    return lines.join('\n')
  }
  lines.push('')
  for (const feed of feeds.slice(0, 10)) {
    const label = String(feed.siteName ?? feed.name ?? feed.deviceId ?? 'sensor')
    const location = formatPm25Location(feed)
    lines.push(`- ${label} · PM2.5 ${formatNumber(feed.pm25)} · PM10 ${formatNumber(feed.pm10)} · ${String(feed.timestamp ?? 'unknown time')}${location !== '' ? ` · ${location}` : ''}`)
  }
  if (feeds.length > 10) {
    lines.push(pc.dim(`… ${feeds.length - 10} more feed row(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('next')} ${options.next}`)
  return lines.join('\n')
}

function formatPm25Location(feed: Record<string, unknown>): string {
  return typeof feed.latitude === 'number' && typeof feed.longitude === 'number' && (feed.latitude !== 0 || feed.longitude !== 0)
    ? `${feed.latitude.toFixed(3)},${feed.longitude.toFixed(3)}`
    : ''
}

