function renderPoetryDbPoems(
  value: Record<string, unknown>,
  options: {
    title: string
    defaultEndpoint: string
    empty: string
    nextCommands: (query: Record<string, unknown>, poems: Record<string, unknown>[], api: Record<string, unknown>) => Array<{ label: string; command: string }>
  },
): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const poems = Array.isArray(value.poems) ? value.poems.filter(isRecord) : []
  const displayLineLimit = readPoetryDbDisplayLineLimit(query, api)
  const lines = [
    `${pc.bold(pc.cyan(options.title))} ${pc.dim(String(api.endpoint ?? options.defaultEndpoint))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? poems.length)} poem(s) · CLI count cap ${String(api.cliCountCap ?? 20)} · line cap ${String(api.cliLineLimitCap ?? 80)}`,
  ]

  if (poems.length === 0) {
    lines.push('', pc.yellow(options.empty))
    appendPoetryDbNextCommands(lines, options.nextCommands(query, poems, api))
    return lines.join('\n')
  }

  for (const [poemIndex, poem] of poems.slice(0, 20).entries()) {
    lines.push('', `${pc.bold(`${poemIndex + 1}. ${String(poem.title ?? '(untitled)')}`)} ${pc.dim(String(poem.author ?? 'unknown author'))}`)
    if (poem.linecount !== undefined) {
      lines.push(pc.dim(`${String(poem.linecount)} line(s)`))
    }
    const poemLines = Array.isArray(poem.lines) ? poem.lines.filter(entry => typeof entry === 'string') : []
    for (const poemLine of poemLines.slice(0, displayLineLimit)) {
      lines.push(wrapLine(`  ${poemLine}`, 100))
    }
    if (typeof poem.truncatedLines === 'number' && poem.truncatedLines > 0) {
      lines.push(pc.dim(`  … ${String(poem.truncatedLines)} more line(s) truncated`))
    }
  }

  appendPoetryDbNextCommands(lines, options.nextCommands(query, poems, api))
  return lines.join('\n')
}

function appendPoetryDbNextCommands(lines: string[], commands: Array<{ label: string; command: string }>): void {
  if (commands.length === 0) {
    return
  }
  lines.push('')
  for (const entry of commands) {
    lines.push(`${pc.dim(entry.label)} ${entry.command}`)
  }
}

function buildPoetryDbSearchNextCommands(query: Record<string, unknown>, poems: Record<string, unknown>[], api: Record<string, unknown>): Array<{ label: string; command: string }> {
  const commands: Array<{ label: string; command: string }> = []
  const hasTruncatedLines = poems.some(poem => typeof poem.truncatedLines === 'number' && poem.truncatedLines > 0)
  if (hasTruncatedLines || query.includeLines === false) {
    commands.push({
      label: hasTruncatedLines ? 'more lines' : 'read lines',
      command: buildPoetryDbSearchCommand(query, {
        includeLines: true,
        lineLimit: typeof api.cliLineLimitCap === 'number' ? api.cliLineLimitCap : 80,
      }),
    })
  }
  if (poems.length === 0 && query.exact === true) {
    commands.push({
      label: 'try broader',
      command: buildPoetryDbSearchCommand(query, { exact: false, includeLines: true }),
    })
  }
  commands.push({
    label: poems.length === 0 ? 'try default' : 'next',
    command: 'public-apis apis run poetrydb.random -- --count 1 --include-lines true --line-limit 12',
  })
  return commands
}

function buildPoetryDbRandomNextCommands(query: Record<string, unknown>, poems: Record<string, unknown>[], api: Record<string, unknown>): Array<{ label: string; command: string }> {
  const commands: Array<{ label: string; command: string }> = []
  const firstTitle = poems.find(poem => typeof poem.title === 'string')?.title
  if (typeof firstTitle === 'string' && firstTitle.trim() !== '') {
    commands.push({
      label: 'read lines',
      command: buildPoetryDbSearchCommand(
        { field: 'title', term: firstTitle, exact: true, count: 1 },
        { includeLines: true, lineLimit: typeof api.cliLineLimitCap === 'number' ? api.cliLineLimitCap : 80 },
      ),
    })
  }
  commands.push({
    label: 'more random',
    command: `public-apis apis run poetrydb.random -- --count ${formatCliArg(query.count ?? 1)} --include-lines ${String(query.includeLines ?? false)} --line-limit ${formatCliArg(query.lineLimit ?? 12)}`,
  })
  return commands
}

function buildPoetryDbSearchCommand(query: Record<string, unknown>, overrides: Record<string, unknown> = {}): string {
  const merged = { ...query, ...overrides }
  return [
    'public-apis apis run poetrydb.search --',
    `--field ${formatCliArg(merged.field ?? 'title')}`,
    `--term ${formatCliArg(merged.term ?? 'Ozymandias')}`,
    `--exact ${String(merged.exact ?? false)}`,
    `--count ${formatCliArg(merged.count ?? 20)}`,
    `--include-lines ${String(merged.includeLines ?? true)}`,
    `--line-limit ${formatCliArg(merged.lineLimit ?? 12)}`,
  ].join(' ')
}

function readPoetryDbDisplayLineLimit(query: Record<string, unknown>, api: Record<string, unknown>): number {
  const fallback = 12
  const cap = typeof api.cliLineLimitCap === 'number' ? api.cliLineLimitCap : 80
  const value = typeof query.lineLimit === 'number' ? query.lineLimit : fallback
  if (!Number.isFinite(value) || value < 0) {
    return fallback
  }
  return Math.min(Math.trunc(value), cap)
}

function renderQuranCloudAyah(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const ayah = isRecord(value.ayah) ? value.ayah : {}
  const surah = isRecord(ayah.surah) ? ayah.surah : {}
  const edition = isRecord(ayah.edition) ? ayah.edition : {}
  const lines = [
    `${pc.bold(pc.cyan('Quran Cloud Ayah'))} ${pc.dim(String(api.endpoint ?? 'GET /v1/ayah/{reference}/{edition}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.bold(`${String(surah.englishName ?? 'Surah')} ${String(ayah.numberInSurah ?? '')}`)} ${pc.dim(`global ${String(ayah.number ?? '-')}`)}`,
    `${pc.dim('edition')} ${String(edition.identifier ?? query.edition ?? api.defaultEdition ?? '-')}`,
  ]
  if (typeof ayah.text === 'string') {
    lines.push('', wrapText(ayah.text, 100))
  }
  const meta = [
    ayah.juz !== undefined ? `juz ${String(ayah.juz)}` : undefined,
    ayah.page !== undefined ? `page ${String(ayah.page)}` : undefined,
    surah.number !== undefined ? `surah ${String(surah.number)}` : undefined,
  ].filter((entry): entry is string => typeof entry === 'string')
  if (meta.length > 0) {
    lines.push('', pc.dim(meta.join(' · ')))
  }
  lines.push('', `${pc.dim('context')} ${buildQuranCloudSurahCommand({
    surah: surah.number ?? 1,
    edition: query.edition ?? api.defaultEdition ?? 'en.asad',
    offset: Math.max(0, typeof ayah.numberInSurah === 'number' ? ayah.numberInSurah - 1 : 0),
    limit: 20,
  })}`)
  lines.push(`${pc.dim('full surah')} ${buildQuranCloudSurahCommand({
    surah: surah.number ?? 1,
    edition: query.edition ?? api.defaultEdition ?? 'en.asad',
    limit: api.cliSurahLimitCap ?? 286,
  })}`)
  return lines.join('\n')
}

function renderQuranApiVerse(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const verse = isRecord(value.verse) ? value.verse : {}
  const lines = [
    `${pc.bold(pc.cyan('Quran-api Verse'))} ${pc.dim(String(api.endpoint ?? 'GET /editions/{edition}/{chapter}/{verse}.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.bold(`Chapter ${String(verse.chapter ?? query.chapter ?? '-')}:${String(verse.verse ?? query.verse ?? '-')}`)} ${pc.dim(String(query.edition ?? api.defaultEdition ?? ''))}`,
  ]
  if (typeof verse.text === 'string') {
    lines.push('', wrapText(verse.text, 100))
  }
  lines.push('', `${pc.dim('context')} ${buildQuranApiChapterCommand({
    edition: query.edition ?? api.defaultEdition ?? 'eng-ummmuhammad',
    chapter: verse.chapter ?? query.chapter ?? 1,
    offset: Math.max(0, typeof verse.verse === 'number' ? verse.verse - 1 : 0),
    limit: 20,
  })}`)
  lines.push(`${pc.dim('full chapter')} ${buildQuranApiChapterCommand({
    edition: query.edition ?? api.defaultEdition ?? 'eng-ummmuhammad',
    chapter: verse.chapter ?? query.chapter ?? 1,
    limit: api.cliChapterLimitCap ?? 286,
  })}`)
  return lines.join('\n')
}

function renderQuranApiChapter(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const verses = Array.isArray(value.verses) ? value.verses.filter(isRecord) : []
  const offset = typeof query.offset === 'number' && Number.isFinite(query.offset) ? Math.max(0, Math.trunc(query.offset)) : 0
  const requestedLimit = typeof query.limit === 'number' && Number.isFinite(query.limit) ? Math.max(1, Math.trunc(query.limit)) : 286
  const displayLimit = Math.min(requestedLimit, 20)
  const visibleVerses = verses.slice(0, displayLimit)
  const totalVerses = typeof value.totalVerses === 'number' ? value.totalVerses : undefined
  const firstVisibleVerse = typeof visibleVerses[0]?.verse === 'number' ? visibleVerses[0].verse : offset + 1
  const lastVisible = visibleVerses.at(-1)
  const lastVisibleVerse = typeof lastVisible?.verse === 'number' ? lastVisible.verse : offset + visibleVerses.length
  const rangeText = visibleVerses.length > 0
    ? `showing ${String(firstVisibleVerse)}-${String(lastVisibleVerse)}${totalVerses !== undefined ? ` of ${String(totalVerses)}` : ''}`
    : 'showing none'
  const lines = [
    `${pc.bold(pc.cyan('Quran-api Chapter'))} ${pc.dim(String(api.endpoint ?? 'GET /editions/{edition}/{chapter}.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.bold(`Chapter ${String(query.chapter ?? verses[0]?.chapter ?? '-')}`)} ${pc.dim(String(query.edition ?? api.defaultEdition ?? ''))}`,
    `${pc.dim('count')} ${rangeText} · request ${String(value.count ?? verses.length)} verse(s) · limit cap ${String(api.cliChapterLimitCap ?? 286)} · README claims no rate limits`,
  ]

  if (verses.length === 0) {
    lines.push('', pc.yellow('No Quran-api verses returned for this chapter query.'))
    lines.push(`${pc.dim('restart')} ${buildQuranApiChapterCommand({
      edition: query.edition ?? api.defaultEdition ?? 'eng-ummmuhammad',
      chapter: query.chapter ?? 1,
      offset: 0,
      limit: 20,
    })}`)
    return lines.join('\n')
  }

  for (const verse of visibleVerses) {
    const wrappedText = wrapText(String(verse.text ?? ''), 100).split('\n')
    const [firstLine, ...remainingLines] = wrappedText.length > 0 ? wrappedText : ['']
    lines.push('', `${pc.bold(String(verse.verse ?? '-'))}. ${firstLine}`)
    for (const continuationLine of remainingLines) {
      lines.push(`   ${continuationLine}`)
    }
  }
  if (verses.length > displayLimit) {
    lines.push('', pc.dim(`… ${String(verses.length - displayLimit)} fetched verse(s) not shown in text view`))
  }
  appendQuranApiChapterNavigation(lines, query, api, offset, displayLimit, totalVerses, lastVisibleVerse)
  lines.push('', `${pc.dim('verse')} public-apis apis run quranapi.verse -- --edition ${formatCliArg(query.edition ?? api.defaultEdition ?? 'eng-ummmuhammad')} --chapter ${formatCliArg(query.chapter ?? verses[0]?.chapter ?? 1)} --verse ${formatCliArg(firstVisibleVerse)}`)
  return lines.join('\n')
}

function appendQuranApiChapterNavigation(
  lines: string[],
  query: Record<string, unknown>,
  api: Record<string, unknown>,
  offset: number,
  pageSize: number,
  totalVerses: number | undefined,
  lastVisibleVerse: number,
): void {
  const edition = query.edition ?? api.defaultEdition ?? 'eng-ummmuhammad'
  const chapter = query.chapter ?? 1
  const previousOffset = Math.max(0, offset - pageSize)
  const hasPrevious = offset > 0
  const hasNext = totalVerses === undefined ? false : lastVisibleVerse < totalVerses
  if (!hasPrevious && !hasNext) {
    return
  }

  lines.push('')
  if (hasPrevious) {
    lines.push(`${pc.dim('previous page')} ${buildQuranApiChapterCommand({ edition, chapter, offset: previousOffset, limit: pageSize })}`)
  }
  if (hasNext) {
    lines.push(`${pc.dim('next page')} ${buildQuranApiChapterCommand({ edition, chapter, offset: lastVisibleVerse, limit: pageSize })}`)
  }
}

function buildQuranApiChapterCommand(params: Record<string, unknown>): string {
  const parts = [
    'public-apis apis run quranapi.chapter --',
    `--edition ${formatCliArg(params.edition ?? 'eng-ummmuhammad')}`,
    `--chapter ${formatCliArg(params.chapter ?? 1)}`,
  ]
  if (params.offset !== undefined) {
    parts.push(`--offset ${formatCliArg(params.offset)}`)
  }
  parts.push(`--limit ${formatCliArg(params.limit ?? 20)}`)
  return parts.join(' ')
}

function renderQuranCloudSurah(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const surah = isRecord(value.surah) ? value.surah : {}
  const ayahs = Array.isArray(value.ayahs) ? value.ayahs.filter(isRecord) : []
  const edition = isRecord(surah.edition) ? surah.edition : {}
  const offset = typeof query.offset === 'number' && Number.isFinite(query.offset) ? Math.max(0, Math.trunc(query.offset)) : 0
  const requestedLimit = typeof query.limit === 'number' && Number.isFinite(query.limit) ? Math.max(1, Math.trunc(query.limit)) : 286
  const displayLimit = Math.min(requestedLimit, 20)
  const visibleAyahs = ayahs.slice(0, displayLimit)
  const totalAyahs = typeof surah.numberOfAyahs === 'number' ? surah.numberOfAyahs : undefined
  const firstVisibleAyah = typeof visibleAyahs[0]?.numberInSurah === 'number' ? visibleAyahs[0].numberInSurah : offset + 1
  const lastVisible = visibleAyahs.at(-1)
  const lastVisibleAyah = typeof lastVisible?.numberInSurah === 'number' ? lastVisible.numberInSurah : offset + visibleAyahs.length
  const rangeText = visibleAyahs.length > 0
    ? `showing ${String(firstVisibleAyah)}-${String(lastVisibleAyah)}${totalAyahs !== undefined ? ` of ${String(totalAyahs)}` : ''}`
    : 'showing none'
  const lines = [
    `${pc.bold(pc.cyan('Quran Cloud Surah'))} ${pc.dim(String(api.endpoint ?? 'GET /v1/surah/{surah}/{edition}?offset=&limit='))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.bold(`${String(surah.number ?? query.surah ?? '-')}. ${String(surah.englishName ?? '(unknown)')}`)} ${pc.dim(String(surah.name ?? ''))}`,
    `${pc.dim('edition')} ${String(edition.identifier ?? query.edition ?? api.defaultEdition ?? '-')} · ${rangeText} · request ${String(value.count ?? ayahs.length)} ayah(s) · limit cap ${String(api.cliSurahLimitCap ?? 286)}`,
  ]

  if (ayahs.length === 0) {
    lines.push('', pc.yellow('No Quran Cloud ayahs returned for this surah query.'))
    lines.push(`${pc.dim('restart')} ${buildQuranCloudSurahCommand({
      surah: surah.number ?? query.surah ?? 1,
      edition: query.edition ?? api.defaultEdition ?? 'en.asad',
      offset: 0,
      limit: 20,
    })}`)
    return lines.join('\n')
  }

  for (const ayah of visibleAyahs) {
    const wrappedText = wrapText(String(ayah.text ?? ''), 100).split('\n')
    const [firstLine, ...remainingLines] = wrappedText.length > 0 ? wrappedText : ['']
    lines.push('', `${pc.bold(String(ayah.numberInSurah ?? '-'))}. ${firstLine}`)
    for (const continuationLine of remainingLines) {
      lines.push(`   ${continuationLine}`)
    }
  }
  if (ayahs.length > displayLimit) {
    lines.push('', pc.dim(`… ${String(ayahs.length - displayLimit)} fetched ayah(s) not shown in text view`))
  }
  appendQuranCloudSurahNavigation(lines, query, surah, api, offset, displayLimit, totalAyahs, lastVisibleAyah)
  lines.push('', `${pc.dim('ayah')} public-apis apis run qurancloud.ayah -- --reference ${formatCliArg(`${String(surah.number ?? query.surah ?? 1)}:${String(firstVisibleAyah)}`)} --edition ${formatCliArg(query.edition ?? api.defaultEdition ?? 'en.asad')}`)
  return lines.join('\n')
}

function appendQuranCloudSurahNavigation(
  lines: string[],
  query: Record<string, unknown>,
  surah: Record<string, unknown>,
  api: Record<string, unknown>,
  offset: number,
  pageSize: number,
  totalAyahs: number | undefined,
  lastVisibleAyah: number,
): void {
  const surahNumber = surah.number ?? query.surah ?? 1
  const edition = query.edition ?? api.defaultEdition ?? 'en.asad'
  const previousOffset = Math.max(0, offset - pageSize)
  const hasPrevious = offset > 0
  const hasNext = totalAyahs === undefined ? false : lastVisibleAyah < totalAyahs
  if (!hasPrevious && !hasNext) {
    return
  }

  lines.push('')
  if (hasPrevious) {
    lines.push(`${pc.dim('previous page')} ${buildQuranCloudSurahCommand({ surah: surahNumber, edition, offset: previousOffset, limit: pageSize })}`)
  }
  if (hasNext) {
    lines.push(`${pc.dim('next page')} ${buildQuranCloudSurahCommand({ surah: surahNumber, edition, offset: lastVisibleAyah, limit: pageSize })}`)
  }
}

function buildQuranCloudSurahCommand(params: Record<string, unknown>): string {
  const parts = [
    'public-apis apis run qurancloud.surah --',
    `--surah ${formatCliArg(params.surah ?? 1)}`,
    `--edition ${formatCliArg(params.edition ?? 'en.asad')}`,
  ]
  if (params.offset !== undefined) {
    parts.push(`--offset ${formatCliArg(params.offset)}`)
  }
  parts.push(`--limit ${formatCliArg(params.limit ?? 20)}`)
  return parts.join(' ')
}

function renderMetMuseumSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const objects = Array.isArray(value.objects) ? value.objects.filter(isRecord) : []
  const objectIds = Array.isArray(value.objectIds) ? value.objectIds.filter(id => typeof id === 'number') : []
  const lines = [
    `${pc.bold(pc.cyan('Met Museum Search'))} ${pc.dim(String(api.endpoint ?? 'GET /search'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('total')} ${String(value.total ?? 0)} match(es) · ${String(value.count ?? objectIds.length)} id(s) kept · ${objects.length} detail(s)`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? '80 requests/second')}`,
  ]

  if (objectIds.length === 0) {
    lines.push('', pc.yellow('No Met Museum objects matched this query.'))
    lines.push(`${pc.dim('try')} ${buildMetMuseumSearchCommand({ query: 'cat', hasImages: true, limit: query.limit ?? 100, detailLimit: query.detailLimit ?? 5 })}`)
    lines.push(`${pc.dim('departments')} public-apis apis run metmuseum.departments -- --limit 100`)
    return lines.join('\n')
  }

  if (objects.length > 0) {
    for (const object of objects) {
      lines.push(...formatMetMuseumObjectLines(object))
    }
  } else {
    lines.push('', `object ids: ${objectIds.slice(0, 50).join(', ')}`)
  }
  lines.push('', `${pc.dim('again')} ${buildMetMuseumSearchCommand(query)}`)
  lines.push(`${pc.dim('object')} public-apis apis run metmuseum.object -- --object-id ${String(objectIds[0] ?? '<id>')}`)
  lines.push(`${pc.dim('departments')} public-apis apis run metmuseum.departments -- --limit 100`)
  return lines.join('\n')
}

function renderMetMuseumObject(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const object = isRecord(value.object) ? value.object : {}
  return [
    `${pc.bold(pc.cyan('Met Museum Object'))} ${pc.dim(String(api.endpoint ?? 'GET /objects/:objectID'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    ...formatMetMuseumObjectLines(object),
    '',
    `${pc.dim('search')} ${buildMetMuseumSearchCommand({ query: object.title ?? 'cat', hasImages: true, limit: 3, detailLimit: 1 })}`,
    `${pc.dim('departments')} public-apis apis run metmuseum.departments -- --limit 100`,
  ].join('\n')
}

function renderMetMuseumDepartments(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const departments = Array.isArray(value.departments) ? value.departments.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('Met Museum Departments'))} ${pc.dim(String(api.endpoint ?? 'GET /departments'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? departments.length)}`,
  ]

  if (departments.length === 0) {
    lines.push('', pc.yellow('No Met Museum departments returned.'))
    lines.push(`${pc.dim('try')} public-apis apis run metmuseum.departments -- --limit 100`)
    return lines.join('\n')
  }

  for (const department of departments) {
    lines.push(`- ${String(department.departmentId ?? '')} · ${String(department.displayName ?? '')}`)
  }
  const firstDepartment = departments[0] ?? {}
  lines.push('', `${pc.dim('search')} ${buildMetMuseumSearchCommand({ query: 'cat', departmentId: firstDepartment.departmentId, hasImages: true, limit: 10, detailLimit: 3 })}`)
  lines.push(`${pc.dim('again')} public-apis apis run metmuseum.departments -- --limit ${String(query.limit ?? 100)}`)
  return lines.join('\n')
}

function buildMetMuseumSearchCommand(query: Record<string, unknown>): string {
  const parts = ['public-apis apis run metmuseum.search --', `--query ${formatCliArg(query.query ?? 'cat')}`]
  if (typeof query.departmentId === 'number') {
    parts.push(`--department-id ${String(query.departmentId)}`)
  }
  if (typeof query.hasImages === 'boolean') {
    parts.push(`--has-images ${String(query.hasImages)}`)
  }
  if (typeof query.isPublicDomain === 'boolean') {
    parts.push(`--is-public-domain ${String(query.isPublicDomain)}`)
  }
  parts.push(`--limit ${String(query.limit ?? 100)}`)
  parts.push(`--detail-limit ${String(query.detailLimit ?? 5)}`)
  return parts.join(' ')
}

function renderNagerDateCountries(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const countries = Array.isArray(value.countries) ? value.countries.filter(isRecord) : []
  const year = readNagerDateYear(api, query)
  const lines = [
    `${pc.bold(pc.cyan('Nager.Date Countries'))} ${pc.dim(String(api.endpoint ?? 'GET /availablecountries'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? countries.length)} countr${countries.length === 1 ? 'y' : 'ies'} · cap ${String(api.countryLimitCap ?? 250)}`,
    `${pc.dim('rate')} ${api.noRateLimitClaim === true ? 'provider advertises no rate limit' : 'not documented'}`,
  ]

  if (countries.length === 0) {
    lines.push('', pc.yellow('No Nager.Date countries matched this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run nagerdate.countries -- --query United --limit ${String(query.limit ?? api.defaultCountryLimit ?? 20)}`)
    return lines.join('\n')
  }

  for (const country of countries.slice(0, 40)) {
    lines.push(`- ${String(country.countryCode ?? '')} · ${String(country.name ?? '')}`)
  }
  if (countries.length > 40) {
    lines.push(pc.dim(`showing 40 of ${countries.length} countries`))
  }
  lines.push('', `${pc.dim('next')} public-apis apis run nagerdate.holidays -- --country-code ${formatCliArg(countries[0]?.countryCode ?? api.defaultCountryCode ?? 'US')} --year ${String(year)}`)
  return lines.join('\n')
}

function renderNamedaysDate(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const countries = Array.isArray(value.countries) ? value.countries.filter(isRecord) : []
  const suppressedCountries = Array.isArray(value.suppressedCountries)
    ? value.suppressedCountries.filter((country): country is string => typeof country === 'string' && country.trim() !== '')
    : []
  const warningMessage = typeof value.warningMessage === 'string' ? value.warningMessage : undefined
  const date = readNamedaysDateParts(query, api)
  const previousDate = shiftNamedaysDate(date, -1)
  const nextDate = shiftNamedaysDate(date, 1)
  const country = typeof query.country === 'string' && query.country.trim() !== '' ? query.country : undefined
  const limit = typeof query.limit === 'number' ? query.limit : typeof api.defaultCountryLimit === 'number' ? api.defaultCountryLimit : 30
  const totalCountries = typeof value.totalCountries === 'number' ? value.totalCountries : countries.length + suppressedCountries.length
  const countSummary = suppressedCountries.length === 0
    ? `${String(value.count ?? countries.length)} countr${countries.length === 1 ? 'y' : 'ies'} · cap ${String(api.countryLimitCap ?? 30)}`
    : `${countries.length} shown of ${totalCountries} countries · hidden ${suppressedCountries.join(', ')} unstable entry · cap ${String(api.countryLimitCap ?? 30)}`
  const lines = [
    `${pc.bold(pc.cyan('Namedays Calendar Date'))} ${pc.dim(String(api.endpoint ?? 'GET /V2/date'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${countSummary}`,
    `${pc.dim('docs')} ${String(api.docs ?? 'https://nameday.abalin.net/docs/api')}`,
  ]
  if (warningMessage !== undefined) {
    lines.push(`${pc.dim('warning')} ${warningMessage}`)
  }

  if (countries.length === 0) {
    lines.push('', pc.yellow('No Namedays Calendar countries matched this date and filter.'))
    lines.push(`${pc.dim('today')} ${buildNamedaysDateCommand(date, { limit })}`)
    lines.push(`${pc.dim('prev day')} ${buildNamedaysDateCommand(previousDate, { country, limit })}`)
    lines.push(`${pc.dim('next day')} ${buildNamedaysDateCommand(nextDate, { country, limit })}`)
    if (country !== undefined) {
      lines.push(`${pc.dim('all countries')} ${buildNamedaysDateCommand(date, { limit })}`)
    }
    return lines.join('\n')
  }

  for (const entry of countries) {
    lines.push(`- ${String(entry.country ?? '')} · ${String(entry.names ?? '')}`)
  }
  lines.push('', `${pc.dim('search')} ${buildNamedaysNameCommand(firstNameFromNamedays(countries[0]), country)}`)
  lines.push(`${pc.dim('prev day')} ${buildNamedaysDateCommand(previousDate, { country, limit })}`)
  lines.push(`${pc.dim('next day')} ${buildNamedaysDateCommand(nextDate, { country, limit })}`)
  if (country !== undefined) {
    lines.push(`${pc.dim('all countries')} ${buildNamedaysDateCommand(date, { limit })}`)
  }
  return lines.join('\n')
}

function renderNamedaysName(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const matches = Array.isArray(value.matches) ? value.matches.filter(isRecord) : []
  const defaultDate = readNamedaysDateParts(query, api)
  const filteredCountry = typeof query.country === 'string' && query.country.trim() !== '' ? query.country : undefined
  const defaultName = typeof query.name === 'string' && query.name.trim() !== '' ? query.name : String(api.defaultName ?? 'John')
  const lines = [
    `${pc.bold(pc.cyan('Namedays Calendar Name Search'))} ${pc.dim(String(api.endpoint ?? 'POST /V2/getname'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? matches.length)} match(es) · cap ${String(api.matchLimitCap ?? 50)}`,
    `${pc.dim('docs')} ${String(api.docs ?? 'https://nameday.abalin.net/docs/api')}`,
  ]

  if (matches.length === 0) {
    lines.push('', pc.yellow('No Namedays Calendar matches found for this name/filter.'))
    lines.push(`${pc.dim('today')} ${buildNamedaysDateCommand(defaultDate, { country: filteredCountry })}`)
    lines.push(`${pc.dim('again')} ${buildNamedaysNameCommand(defaultName, filteredCountry)}`)
    return lines.join('\n')
  }

  for (const match of matches) {
    lines.push('', `${pc.bold(`${String(match.month ?? '?')}/${String(match.day ?? '?')}`)} · ${String(match.country ?? '')}`)
    lines.push(String(match.names ?? ''))
  }
  const firstMatch = matches[0]
  const firstMatchCountry = typeof firstMatch?.country === 'string' && firstMatch.country.trim() !== '' ? firstMatch.country : filteredCountry
  lines.push('', `${pc.dim('date')} ${buildNamedaysDateCommand({
    day: typeof firstMatch?.day === 'number' ? firstMatch.day : defaultDate.day,
    month: typeof firstMatch?.month === 'number' ? firstMatch.month : defaultDate.month,
  }, { country: firstMatchCountry })}`)
  lines.push(`${pc.dim('today')} ${buildNamedaysDateCommand(defaultDate, { country: filteredCountry })}`)
  if (filteredCountry === undefined && firstMatchCountry !== undefined) {
    lines.push(`${pc.dim('same country')} ${buildNamedaysNameCommand(defaultName, firstMatchCountry)}`)
  }
  return lines.join('\n')
}

function renderNagerDateHolidays(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const holidays = Array.isArray(value.holidays) ? value.holidays.filter(isRecord) : []
  const countryCode = String(query.countryCode ?? api.defaultCountryCode ?? 'US')
  const year = readNagerDateYear(api, query)
  const lines = [
    `${pc.bold(pc.cyan('Nager.Date Public Holidays'))} ${pc.dim(String(api.endpoint ?? 'GET /publicholidays/{year}/{countryCode}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? holidays.length)} holiday(s)`,
    `${pc.dim('rate')} ${api.noRateLimitClaim === true ? 'provider advertises no rate limit' : 'not documented'}`,
  ]

  if (holidays.length === 0) {
    lines.push('', pc.yellow('No Nager.Date holidays matched this query and filters.'))
    lines.push(`${pc.dim('try')} public-apis apis run nagerdate.holidays -- --country-code ${formatCliArg(countryCode)} --year ${String(year)}`)
    lines.push(`${pc.dim('countries')} public-apis apis run nagerdate.countries -- --query ${formatCliArg(countryCode)}`)
    return lines.join('\n')
  }

  for (const holiday of holidays) {
    const types = Array.isArray(holiday.types) ? holiday.types.filter((type): type is string => typeof type === 'string') : []
    const counties = Array.isArray(holiday.counties) ? holiday.counties.filter((county): county is string => typeof county === 'string') : []
    const scope = holiday.global === true ? 'global' : counties.slice(0, 4).join(', ')
    lines.push('', `${pc.bold(String(holiday.date ?? 'date'))} · ${String(holiday.name ?? 'holiday')}`)
    if (typeof holiday.localName === 'string' && holiday.localName !== holiday.name) {
      lines.push(`local: ${holiday.localName}`)
    }
    lines.push(pc.dim([String(holiday.countryCode ?? ''), holiday.fixed === true ? 'fixed' : 'variable', scope, types.join('/')].filter(part => part !== '').join(' · ')))
  }
  lines.push('', `${pc.dim('again')} public-apis apis run nagerdate.holidays -- --country-code ${formatCliArg(countryCode)} --year ${String(year)}`)
  lines.push(`${pc.dim('next year')} public-apis apis run nagerdate.holidays -- --country-code ${formatCliArg(countryCode)} --year ${String(year + 1)}`)
  lines.push(`${pc.dim('countries')} public-apis apis run nagerdate.countries -- --query ${formatCliArg(countryCode)}`)
  return lines.join('\n')
}

function readNagerDateYear(api: Record<string, unknown>, query: Record<string, unknown>): number {
  const year = query.year ?? api.defaultYear
  return typeof year === 'number' && Number.isInteger(year) ? year : new Date().getFullYear()
}

function renderUkBankHolidaysEvents(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const divisions = Array.isArray(value.divisions) ? value.divisions.filter(isRecord) : []
  const events = Array.isArray(value.events) ? value.events.filter(isRecord) : []
  const year = readUkBankHolidaysYear(api, query)
  const currentYear = readUkBankHolidaysDefaultYear(api)
  const division = typeof query.division === 'string' && query.division.trim() !== '' ? query.division : undefined
  const limit = typeof query.limit === 'number' ? query.limit : typeof api.defaultLimit === 'number' ? api.defaultLimit : 100
  const totalEvents = typeof value.totalEvents === 'number' ? value.totalEvents : events.length
  const shownLabel = totalEvents > events.length
    ? `${String(events.length)} shown of ${String(totalEvents)} event(s) · limit ${String(limit)} · cap ${String(api.limitCap ?? 200)}`
    : `${String(value.count ?? events.length)} event(s) shown · limit ${String(limit)} · cap ${String(api.limitCap ?? 200)}`
  const divisionLabel = divisions.length > 0
    ? divisions.map(entry => `${String(entry.division ?? '-')}:${String(entry.count ?? 0)}`).join(' · ')
    : division ?? 'none'
  const lines = [
    `${pc.bold(pc.cyan('UK Bank Holidays'))} ${pc.dim(String(api.endpoint ?? 'GET /bank-holidays.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${shownLabel}`,
    `${pc.dim('divisions')} ${divisionLabel}`,
  ]

  if (events.length === 0) {
    lines.push('', pc.yellow('No UK bank holidays matched this query.'))
    lines.push(`${pc.dim('current year')} ${buildUkBankHolidaysCommand({ division, year: currentYear, limit })}`)
    if (query.upcoming === true) {
      lines.push(`${pc.dim('same year')} ${buildUkBankHolidaysCommand({ division, year, limit })}`)
    } else {
      lines.push(`${pc.dim('upcoming')} ${buildUkBankHolidaysCommand({ division, year: currentYear, upcoming: true, limit })}`)
    }
    if (division === undefined) {
      lines.push(`${pc.dim('england+wales')} ${buildUkBankHolidaysCommand({ division: 'england-and-wales', year: currentYear, limit })}`)
    } else {
      lines.push(`${pc.dim('all divisions')} ${buildUkBankHolidaysCommand({ year: currentYear, limit })}`)
    }
    return lines.join('\n')
  }

  for (const event of events.slice(0, 40)) {
    const notes = typeof event.notes === 'string' && event.notes.trim() !== '' ? ` · ${event.notes}` : ''
    const bunting = event.bunting === true ? ' · bunting' : ''
    lines.push(`${pc.bold(String(event.date ?? '?'))} ${String(event.division ?? '-')} · ${String(event.title ?? '(untitled)')}${notes}${bunting}`)
  }
  if (events.length > 40) {
    lines.push(pc.dim(`… ${events.length - 40} more event(s); use --format json for the full list.`))
  }
  lines.push('', `${pc.dim('again')} ${buildUkBankHolidaysCommand({ division, year, upcoming: query.upcoming === true, limit })}`)
  lines.push(`${pc.dim('next year')} ${buildUkBankHolidaysCommand({ division, year: year + 1, upcoming: query.upcoming === true, limit })}`)
  if (year > 1900) {
    lines.push(`${pc.dim('prev year')} ${buildUkBankHolidaysCommand({ division, year: year - 1, upcoming: query.upcoming === true, limit })}`)
  }
  if (division === undefined) {
    lines.push(`${pc.dim('scotland')} ${buildUkBankHolidaysCommand({ division: 'scotland', year, limit })}`)
    lines.push(`${pc.dim('england+wales')} ${buildUkBankHolidaysCommand({ division: 'england-and-wales', year, limit })}`)
  } else {
    lines.push(`${pc.dim('all divisions')} ${buildUkBankHolidaysCommand({ year, upcoming: query.upcoming === true, limit })}`)
  }
  if (query.upcoming === true) {
    lines.push(`${pc.dim('full year')} ${buildUkBankHolidaysCommand({ division, year, limit })}`)
  } else {
    lines.push(`${pc.dim('upcoming')} ${buildUkBankHolidaysCommand({ division, year, upcoming: true, limit })}`)
  }
  return lines.join('\n')
}

function readUkBankHolidaysYear(api: Record<string, unknown>, query: Record<string, unknown>): number {
  const year = query.year ?? api.defaultYear
  return typeof year === 'number' && Number.isInteger(year) ? year : new Date().getFullYear()
}

function readUkBankHolidaysDefaultYear(api: Record<string, unknown>): number {
  return typeof api.defaultYear === 'number' && Number.isInteger(api.defaultYear) ? api.defaultYear : new Date().getFullYear()
}

function buildUkBankHolidaysCommand(params: {
  division?: string | undefined
  year: number
  upcoming?: boolean | undefined
  limit?: number | undefined
}): string {
  const parts = ['public-apis apis run ukbankholidays.events --', `--year ${String(params.year)}`]
  if (typeof params.division === 'string' && params.division.trim() !== '') {
    parts.push(`--division ${formatCliArg(params.division)}`)
  }
  if (params.upcoming === true) {
    parts.push('--upcoming true')
  }
  if (typeof params.limit === 'number') {
    parts.push(`--limit ${String(params.limit)}`)
  }
  return parts.join(' ')
}

function renderUkPoliceStreetCrimes(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const crimes = Array.isArray(value.crimes) ? value.crimes.filter(isRecord) : []
  const args = buildUkPoliceStreetCrimesArgs(query, pagination)
  const endpoint = String(api.endpoint ?? 'GET /api/crimes-street/{category}')
  const boundary = 'open REST API only · no auth · no Chrome clickstream'
  const safety = String(
    api.safety ??
      [
        'Read-only public street-crime records only; reporting/contact/',
        'person-search surfaces are not exposed.',
      ].join(''),
  )
  const returned = String(pagination.returned ?? crimes.length)
  const totalAvailable = String(pagination.totalAvailable ?? '?')
  const limit = String(pagination.limit ?? query.limit ?? '?')
  const maxLimit = String(pagination.maxLimit ?? '?')
  const title = [
    pc.bold(pc.cyan('UK Police Street-level Crimes')),
    pc.dim(endpoint),
  ].join(' ')
  const lines = [
    title,
    `${pc.dim('mode')} ${formatStorageMode(value)}`,
    `${pc.dim('boundary')} ${boundary} · public approximate street-level open data`,
    [
      `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS JSON REST')}`,
      String(api.platform ?? 'data.police.uk API'),
    ].join(' · '),
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('safety')} ${safety}`,
    [
      `${pc.dim('pagination')} returned ${returned} / available ${totalAvailable}`,
      `limit ${limit}`,
      `max ${maxLimit}`,
    ].join(' · '),
  ]
  if (typeof value.latestKnownDate === 'string') {
    lines.push(`${pc.dim('data month')} ${value.latestKnownDate}`)
  }

  if (crimes.length === 0) {
    lines.push('', pc.yellow('No UK Police street-crime rows returned for this query.'))
    lines.push(
      [
        pc.dim('again'),
        'public-apis apis run ukpolice.streetCrimes --online --persist --',
        args,
      ].join(' '),
    )
    lines.push(
      [
        pc.dim('sample'),
        'public-apis apis run ukpolice.streetCrimes --online --persist --',
        '--latitude 52.629729 --longitude -1.131592',
        '--category all-crime --limit 25',
      ].join(' '),
    )
    lines.push(
      [
        pc.dim('category'),
        'public-apis apis run ukpolice.streetCrimes --online --persist --',
        `--latitude ${formatCliArg(query.latitude ?? 52.629729)}`,
        `--longitude ${formatCliArg(query.longitude ?? -1.131592)}`,
        `--category anti-social-behaviour --limit ${limit}`,
      ].join(' '),
    )
    lines.push(
      [
        pc.dim('replay'),
        `public-apis apis run ukpolice.streetCrimes --offline -- ${args}`,
      ].join(' '),
    )
    return lines.join('\n')
  }

  for (const crime of crimes.slice(0, 30)) {
    const location = isRecord(crime.location) ? crime.location : {}
    const outcome = isRecord(crime.outcomeStatus) ? crime.outcomeStatus : {}
    const details = [
      typeof crime.month === 'string' ? crime.month : undefined,
      typeof location.streetName === 'string' ? location.streetName : undefined,
      typeof outcome.category === 'string' ? `outcome ${outcome.category}` : undefined,
      crime.persistentIdPresent === true ? 'persistent id present' : undefined,
    ].filter(
      (entry): entry is string =>
        typeof entry === 'string' && entry.trim() !== '',
    )
    lines.push(
      '',
      [
        pc.bold(String(crime.category ?? 'crime')),
        pc.dim(`#${String(crime.id ?? '?')}`),
      ].join(' '),
    )
    if (details.length > 0) {
      lines.push(pc.dim(details.join(' · ')))
    }
    const hasCoordinates = typeof location.latitude === 'number' &&
      typeof location.longitude === 'number'
    if (hasCoordinates) {
      lines.push(
        [
          pc.dim('approx coords'),
          `${String(location.latitude)}, ${String(location.longitude)}`,
        ].join(' '),
      )
    }
  }
  if (crimes.length > 30) {
    const moreRows = [
      `… ${crimes.length - 30} more crime row(s);`,
      'use --format json.',
    ].join(' ')
    lines.push(pc.dim(moreRows))
  }
  lines.push(
    '',
    [
      pc.dim('again'),
      'public-apis apis run ukpolice.streetCrimes --online --persist --',
      args,
    ].join(' '),
  )
  lines.push(
    [
      pc.dim('replay'),
      `public-apis apis run ukpolice.streetCrimes --offline -- ${args}`,
    ].join(' '),
  )
  lines.push(
    [
      pc.dim('category'),
      'public-apis apis run ukpolice.streetCrimes --online --persist --',
      `--latitude ${formatCliArg(query.latitude ?? 52.629729)}`,
      `--longitude ${formatCliArg(query.longitude ?? -1.131592)}`,
      `--category anti-social-behaviour --limit ${limit}`,
    ].join(' '),
  )
  return lines.join('\n')
}

function buildUkPoliceStreetCrimesArgs(
  query: Record<string, unknown>,
  pagination: Record<string, unknown> = {},
): string {
  const parts = [
    '--latitude',
    formatCliArg(query.latitude ?? 52.629729),
    '--longitude',
    formatCliArg(query.longitude ?? -1.131592),
    '--category',
    formatCliArg(query.category ?? 'all-crime'),
  ]
  if (typeof query.date === 'string' && query.date.trim() !== '') {
    parts.push('--date', formatCliArg(query.date))
  }
  parts.push('--limit', String(pagination.limit ?? query.limit ?? 25))
  return parts.join(' ')
}

function renderApisGuruProviders(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const providers = Array.isArray(value.providers) ? value.providers.filter((entry): entry is string => typeof entry === 'string') : []
  const limitCap = typeof api.limitCap === 'number' ? api.limitCap : 100
  const queryLimit = typeof query.limit === 'number' ? query.limit : providers.length
  const matchedProviders = typeof value.matchedProviders === 'number' ? value.matchedProviders : providers.length
  const firstProvider = providers[0] ?? 'googleapis.com'
  const lines = [
    `${pc.bold(pc.cyan('APIs.guru Providers'))} ${pc.dim(String(api.endpoint ?? 'GET /providers.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? providers.length)} shown · matched ${String(matchedProviders)} · total providers ${String(value.totalProviders ?? providers.length)} · limit cap ${String(limitCap)}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'not documented')}`,
  ]

  if (providers.length === 0) {
    lines.push('', pc.yellow('No APIs.guru providers matched this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run apisguru.providers -- --query google --limit 20`)
    lines.push(`${pc.dim('search')} public-apis apis run apisguru.search -- --query openapi --limit 20`)
    return lines.join('\n')
  }

  for (const provider of providers.slice(0, 50)) {
    lines.push(`- ${provider}`)
  }
  if (providers.length > 50) {
    lines.push(pc.dim(`… ${providers.length - 50} more provider(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('search')} public-apis apis run apisguru.search -- --provider ${formatCliArg(firstProvider)} --limit 20`)
  if (matchedProviders > providers.length && queryLimit < limitCap) {
    lines.push(`${pc.dim('more')} ${buildApisGuruProvidersCommand(query, Math.min(limitCap, Math.max(queryLimit + 20, providers.length + 20)))}`)
  }
  lines.push(`${pc.dim('metrics')} public-apis apis run apisguru.metrics`)
  return lines.join('\n')
}

function renderApisGuruSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const apis = Array.isArray(value.apis) ? value.apis.filter(isRecord) : []
  const limitCap = typeof api.limitCap === 'number' ? api.limitCap : 100
  const queryLimit = typeof query.limit === 'number' ? query.limit : apis.length
  const matchedApis = typeof value.matchedApis === 'number' ? value.matchedApis : apis.length
  const lines = [
    `${pc.bold(pc.cyan('APIs.guru Search'))} ${pc.dim(String(api.endpoint ?? 'GET /list.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? apis.length)} shown · matched ${String(matchedApis)} · total APIs ${String(value.totalApis ?? '?')} · upstream pagination ${String(api.upstreamPagination ?? 'none')}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'not documented')} · ${pc.dim('limit cap')} ${String(limitCap)}`,
  ]

  if (apis.length === 0) {
    lines.push('', pc.yellow('No APIs.guru API entries matched this query and filters.'))
    lines.push(`${pc.dim('try')} public-apis apis run apisguru.search -- --query openapi --limit 20`)
    lines.push(`${pc.dim('providers')} public-apis apis run apisguru.providers -- --limit 20`)
    return lines.join('\n')
  }

  for (const entry of apis.slice(0, 20)) {
    const categories = Array.isArray(entry.categories) ? entry.categories.filter((category): category is string => typeof category === 'string') : []
    const summary = [
      entry.providerName,
      typeof entry.serviceName === 'string' ? `service ${entry.serviceName}` : undefined,
      typeof entry.version === 'string' ? `version ${entry.version}` : undefined,
      entry.preferred === true ? 'preferred' : undefined,
      entry.unofficial === true ? 'unofficial' : undefined,
      categories.join(', '),
    ].filter((part): part is string => typeof part === 'string' && part.trim() !== '')
    lines.push('', `${pc.bold(String(entry.title ?? entry.id ?? 'API'))} ${pc.dim(String(entry.id ?? ''))}`)
    lines.push(pc.dim(summary.join(' · ')))
    if (typeof entry.updated === 'string') {
      lines.push(`updated: ${entry.updated}`)
    }
    if (typeof entry.description === 'string' && entry.description.trim() !== '') {
      lines.push(wrapLine(truncateText(entry.description.replace(/\s+/gu, ' ').trim(), 180), 110))
    }
    if (typeof entry.swaggerUrl === 'string') {
      lines.push(`json: ${pc.blue(entry.swaggerUrl)}`)
    }
    if (typeof entry.swaggerYamlUrl === 'string') {
      lines.push(`yaml: ${pc.blue(entry.swaggerYamlUrl)}`)
    }
  }
  if (apis.length > 20) {
    lines.push(pc.dim(`… ${apis.length - 20} more API entr${apis.length - 20 === 1 ? 'y' : 'ies'}; use --format json for full output.`))
  }
  const firstEntry = apis[0] ?? {}
  const firstCategory = Array.isArray(firstEntry.categories) ? firstEntry.categories.find((category): category is string => typeof category === 'string') : undefined
  lines.push('')
  if (typeof firstEntry.providerName === 'string') {
    lines.push(`${pc.dim('provider')} public-apis apis run apisguru.search -- --provider ${formatCliArg(firstEntry.providerName)} --limit 20`)
  }
  if (typeof firstCategory === 'string') {
    lines.push(`${pc.dim('category')} public-apis apis run apisguru.search -- --category ${formatCliArg(firstCategory)} --limit 20`)
  }
  if (matchedApis > apis.length && queryLimit < limitCap) {
    lines.push(`${pc.dim('more')} ${buildApisGuruSearchCommand(query, Math.min(limitCap, Math.max(queryLimit + 20, apis.length + 20)))}`)
  }
  lines.push(`${pc.dim('providers')} public-apis apis run apisguru.providers -- --limit 20`)
  lines.push(`${pc.dim('metrics')} public-apis apis run apisguru.metrics`)
  return lines.join('\n')
}

function renderApisGuruMetrics(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const metrics = isRecord(value.metrics) ? value.metrics : {}
  const datasets = Array.isArray(value.datasets) ? value.datasets.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('APIs.guru Metrics'))} ${pc.dim(String(api.endpoint ?? 'GET /metrics.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} none`,
    `${pc.dim('count')} specs ${String(metrics.numSpecs ?? '?')} · APIs ${String(metrics.numAPIs ?? '?')} · endpoints ${String(metrics.numEndpoints ?? '?')} · providers ${String(metrics.numProviders ?? '?')}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'not documented')}`,
  ]

  const quality = [
    typeof metrics.unreachable === 'number' ? `unreachable ${String(metrics.unreachable)}` : undefined,
    typeof metrics.invalid === 'number' ? `invalid ${String(metrics.invalid)}` : undefined,
    typeof metrics.unofficial === 'number' ? `unofficial ${String(metrics.unofficial)}` : undefined,
    typeof metrics.fixedPct === 'number' ? `fixed ${String(metrics.fixedPct)}%` : undefined,
  ].filter((part): part is string => part !== undefined)
  if (quality.length > 0) {
    lines.push(`${pc.dim('quality')} ${quality.join(' · ')}`)
  }

  const thisWeek = isRecord(metrics.thisWeek) ? metrics.thisWeek : {}
  if (Object.keys(thisWeek).length > 0) {
    lines.push(`${pc.dim('this week')} added ${String(thisWeek.added ?? 0)} · updated ${String(thisWeek.updated ?? 0)}`)
  }

  for (const dataset of datasets.slice(0, 3)) {
    const top = Array.isArray(dataset.top) ? dataset.top.filter(isRecord) : []
    lines.push('', pc.bold(String(dataset.title ?? 'Dataset')))
    if (top.length === 0) {
      lines.push(pc.yellow('No metric rows returned for this dataset.'))
      continue
    }
    for (const row of top.slice(0, 10)) {
      lines.push(`- ${String(row.key ?? '-')}: ${String(row.value ?? 0)}`)
    }
  }

  const topProvider = findApisGuruTopProvider(datasets)
  lines.push('')
  if (topProvider !== undefined) {
    lines.push(`${pc.dim('top provider')} public-apis apis run apisguru.search -- --provider ${formatCliArg(topProvider)} --limit 20`)
  }
  lines.push(`${pc.dim('search')} public-apis apis run apisguru.search -- --query openapi --limit 20`)
  lines.push(`${pc.dim('providers')} public-apis apis run apisguru.providers -- --limit 20`)
  return lines.join('\n')
}

function buildApisGuruProvidersCommand(query: Record<string, unknown>, limit: number): string {
  const parts = ['public-apis apis run apisguru.providers --']
  if (typeof query.query === 'string' && query.query.trim() !== '') {
    parts.push(`--query ${formatCliArg(query.query)}`)
  }
  parts.push(`--limit ${String(limit)}`)
  return parts.join(' ')
}

function buildApisGuruSearchCommand(query: Record<string, unknown>, limit: number): string {
  const parts = ['public-apis apis run apisguru.search --']
  if (typeof query.query === 'string' && query.query.trim() !== '') {
    parts.push(`--query ${formatCliArg(query.query)}`)
  }
  if (typeof query.category === 'string' && query.category.trim() !== '') {
    parts.push(`--category ${formatCliArg(query.category)}`)
  }
  if (typeof query.provider === 'string' && query.provider.trim() !== '') {
    parts.push(`--provider ${formatCliArg(query.provider)}`)
  }
  if (query.includeUnofficial === true) {
    parts.push('--include-unofficial true')
  }
  if (typeof query.sort === 'string' && query.sort !== 'updated') {
    parts.push(`--sort ${formatCliArg(query.sort)}`)
  }
  parts.push(`--limit ${String(limit)}`)
  return parts.join(' ')
}

function findApisGuruTopProvider(datasets: Record<string, unknown>[]): string | undefined {
  for (const dataset of datasets) {
    if (dataset.title !== 'providerCount') {
      continue
    }
    const top = Array.isArray(dataset.top) ? dataset.top.filter(isRecord) : []
    const provider = top.find(row => typeof row.key === 'string' && row.key !== 'Others')
    if (typeof provider?.key === 'string') {
      return provider.key
    }
  }
  return undefined
}

function renderCdnjsSearch(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const pagination = isRecord(value.pagination) ? value.pagination : {}
  const libraries = Array.isArray(value.libraries) ? value.libraries.filter(isRecord) : []
  const firstLibrary = libraries[0]
  const lines = [
    `${pc.bold(pc.cyan('CDNJS Library Search'))} ${pc.dim(String(api.endpoint ?? 'GET /libraries'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? libraries.length)} shown · returned ${String(pagination.total ?? libraries.length)} · catalog available ${String(pagination.available ?? '?')} · limit cap ${String(api.limitCap ?? 1000)}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'not documented')}`,
  ]

  if (libraries.length === 0) {
    lines.push('', pc.yellow('No CDNJS libraries matched this query.'))
    lines.push(`${pc.dim('try')} public-apis apis run cdnjs.search -- --query react --limit 1000`)
    return lines.join('\n')
  }

  for (const library of libraries.slice(0, 30)) {
    const github = isRecord(library.github) ? library.github : {}
    const meta = [
      library.version,
      library.license,
      typeof github.stars === 'number' ? `★ ${String(github.stars)}` : undefined,
      Array.isArray(library.keywords) ? library.keywords.filter((keyword): keyword is string => typeof keyword === 'string').slice(0, 4).join(', ') : undefined,
    ].filter((part): part is string => typeof part === 'string' && part.trim() !== '')
    lines.push('', `${pc.bold(String(library.name ?? 'library'))} ${pc.dim(meta.join(' · '))}`)
    if (typeof library.description === 'string') {
      lines.push(wrapLine(cleanCdnjsText(library.description), 110))
    }
    if (typeof library.latest === 'string' && library.latest !== '') {
      lines.push(`latest: ${pc.blue(library.latest)}`)
    }
  }
  if (libraries.length > 30) {
    lines.push(pc.dim(`… ${libraries.length - 30} more librar${libraries.length - 30 === 1 ? 'y' : 'ies'}; use --format json for full output.`))
  }
  lines.push('', `${pc.dim('library')} public-apis apis run cdnjs.library -- --name ${formatCliArg(firstLibrary?.name ?? 'jquery')} --version-limit 20`)
  if (typeof firstLibrary?.version === 'string') {
    lines.push(`${pc.dim('version')} public-apis apis run cdnjs.version -- --name ${formatCliArg(firstLibrary.name ?? 'jquery')} --version ${formatCliArg(firstLibrary.version)} --file-limit 50`)
  }
  lines.push(`${pc.dim('compare')} public-apis apis run cdnjs.search -- --query react --limit 20`)
  return lines.join('\n')
}

function renderCdnjsLibrary(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const library = isRecord(value.library) ? value.library : {}
  const assets = Array.isArray(library.assets) ? library.assets.filter(isRecord) : []
  const github = isRecord(library.github) ? library.github : {}
  const lines = [
    `${pc.bold(pc.cyan('CDNJS Library'))} ${pc.dim(String(api.endpoint ?? 'GET /libraries/{library}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? assets.length)} version(s) shown · version cap ${String(api.versionLimitCap ?? 200)} · file cap ${String(api.fileLimitCap ?? 500)}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'not documented')}`,
  ]

  lines.push('', `${pc.bold(String(library.name ?? query.name ?? 'library'))} ${pc.dim(String(library.version ?? ''))}`)
  if (typeof library.description === 'string') {
    lines.push(wrapLine(cleanCdnjsText(library.description), 110))
  }
  const meta = [
    library.license,
    typeof github.stars === 'number' ? `★ ${String(github.stars)}` : undefined,
    typeof library.repositoryUrl === 'string' ? `repo ${library.repositoryUrl}` : undefined,
  ].filter((part): part is string => typeof part === 'string' && part.trim() !== '')
  if (meta.length > 0) {
    lines.push(pc.dim(meta.join(' · ')))
  }
  if (typeof library.latest === 'string' && library.latest !== '') {
    lines.push(`latest: ${pc.blue(library.latest)}`)
  }
  const scriptSnippet = buildCdnjsScriptTag(library.latest, library.sri)
  if (scriptSnippet !== undefined) {
    lines.push(`${pc.dim('script')} ${scriptSnippet}`)
  }

  if (assets.length === 0) {
    lines.push('', pc.yellow('No CDNJS versions/assets returned for this library.'))
    lines.push(`${pc.dim('try')} public-apis apis run cdnjs.search -- --query ${String(query.name ?? 'jquery')}`)
    return lines.join('\n')
  }

  for (const asset of assets.slice(0, 10)) {
    const files = Array.isArray(asset.files) ? asset.files.filter(isRecord) : []
    lines.push('', `${pc.bold(`v${String(asset.version ?? '?')}`)} ${pc.dim(`${String(asset.fileCount ?? files.length)} file(s)`)}`)
    for (const file of files.slice(0, 8)) {
      lines.push(`- ${String(file.name ?? 'file')} ${typeof file.sri === 'string' ? pc.dim('SRI') : ''}`)
    }
    if (files.length > 8) {
      lines.push(pc.dim(`  … ${files.length - 8} more file(s); use --format json for full output.`))
    }
  }
  if (assets.length > 10) {
    lines.push(pc.dim(`… ${assets.length - 10} more version(s); increase --version-limit or use --format json.`))
  }
  lines.push('', `${pc.dim('version')} public-apis apis run cdnjs.version -- --name ${formatCliArg(query.name ?? library.name ?? 'jquery')} --version ${formatCliArg(library.version ?? '3.7.1')} --file-limit ${String(query.fileLimit ?? 50)}`)
  lines.push(`${pc.dim('search')} public-apis apis run cdnjs.search -- --query ${formatCliArg(query.name ?? library.name ?? 'jquery')} --limit 20`)
  return lines.join('\n')
}

function renderCdnjsVersion(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const files = Array.isArray(value.files) ? value.files.filter(isRecord) : []
  const totalFiles = typeof value.totalFiles === 'number' ? value.totalFiles : files.length
  const firstScript = files.find(file => typeof file.url === 'string' && String(file.name ?? '').endsWith('.min.js'))
    ?? files.find(file => typeof file.url === 'string' && String(file.name ?? '').endsWith('.js'))
  const lines = [
    `${pc.bold(pc.cyan('CDNJS Version Files'))} ${pc.dim(String(api.endpoint ?? 'GET /libraries/{library}/{version}'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? files.length)} file(s) shown · total files ${String(totalFiles)} · file cap ${String(api.fileLimitCap ?? 500)}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'not documented')}`,
  ]

  if (files.length === 0) {
    lines.push('', pc.yellow('No CDNJS files returned for this library version.'))
    lines.push(`${pc.dim('try')} public-apis apis run cdnjs.library -- --name ${String(query.name ?? 'jquery')}`)
    return lines.join('\n')
  }

  const scriptSnippet = buildCdnjsScriptTag(firstScript?.url, firstScript?.sri)
  if (scriptSnippet !== undefined) {
    lines.push('', `${pc.dim('script')} ${scriptSnippet}`)
  }

  for (const file of files.slice(0, 40)) {
    lines.push('', `${pc.bold(String(file.name ?? 'file'))} ${typeof file.sri === 'string' ? pc.dim('SRI available') : pc.dim('no SRI')}`)
    if (typeof file.url === 'string') {
      lines.push(pc.blue(file.url))
    }
    if (typeof file.sri === 'string') {
      lines.push(pc.dim(file.sri))
    }
  }
  if (files.length > 40) {
    lines.push(pc.dim(`… ${files.length - 40} more file(s); use --format json for full output.`))
  }
  lines.push('')
  if (totalFiles > files.length) {
    lines.push(`${pc.dim('more')} public-apis apis run cdnjs.version -- --name ${formatCliArg(query.name ?? 'jquery')} --version ${formatCliArg(query.version ?? '3.7.1')} --file-limit ${String(Math.min(typeof api.fileLimitCap === 'number' ? api.fileLimitCap : 500, totalFiles))}`)
  }
  lines.push(`${pc.dim('library')} public-apis apis run cdnjs.library -- --name ${formatCliArg(query.name ?? 'jquery')} --version-limit 20`)
  lines.push(`${pc.dim('search')} public-apis apis run cdnjs.search -- --query ${formatCliArg(query.name ?? 'jquery')} --limit 20`)
  return lines.join('\n')
}

function cleanCdnjsText(value: string): string {
  return value
    .replace(/&amp;/gu, '&')
    .replace(/&lt;/gu, '<')
    .replace(/&gt;/gu, '>')
    .replace(/&quot;/gu, '"')
    .replace(/&#39;|&apos;/gu, "'")
    .replace(/\s+/gu, ' ')
    .trim()
}

function buildCdnjsScriptTag(url: unknown, sri: unknown): string | undefined {
  if (typeof url !== 'string' || url.trim() === '' || !url.endsWith('.js')) {
    return undefined
  }
  const integrity = typeof sri === 'string' && sri.trim() !== '' ? ` integrity="${sri}"` : ''
  return `<script src="${url}"${integrity} crossorigin="anonymous" referrerpolicy="no-referrer"></script>`
}

function renderCloudflareTrace(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const trace = isRecord(value.trace) ? value.trace : {}
  const fields = isRecord(value.fields) ? value.fields : {}
  const currentEndpoint = typeof query.endpoint === 'string' ? query.endpoint : String(api.defaultEndpoint ?? 'one.one.one.one')
  const nextEndpoint = currentEndpoint === 'cloudflare.com' ? String(api.defaultEndpoint ?? 'one.one.one.one') : 'cloudflare.com'
  const lines = [
    `${pc.bold(pc.cyan('Cloudflare Trace'))} ${pc.dim(String(api.endpoint ?? 'GET /cdn-cgi/trace'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('transport')} ${String(api.transport ?? 'HTTPS text/plain key-value')}`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(Object.keys(fields).length)} field(s) parsed`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'not documented')}`,
  ]

  const summary = [
    typeof trace.ip === 'string' ? `ip ${trace.ip}` : undefined,
    typeof trace.country === 'string' ? `country ${trace.country}` : undefined,
    typeof trace.colo === 'string' ? `colo ${trace.colo}` : undefined,
    typeof trace.http === 'string' ? trace.http : undefined,
    typeof trace.tls === 'string' ? trace.tls : undefined,
  ].filter((part): part is string => typeof part === 'string' && part.trim() !== '')
  if (summary.length > 0) {
    lines.push(`${pc.dim('summary')} ${summary.join(' · ')}`)
  }
  if (typeof query.url === 'string') {
    lines.push(`${pc.dim('url')} ${pc.blue(query.url)}`)
  }

  const rows = [
    ['host', trace.host],
    ['cloudflareWorker', trace.cloudflareWorker],
    ['timestamp', trace.timestamp],
    ['visitScheme', trace.visitScheme],
    ['userAgent', trace.userAgent],
    ['sliver', trace.sliver],
    ['sni', trace.sni],
    ['warp', trace.warp],
    ['gateway', trace.gateway],
    ['rbi', trace.rbi],
    ['keyExchange', trace.keyExchange],
  ].filter(([, entry]) => entry !== undefined && entry !== '')
  if (rows.length === 0) {
    lines.push('', pc.yellow('No recognized Cloudflare Trace fields were parsed.'))
    lines.push(`${pc.dim('try')} public-apis apis run cloudflaretrace.trace -- --endpoint ${formatCliArg(nextEndpoint)}`)
    return lines.join('\n')
  }

  lines.push('')
  for (const [label, entry] of rows) {
    lines.push(`${label}: ${String(entry)}`)
  }
  if (typeof value.raw === 'string') {
    lines.push('', pc.dim('raw response included in JSON result; use --format json for exact key=value text.'))
  }
  lines.push('', `${pc.dim(currentEndpoint === 'cloudflare.com' ? 'compare' : 'next')} public-apis apis run cloudflaretrace.trace -- --endpoint ${formatCliArg(nextEndpoint)}`)
  return lines.join('\n')
}

function renderDigitalOceanStatusSummary(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const page = isRecord(value.page) ? value.page : {}
  const status = isRecord(value.status) ? value.status : {}
  const totals = isRecord(value.totals) ? value.totals : {}
  const components = Array.isArray(value.components) ? value.components.filter(isRecord) : []
  const activeIncidents = Array.isArray(value.activeIncidents) ? value.activeIncidents.filter(isRecord) : []
  const scheduledMaintenances = Array.isArray(value.scheduledMaintenances) ? value.scheduledMaintenances.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('DigitalOcean Status Summary'))} ${pc.dim(String(api.endpoint ?? 'GET /summary.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('status')} ${String(status.indicator ?? 'unknown')} · ${String(status.description ?? '')}`,
    `${pc.dim('count')} ${String(value.count ?? components.length)} component(s) shown · total ${String(totals.components ?? '?')} · incidents ${String(totals.incidents ?? 0)} · maintenances ${String(totals.scheduledMaintenances ?? 0)}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'not documented')} · ${String(api.cacheControl ?? 'cache-control not projected')}`,
  ]
  if (typeof page.updatedAt === 'string') {
    lines.push(`${pc.dim('updated')} ${page.updatedAt}`)
  }

  if (activeIncidents.length > 0) {
    lines.push('', pc.bold('Active Incidents'))
    for (const event of activeIncidents.slice(0, 5)) {
      lines.push(`- ${String(event.name ?? 'incident')} · ${String(event.status ?? '?')} · ${String(event.impact ?? '?')}`)
    }
  }
  if (scheduledMaintenances.length > 0) {
    lines.push('', pc.bold('Scheduled Maintenance'))
    for (const event of scheduledMaintenances.slice(0, 5)) {
      lines.push(`- ${String(event.name ?? 'maintenance')} · ${String(event.status ?? '?')} · ${String(event.scheduledFor ?? event.startedAt ?? '')}`)
    }
  }

  lines.push('', pc.bold('Components'))
  if (components.length === 0) {
    lines.push(pc.yellow('No DigitalOcean components matched this query and status filter.'))
    lines.push(`${pc.dim('try')} public-apis apis run digitaloceanstatus.summary -- --component-query API --component-limit 50`)
    return lines.join('\n')
  }
  for (const component of components.slice(0, 30)) {
    const group = component.group === true
      ? `group${typeof component.componentCount === 'number' ? ` · ${String(component.componentCount)} child component(s)` : ''}`
      : typeof component.groupName === 'string'
        ? `group ${component.groupName}`
        : typeof component.groupId === 'string'
          ? `group ${component.groupId}`
          : undefined
    lines.push(`- ${String(component.name ?? 'component')} · ${String(component.status ?? 'unknown')}${group !== undefined ? ` · ${group}` : ''}`)
  }
  if (components.length > 30) {
    lines.push(pc.dim(`… ${components.length - 30} more component(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('next')} public-apis apis run digitaloceanstatus.incidents -- --scope unresolved`)
  return lines.join('\n')
}

function renderDigitalOceanStatusEvents(value: Record<string, unknown>): string {
  const api = isRecord(value.api) ? value.api : {}
  const query = isRecord(value.query) ? value.query : {}
  const page = isRecord(value.page) ? value.page : {}
  const events = Array.isArray(value.events) ? value.events.filter(isRecord) : []
  const isMaintenance = value.kind === 'digitaloceanstatus.maintenances'
  const title = isMaintenance ? 'DigitalOcean Scheduled Maintenances' : 'DigitalOcean Incidents'
  const empty = isMaintenance ? 'No DigitalOcean scheduled maintenances matched this scope.' : 'No DigitalOcean incidents matched this scope.'
  const next = isMaintenance
    ? 'public-apis apis run digitaloceanstatus.summary -- --component-limit 50'
    : 'public-apis apis run digitaloceanstatus.maintenances -- --scope upcoming'
  const lines = [
    `${pc.bold(pc.cyan(title))} ${pc.dim(String(api.endpoint ?? 'GET /statuspage-feed.json'))}`,
    `${pc.dim('mode')} ${formatStorageMode(value)} · open REST API only · no auth · no Chrome clickstream`,
    `${pc.dim('query')} ${formatQuery(query)}`,
    `${pc.dim('count')} ${String(value.count ?? events.length)} event(s) shown · limit cap ${String(api.limitCap ?? 100)}`,
    `${pc.dim('rate')} ${String(api.rateLimit ?? 'not documented')} · ${String(api.cacheControl ?? 'cache-control not projected')}`,
  ]
  if (typeof page.updatedAt === 'string') {
    lines.push(`${pc.dim('updated')} ${page.updatedAt}`)
  }
  if (events.length === 0) {
    lines.push('', pc.yellow(empty))
    lines.push(`${pc.dim('next')} ${next}`)
    return lines.join('\n')
  }

  for (const event of events.slice(0, 20)) {
    const components = Array.isArray(event.componentNames) ? event.componentNames.filter((name): name is string => typeof name === 'string') : []
    lines.push('', `${pc.bold(String(event.name ?? 'event'))} · ${String(event.status ?? '?')} · ${String(event.impact ?? '?')}`)
    const timing = [
      event.scheduledFor,
      event.scheduledUntil,
      event.startedAt,
      event.resolvedAt,
      event.updatedAt,
    ].filter((entry): entry is string => typeof entry === 'string' && entry.trim() !== '')
    if (timing.length > 0) {
      lines.push(pc.dim(timing.join(' → ')))
    }
    if (components.length > 0) {
      lines.push(`components: ${formatDigitalOceanComponentNames(components)}`)
    }
    const latest = isRecord(event.latestUpdate) ? event.latestUpdate : {}
    if (typeof latest.body === 'string') {
      lines.push(wrapLine(latest.body.replace(/\s+/gu, ' '), 140))
    }
    if (typeof event.shortlink === 'string') {
      lines.push(pc.blue(event.shortlink))
    }
  }
  if (events.length > 20) {
    lines.push(pc.dim(`… ${events.length - 20} more event(s); use --format json for full output.`))
  }
  lines.push('', `${pc.dim('next')} ${next}`)
  return lines.join('\n')
}

function formatDigitalOceanComponentNames(componentNames: string[]): string {
  const counts = new Map<string, number>()
  for (const componentName of componentNames) {
    counts.set(componentName, (counts.get(componentName) ?? 0) + 1)
  }
  const compactNames = Array.from(counts.entries()).map(([componentName, count]) => count > 1 ? `${componentName} ×${count}` : componentName)
  return `${compactNames.slice(0, 8).join(', ')}${compactNames.length > 8 ? ` +${compactNames.length - 8}` : ''}`
}

function formatMetMuseumObjectLines(object: Record<string, unknown>): string[] {
  const title = String(object.title ?? '(untitled)')
  const summary = [
    object.objectName,
    object.artistDisplayName,
    object.objectDate,
    object.department,
    object.isPublicDomain === true ? 'public domain' : 'rights restricted/unknown',
  ].filter(part => typeof part === 'string' && part.trim() !== '').join(' · ')
  const lines = [
    '',
    `${pc.bold(`${String(object.objectId ?? '?')}. ${title}`)}`,
  ]
  if (summary !== '') {
    lines.push(pc.dim(summary))
  }
  if (typeof object.medium === 'string' && object.medium.trim() !== '') {
    lines.push(`medium: ${object.medium}`)
  }
  if (typeof object.primaryImageSmall === 'string') {
    lines.push(`image: ${pc.blue(object.primaryImageSmall)}`)
  }
  if (typeof object.objectUrl === 'string') {
    lines.push(`page: ${pc.blue(object.objectUrl)}`)
  }
  return lines
}

function firstNameFromNamedays(entry: Record<string, unknown> | undefined): string {
  if (entry === undefined || typeof entry.names !== 'string') {
    return 'John'
  }
  const [firstName] = entry.names.split(',').map(name => name.trim()).filter(name => name !== '' && name !== 'n/a')
  return firstName ?? 'John'
}

function readNamedaysDateParts(query: Record<string, unknown>, api: Record<string, unknown>): { day: number; month: number } {
  const day = typeof query.day === 'number'
    ? query.day
    : typeof api.defaultDay === 'number'
      ? api.defaultDay
      : new Date().getDate()
  const month = typeof query.month === 'number'
    ? query.month
    : typeof api.defaultMonth === 'number'
      ? api.defaultMonth
      : new Date().getMonth() + 1
  return { day, month }
}

function shiftNamedaysDate(date: { day: number; month: number }, deltaDays: number): { day: number; month: number } {
  const parsed = new Date(Date.UTC(2024, date.month - 1, date.day))
  parsed.setUTCDate(parsed.getUTCDate() + deltaDays)
  return {
    day: parsed.getUTCDate(),
    month: parsed.getUTCMonth() + 1,
  }
}

function buildNamedaysDateCommand(
  date: { day: number; month: number },
  options: { country?: string | undefined; limit?: number | undefined } = {},
): string {
  const parts = ['public-apis apis run namedays.date --', `--day ${String(date.day)}`, `--month ${String(date.month)}`]
  if (typeof options.country === 'string' && options.country.trim() !== '') {
    parts.push(`--country ${formatCliArg(options.country)}`)
  }
  if (typeof options.limit === 'number') {
    parts.push(`--limit ${String(options.limit)}`)
  }
  return parts.join(' ')
}

function buildNamedaysNameCommand(name: string, country?: string | undefined): string {
  const parts = ['public-apis apis run namedays.name --', `--name ${formatCliArg(name)}`]
  if (typeof country === 'string' && country.trim() !== '') {
    parts.push(`--country ${formatCliArg(country)}`)
  }
  return parts.join(' ')
}

function formatStorageMode(value: Record<string, unknown>): string {
  const storage = isRecord(value.storage) ? value.storage : {}
  const mode = typeof storage.mode === 'string' ? storage.mode : 'online'
  const persisted = storage.persisted === true ? 'persisted' : 'not persisted'
  const cachedAt = typeof storage.cachedAt === 'string' ? ` · cached ${storage.cachedAt}` : ''
  return `${mode} · ${persisted}${cachedAt}`
}

function renderPublicApisList(value: Record<string, unknown>): string {
  const providers = Array.isArray(value.providers) ? value.providers.filter(isRecord) : []
  const operations = Array.isArray(value.operations) ? value.operations.filter(isRecord) : []
  const lines = [
    pc.bold(pc.cyan('Public APIs')),
    `${pc.dim('providers')} ${String(value.providerCount ?? providers.length)} · ${pc.dim('operations')} ${String(value.operationCount ?? operations.length)}`,
    '',
    pc.bold('Providers'),
  ]

  for (const provider of providers) {
    const auth = isRecord(provider.auth) ? provider.auth.mode : 'unknown'
    lines.push(`- ${String(provider.id)} — ${String(provider.name)} (${String(provider.publicApisCategory ?? 'uncategorized')}, auth: ${String(auth)})`)
  }

  lines.push('', pc.bold('Operations'))
  if (operations.length === 0) {
    lines.push('No public API operations configured.')
  } else {
    for (const operation of operations) {
      lines.push(`- ${String(operation.id)} · ${String(operation.command)} · ${String(operation.description)}`)
    }
  }

  lines.push('', `${pc.dim('next')} public-apis apis info <provider-or-operation>`)
  lines.push(`${pc.dim('run')} public-apis apis run <operation> -- <operation-options>`)
  return lines.join('\n')
}

function renderPublicApisInfo(value: Record<string, unknown>): string {
  const provider = isRecord(value.provider) ? value.provider : {}
  const operations = Array.isArray(value.operations) ? value.operations.filter(isRecord) : []
  const endpoints = Array.isArray(value.endpoints) ? value.endpoints.filter(isRecord) : []
  const auth = isRecord(provider.auth) ? provider.auth : {}
  const lines = [
    `${pc.bold(pc.cyan(String(provider.name ?? provider.id ?? 'Public API')))} ${pc.dim(String(provider.id ?? ''))}`,
    String(provider.description ?? ''),
    `${pc.dim('category')} ${String(provider.publicApisCategory ?? 'unknown')} · ${pc.dim('auth')} ${String(auth.mode ?? 'unknown')}`,
  ]

  if (typeof provider.docsUrl === 'string') {
    lines.push(`${pc.dim('docs')} ${provider.docsUrl}`)
  }

  if (operations.length > 0) {
    lines.push('', pc.bold('Operations'))
    for (const operation of operations) {
      lines.push(`- ${String(operation.id)} · ${String(operation.command)} · ${String(operation.description)}`)
      const cli = isRecord(operation.cli) ? operation.cli : {}
      const options = Array.isArray(cli.options) ? cli.options.filter(isRecord) : []
      lines.push(`  CLI options: ${String(cli.exposedOptionCount ?? options.length)} exposed / ${String(cli.optionCount ?? options.length)} documented`)
      const groupedOptions = groupRecordsByString(options, 'group')
      for (const [group, entries] of groupedOptions) {
        lines.push(`  ${group}: ${entries.map(entry => `${String(entry.flag)} (${String(entry.exposure)})`).join(', ')}`)
      }
    }
  }
  if (operations.length === 0) {
    lines.push('', 'No operations configured for this provider.')
  }

  if (endpoints.length > 0) {
    lines.push('', pc.bold('Endpoints'))
    for (const endpoint of endpoints) {
      lines.push(`- ${String(endpoint.method ?? 'GET')} ${String(endpoint.urlPattern)} (${String(endpoint.evidenceStatus ?? 'unknown')})`)
    }
  }

  lines.push('', `${pc.dim('help')} public-apis apis run <operation> --help`)
  lines.push(`${pc.dim('run')} public-apis apis run <operation> -- <operation-options>`)

  return lines.filter(line => line !== '').join('\n')
}

function renderPublicApisConfig(value: Record<string, unknown>): string {
  const config = isRecord(value.config) ? value.config : {}
  const persistence = isRecord(config.persistence) ? config.persistence : {}
  const secretNames = isRecord(config.secrets) ? Object.keys(config.secrets).sort() : []
  return [
    `${pc.bold(pc.cyan('Public API Config'))} ${String(value.providerId ?? '')}`,
    `${pc.dim('config')} ${String(value.configFile ?? '')}`,
    `${pc.dim('sqlite')} ${String(value.databaseFile ?? '')}`,
    `${pc.dim('persistence')} ${persistence.enabled === true ? 'enabled' : 'disabled'}`,
    `${pc.dim('default mode')} ${String(persistence.defaultMode ?? 'online')}`,
    `${pc.dim('secrets')} ${secretNames.length > 0 ? secretNames.map(name => `${name}=<redacted>`).join(', ') : 'none'}`,
    '',
    `${pc.dim('secret')} public-apis apis config ${String(value.providerId ?? '<provider>')} --set-secret NAME=value`,
    `${pc.dim('next')} public-apis ${String(value.providerId ?? '<provider>')} <operation> --online --persist`,
    `${pc.dim('run')} public-apis apis run <operation> --online --persist -- <operation-options>`,
    `${pc.dim('offline')} public-apis ${String(value.providerId ?? '<provider>')} <operation> --offline`,
  ].join('\n')
}

function renderPublicApisCacheList(value: Record<string, unknown>): string {
  const entries = Array.isArray(value.entries) ? value.entries.filter(isRecord) : []
  const lines = [
    `${pc.bold(pc.cyan('Public API Cache'))} ${String(value.providerId ?? '')}`,
    `${pc.dim('operation')} ${String(value.operationId ?? 'all')}`,
    `${pc.dim('entries')} ${entries.length}`,
  ]

  if (entries.length === 0) {
    lines.push('', 'No cached results found for this target.')
    lines.push(`${pc.dim('try')} public-apis apis run <operation> --online --persist -- <operation-options>`)
    return lines.join('\n')
  }

  for (const entry of entries) {
    lines.push(
      '',
      `${pc.bold(String(entry.operationId ?? 'operation'))} · ${String(entry.fetchedAt ?? 'unknown time')} · ${String(entry.resultBytes ?? 0)} bytes`,
      `${pc.dim('query')} ${String(entry.querySummary ?? entry.queryKey ?? '{}')}`,
    )
  }

  lines.push('', `${pc.dim('clear')} public-apis apis cache clear ${String(value.operationId ?? value.providerId ?? '<target>')}`)
  return lines.join('\n')
}

function renderPublicApisCacheClear(value: Record<string, unknown>): string {
  const cleared = typeof value.cleared === 'number' ? value.cleared : 0
  return [
    `${pc.bold(pc.cyan('Public API Cache Cleared'))} ${String(value.providerId ?? '')}`,
    `${pc.dim('operation')} ${String(value.operationId ?? 'all')}`,
    `${pc.dim('cleared')} ${cleared} entr${cleared === 1 ? 'y' : 'ies'}`,
  ].join('\n')
}

function renderSystemDescription(value: Record<string, unknown>): string {
  const commands = Array.isArray(value.commands) ? value.commands : []
  const rpcMethods = Array.isArray(value.rpcMethods) ? value.rpcMethods : []
  const registry = isRecord(value.registry) ? value.registry : {}
  const publicApis = isRecord(value.publicApis) ? value.publicApis : {}
  return [
    `${pc.bold(pc.cyan('Public APIs CLI'))} ${String(value.version ?? '')}`,
    `${pc.dim('package')} ${String(value.name ?? 'unknown')}`,
    `${pc.dim('default site')} ${String(registry.defaultSiteId ?? 'unknown')}`,
    `${pc.dim('public APIs')} ${String(publicApis.providerCount ?? 0)} provider(s), ${String(publicApis.operationCount ?? 0)} operation(s)`,
    `${pc.dim('commands')} ${commands.length}`,
    `${pc.dim('RPC methods')} ${rpcMethods.length}`,
    '',
    `${pc.dim('next')} public-apis apis list`,
    `${pc.dim('json')} public-apis describe --format json`,
  ].join('\n')
}

function renderSites(value: Record<string, unknown>): string {
  const sites = Array.isArray(value.sites) ? value.sites.filter(isRecord) : []
  const lines = [
    pc.bold(pc.cyan('Configured Sites')),
    `${pc.dim('default')} ${String(value.defaultSiteId ?? 'unknown')}`,
  ]

  for (const site of sites) {
    const auth = isRecord(site.auth) ? site.auth.mode : 'unknown'
    const roles = Array.isArray(site.roles) ? site.roles.join(',') : ''
    lines.push(`- ${String(site.id)} — ${String(site.name)} · auth=${String(auth)} · roles=${roles}`)
    lines.push(`  ${String(site.baseUrl ?? '')}`)
  }
  if (sites.length === 0) {
    lines.push('', 'No sites configured.')
  }

  return lines.join('\n')
}

function renderWorkflows(value: Record<string, unknown>): string {
  const workflows = Array.isArray(value.workflows) ? value.workflows.filter(isRecord) : []
  const lines = [pc.bold(pc.cyan('Workflows'))]
  for (const workflow of workflows) {
    const steps = Array.isArray(workflow.steps) ? workflow.steps.filter(isRecord) : []
    lines.push(`- ${String(workflow.id)} — ${String(workflow.name)}`)
    lines.push(`  ${String(workflow.description ?? '')}`)
    if (steps.length > 0) {
      lines.push(`  steps: ${steps.map(step => String(step.id ?? step.kind ?? 'step')).join(' -> ')}`)
    }
  }
  if (workflows.length === 0) {
    lines.push('', 'No workflows configured.')
  }

  return lines.join('\n')
}

function renderEndpoints(value: Record<string, unknown>): string {
  const endpoints = Array.isArray(value.endpoints) ? value.endpoints.filter(isRecord) : []
  const lines = [
    pc.bold(pc.cyan('Endpoint Catalog')),
    `${pc.dim('records')} ${endpoints.length}`,
  ]

  for (const endpoint of endpoints) {
    lines.push(`- ${String(endpoint.id)} · ${String(endpoint.method ?? 'GET')} ${String(endpoint.urlPattern)}`)
    lines.push(`  ${String(endpoint.description ?? '')}`)
    if (typeof endpoint.evidenceStatus === 'string') {
      lines.push(`  evidence: ${endpoint.evidenceStatus}`)
    }
  }
  if (endpoints.length === 0) {
    lines.push('', 'No endpoints configured.')
  }

  return lines.join('\n')
}

function isSystemDescription(value: unknown): value is Record<string, unknown> {
  return isRecord(value) && Array.isArray(value.commands) && Array.isArray(value.rpcMethods) && isRecord(value.registry)
}

function isSitesResult(value: unknown): value is Record<string, unknown> {
  return isRecord(value) && typeof value.defaultSiteId === 'string' && Array.isArray(value.sites)
}

function isWorkflowsResult(value: unknown): value is Record<string, unknown> {
  return isRecord(value) && Array.isArray(value.workflows)
}

function isEndpointsResult(value: unknown): value is Record<string, unknown> {
  return isRecord(value) && Array.isArray(value.endpoints)
}

function formatQuery(query: Record<string, unknown>): string {
  const entries = Object.entries(query)
    .filter(([, value]) => value !== undefined && value !== '' && (!Array.isArray(value) || value.length > 0))
    .map(([key, value]) => `${key}=${Array.isArray(value) ? value.join(',') : String(value)}`)

  return entries.length > 0 ? entries.join(' ') : 'default parameters'
}

function formatCliArg(value: unknown): string {
  const text = String(value ?? '')
  return /^[A-Za-z0-9._/:@%+=,-]+$/u.test(text) ? text : `'${text.replaceAll("'", "'\\''")}'`
}

function formatCrossrefRateLimit(rateLimit: Record<string, unknown>): string {
  const limit = typeof rateLimit.limit === 'string' ? rateLimit.limit : '?'
  const interval = typeof rateLimit.interval === 'string' ? rateLimit.interval : '?'
  const concurrency = typeof rateLimit.concurrencyLimit === 'string' ? rateLimit.concurrencyLimit : '?'
  const pool = typeof rateLimit.apiPool === 'string' ? rateLimit.apiPool : 'public'
  return `${limit}/${interval} · concurrency ${concurrency} · ${pool}`
}

function formatGenericRateLimit(rateLimit: Record<string, unknown>, fallback: string): string {
  const limit = typeof rateLimit.limit === 'string' ? rateLimit.limit : undefined
  const remaining = typeof rateLimit.remaining === 'string' ? rateLimit.remaining : undefined
  const reset = typeof rateLimit.reset === 'string' ? rateLimit.reset : undefined
  if (limit === undefined && remaining === undefined && reset === undefined) {
    return fallback
  }
  return `limit ${limit ?? '?'} · remaining ${remaining ?? '?'} · reset ${reset ?? '?'}`
}

function formatAgifyRateLimit(rateLimit: Record<string, unknown>): string {
  const limit = typeof rateLimit.limit === 'string' ? rateLimit.limit : '?'
  const remaining = typeof rateLimit.remaining === 'string' ? rateLimit.remaining : '?'
  const reset = typeof rateLimit.reset === 'string' ? rateLimit.reset : undefined
  return `remaining ${remaining} / ${limit} · reset ${formatDurationSeconds(reset)}`
}

function formatDurationSeconds(value: unknown): string {
  if (typeof value !== 'string' && typeof value !== 'number') {
    return '?'
  }
  const seconds = typeof value === 'number' ? value : Number.parseInt(value, 10)
  if (!Number.isFinite(seconds) || seconds < 0) {
    return String(value)
  }
  const hours = Math.floor(seconds / 3600)
  const minutes = Math.floor((seconds % 3600) / 60)
  if (hours > 0) {
    return `${String(hours)}h ${String(minutes)}m`
  }
  if (minutes === 0 && seconds > 0) {
    return '<1m'
  }
  return `${String(minutes)}m`
}

function formatAgifyConfidence(age: unknown, count: number): string {
  if (age === null || count === 0) {
    return 'no estimate available yet; try a common first name or remove the country filter'
  }
  if (count < 100) {
    return 'low sample count; compare without country filter before relying on this estimate'
  }
  if (count < 1000) {
    return 'moderate sample count; useful for exploration, not identity verification'
  }
  return 'large sample count; use as demographic estimate, not as identity or eligibility evidence'
}

function buildAgifyCommand(query: { name: string; countryId?: string | undefined }): string {
  const parts = ['public-apis apis run agify.age --', `--name ${formatCliArg(query.name)}`]
  if (typeof query.countryId === 'string' && query.countryId.trim() !== '') {
    parts.push(`--country-id ${formatCliArg(query.countryId)}`)
  }
  return parts.join(' ')
}

function buildAgifyCompareCommand(query: { name: string; countryId?: string | undefined }): string {
  if (typeof query.countryId === 'string' && query.countryId.trim() !== '') {
    return buildAgifyCommand({ name: query.name })
  }
  return buildAgifyCommand({ name: query.name, countryId: 'US' })
}

function formatMatrixShape(value: unknown): string {
  if (!Array.isArray(value)) {
    return 'default'
  }
  const rowCount = value.length
  const columnCount = Array.isArray(value[0]) ? value[0].length : 0
  return `${rowCount}x${columnCount}`
}

function formatVectorShape(value: unknown): string {
  return Array.isArray(value) ? `${value.length}` : 'none'
}

function formatArrayPreview(value: unknown): string {
  if (!Array.isArray(value) || value.length === 0) {
    return '-'
  }
  return value.slice(0, 5).map(entry => String(entry)).join(', ')
}

function formatInteger(value: unknown): string {
  return typeof value === 'number' && Number.isFinite(value) ? new Intl.NumberFormat('en-US').format(value) : '-'
}

function formatIntegerOrText(value: unknown): string {
  if (typeof value === 'number' && Number.isFinite(value)) {
    return new Intl.NumberFormat('en-US').format(value)
  }
  return typeof value === 'string' && value.trim() !== '' ? value : '-'
}

function formatCurrency(value: unknown): string {
  return typeof value === 'number' && Number.isFinite(value) ? new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(value) : '-'
}

function formatCurrencyMyr(value: unknown): string {
  return typeof value === 'number' && Number.isFinite(value) ? new Intl.NumberFormat('en-MY', { style: 'currency', currency: 'MYR', maximumFractionDigits: 0 }).format(value) : '-'
}

function formatOpenCollectiveMoney(value: unknown): string {
  if (!isRecord(value) || typeof value.valueInCents !== 'number' || typeof value.currency !== 'string') {
    return '-'
  }
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: value.currency, maximumFractionDigits: 0 }).format(value.valueInCents / 100)
}

function formatNumber(value: unknown): string {
  return typeof value === 'number' && Number.isFinite(value) ? new Intl.NumberFormat('en-US', { maximumFractionDigits: 2 }).format(value) : '-'
}

function formatHkoValueUnit(value: unknown): string {
  if (!isRecord(value)) {
    return String(value ?? '?')
  }
  const rawValue = value.value ?? '?'
  const unit = typeof value.unit === 'string' ? value.unit : ''
  const normalizedUnit = unit === 'percent' ? '%' : unit
  return `${String(rawValue)}${normalizedUnit}`
}

function formatPercent(value: unknown): string {
  return typeof value === 'number' && Number.isFinite(value) ? `${Math.round(value * 100)}%` : 'unknown'
}

function formatPercentDecimal(value: unknown): string {
  return typeof value === 'number' && Number.isFinite(value) ? `${new Intl.NumberFormat('en-US', { maximumFractionDigits: 1 }).format(value * 100)}%` : 'unknown'
}

function formatBooleanBadge(value: unknown): string {
  if (typeof value !== 'boolean') {
    return 'unknown'
  }
  return value ? 'yes' : 'no'
}

function formatBytes(value: unknown): string {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    return '-'
  }
  const units = ['B', 'KB', 'MB', 'GB', 'TB', 'PB']
  let size = value
  let unitIndex = 0
  while (size >= 1024 && unitIndex < units.length - 1) {
    size /= 1024
    unitIndex += 1
  }
  return `${size.toFixed(size >= 10 || unitIndex === 0 ? 0 : 1)} ${units[unitIndex]}`
}

function wrapLine(value: string, width: number): string {
  if (value.length <= width) {
    return value
  }

  return `${value.slice(0, width - 1).trimEnd()}…`
}

function wrapText(value: string, width: number): string {
  const paragraphs = value
    .split(/\n+/u)
    .map(paragraph => paragraph.trim())
    .filter(paragraph => paragraph !== '')

  if (paragraphs.length === 0) {
    return ''
  }

  return paragraphs.map(paragraph => wrapParagraph(paragraph, width)).join('\n')
}

function wrapParagraph(value: string, width: number): string {
  const words = value.replace(/\s+/gu, ' ').trim().split(' ')
  const lines: string[] = []
  let currentLine = ''

  for (const word of words) {
    if (currentLine === '') {
      currentLine = word
      continue
    }
    if (`${currentLine} ${word}`.length > width) {
      lines.push(currentLine)
      currentLine = word
      continue
    }
    currentLine = `${currentLine} ${word}`
  }

  if (currentLine !== '') {
    lines.push(currentLine)
  }
  return lines.join('\n')
}

function quoteCliArg(value: string): string {
  if (/^[A-Za-z0-9._:/-]+$/u.test(value)) {
    return value
  }
  return `"${value.replace(/(["\\$`])/gu, '\\$1')}"`
}

function buildBibleRandomCommand(query: Record<string, unknown>, translationId: string): string {
  const parts = ['public-apis apis run bibleapi.random --', '--translation', translationId]
  if (typeof query.book === 'string' && query.book.trim() !== '') {
    parts.push('--book', query.book)
  }
  if (typeof query.chapter === 'number') {
    parts.push('--chapter', String(query.chapter))
  }
  return parts.join(' ')
}

function buildCrossrefWorksCommand(query: Record<string, unknown>, offset: number): string {
  const parts = [
    'public-apis apis run crossref.works --',
    '--query',
    quoteCliArg(String(query.query ?? 'metadata')),
    '--rows',
    String(typeof query.rows === 'number' ? query.rows : 20),
    '--offset',
    String(offset),
  ]
  if (typeof query.filter === 'string' && query.filter.trim() !== '') {
    parts.push('--filter', quoteCliArg(query.filter))
  }
  if (typeof query.sort === 'string' && query.sort.trim() !== '') {
    parts.push('--sort', quoteCliArg(query.sort))
  }
  if (query.order === 'asc' || query.order === 'desc') {
    parts.push('--order', query.order)
  }
  return parts.join(' ')
}

function buildArxivSearchCommand(
  query: Record<string, unknown>,
  start: number,
): string {
  const parts = [
    'public-apis apis run arxiv.search --',
    '--query',
    formatCliArg(query.searchQuery ?? 'all:electron'),
    '--max-results',
    String(typeof query.maxResults === 'number' ? query.maxResults : 10),
    '--start',
    String(start),
  ]
  if (typeof query.category === 'string' && query.category.trim() !== '') {
    parts.push('--category', formatCliArg(query.category))
  }
  if (typeof query.sortBy === 'string' && query.sortBy !== 'relevance') {
    parts.push('--sort-by', formatCliArg(query.sortBy))
  }
  if (typeof query.sortOrder === 'string' && query.sortOrder !== 'descending') {
    parts.push('--sort-order', formatCliArg(query.sortOrder))
  }
  return parts.join(' ')
}

function buildArxivPaperCommand(id: string): string {
  return `public-apis apis run arxiv.paper -- --id ${formatCliArg(id)}`
}

function buildGutendexBooksCommand(query: Record<string, unknown>, page: number): string {
  const parts = ['public-apis apis run gutendex.books --']
  if (typeof query.search === 'string' && query.search.trim() !== '') {
    parts.push('--search', quoteCliArg(query.search))
  }
  if (typeof query.topic === 'string' && query.topic.trim() !== '') {
    parts.push('--topic', quoteCliArg(query.topic))
  }
  if (typeof query.languages === 'string' && query.languages.trim() !== '') {
    parts.push('--languages', quoteCliArg(query.languages))
  }
  if (typeof query.sort === 'string' && query.sort.trim() !== '') {
    parts.push('--sort', query.sort)
  }
  if (typeof query.ids === 'string' && query.ids.trim() !== '') {
    parts.push('--ids', quoteCliArg(query.ids))
  }
  parts.push('--page', String(Math.max(1, page)))
  return parts.join(' ')
}

function buildOpenLibrarySearchCommand(query: Record<string, unknown>, offset: number): string {
  const parts = ['public-apis apis run openlibrary.search --']
  for (const [flag, value] of [
    ['--query', query.query],
    ['--title', query.title],
    ['--author', query.author],
    ['--subject', query.subject],
    ['--language', query.language],
    ['--ebook-access', query.ebookAccess],
    ['--sort', query.sort],
  ] as const) {
    if (typeof value === 'string' && value.trim() !== '') {
      parts.push(flag, quoteCliArg(value))
    }
  }
  if (typeof query.hasFulltext === 'boolean') {
    parts.push('--has-fulltext', String(query.hasFulltext))
  }
  parts.push('--offset', String(Math.max(0, offset)))
  parts.push('--limit', String(typeof query.limit === 'number' ? query.limit : 100))
  return parts.join(' ')
}

function stripHtml(value: string): string {
  return value.replace(/<[^>]*>/gu, ' ').replace(/\s+/gu, ' ').trim()
}

function stripMarkdownImages(value: string): string {
  return value.replace(/!\[[^\]]*\]\([^)]*\)/gu, ' ').replace(/https?:\/\/\S+\.(?:png|jpe?g|gif|webp)(?:\?\S*)?/giu, ' ')
}

function truncateText(value: string, maxLength: number): string {
  return value.length > maxLength ? `${value.slice(0, Math.max(0, maxLength - 1))}…` : value
}

function readStringList(value: unknown): string[] {
  return Array.isArray(value)
    ? value
      .map(String)
      .filter(entry => entry.trim() !== '')
    : []
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return value !== null && typeof value === 'object' && !Array.isArray(value)
}

function groupRecordsByString(records: Record<string, unknown>[], key: string): Map<string, Record<string, unknown>[]> {
  const grouped = new Map<string, Record<string, unknown>[]>()
  for (const record of records) {
    const group = typeof record[key] === 'string' ? record[key] : 'options'
    grouped.set(group, [...(grouped.get(group) ?? []), record])
  }

  return grouped
}
